import { NextRequest, NextResponse } from 'next/server'
import { createClient as createAdminClient } from '@supabase/supabase-js'
import { createClient } from '@/lib/supabase/server'
import { sendEmail } from '@/lib/email'
import { getEventAccessForUser } from '@/lib/event-team'
import { eventUpdateEmail, eventFollowUpEmail, eventReminderEmail } from '@/lib/email-templates'
import { createBulkNotifications, type CreateNotificationParams } from '@/lib/notifications'

const supabaseAdmin = createAdminClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_ROLE_KEY!
)

const INFO_FROM_EMAIL = process.env.INFO_FROM_EMAIL || 'Ziyawa <info@zande.io>'
const INFO_REPLY_TO = process.env.INFO_EMAIL || process.env.SUPPORT_EMAIL || 'support@zande.io'

type AudienceFilter = 'all' | 'paid' | 'guest_list' | 'checked_in' | 'not_checked_in'
type CampaignType = 'event_update' | 'event_reminder' | 'review_request'

interface UnifiedAttendee {
  id: string
  source: 'ticket' | 'guest_pass'
  userId: string | null
  name: string
  email: string | null
  phone: string | null
  code: string
  entryType: string
  checkedIn: boolean
  checkedInAt: string | null
  createdAt: string
  pricePaid: number
  buyerName?: string | null
  buyerEmail?: string | null
  claimedAt?: string | null
  deliveryStatus?: string | null
}

function formatEventTime(startTime?: string | null) {
  if (!startTime) return 'TBA'
  try {
    return new Date(`1970-01-01T${startTime}`).toLocaleTimeString([], {
      hour: '2-digit',
      minute: '2-digit',
    })
  } catch {
    return startTime
  }
}

async function getAuthorizedEvent(eventId: string, userId: string) {
  const access = await getEventAccessForUser(supabaseAdmin, eventId, userId)

  if (!access.event) {
    return { event: null, access, response: NextResponse.json({ error: 'Event not found' }, { status: 404 }) }
  }

  if (!access.isOwner && !access.permissions.canViewAttendees) {
    return { event: null, access, response: NextResponse.json({ error: 'Not authorized' }, { status: 403 }) }
  }

  return { event: access.event, access, response: null }
}

async function loadAttendees(_supabase: Awaited<ReturnType<typeof createClient>>, eventId: string) {
  let tickets: any[] = []

  const { data: enrichedTickets, error: enrichedTicketError } = await supabaseAdmin
    .from('tickets')
    .select('id, user_id, ticket_code, ticket_type, price_paid, is_used, used_at, created_at, buyer_name, buyer_email, attendee_name, attendee_email, attendee_phone, claimed_at, delivery_status')
    .eq('event_id', eventId)
    .order('created_at', { ascending: false })

  if (enrichedTicketError) {
    const { data: fallbackTickets, error: fallbackTicketError } = await supabaseAdmin
      .from('tickets')
      .select('id, user_id, ticket_code, ticket_type, price_paid, is_used, used_at, created_at')
      .eq('event_id', eventId)
      .order('created_at', { ascending: false })

    if (fallbackTicketError) {
      throw fallbackTicketError
    }

    tickets = fallbackTickets || []
  } else {
    tickets = enrichedTickets || []
  }

  const userIds = Array.from(new Set((tickets || []).map((ticket) => ticket.user_id as string | undefined).filter(Boolean)))
  const { data: profiles, error: profilesError } = userIds.length > 0
    ? await supabaseAdmin
        .from('profiles')
        .select('id, full_name, email, phone')
        .in('id', userIds)
    : { data: [], error: null }

  if (profilesError) {
    throw profilesError
  }

  const profilesById = new Map((profiles || []).map((profile) => [profile.id, profile]))

  const { data: passes, error: passError } = await supabaseAdmin
    .from('event_access_passes')
    .select('id, full_name, email, phone, code, pass_type, checked_in, checked_in_at, created_at')
    .eq('event_id', eventId)
    .order('created_at', { ascending: false })

  if (passError && passError.code !== 'PGRST205') {
    throw passError
  }

  const paidAttendees: UnifiedAttendee[] = (tickets || []).map((ticket) => {
    const profile = profilesById.get(String(ticket.user_id || ''))
    const buyerName = String(ticket.buyer_name || profile?.full_name || 'Ticket Buyer')
    const buyerEmail = ticket.buyer_email ? String(ticket.buyer_email) : (profile?.email || null)
    const attendeeName = String(ticket.attendee_name || profile?.full_name || buyerName)
    const attendeeEmail = ticket.attendee_email ? String(ticket.attendee_email) : (profile?.email || buyerEmail)
    const attendeePhone = ticket.attendee_phone ? String(ticket.attendee_phone) : (profile?.phone || null)

    return {
      id: String(ticket.id),
      source: 'ticket',
      userId: ticket.user_id ? String(ticket.user_id) : null,
      name: attendeeName,
      email: attendeeEmail,
      phone: attendeePhone,
      code: String(ticket.ticket_code || ''),
      entryType: String(ticket.ticket_type || 'General Admission'),
      checkedIn: Boolean(ticket.is_used),
      checkedInAt: ticket.used_at ? String(ticket.used_at) : null,
      createdAt: String(ticket.created_at || new Date().toISOString()),
      pricePaid: Number(ticket.price_paid || 0),
      buyerName,
      buyerEmail,
      claimedAt: ticket.claimed_at ? String(ticket.claimed_at) : null,
      deliveryStatus: ticket.delivery_status ? String(ticket.delivery_status) : null,
    }
  })

  const guestAttendees: UnifiedAttendee[] = (passes || []).map((pass) => ({
    id: pass.id,
    source: 'guest_pass',
    userId: null,
    name: pass.full_name || 'Guest',
    email: pass.email || null,
    phone: pass.phone || null,
    code: pass.code,
    entryType: pass.pass_type || 'guest_list',
    checkedIn: Boolean(pass.checked_in),
    checkedInAt: pass.checked_in_at || null,
    createdAt: pass.created_at,
    pricePaid: 0,
  }))

  const attendees = [...paidAttendees, ...guestAttendees].sort(
    (a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
  )

  const uniqueBuyers = new Set(
    paidAttendees.map((attendee) => attendee.userId || attendee.buyerEmail || attendee.email || attendee.code)
  ).size

  const stats = {
    totalPeople: attendees.length,
    paidTickets: paidAttendees.length,
    guestPasses: guestAttendees.length,
    checkedIn: attendees.filter((attendee) => attendee.checkedIn).length,
    pendingArrival: attendees.filter((attendee) => !attendee.checkedIn).length,
    uniqueBuyers,
    emailableContacts: new Set(
      attendees
        .map((attendee) => attendee.email?.trim().toLowerCase())
        .filter(Boolean)
    ).size,
  }

  return { attendees, stats }
}

function filterAudience(attendees: UnifiedAttendee[], audience: AudienceFilter) {
  switch (audience) {
    case 'paid':
      return attendees.filter((attendee) => attendee.source === 'ticket')
    case 'guest_list':
      return attendees.filter((attendee) => attendee.source === 'guest_pass')
    case 'checked_in':
      return attendees.filter((attendee) => attendee.checkedIn)
    case 'not_checked_in':
      return attendees.filter((attendee) => !attendee.checkedIn)
    default:
      return attendees
  }
}

export async function GET(
  _request: NextRequest,
  context: { params: Promise<{ id: string }> }
) {
  try {
    const { id: eventId } = await context.params
    const supabase = await createClient()

    const { data: { user } } = await supabase.auth.getUser()
    if (!user) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const authorized = await getAuthorizedEvent(eventId, user.id)
    if (authorized.response || !authorized.event) {
      return authorized.response as NextResponse
    }

    const { attendees, stats } = await loadAttendees(supabase, eventId)

    return NextResponse.json({
      event: authorized.event,
      attendees,
      stats,
    })
  } catch (error) {
    console.error('Attendees load error:', error)
    return NextResponse.json({ error: 'Failed to load attendees' }, { status: 500 })
  }
}

export async function POST(
  request: NextRequest,
  context: { params: Promise<{ id: string }> }
) {
  try {
    const { id: eventId } = await context.params
    const supabase = await createClient()

    const { data: { user } } = await supabase.auth.getUser()
    if (!user) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const authorized = await getAuthorizedEvent(eventId, user.id)
    if (authorized.response || !authorized.event) {
      return authorized.response as NextResponse
    }

    if (!authorized.access.isOwner && !authorized.access.permissions.canSendEventUpdates) {
      return NextResponse.json({ error: 'Not authorized to send event updates' }, { status: 403 })
    }

    const body = await request.json()
    const subject = String(body.subject || '').trim()
    const message = String(body.message || '').trim()
    const audience = (body.audience || 'all') as AudienceFilter
    const campaignType = (body.campaignType || 'event_update') as CampaignType

    if (!subject || !message) {
      return NextResponse.json({ error: 'Subject and message are required' }, { status: 400 })
    }

    const { attendees } = await loadAttendees(supabase, eventId)
    const filtered = filterAudience(attendees, audience)

    const recipients = new Map<string, { email: string; name: string; userId: string | null }>()
    for (const attendee of filtered) {
      const normalizedEmail = attendee.email?.trim().toLowerCase()
      if (!normalizedEmail) continue
      if (!recipients.has(normalizedEmail)) {
        recipients.set(normalizedEmail, {
          email: attendee.email!,
          name: attendee.name,
          userId: attendee.userId,
        })
      }
    }

    const recipientList = Array.from(recipients.values())
    if (recipientList.length === 0) {
      return NextResponse.json({ error: 'No attendees with email addresses match this filter' }, { status: 400 })
    }

    const appUrl = process.env.NEXT_PUBLIC_APP_URL || 'https://ziyawa.vercel.app'
    const eventUrl = `${appUrl}/events/${eventId}`
    const formattedEventDate = authorized.event.event_date
      ? new Date(authorized.event.event_date).toLocaleDateString('en-ZA', {
          weekday: 'short',
          day: 'numeric',
          month: 'long',
          year: 'numeric',
        })
      : 'TBA'
    const formattedEventTime = formatEventTime(authorized.event.start_time)

    let sentCount = 0
    let failedCount = 0
    const notifications: CreateNotificationParams[] = []

    for (const recipient of recipientList) {
      const firstName = recipient.name?.split(' ')[0] || 'there'

      let html = ''
      let notificationType: 'event_updated' | 'event_reminder' | 'review_requested' = 'event_updated'

      if (campaignType === 'event_reminder') {
        notificationType = 'event_reminder'
        html = eventReminderEmail({
          recipientName: firstName,
          eventName: authorized.event.title,
          eventDate: formattedEventDate,
          eventTime: formattedEventTime,
          eventLocation: authorized.event.venue || 'Venue to be confirmed',
          eventUrl,
        })
      } else if (campaignType === 'review_request') {
        notificationType = 'review_requested'
        html = eventFollowUpEmail({
          recipientName: firstName,
          eventName: authorized.event.title,
          eventDate: formattedEventDate,
          message,
          reviewUrl: `${eventUrl}#reviews`,
          discoverUrl: `${appUrl}/events`,
        })
      } else {
        notificationType = 'event_updated'
        html = eventUpdateEmail({
          recipientName: firstName,
          eventName: authorized.event.title,
          eventDate: formattedEventDate,
          eventTime: formattedEventTime,
          eventLocation: authorized.event.venue || 'Venue to be confirmed',
          message,
          eventUrl,
        })
      }

      const emailResult = await sendEmail({
        from: INFO_FROM_EMAIL,
        replyTo: INFO_REPLY_TO,
        to: recipient.email,
        subject,
        html,
        tags: [
          { name: 'category', value: 'event-attendees' },
          { name: 'campaign', value: campaignType },
        ],
      })

      if (emailResult.success) {
        sentCount += 1
        if (recipient.userId) {
          notifications.push({
            userId: recipient.userId,
            type: notificationType,
            title: subject,
            message,
            link: `/events/${eventId}`,
            eventId,
            sendEmail: false,
          })
        }
      } else {
        failedCount += 1
      }
    }

    if (notifications.length > 0) {
      await createBulkNotifications(notifications)
    }

    try {
      await supabaseAdmin.from('email_logs').insert({
        sender_id: user.id,
        recipient_ids: notifications.map((item) => item.userId),
        recipient_emails: recipientList.map((item) => item.email),
        subject,
        body: message,
        email_type: campaignType === 'review_request' ? 'automated' : 'bulk',
        status: failedCount === 0 ? 'sent' : sentCount > 0 ? 'pending' : 'failed',
      })
    } catch (logError) {
      console.error('Email log insert error:', logError)
    }

    return NextResponse.json({
      success: true,
      sentCount,
      failedCount,
      audience,
    })
  } catch (error) {
    console.error('Attendee email send error:', error)
    return NextResponse.json({ error: 'Failed to send attendee email' }, { status: 500 })
  }
}

/**
 * TICKET CHECK-IN API
 * POST /api/tickets/checkin
 * 
 * Marks a ticket as checked in
 */

import { NextRequest, NextResponse } from 'next/server';
import { createClient as createAdminClient } from '@supabase/supabase-js';
import { createClient } from '@/lib/supabase/server';
import { getEventAccessForUser } from '@/lib/event-team';

const supabaseAdmin = createAdminClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_ROLE_KEY!
);

function resolveScannedInput(value: string | null | undefined) {
  const raw = String(value || '').trim();

  if (!raw) {
    return { normalizedCode: null, parsedTicketId: null };
  }

  try {
    const parsed = JSON.parse(raw) as { code?: string; ticket?: string };
    return {
      normalizedCode: parsed.code ? String(parsed.code).trim().toUpperCase() : raw.toUpperCase(),
      parsedTicketId: parsed.ticket ? String(parsed.ticket).trim() : null,
    };
  } catch {
    return {
      normalizedCode: raw.toUpperCase(),
      parsedTicketId: null,
    };
  }
}

export async function POST(request: NextRequest) {
  try {
    const supabase = await createClient();

    // Get authenticated user
    const { data: { user }, error: authError } = await supabase.auth.getUser();
    
    if (authError || !user) {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    const body = await request.json();
    const { ticketCode, eventId, ticketId, selfCheckIn = false } = body;

    // Validate input - need either ticketCode or ticketId
    if (!ticketCode && !ticketId) {
      return NextResponse.json(
        { error: 'Ticket code or ticket ID is required' },
        { status: 400 }
      );
    }

    const { normalizedCode, parsedTicketId } = resolveScannedInput(ticketCode);

    let entryId = '';
    let entryCode = '';
    let entryType = '';
    let entryHolder = 'Guest';
    let entryCheckedIn = false;
    let entryCheckedInAt: string | null = null;
    let entryEventId = '';
    let organizerId = '';
    let eventDateValue = '';
    let entryUserId: string | null = null;
    let sourceTable: 'tickets' | 'event_access_passes' = 'tickets';

    // Try normal ticket first
    let ticketQuery = supabaseAdmin
      .from('tickets')
      .select(`
        id,
        ticket_code,
        ticket_type,
        is_used,
        used_at,
        event_id,
        user_id,
        events (
          id,
          title,
          event_date,
          organizer_id
        ),
        profiles:user_id (
          full_name
        )
      `);

    if (ticketId || parsedTicketId) {
      ticketQuery = ticketQuery.eq('id', ticketId || parsedTicketId);
    } else if (normalizedCode) {
      ticketQuery = ticketQuery.eq('ticket_code', normalizedCode);
    }

    const { data: ticket } = await ticketQuery.single();

    if (ticket) {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const event = ticket.events as any;
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const profile = ticket.profiles as any;

      entryId = ticket.id;
      entryCode = ticket.ticket_code;
      entryType = ticket.ticket_type;
      entryHolder = profile?.full_name || 'Guest';
      entryCheckedIn = ticket.is_used;
      entryCheckedInAt = ticket.used_at;
      entryEventId = ticket.event_id;
      organizerId = event?.organizer_id || '';
      eventDateValue = event?.event_date || '';
      entryUserId = ticket.user_id || null;
      sourceTable = 'tickets';
    } else {
      let passQuery = supabaseAdmin
        .from('event_access_passes')
        .select(`
          id,
          code,
          pass_type,
          checked_in,
          checked_in_at,
          event_id,
          full_name,
          events (
            id,
            title,
            event_date,
            organizer_id
          )
        `);

      if (ticketId || parsedTicketId) {
        passQuery = passQuery.eq('id', ticketId || parsedTicketId);
      } else if (normalizedCode) {
        passQuery = passQuery.eq('code', normalizedCode);
      }

      const { data: pass, error: passError } = await passQuery.single();

      if (passError || !pass) {
        return NextResponse.json(
          {
            success: false,
            error: 'Ticket not found',
            message: 'This ticket or guest pass does not exist.'
          },
          { status: 404 }
        );
      }

      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const event = pass.events as any;

      entryId = pass.id;
      entryCode = pass.code;
      entryType = pass.pass_type;
      entryHolder = pass.full_name || 'Guest';
      entryCheckedIn = pass.checked_in;
      entryCheckedInAt = pass.checked_in_at;
      entryEventId = pass.event_id;
      organizerId = event?.organizer_id || '';
      eventDateValue = event?.event_date || '';
      sourceTable = 'event_access_passes';
    }

    // Verify event matches if provided
    if (eventId && entryEventId !== eventId) {
      return NextResponse.json(
        { 
          success: false,
          error: 'Wrong event',
          message: 'This pass is for a different event.'
        },
        { status: 400 }
      );
    }

    const access = await getEventAccessForUser(supabaseAdmin, entryEventId, user.id);
    const isOrganizer = access.isOwner;
    const isTeamMember = access.permissions.canCheckIn;
    const isTicketOwner = sourceTable === 'tickets' && entryUserId === user.id;

    if (!isOrganizer && !isTeamMember && !isTicketOwner) {
      return NextResponse.json(
        { error: 'Not authorized to check in entries for this event' },
        { status: 403 }
      );
    }

    if (selfCheckIn && !isTicketOwner) {
      return NextResponse.json(
        { error: 'Only the ticket holder can self check-in' },
        { status: 403 }
      );
    }

    if (entryCheckedIn) {
      return NextResponse.json({
        success: false,
        alreadyCheckedIn: true,
        message: `Already checked in at ${new Date(entryCheckedInAt!).toLocaleTimeString()}`,
        ticket: {
          id: entryId,
          code: entryCode,
          type: entryType,
          holder: entryHolder,
          checkedInAt: entryCheckedInAt,
        },
      });
    }

    // Check event date (allow check-in on event day and day before)
    const eventDate = new Date(eventDateValue);
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    eventDate.setHours(0, 0, 0, 0);
    
    const daysDiff = Math.floor((eventDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));

    if (selfCheckIn && daysDiff !== 0) {
      return NextResponse.json({
        success: false,
        error: 'Not available yet',
        message: 'Self check-in is available on the event day only.',
      }, { status: 400 });
    }

    if (daysDiff > 1) {
      return NextResponse.json({
        success: false,
        error: 'Too early',
        message: `Check-in for this event opens on ${eventDate.toLocaleDateString()}`,
      }, { status: 400 });
    }

    if (daysDiff < -1) {
      return NextResponse.json({
        success: false,
        error: 'Event ended',
        message: 'This event has already ended.',
      }, { status: 400 });
    }

    // Perform check-in
    const checkedInAt = new Date().toISOString();
    
    const updatePayload = sourceTable === 'tickets'
      ? {
          is_used: true,
          used_at: checkedInAt,
          checked_in_by: user.id,
        }
      : {
          checked_in: true,
          checked_in_at: checkedInAt,
          checked_in_by: user.id,
        };

    const { error: updateError } = await supabaseAdmin
      .from(sourceTable)
      .update(updatePayload)
      .eq('id', entryId);

    if (updateError) {
      console.error('Check-in update error:', updateError);
      return NextResponse.json(
        { error: 'Failed to check in ticket' },
        { status: 500 }
      );
    }

    // Get updated attendance count
    const { count: checkedInCount } = await supabaseAdmin
      .from('tickets')
      .select('*', { count: 'exact', head: true })
      .eq('event_id', entryEventId)
      .eq('is_used', true);

    const { count: totalCount } = await supabaseAdmin
      .from('tickets')
      .select('*', { count: 'exact', head: true })
      .eq('event_id', entryEventId);

    const { count: guestCheckedInCount, error: guestCheckedInError } = await supabaseAdmin
      .from('event_access_passes')
      .select('*', { count: 'exact', head: true })
      .eq('event_id', entryEventId)
      .eq('checked_in', true);

    const { count: guestTotalCount, error: guestTotalError } = await supabaseAdmin
      .from('event_access_passes')
      .select('*', { count: 'exact', head: true })
      .eq('event_id', entryEventId);
    
    return NextResponse.json({
      success: true,
      message: selfCheckIn ? 'You are checked in. The organizer can now find you on the list.' : 'Check-in successful!',
      ticket: {
        id: entryId,
        code: entryCode,
        type: entryType,
        holder: entryHolder,
        checkedInAt,
      },
      attendance: {
        checkedIn: (checkedInCount || 0) + ((guestCheckedInError?.code === 'PGRST205' ? 0 : guestCheckedInCount) || 0),
        total: (totalCount || 0) + ((guestTotalError?.code === 'PGRST205' ? 0 : guestTotalCount) || 0),
      },
    });

  } catch (error) {
    console.error('Check-in error:', error);
    return NextResponse.json(
      { error: 'Check-in failed' },
      { status: 500 }
    );
  }
}

import { createClient } from '@supabase/supabase-js';
import { NextRequest, NextResponse } from 'next/server';

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_ROLE_KEY!
);

export async function GET(request: NextRequest) {
  try {
    const searchParams = request.nextUrl.searchParams;
    
    // Extract query parameters
    const startDate = searchParams.get('startDate');
    const endDate = searchParams.get('endDate');
    const city = searchParams.get('city');
    const province = searchParams.get('province');
    const category = searchParams.get('category');
    const isFree = searchParams.get('free') === 'true';
    const maxPrice = searchParams.get('maxPrice');
    const searchText = searchParams.get('q');
    
    // Build the query - using correct column names from Event interface
    let query = supabase
      .from('events')
      .select(`
        id,
        title,
        description,
        event_date,
        start_time,
        venue,
        venue_address,
        location,
        cover_image,
        ticket_price,
        capacity,
        tickets_sold
      `)
      .eq('state', 'published')
      .order('event_date', { ascending: true })
      .limit(10);
    
    // Date filter - convert ISO string to date only
    if (startDate) {
      const startDateOnly = startDate.split('T')[0];
      query = query.gte('event_date', startDateOnly);
    } else {
      // Default to upcoming events
      query = query.gte('event_date', new Date().toISOString().split('T')[0]);
    }
    
    if (endDate) {
      const endDateOnly = endDate.split('T')[0];
      query = query.lte('event_date', endDateOnly);
    }
    
    // Location filter (province)
    if (province) {
      query = query.eq('location', province);
    }
    
    // City search in venue or venue_address
    if (city) {
      query = query.or(`venue.ilike.%${city}%,venue_address.ilike.%${city}%`);
    }
    
    // Text search
    if (searchText) {
      query = query.or(`title.ilike.%${searchText}%,description.ilike.%${searchText}%,venue.ilike.%${searchText}%`);
    }
    
    // Price filters
    if (isFree) {
      query = query.eq('ticket_price', 0);
    } else if (maxPrice) {
      query = query.lte('ticket_price', parseInt(maxPrice));
    }
    
    const { data: events, error } = await query;
    
    if (error) {
      console.error('Ziwaphi search error:', error);
      return NextResponse.json({ error: 'Search failed', details: error.message }, { status: 500 });
    }
    
    // Process events to match expected format
    const processedEvents = (events || []).map(event => {
      return {
        id: event.id,
        title: event.title,
        date: event.event_date,
        time: event.start_time,
        venue: event.venue,
        city: event.venue_address || '',
        province: event.location,
        image_url: event.cover_image,
        category: null, // Events don't have category in current schema
        min_price: event.ticket_price || 0,
        max_price: event.ticket_price || 0,
        is_free: event.ticket_price === 0,
      };
    });
    
    return NextResponse.json({ 
      events: processedEvents,
      count: processedEvents.length,
    });
  } catch (error) {
    console.error('Ziwaphi search error:', error);
    return NextResponse.json({ error: 'Search failed' }, { status: 500 });
  }
}

'use client'

import { useEffect, useState } from 'react'
import Link from 'next/link'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Badge } from '@/components/ui/badge'
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import { 
  Search, 
  MapPin, 
  Star, 
  Briefcase,
  Loader2,
  Users
} from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import { 
  type PublicProvider, 
  type ServiceCategory, 
  type SaProvince,
  SERVICE_CATEGORY_LABELS 
} from '@/types/database'

// Province labels
const PROVINCE_LABELS: Record<SaProvince, string> = {
  gauteng: 'Gauteng',
  western_cape: 'Western Cape',
  kwazulu_natal: 'KwaZulu-Natal',
  eastern_cape: 'Eastern Cape',
  free_state: 'Free State',
  mpumalanga: 'Mpumalanga',
  limpopo: 'Limpopo',
  north_west: 'North West',
  northern_cape: 'Northern Cape',
}

// Category icons/colors
const CATEGORY_COLORS: Record<ServiceCategory, string> = {
  sound_lighting: 'bg-yellow-100 text-yellow-700',
  staging_av: 'bg-blue-100 text-blue-700',
  event_staff: 'bg-green-100 text-green-700',
  venue_hire: 'bg-purple-100 text-purple-700',
  catering: 'bg-red-100 text-red-700',
  music_licensing: 'bg-indigo-100 text-indigo-700',
  photography_video: 'bg-pink-100 text-pink-700',
  decor_design: 'bg-orange-100 text-orange-700',
  transport: 'bg-cyan-100 text-cyan-700',
  mc_hosts: 'bg-emerald-100 text-emerald-700',
  equipment_rental: 'bg-slate-100 text-slate-700',
  marketing: 'bg-violet-100 text-violet-700',
  other: 'bg-gray-100 text-gray-700',
}

export default function CrewPage() {
  const [providers, setProviders] = useState<PublicProvider[]>([])
  const [loading, setLoading] = useState(true)
  const [searchQuery, setSearchQuery] = useState('')
  const [selectedCategory, setSelectedCategory] = useState<ServiceCategory | 'all'>('all')
  const [selectedProvince, setSelectedProvince] = useState<SaProvince | 'all'>('all')

  useEffect(() => {
    fetchProviders()
  }, [selectedCategory, selectedProvince])

  const fetchProviders = async () => {
    setLoading(true)
    try {
      const supabase = createClient()
      
      let query = supabase
        .from('v_public_providers')
        .select('*')
        .eq('is_available', true)
        .order('completed_bookings', { ascending: false })

      if (selectedCategory !== 'all') {
        query = query.eq('primary_category', selectedCategory)
      }

      if (selectedProvince !== 'all') {
        query = query.eq('location', selectedProvince)
      }

      const { data, error } = await query

      if (error) {
        console.error('Error fetching providers:', error)
        // If view doesn't exist yet (migration not run), show empty
        setProviders([])
      } else {
        const baseProviders = data || []
        if (baseProviders.length === 0) {
          setProviders([])
        } else {
          const { data: providerModes } = await supabase
            .from('providers')
            .select('id, work_mode')
            .in('id', baseProviders.map((provider) => provider.id))

          const modesById = new Map((providerModes || []).map((provider) => [provider.id, provider.work_mode]))
          setProviders(baseProviders.map((provider) => ({
            ...provider,
            work_mode: modesById.get(provider.id) || provider.work_mode || null,
          })))
        }
      }
    } catch (error) {
      console.error('Error:', error)
      setProviders([])
    } finally {
      setLoading(false)
    }
  }

  // Filter by search query
  const filteredProviders = providers.filter(provider => 
    provider.business_name.toLowerCase().includes(searchQuery.toLowerCase()) ||
    provider.description?.toLowerCase().includes(searchQuery.toLowerCase())
  )

  const categories = Object.entries(SERVICE_CATEGORY_LABELS) as [ServiceCategory, string][]

  return (
    <div className="container mx-auto px-4 py-8">
      {/* Header */}
      <div className="text-center mb-8">
        <h1 className="text-4xl font-bold mb-2">Find Your Crew</h1>
        <p className="text-muted-foreground text-lg">
          Discover event staff and service providers for every part of your event
        </p>
      </div>

      {/* Search & Filters */}
      <div className="mb-8 space-y-4">
        {/* Search and Filter Row */}
        <div className="flex flex-col md:flex-row gap-4 max-w-4xl mx-auto">
          {/* Search Bar */}
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              placeholder="Search staff or services..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-10"
            />
          </div>

          {/* Category Dropdown */}
          <Select 
            value={selectedCategory} 
            onValueChange={(v) => setSelectedCategory(v as ServiceCategory | 'all')}
          >
            <SelectTrigger className="w-full md:w-56">
              <SelectValue placeholder="All Categories" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">All Categories</SelectItem>
              {categories.map(([value, label]) => (
                <SelectItem key={value} value={value}>{label}</SelectItem>
              ))}
            </SelectContent>
          </Select>

          {/* Province Dropdown */}
          <Select 
            value={selectedProvince} 
            onValueChange={(v) => setSelectedProvince(v as SaProvince | 'all')}
          >
            <SelectTrigger className="w-full md:w-48">
              <SelectValue placeholder="All Provinces" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">All Provinces</SelectItem>
              {Object.entries(PROVINCE_LABELS).map(([value, label]) => (
                <SelectItem key={value} value={value}>{label}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      </div>

      {/* Results */}
      {loading ? (
        <div className="flex justify-center py-12">
          <Loader2 className="h-8 w-8 animate-spin text-primary" />
        </div>
      ) : filteredProviders.length === 0 ? (
        <Card className="max-w-md mx-auto">
          <CardContent className="pt-6 text-center">
            <Users className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
            <h3 className="font-semibold text-lg mb-2">No providers found</h3>
            <p className="text-muted-foreground mb-4">
              {searchQuery || selectedCategory !== 'all' || selectedProvince !== 'all'
                ? 'Try adjusting your filters'
                : 'Be the first to join the crew!'}
            </p>
            <Link href="/profile">
              <Button>Become a Provider</Button>
            </Link>
          </CardContent>
        </Card>
      ) : (
        <>
          <p className="text-sm text-muted-foreground mb-4">
            {filteredProviders.length} crew profile{filteredProviders.length !== 1 ? 's' : ''} found
          </p>
          
          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredProviders.map((provider) => (
              <Link key={provider.id} href={`/crew/${provider.id}`}>
                <Card className="hover:border-orange-500 transition-all hover:shadow-lg cursor-pointer h-full">
                  <CardHeader className="pb-3">
                    <div className="flex items-start gap-4">
                      <Avatar className="h-16 w-16">
                        <AvatarImage src={provider.profile_image || undefined} />
                        <AvatarFallback className="text-xl bg-orange-100 text-orange-600">
                          {provider.business_name.charAt(0).toUpperCase()}
                        </AvatarFallback>
                      </Avatar>
                      <div className="flex-1 min-w-0">
                        <CardTitle className="text-lg truncate">{provider.business_name}</CardTitle>
                        <div className="mt-1 flex flex-wrap gap-1">
                          {(provider.work_mode === 'looking_for_work' || provider.work_mode === 'both') && (
                            <Badge variant="secondary">Event Staff</Badge>
                          )}
                          {(provider.work_mode === 'offering_services' || provider.work_mode === 'both' || provider.service_count > 0) && (
                            <Badge variant="outline" className={provider.primary_category !== 'event_staff' ? CATEGORY_COLORS[provider.primary_category] : ''}>
                              {provider.primary_category !== 'event_staff'
                                ? SERVICE_CATEGORY_LABELS[provider.primary_category]
                                : 'Service Provider'}
                            </Badge>
                          )}
                          {!provider.work_mode && (
                            <Badge variant="outline" className={CATEGORY_COLORS[provider.primary_category]}>
                              {SERVICE_CATEGORY_LABELS[provider.primary_category]}
                            </Badge>
                          )}
                        </div>
                      </div>
                    </div>
                  </CardHeader>
                  <CardContent>
                    {provider.description && (
                      <p className="text-sm text-muted-foreground mb-3 line-clamp-2">
                        {provider.description}
                      </p>
                    )}
                    
                    <div className="flex items-center gap-4 text-sm text-muted-foreground">
                      <span className="flex items-center gap-1">
                        <MapPin className="h-4 w-4" />
                        {PROVINCE_LABELS[provider.location]}
                      </span>
                      
                      {provider.average_rating > 0 && (
                        <span className="flex items-center gap-1">
                          <Star className="h-4 w-4 fill-yellow-400 text-yellow-400" />
                          {provider.average_rating.toFixed(1)}
                        </span>
                      )}
                      
                      <span className="flex items-center gap-1">
                        <Briefcase className="h-4 w-4" />
                        {provider.service_count > 0
                          ? `${provider.service_count} service${provider.service_count !== 1 ? 's' : ''}`
                          : 'Event work available'}
                      </span>
                    </div>

                    {provider.completed_bookings > 0 && (
                      <p className="text-xs text-green-600 mt-2">
                        {provider.completed_bookings} job{provider.completed_bookings !== 1 ? 's' : ''} completed
                      </p>
                    )}
                  </CardContent>
                </Card>
              </Link>
            ))}
          </div>
        </>
      )}
    </div>
  )
}

'use client';

import { useState } from 'react';
import Image from 'next/image';
import { createClient } from '@/lib/supabase/client';
import { 
  Plus, 
  Trash2, 
  Music2,
  Calendar,
  ExternalLink,
  Upload,
  Disc3
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { ArtistDiscography, ReleaseType, RELEASE_TYPE_LABELS } from '@/types/database';

interface DiscographyManagerProps {
  artistId: string;
  initialReleases: ArtistDiscography[];
}

export function DiscographyManager({ artistId, initialReleases }: DiscographyManagerProps) {
  const [releases, setReleases] = useState<ArtistDiscography[]>(initialReleases);
  const [isAddingRelease, setIsAddingRelease] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [newRelease, setNewRelease] = useState({
    title: '',
    release_type: 'single' as ReleaseType,
    release_date: '',
    cover_art_url: '',
    spotify_url: '',
    apple_music_url: '',
    youtube_music_url: '',
    soundcloud_url: '',
    bandcamp_url: '',
  });
  const supabase = createClient();

  // Handle cover art upload
  const handleCoverUpload = async (file: File) => {
    setUploading(true);
    try {
      const fileExt = file.name.split('.').pop();
      const filePath = `artists/${artistId}/releases/${Date.now()}.${fileExt}`;
      
      const { error: uploadError } = await supabase.storage
        .from('media')
        .upload(filePath, file);

      if (uploadError) throw uploadError;

      const { data: { publicUrl } } = supabase.storage
        .from('media')
        .getPublicUrl(filePath);

      setNewRelease(prev => ({ ...prev, cover_art_url: publicUrl }));
    } catch (error) {
      console.error('Upload error:', error);
      alert('Failed to upload cover art');
    } finally {
      setUploading(false);
    }
  };

  // Add release
  const handleAddRelease = async () => {
    if (!newRelease.title) return;

    const { data, error } = await supabase
      .from('artist_discography')
      .insert({
        artist_id: artistId,
        title: newRelease.title,
        release_type: newRelease.release_type,
        release_date: newRelease.release_date || null,
        cover_art_url: newRelease.cover_art_url || null,
        spotify_url: newRelease.spotify_url || null,
        apple_music_url: newRelease.apple_music_url || null,
        youtube_music_url: newRelease.youtube_music_url || null,
        soundcloud_url: newRelease.soundcloud_url || null,
        bandcamp_url: newRelease.bandcamp_url || null,
      })
      .select()
      .single();

    if (error) {
      console.error('Error adding release:', error);
      alert('Failed to add release');
      return;
    }

    setReleases(prev => [data, ...prev]);
    setNewRelease({
      title: '',
      release_type: 'single',
      release_date: '',
      cover_art_url: '',
      spotify_url: '',
      apple_music_url: '',
      youtube_music_url: '',
      soundcloud_url: '',
      bandcamp_url: '',
    });
    setIsAddingRelease(false);
  };

  // Delete release
  const handleDeleteRelease = async (id: string) => {
    if (!confirm('Are you sure you want to delete this release?')) return;

    const { error } = await supabase
      .from('artist_discography')
      .delete()
      .eq('id', id);

    if (error) {
      console.error('Error deleting release:', error);
      return;
    }

    setReleases(prev => prev.filter(r => r.id !== id));
  };

  // Format date
  const formatDate = (dateStr: string | null): string => {
    if (!dateStr) return 'No date';
    return new Date(dateStr).toLocaleDateString('en-ZA', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    });
  };

  // Get streaming links count
  const getStreamingLinksCount = (release: ArtistDiscography): number => {
    return [
      release.spotify_url,
      release.apple_music_url,
      release.youtube_music_url,
      release.soundcloud_url,
      release.bandcamp_url,
    ].filter(Boolean).length;
  };

  return (
    <div className="space-y-6">
      {/* Add Release Button */}
      <Dialog open={isAddingRelease} onOpenChange={setIsAddingRelease}>
        <DialogTrigger asChild>
          <Button>
            <Plus className="h-4 w-4 mr-2" />
            Add Release
          </Button>
        </DialogTrigger>
        <DialogContent className="max-w-lg max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Add Music Release</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-4">
            {/* Cover Art */}
            <div className="space-y-2">
              <Label>Cover Art</Label>
              <div className="flex gap-4">
                <div className="w-24 h-24 rounded-lg bg-neutral-100 overflow-hidden flex items-center justify-center">
                  {newRelease.cover_art_url ? (
                    <Image
                      src={newRelease.cover_art_url}
                      alt="Cover"
                      width={96}
                      height={96}
                      className="object-cover w-full h-full"
                    />
                  ) : (
                    <Disc3 className="h-8 w-8 text-neutral-300" />
                  )}
                </div>
                <div className="flex-1">
                  <input
                    type="file"
                    accept="image/*"
                    onChange={(e) => {
                      const file = e.target.files?.[0];
                      if (file) handleCoverUpload(file);
                    }}
                    className="hidden"
                    id="cover-upload"
                  />
                  <label htmlFor="cover-upload">
                    <Button variant="outline" size="sm" asChild>
                      <span className="cursor-pointer">
                        {uploading ? (
                          <span className="animate-pulse">Uploading...</span>
                        ) : (
                          <>
                            <Upload className="h-4 w-4 mr-2" />
                            Upload Cover
                          </>
                        )}
                      </span>
                    </Button>
                  </label>
                  <p className="text-xs text-neutral-500 mt-1">Square image recommended</p>
                </div>
              </div>
            </div>

            {/* Title */}
            <div className="space-y-2">
              <Label>Title *</Label>
              <Input
                placeholder="e.g., Summer Vibes"
                value={newRelease.title}
                onChange={(e) => setNewRelease(prev => ({ ...prev, title: e.target.value }))}
              />
            </div>

            {/* Type */}
            <div className="space-y-2">
              <Label>Release Type</Label>
              <Select
                value={newRelease.release_type}
                onValueChange={(v) => setNewRelease(prev => ({ ...prev, release_type: v as ReleaseType }))}
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {(Object.keys(RELEASE_TYPE_LABELS) as ReleaseType[]).map((type) => (
                    <SelectItem key={type} value={type}>
                      {RELEASE_TYPE_LABELS[type]}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* Release Date */}
            <div className="space-y-2">
              <Label>Release Date</Label>
              <Input
                type="date"
                value={newRelease.release_date}
                onChange={(e) => setNewRelease(prev => ({ ...prev, release_date: e.target.value }))}
              />
            </div>

            {/* Streaming Links */}
            <div className="border-t pt-4">
              <Label className="text-base">Streaming Links</Label>
              <p className="text-xs text-neutral-500 mb-3">Add links so fans can listen to your music</p>
              
              <div className="space-y-3">
                <div className="space-y-1">
                  <Label className="text-sm font-normal text-neutral-600">Spotify</Label>
                  <Input
                    placeholder="https://open.spotify.com/track/..."
                    value={newRelease.spotify_url}
                    onChange={(e) => setNewRelease(prev => ({ ...prev, spotify_url: e.target.value }))}
                  />
                </div>
                
                <div className="space-y-1">
                  <Label className="text-sm font-normal text-neutral-600">Apple Music</Label>
                  <Input
                    placeholder="https://music.apple.com/..."
                    value={newRelease.apple_music_url}
                    onChange={(e) => setNewRelease(prev => ({ ...prev, apple_music_url: e.target.value }))}
                  />
                </div>

                <div className="space-y-1">
                  <Label className="text-sm font-normal text-neutral-600">YouTube Music</Label>
                  <Input
                    placeholder="https://music.youtube.com/..."
                    value={newRelease.youtube_music_url}
                    onChange={(e) => setNewRelease(prev => ({ ...prev, youtube_music_url: e.target.value }))}
                  />
                </div>

                <div className="space-y-1">
                  <Label className="text-sm font-normal text-neutral-600">SoundCloud</Label>
                  <Input
                    placeholder="https://soundcloud.com/..."
                    value={newRelease.soundcloud_url}
                    onChange={(e) => setNewRelease(prev => ({ ...prev, soundcloud_url: e.target.value }))}
                  />
                </div>

                <div className="space-y-1">
                  <Label className="text-sm font-normal text-neutral-600">Bandcamp</Label>
                  <Input
                    placeholder="https://yourname.bandcamp.com/..."
                    value={newRelease.bandcamp_url}
                    onChange={(e) => setNewRelease(prev => ({ ...prev, bandcamp_url: e.target.value }))}
                  />
                </div>
              </div>
            </div>

            <Button 
              onClick={handleAddRelease} 
              className="w-full"
              disabled={!newRelease.title || uploading}
            >
              Add Release
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      {/* Releases Grid */}
      {releases.length > 0 ? (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
          {releases.map((release) => (
            <div key={release.id} className="group bg-white rounded-xl overflow-hidden border border-neutral-200 hover:shadow-lg transition-shadow">
              {/* Cover */}
              <div className="aspect-square relative bg-neutral-100">
                {release.cover_art_url ? (
                  <Image
                    src={release.cover_art_url}
                    alt={release.title}
                    fill
                    className="object-cover"
                  />
                ) : (
                  <div className="w-full h-full flex items-center justify-center">
                    <Disc3 className="h-16 w-16 text-neutral-300" />
                  </div>
                )}
                {/* Delete button */}
                <button
                  onClick={() => handleDeleteRelease(release.id)}
                  className="absolute top-2 right-2 p-2 bg-black/60 rounded-full text-white opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-500"
                >
                  <Trash2 className="h-4 w-4" />
                </button>
              </div>
              
              {/* Info */}
              <div className="p-3">
                <h3 className="font-medium text-neutral-900 truncate">{release.title}</h3>
                <div className="flex items-center gap-2 text-sm text-neutral-500 mt-1">
                  <span className="px-2 py-0.5 bg-neutral-100 rounded text-xs">
                    {RELEASE_TYPE_LABELS[release.release_type]}
                  </span>
                </div>
                <div className="flex items-center gap-1 text-xs text-neutral-400 mt-2">
                  <Calendar className="h-3 w-3" />
                  <span>{formatDate(release.release_date)}</span>
                </div>
                {/* Streaming links indicators */}
                {getStreamingLinksCount(release) > 0 && (
                  <div className="flex items-center gap-2 mt-2">
                    {release.spotify_url && (
                      <a href={release.spotify_url} target="_blank" rel="noopener noreferrer" 
                         className="w-6 h-6 rounded-full bg-green-500 flex items-center justify-center">
                        <Music2 className="h-3 w-3 text-white" />
                      </a>
                    )}
                    {release.apple_music_url && (
                      <a href={release.apple_music_url} target="_blank" rel="noopener noreferrer"
                         className="w-6 h-6 rounded-full bg-gradient-to-br from-pink-500 to-red-500 flex items-center justify-center">
                        <Music2 className="h-3 w-3 text-white" />
                      </a>
                    )}
                    {release.soundcloud_url && (
                      <a href={release.soundcloud_url} target="_blank" rel="noopener noreferrer"
                         className="w-6 h-6 rounded-full bg-orange-500 flex items-center justify-center">
                        <Music2 className="h-3 w-3 text-white" />
                      </a>
                    )}
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="text-center py-16 bg-white rounded-xl border border-neutral-200">
          <div className="w-16 h-16 mx-auto mb-4 rounded-full bg-neutral-100 flex items-center justify-center">
            <Disc3 className="h-8 w-8 text-neutral-400" />
          </div>
          <h3 className="text-lg font-semibold text-neutral-900 mb-1">No releases yet</h3>
          <p className="text-neutral-500 mb-4">Add your music to showcase your work</p>
          <Button onClick={() => setIsAddingRelease(true)}>
            <Plus className="h-4 w-4 mr-2" />
            Add Your First Release
          </Button>
        </div>
      )}

      {/* Tips */}
      <div className="p-4 bg-neutral-100 rounded-xl">
        <h4 className="font-medium text-neutral-900 mb-2">≡ƒÆí Pro Tips</h4>
        <ul className="text-sm text-neutral-600 space-y-1">
          <li>ΓÇó Add cover art to make your releases stand out</li>
          <li>ΓÇó Link to streaming platforms so organisers can preview your music</li>
          <li>ΓÇó Keep your discography up-to-date to show you're active</li>
        </ul>
      </div>
    </div>
  );
}

'use client';

/**
 * ArtistMediaManager - Enhanced with Supabase Storage
 * 
 * Features:
 * - Profile & cover image upload with real storage
 * - Photo gallery with drag & drop
 * - YouTube/TikTok video embedding
 */

import { useState } from 'react';
import Image from 'next/image';
import { createClient } from '@/lib/supabase/client';
import { 
  Plus, 
  Trash2, 
  Star, 
  Image as ImageIcon, 
  Video, 
  ExternalLink,
  Upload,
  Loader2,
  Camera,
  Play
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Switch } from '@/components/ui/switch';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { 
  uploadUserFile, 
  deleteFile as deleteStorageFile,
  getPathFromUrl,
  extractYouTubeId,
  extractTikTokId,
  getYouTubeThumbnail
} from '@/lib/storage';
import { ArtistMedia, MediaType, MEDIA_TYPE_LABELS } from '@/types/database';
import { cn } from '@/lib/utils';

interface ArtistMediaManagerProps {
  artistId: string;
  userId: string;
  initialMedia: ArtistMedia[];
  profileImage?: string | null;
  coverImage?: string | null;
}

export function ArtistMediaManager({ 
  artistId, 
  userId,
  initialMedia,
  profileImage,
  coverImage
}: ArtistMediaManagerProps) {
  const [media, setMedia] = useState<ArtistMedia[]>(initialMedia);
  const [isAddingMedia, setIsAddingMedia] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [uploadingProfile, setUploadingProfile] = useState(false);
  const [uploadingCover, setUploadingCover] = useState(false);
  const [currentProfile, setCurrentProfile] = useState(profileImage);
  const [currentCover, setCurrentCover] = useState(coverImage);
  const [newMedia, setNewMedia] = useState({
    media_type: 'image' as MediaType,
    url: '',
    title: '',
    description: '',
    is_featured: false,
  });
  const supabase = createClient();

  // Handle profile image upload
  const handleProfileUpload = async (file: File) => {
    setUploadingProfile(true);
    try {
      const result = await uploadUserFile(file, 'artists', userId, 'profile');
      
      if (!result.success) {
        alert(result.error || 'Failed to upload profile image');
        return;
      }

      // Update artist record
      const { error } = await supabase
        .from('artists')
        .update({ profile_image: result.url })
        .eq('id', artistId);

      if (error) {
        console.error('Error updating artist:', error);
        alert('Failed to update profile image');
        return;
      }

      setCurrentProfile(result.url || null);
    } catch (error) {
      console.error('Profile upload error:', error);
      alert('Failed to upload profile image');
    } finally {
      setUploadingProfile(false);
    }
  };

  // Handle cover image upload
  const handleCoverUpload = async (file: File) => {
    setUploadingCover(true);
    try {
      const result = await uploadUserFile(file, 'artists', userId, 'cover');
      
      if (!result.success) {
        alert(result.error || 'Failed to upload cover image');
        return;
      }

      // Find existing cover image media or create new
      const existingCover = media.find(m => m.is_cover_image);
      
      if (existingCover) {
        // Update existing
        const { error } = await supabase
          .from('artist_media')
          .update({ url: result.url })
          .eq('id', existingCover.id);
        
        if (!error) {
          setMedia(prev => prev.map(m => 
            m.id === existingCover.id ? { ...m, url: result.url! } : m
          ));
        }
      } else {
        // Create new cover image media
        const { data, error } = await supabase
          .from('artist_media')
          .insert({
            artist_id: artistId,
            media_type: 'image',
            url: result.url,
            is_cover_image: true,
            is_featured: false,
            is_profile_image: false,
            display_order: 0,
          })
          .select()
          .single();
        
        if (!error && data) {
          setMedia(prev => [data, ...prev]);
        }
      }

      setCurrentCover(result.url || null);
    } catch (error) {
      console.error('Cover upload error:', error);
      alert('Failed to upload cover image');
    } finally {
      setUploadingCover(false);
    }
  };

  // Handle gallery image upload using new storage utility
  const handleFileUpload = async (file: File) => {
    setUploading(true);
    try {
      const result = await uploadUserFile(file, 'artists', userId, 'gallery');

      if (!result.success) {
        alert(result.error || 'Failed to upload');
        return;
      }

      setNewMedia(prev => ({ ...prev, url: result.url! }));
    } catch (error) {
      console.error('Upload error:', error);
      alert('Failed to upload file');
    } finally {
      setUploading(false);
    }
  };

  // Add media to database
  const handleAddMedia = async () => {
    if (!newMedia.url) return;

    // For YouTube videos, extract the ID and get thumbnail
    let embedId: string | null = null;
    let thumbnailUrl: string | null = null;
    
    if (newMedia.media_type === 'youtube_video') {
      embedId = extractYouTubeId(newMedia.url);
      if (embedId) {
        thumbnailUrl = getYouTubeThumbnail(embedId);
      }
    }

    const { data, error } = await supabase
      .from('artist_media')
      .insert({
        artist_id: artistId,
        media_type: newMedia.media_type,
        url: newMedia.url,
        thumbnail_url: thumbnailUrl,
        embed_id: embedId,
        title: newMedia.title || null,
        description: newMedia.description || null,
        is_featured: newMedia.is_featured,
        is_profile_image: false,
        is_cover_image: false,
        display_order: media.length,
      })
      .select()
      .single();

    if (error) {
      console.error('Error adding media:', error);
      alert('Failed to add media');
      return;
    }

    setMedia(prev => [...prev, data]);
    setNewMedia({
      media_type: 'image',
      url: '',
      title: '',
      description: '',
      is_featured: false,
    });
    setIsAddingMedia(false);
  };

  // Delete media - also delete from storage
  const handleDeleteMedia = async (id: string, url?: string) => {
    if (!confirm('Are you sure you want to delete this?')) return;

    // Delete from storage if it's our file
    if (url) {
      const storagePath = getPathFromUrl(url);
      if (storagePath) {
        await deleteStorageFile(storagePath);
      }
    }

    const { error } = await supabase
      .from('artist_media')
      .delete()
      .eq('id', id);

    if (error) {
      console.error('Error deleting media:', error);
      return;
    }

    setMedia(prev => prev.filter(m => m.id !== id));
  };

  // Toggle featured
  const handleToggleFeatured = async (id: string, isFeatured: boolean) => {
    const { error } = await supabase
      .from('artist_media')
      .update({ is_featured: isFeatured })
      .eq('id', id);

    if (error) {
      console.error('Error updating media:', error);
      return;
    }

    setMedia(prev => prev.map(m => m.id === id ? { ...m, is_featured: isFeatured } : m));
  };

  // Get thumbnail for display
  const getThumbnail = (item: ArtistMedia): string => {
    if (item.thumbnail_url) return item.thumbnail_url;
    if (item.embed_id) return getYouTubeThumbnail(item.embed_id, 'hq');
    return item.url;
  };

  const images = media.filter(m => m.media_type === 'image' && !m.is_cover_image);
  const videos = media.filter(m => m.media_type !== 'image');

  return (
    <div className="space-y-10">
      {/* Profile & Cover Images Section */}
      <div className="space-y-6">
        <h2 className="text-lg font-semibold text-neutral-900">Profile Images</h2>
        
        <div className="flex flex-col md:flex-row gap-8 items-start">
          {/* Profile Picture */}
          <div className="flex flex-col items-center gap-3">
            <div 
              className="relative w-32 h-32 rounded-full overflow-hidden bg-neutral-100 border-2 border-neutral-200 cursor-pointer group"
              onClick={() => document.getElementById('profile-upload')?.click()}
            >
              {currentProfile ? (
                <Image
                  src={currentProfile}
                  alt="Profile"
                  fill
                  className="object-cover"
                />
              ) : (
                <div className="absolute inset-0 flex items-center justify-center">
                  <Camera className="h-8 w-8 text-neutral-400" />
                </div>
              )}
              <div className={cn(
                'absolute inset-0 bg-black/50 flex items-center justify-center transition-opacity',
                uploadingProfile ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'
              )}>
                {uploadingProfile ? (
                  <Loader2 className="h-6 w-6 text-white animate-spin" />
                ) : (
                  <Camera className="h-6 w-6 text-white" />
                )}
              </div>
              <input
                id="profile-upload"
                type="file"
                accept="image/jpeg,image/png,image/webp"
                className="hidden"
                onChange={(e) => {
                  const file = e.target.files?.[0];
                  if (file) handleProfileUpload(file);
                }}
              />
            </div>
            <span className="text-sm text-neutral-600">Profile Picture</span>
          </div>

          {/* Cover Image */}
          <div className="flex-1 w-full">
            <div 
              className="relative aspect-[3/1] rounded-xl overflow-hidden bg-neutral-100 border-2 border-dashed border-neutral-300 cursor-pointer group hover:border-neutral-400 transition-colors"
              onClick={() => document.getElementById('cover-upload')?.click()}
            >
              {currentCover ? (
                <Image
                  src={currentCover}
                  alt="Cover"
                  fill
                  className="object-cover"
                />
              ) : (
                <div className="absolute inset-0 flex flex-col items-center justify-center">
                  <Upload className="h-8 w-8 text-neutral-400 mb-2" />
                  <p className="text-sm text-neutral-500">Click to upload cover image</p>
                  <p className="text-xs text-neutral-400">Recommended: 1500 x 500px</p>
                </div>
              )}
              <div className={cn(
                'absolute inset-0 bg-black/50 flex items-center justify-center transition-opacity',
                uploadingCover ? 'opacity-100' : currentCover ? 'opacity-0 group-hover:opacity-100' : 'opacity-0'
              )}>
                {uploadingCover ? (
                  <Loader2 className="h-8 w-8 text-white animate-spin" />
                ) : (
                  <Camera className="h-8 w-8 text-white" />
                )}
              </div>
              <input
                id="cover-upload"
                type="file"
                accept="image/jpeg,image/png,image/webp"
                className="hidden"
                onChange={(e) => {
                  const file = e.target.files?.[0];
                  if (file) handleCoverUpload(file);
                }}
              />
            </div>
            <p className="text-sm text-neutral-500 mt-2">Cover/Banner Image</p>
          </div>
        </div>
      </div>

      {/* Gallery Section */}
      <div>
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-lg font-semibold text-neutral-900 flex items-center gap-2">
            <ImageIcon className="h-5 w-5" />
            Photo Gallery ({images.length})
          </h2>
        </div>
        
      {/* Add Media Button */}
      <Dialog open={isAddingMedia} onOpenChange={setIsAddingMedia}>
        <DialogTrigger asChild>
          <Button className="mb-4">
            <Plus className="h-4 w-4 mr-2" />
            Add Media
          </Button>
        </DialogTrigger>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>Add Media</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-4">
            {/* Media Type */}
            <div className="space-y-2">
              <Label>Media Type</Label>
              <Select
                value={newMedia.media_type}
                onValueChange={(v) => setNewMedia(prev => ({ ...prev, media_type: v as MediaType, url: '' }))}
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="image">Image</SelectItem>
                  <SelectItem value="youtube_video">YouTube Video</SelectItem>
                  <SelectItem value="tiktok_video">TikTok Video</SelectItem>
                  <SelectItem value="instagram_post">Instagram Post</SelectItem>
                </SelectContent>
              </Select>
            </div>

            {/* File Upload (for images) */}
            {newMedia.media_type === 'image' && (
              <div className="space-y-2">
                <Label>Upload Image</Label>
                <div className="border-2 border-dashed border-neutral-200 rounded-lg p-6 text-center">
                  <input
                    type="file"
                    accept="image/*"
                    onChange={(e) => {
                      const file = e.target.files?.[0];
                      if (file) handleFileUpload(file);
                    }}
                    className="hidden"
                    id="media-upload"
                  />
                  <label htmlFor="media-upload" className="cursor-pointer">
                    {uploading ? (
                      <Loader2 className="h-8 w-8 animate-spin mx-auto text-neutral-400" />
                    ) : newMedia.url ? (
                      <div className="relative w-32 h-32 mx-auto">
                        <Image src={newMedia.url} alt="Preview" fill className="object-cover rounded-lg" />
                      </div>
                    ) : (
                      <>
                        <Upload className="h-8 w-8 text-neutral-400 mx-auto mb-2" />
                        <p className="text-sm text-neutral-500">Click to upload</p>
                      </>
                    )}
                  </label>
                </div>
                <p className="text-xs text-neutral-500">Or paste an image URL below</p>
              </div>
            )}

            {/* URL Input */}
            <div className="space-y-2">
              <Label>
                {newMedia.media_type === 'image' ? 'Image URL' : 
                 newMedia.media_type === 'youtube_video' ? 'YouTube URL' :
                 newMedia.media_type === 'tiktok_video' ? 'TikTok URL' :
                 'Instagram URL'}
              </Label>
              <Input
                placeholder={
                  newMedia.media_type === 'youtube_video' 
                    ? 'https://www.youtube.com/watch?v=...' 
                    : 'https://...'
                }
                value={newMedia.url}
                onChange={(e) => setNewMedia(prev => ({ ...prev, url: e.target.value }))}
              />
            </div>

            {/* Title */}
            <div className="space-y-2">
              <Label>Title (optional)</Label>
              <Input
                placeholder="e.g., Live at Rocking the Daisies"
                value={newMedia.title}
                onChange={(e) => setNewMedia(prev => ({ ...prev, title: e.target.value }))}
              />
            </div>

            {/* Description */}
            <div className="space-y-2">
              <Label>Description (optional)</Label>
              <Textarea
                placeholder="Add a description..."
                value={newMedia.description}
                onChange={(e) => setNewMedia(prev => ({ ...prev, description: e.target.value }))}
                rows={2}
              />
            </div>

            {/* Featured Toggle */}
            <div className="flex items-center justify-between">
              <Label htmlFor="featured">Feature this media</Label>
              <Switch
                id="featured"
                checked={newMedia.is_featured}
                onCheckedChange={(v) => setNewMedia(prev => ({ ...prev, is_featured: v }))}
              />
            </div>

            <Button 
              onClick={handleAddMedia} 
              className="w-full"
              disabled={!newMedia.url || uploading}
            >
              Add Media
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      {/* Images Section */}
      <div>
        <h2 className="text-lg font-semibold text-neutral-900 mb-4 flex items-center gap-2">
          <ImageIcon className="h-5 w-5" />
          Photos ({images.length})
        </h2>
        {images.length > 0 ? (
          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
            {images.map((item) => (
              <div key={item.id} className="relative group aspect-square rounded-lg overflow-hidden bg-neutral-100">
                <Image
                  src={item.url}
                  alt={item.title || 'Media'}
                  fill
                  className="object-cover"
                />
                {/* Badges */}
                <div className="absolute top-2 left-2 flex gap-1">
                  {item.is_featured && (
                    <span className="px-2 py-0.5 bg-yellow-500 text-white text-xs rounded">Featured</span>
                  )}
                  {item.is_profile_image && (
                    <span className="px-2 py-0.5 bg-blue-500 text-white text-xs rounded">Profile</span>
                  )}
                  {item.is_cover_image && (
                    <span className="px-2 py-0.5 bg-purple-500 text-white text-xs rounded">Cover</span>
                  )}
                </div>
                {/* Actions overlay */}
                <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                  <button
                    onClick={() => handleToggleFeatured(item.id, !item.is_featured)}
                    className={`p-2 rounded-full ${item.is_featured ? 'bg-yellow-500' : 'bg-white/20'} hover:bg-yellow-500 transition-colors`}
                    title={item.is_featured ? 'Remove from featured' : 'Add to featured'}
                  >
                    <Star className="h-4 w-4 text-white" fill={item.is_featured ? 'currentColor' : 'none'} />
                  </button>
                  <button
                    onClick={() => handleDeleteMedia(item.id, item.url)}
                    className="p-2 rounded-full bg-white/20 hover:bg-red-500 transition-colors"
                    title="Delete"
                  >
                    <Trash2 className="h-4 w-4 text-white" />
                  </button>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="text-center py-12 bg-neutral-50 rounded-xl">
            <ImageIcon className="h-12 w-12 text-neutral-300 mx-auto mb-3" />
            <p className="text-neutral-500">No photos yet</p>
            <p className="text-sm text-neutral-400">Add photos to showcase your performances</p>
          </div>
        )}
      </div>
      </div>

      {/* Videos Section */}
      <div>
        <h2 className="text-lg font-semibold text-neutral-900 mb-4 flex items-center gap-2">
          <Video className="h-5 w-5" />
          Videos ({videos.length})
        </h2>
        {videos.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {videos.map((item) => (
              <div key={item.id} className="relative group rounded-lg overflow-hidden bg-neutral-100">
                <div className="aspect-video relative">
                  <Image
                    src={getThumbnail(item)}
                    alt={item.title || 'Video'}
                    fill
                    className="object-cover"
                  />
                  {/* Play icon */}
                  <div className="absolute inset-0 flex items-center justify-center">
                    <div className="w-14 h-14 rounded-full bg-black/70 flex items-center justify-center">
                      <Video className="h-6 w-6 text-white" />
                    </div>
                  </div>
                </div>
                <div className="p-3 bg-white">
                  <div className="flex items-start justify-between">
                    <div>
                      <p className="font-medium text-neutral-900 truncate">{item.title || 'Untitled'}</p>
                      <p className="text-sm text-neutral-500">{MEDIA_TYPE_LABELS[item.media_type]}</p>
                    </div>
                    <div className="flex gap-1">
                      <a
                        href={item.url}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="p-1.5 text-neutral-400 hover:text-neutral-600"
                        title="Open in new tab"
                        aria-label="Open video in new tab"
                      >
                        <ExternalLink className="h-4 w-4" />
                      </a>
                      <button
                        onClick={() => handleDeleteMedia(item.id, item.url)}
                        className="p-1.5 text-neutral-400 hover:text-red-500"
                        title="Delete video"
                        aria-label="Delete video"
                      >
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="text-center py-12 bg-neutral-50 rounded-xl">
            <Video className="h-12 w-12 text-neutral-300 mx-auto mb-3" />
            <p className="text-neutral-500">No videos yet</p>
            <p className="text-sm text-neutral-400">Add YouTube or TikTok videos</p>
          </div>
        )}
      </div>
    </div>
  );
}

'use client'

import { useEffect, useState } from 'react'
import { useRouter } from 'next/navigation'
import Link from 'next/link'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import { ArrowLeft, Loader2, Music } from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import { PROVINCES, GENRES } from '@/lib/constants'
import { toast } from 'sonner'
import { useAuth } from '@/components/providers/auth-provider'

export default function ArtistSetupPage() {
  const router = useRouter()
  const { profile, refreshProfile } = useAuth()
  const [loading, setLoading] = useState(false)
  const [checkingExisting, setCheckingExisting] = useState(true)
  const [isEditing, setIsEditing] = useState(false)
  const [artistId, setArtistId] = useState<string | null>(null)
  
  const [formData, setFormData] = useState({
    stage_name: '',
    bio: '',
    genre: '',
    base_price: '',
    location: '',
    is_available: 'true',
    advance_notice_days: '3',
    years_active: '',
    record_label: '',
    management_contact: '',
  })

  useEffect(() => {
    if (!profile) {
      router.push('/auth/signin')
      return
    }

    if (!profile.is_artist) {
      router.push('/profile')
      toast.error('You need to become an artist first')
      return
    }

    checkExistingArtist()
  }, [profile, router])

  const checkExistingArtist = async () => {
    if (!profile) return
    
    try {
      const supabase = createClient()
      const { data, error } = await supabase
        .from('artists')
        .select('*')
        .eq('profile_id', profile.id)
        .single()

      if (data && !error) {
        // Pre-fill form with existing data
        setArtistId(data.id)
        setFormData({
          stage_name: data.stage_name || '',
          bio: data.bio || '',
          genre: data.genre || '',
          base_price: data.base_price?.toString() || '',
          location: data.location || '',
          is_available: data.is_available === false ? 'false' : 'true',
          advance_notice_days: data.advance_notice_days?.toString() || '3',
          years_active: data.years_active?.toString() || '',
          record_label: data.record_label || '',
          management_contact: data.management_contact || '',
        })
        setIsEditing(true)
      }
    } catch (error) {
      console.error('Error checking existing artist:', error)
    } finally {
      setCheckingExisting(false)
    }
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    
    if (!profile) {
      toast.error('You must be logged in')
      return
    }

    if (!formData.stage_name.trim()) {
      toast.error('Stage name is required')
      return
    }

    setLoading(true)

    try {
      const supabase = createClient()

      const artistData = {
        profile_id: profile.id,
        stage_name: formData.stage_name.trim(),
        bio: formData.bio.trim() || null,
        genre: formData.genre,
        base_price: parseFloat(formData.base_price) || 0,
        location: formData.location,
        is_available: formData.is_available !== 'false',
        advance_notice_days: parseInt(formData.advance_notice_days) || 3,
        years_active: formData.years_active ? parseInt(formData.years_active) : null,
        record_label: formData.record_label.trim() || null,
        management_contact: formData.management_contact.trim() || null,
      }

      if (isEditing && artistId) {
        // Update existing artist profile
        const { error } = await supabase
          .from('artists')
          .update(artistData)
          .eq('id', artistId)

        if (error) throw error
        toast.success('Artist profile updated!')
      } else {
        // Check if artist already exists (double-check)
        const { data: existing } = await supabase
          .from('artists')
          .select('id')
          .eq('profile_id', profile.id)
          .single()

        if (existing) {
          toast.error('You already have an artist profile. Refreshing...')
          await checkExistingArtist()
          setLoading(false)
          return
        }

        // Create new artist profile
        const { error: artistError } = await supabase
          .from('artists')
          .insert(artistData)

        if (artistError) throw artistError

        // Update profile role
        await supabase
          .from('profiles')
          .update({ role: 'artist' })
          .eq('id', profile.id)

        await refreshProfile()
        toast.success('Artist profile created! ≡ƒÄñ')
      }

      router.push('/dashboard/artist')
      
    } catch (error) {
      console.error('Error saving artist profile:', error)
      toast.error('Failed to save artist profile. Please try again.')
    } finally {
      setLoading(false)
    }
  }

  const updateField = (field: string, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }))
  }

  if (checkingExisting || !profile) {
    return (
      <div className="flex justify-center items-center min-h-[50vh]">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    )
  }

  return (
    <div className="container mx-auto px-4 py-8 max-w-2xl">
      {isEditing && (
        <Link href="/dashboard/artist" className="inline-flex items-center text-muted-foreground hover:text-primary mb-6">
          <ArrowLeft className="h-4 w-4 mr-2" />
          Back to Dashboard
        </Link>
      )}

      <div className="text-center mb-8">
        <div className="inline-flex items-center justify-center p-3 bg-primary/10 rounded-full mb-4">
          <Music className="h-8 w-8 text-primary" />
        </div>
        <h1 className="text-3xl font-bold mb-2">
          {isEditing ? 'Edit Artist Profile' : 'Set Up Your Artist Profile'}
        </h1>
        <p className="text-muted-foreground">
          {isEditing 
            ? 'Update your artist information' 
            : 'Create your artist profile to start receiving booking requests'}
        </p>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Artist Information</CardTitle>
          <CardDescription>
            This information will be displayed on your public profile
          </CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-6">
            {/* Stage Name */}
            <div>
              <Label htmlFor="stage_name">Stage Name *</Label>
              <Input
                id="stage_name"
                placeholder="Your artist/DJ name"
                value={formData.stage_name}
                onChange={(e) => updateField('stage_name', e.target.value)}
                required
              />
            </div>

            {/* Genre */}
            <div>
              <Label htmlFor="genre">Genre *</Label>
              <Select
                value={formData.genre}
                onValueChange={(value) => updateField('genre', value)}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select your primary genre" />
                </SelectTrigger>
                <SelectContent>
                  {GENRES.map((genre) => (
                    <SelectItem key={genre} value={genre}>
                      {genre}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* Location */}
            <div>
              <Label htmlFor="location">Location *</Label>
              <Select
                value={formData.location}
                onValueChange={(value) => updateField('location', value)}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select your province" />
                </SelectTrigger>
                <SelectContent>
                  {Object.entries(PROVINCES).map(([value, label]) => (
                    <SelectItem key={value} value={value}>
                      {label}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* Base Price */}
            <div>
              <Label htmlFor="base_price">Base Price (ZAR) *</Label>
              <Input
                id="base_price"
                type="number"
                min="0"
                step="0.01"
                placeholder="Your starting price for bookings"
                value={formData.base_price}
                onChange={(e) => updateField('base_price', e.target.value)}
                required
              />
              <p className="text-sm text-muted-foreground mt-1">
                This is your minimum rate. Organizers can offer more.
              </p>
            </div>

            {/* Availability */}
            <div>
              <Label htmlFor="is_available">Booking Availability</Label>
              <Select
                value={formData.is_available}
                onValueChange={(value) => updateField('is_available', value)}
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="true">Available for bookings</SelectItem>
                  <SelectItem value="false">Pause bookings for now</SelectItem>
                </SelectContent>
              </Select>
              <p className="text-sm text-muted-foreground mt-1">
                Let organisers know if you are open for new requests right now.
              </p>
            </div>

            {/* Advance Notice */}
            <div>
              <Label htmlFor="advance_notice_days">Advance Notice (Days)</Label>
              <Input
                id="advance_notice_days"
                type="number"
                min="0"
                placeholder="Minimum days notice for bookings"
                value={formData.advance_notice_days}
                onChange={(e) => updateField('advance_notice_days', e.target.value)}
              />
              <p className="text-sm text-muted-foreground mt-1">
                How many days in advance do you need to be booked?
              </p>
            </div>

            {/* Years Active */}
            <div>
              <Label htmlFor="years_active">Years Active</Label>
              <Input
                id="years_active"
                type="number"
                min="0"
                placeholder="How many years have you been performing?"
                value={formData.years_active}
                onChange={(e) => updateField('years_active', e.target.value)}
              />
            </div>

            {/* Record Label */}
            <div>
              <Label htmlFor="record_label">Record Label (if any)</Label>
              <Input
                id="record_label"
                placeholder="Your record label"
                value={formData.record_label}
                onChange={(e) => updateField('record_label', e.target.value)}
              />
            </div>

            {/* Management Contact */}
            <div>
              <Label htmlFor="management_contact">Management Contact</Label>
              <Input
                id="management_contact"
                placeholder="Manager's email or phone"
                value={formData.management_contact}
                onChange={(e) => updateField('management_contact', e.target.value)}
              />
            </div>

            {/* Bio */}
            <div>
              <Label htmlFor="bio">Bio</Label>
              <textarea
                id="bio"
                className="flex min-h-[120px] w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50"
                placeholder="Tell organizers about yourself, your experience, and your music..."
                value={formData.bio}
                onChange={(e) => updateField('bio', e.target.value)}
              />
            </div>

            <Button type="submit" disabled={loading} className="w-full">
              {loading ? (
                <>
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  {isEditing ? 'Saving Changes...' : 'Creating Profile...'}
                </>
              ) : (
                isEditing ? 'Save Changes' : 'Create Artist Profile'
              )}
            </Button>
          </form>
        </CardContent>
      </Card>
    </div>
  )
}

'use client';

import { useState } from 'react';
import { createClient } from '@/lib/supabase/client';
import { 
  Plus, 
  Trash2, 
  ExternalLink,
  Instagram,
  Youtube,
  Twitter,
  Facebook,
  Music2,
  Globe,
  Grip
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Switch } from '@/components/ui/switch';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { ArtistSocialLink, SocialPlatform, SOCIAL_PLATFORM_LABELS } from '@/types/database';

interface ArtistSocialManagerProps {
  artistId: string;
  initialLinks: ArtistSocialLink[];
}

// Platform icons mapping
const platformIcons: Record<SocialPlatform, React.ReactNode> = {
  instagram: <Instagram className="h-5 w-5" />,
  tiktok: <Music2 className="h-5 w-5" />, // Using Music2 as TikTok proxy
  youtube: <Youtube className="h-5 w-5" />,
  twitter: <Twitter className="h-5 w-5" />,
  facebook: <Facebook className="h-5 w-5" />,
  spotify: <Music2 className="h-5 w-5" />,
  apple_music: <Music2 className="h-5 w-5" />,
  soundcloud: <Music2 className="h-5 w-5" />,
  bandcamp: <Music2 className="h-5 w-5" />,
  deezer: <Music2 className="h-5 w-5" />,
  website: <Globe className="h-5 w-5" />,
  linkedin: <Globe className="h-5 w-5" />,
  other: <Globe className="h-5 w-5" />,
};

// Platform colors for styling
const platformColors: Record<SocialPlatform, string> = {
  instagram: 'from-purple-500 to-pink-500',
  tiktok: 'from-neutral-800 to-neutral-900',
  youtube: 'from-red-500 to-red-600',
  twitter: 'from-blue-400 to-blue-500',
  facebook: 'from-blue-600 to-blue-700',
  spotify: 'from-green-500 to-green-600',
  apple_music: 'from-pink-500 to-red-500',
  soundcloud: 'from-orange-500 to-orange-600',
  bandcamp: 'from-cyan-500 to-blue-500',
  deezer: 'from-purple-600 to-pink-600',
  website: 'from-neutral-600 to-neutral-700',
  linkedin: 'from-blue-600 to-blue-800',
  other: 'from-neutral-500 to-neutral-600',
};

// URL templates for platforms
const platformUrlTemplates: Record<SocialPlatform, string> = {
  instagram: 'https://instagram.com/',
  tiktok: 'https://tiktok.com/@',
  youtube: 'https://youtube.com/@',
  twitter: 'https://twitter.com/',
  facebook: 'https://facebook.com/',
  spotify: 'https://open.spotify.com/artist/',
  apple_music: 'https://music.apple.com/artist/',
  soundcloud: 'https://soundcloud.com/',
  bandcamp: 'https://',
  deezer: 'https://www.deezer.com/artist/',
  website: '',
  linkedin: 'https://linkedin.com/in/',
  other: '',
};

export function ArtistSocialManager({ artistId, initialLinks }: ArtistSocialManagerProps) {
  const [links, setLinks] = useState<ArtistSocialLink[]>(initialLinks);
  const [isAddingLink, setIsAddingLink] = useState(false);
  const [newLink, setNewLink] = useState({
    platform: 'instagram' as SocialPlatform,
    url: '',
    username: '',
    is_primary: false,
  });
  const supabase = createClient();

  // Build full URL from username
  const buildUrl = (platform: SocialPlatform, usernameOrUrl: string): string => {
    // If it's already a URL, return it
    if (usernameOrUrl.startsWith('http')) return usernameOrUrl;
    
    const template = platformUrlTemplates[platform];
    return template + usernameOrUrl;
  };

  // Extract username from URL
  const extractUsername = (platform: SocialPlatform, url: string): string => {
    const template = platformUrlTemplates[platform];
    if (url.startsWith(template)) {
      return url.replace(template, '').split('/')[0].split('?')[0];
    }
    return url;
  };

  // Add social link
  const handleAddLink = async () => {
    if (!newLink.url && !newLink.username) return;

    const urlToUse = newLink.url || buildUrl(newLink.platform, newLink.username);
    const usernameToUse = newLink.username || extractUsername(newLink.platform, newLink.url);

    const { data, error } = await supabase
      .from('artist_social_links')
      .insert({
        artist_id: artistId,
        platform: newLink.platform,
        url: urlToUse,
        username: usernameToUse || null,
        is_primary: newLink.is_primary,
        display_order: links.length,
      })
      .select()
      .single();

    if (error) {
      console.error('Error adding social link:', error);
      alert('Failed to add social link');
      return;
    }

    setLinks(prev => [...prev, data]);
    setNewLink({
      platform: 'instagram',
      url: '',
      username: '',
      is_primary: false,
    });
    setIsAddingLink(false);
  };

  // Delete social link
  const handleDeleteLink = async (id: string) => {
    if (!confirm('Are you sure you want to remove this social link?')) return;

    const { error } = await supabase
      .from('artist_social_links')
      .delete()
      .eq('id', id);

    if (error) {
      console.error('Error deleting social link:', error);
      return;
    }

    setLinks(prev => prev.filter(l => l.id !== id));
  };

  // Toggle primary
  const handleTogglePrimary = async (id: string, isPrimary: boolean) => {
    // If setting as primary, unset others first
    if (isPrimary) {
      await supabase
        .from('artist_social_links')
        .update({ is_primary: false })
        .eq('artist_id', artistId);
    }

    const { error } = await supabase
      .from('artist_social_links')
      .update({ is_primary: isPrimary })
      .eq('id', id);

    if (error) {
      console.error('Error updating social link:', error);
      return;
    }

    setLinks(prev => prev.map(l => ({
      ...l,
      is_primary: l.id === id ? isPrimary : (isPrimary ? false : l.is_primary)
    })));
  };

  // Check if platform already exists
  const platformExists = (platform: SocialPlatform): boolean => {
    return links.some(l => l.platform === platform);
  };

  return (
    <div className="space-y-6">
      {/* Add Link Button */}
      <Dialog open={isAddingLink} onOpenChange={setIsAddingLink}>
        <DialogTrigger asChild>
          <Button>
            <Plus className="h-4 w-4 mr-2" />
            Add Social Link
          </Button>
        </DialogTrigger>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>Add Social Link</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-4">
            {/* Platform */}
            <div className="space-y-2">
              <Label>Platform</Label>
              <Select
                value={newLink.platform}
                onValueChange={(v) => setNewLink(prev => ({ ...prev, platform: v as SocialPlatform, url: '', username: '' }))}
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {(Object.keys(SOCIAL_PLATFORM_LABELS) as SocialPlatform[]).map((platform) => (
                    <SelectItem 
                      key={platform} 
                      value={platform}
                      disabled={platformExists(platform)}
                    >
                      <div className="flex items-center gap-2">
                        {platformIcons[platform]}
                        <span>{SOCIAL_PLATFORM_LABELS[platform]}</span>
                        {platformExists(platform) && (
                          <span className="text-xs text-neutral-400">(added)</span>
                        )}
                      </div>
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* Username or URL */}
            <div className="space-y-2">
              <Label>
                {newLink.platform === 'website' || newLink.platform === 'other' ? 'URL' : 'Username or URL'}
              </Label>
              <div className="flex gap-2">
                {newLink.platform !== 'website' && newLink.platform !== 'other' && (
                  <div className="flex items-center px-3 bg-neutral-100 rounded-l-md text-sm text-neutral-500">
                    @
                  </div>
                )}
                <Input
                  placeholder={
                    newLink.platform === 'website' 
                      ? 'https://yourwebsite.com' 
                      : 'username'
                  }
                  value={newLink.username || newLink.url}
                  onChange={(e) => {
                    const value = e.target.value;
                    if (value.startsWith('http')) {
                      setNewLink(prev => ({ ...prev, url: value, username: '' }));
                    } else {
                      setNewLink(prev => ({ ...prev, username: value, url: '' }));
                    }
                  }}
                  className={newLink.platform !== 'website' && newLink.platform !== 'other' ? 'rounded-l-none' : ''}
                />
              </div>
              {newLink.platform !== 'website' && newLink.platform !== 'other' && (
                <p className="text-xs text-neutral-500">
                  Your profile will link to: {buildUrl(newLink.platform, newLink.username || 'username')}
                </p>
              )}
            </div>

            {/* Primary toggle */}
            <div className="flex items-center justify-between">
              <div>
                <Label htmlFor="primary">Primary Link</Label>
                <p className="text-xs text-neutral-500">Show prominently on your profile</p>
              </div>
              <Switch
                id="primary"
                checked={newLink.is_primary}
                onCheckedChange={(v) => setNewLink(prev => ({ ...prev, is_primary: v }))}
              />
            </div>

            <Button 
              onClick={handleAddLink} 
              className="w-full"
              disabled={!newLink.url && !newLink.username}
            >
              Add Link
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      {/* Links List */}
      {links.length > 0 ? (
        <div className="space-y-3">
          {links.map((link) => (
            <div 
              key={link.id} 
              className="flex items-center gap-4 p-4 bg-white rounded-xl border border-neutral-200 group"
            >
              {/* Drag handle */}
              <div className="text-neutral-300 cursor-grab">
                <Grip className="h-5 w-5" />
              </div>

              {/* Platform icon */}
              <div className={`w-10 h-10 rounded-lg bg-gradient-to-br ${platformColors[link.platform]} flex items-center justify-center text-white`}>
                {platformIcons[link.platform]}
              </div>

              {/* Info */}
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2">
                  <span className="font-medium text-neutral-900">{SOCIAL_PLATFORM_LABELS[link.platform]}</span>
                  {link.is_primary && (
                    <span className="px-2 py-0.5 bg-black text-white text-xs rounded-full">Primary</span>
                  )}
                </div>
                <p className="text-sm text-neutral-500 truncate">
                  {link.username ? `@${link.username}` : link.url}
                </p>
              </div>

              {/* Actions */}
              <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                <button
                  onClick={() => handleTogglePrimary(link.id, !link.is_primary)}
                  className={`px-3 py-1 text-xs rounded-full border transition-colors ${
                    link.is_primary 
                      ? 'border-black bg-black text-white' 
                      : 'border-neutral-300 text-neutral-600 hover:border-neutral-400'
                  }`}
                >
                  {link.is_primary ? 'Primary' : 'Set as Primary'}
                </button>
                <a
                  href={link.url}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="p-2 text-neutral-400 hover:text-neutral-600"
                >
                  <ExternalLink className="h-4 w-4" />
                </a>
                <button
                  onClick={() => handleDeleteLink(link.id)}
                  className="p-2 text-neutral-400 hover:text-red-500"
                >
                  <Trash2 className="h-4 w-4" />
                </button>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="text-center py-16 bg-white rounded-xl border border-neutral-200">
          <div className="w-16 h-16 mx-auto mb-4 rounded-full bg-neutral-100 flex items-center justify-center">
            <Globe className="h-8 w-8 text-neutral-400" />
          </div>
          <h3 className="text-lg font-semibold text-neutral-900 mb-1">No social links yet</h3>
          <p className="text-neutral-500 mb-4">Connect your social media to let fans and organisers find you</p>
          <Button onClick={() => setIsAddingLink(true)}>
            <Plus className="h-4 w-4 mr-2" />
            Add Your First Link
          </Button>
        </div>
      )}

      {/* Tips */}
      <div className="p-4 bg-neutral-100 rounded-xl">
        <h4 className="font-medium text-neutral-900 mb-2">≡ƒÆí Pro Tips</h4>
        <ul className="text-sm text-neutral-600 space-y-1">
          <li>ΓÇó Set your most active platform as "Primary" - it will be shown first</li>
          <li>ΓÇó Add your Spotify/Apple Music links so fans can stream your music</li>
          <li>ΓÇó Instagram and TikTok help organisers see your audience engagement</li>
        </ul>
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { Bell, Check, CheckCheck, Trash2, Filter, Loader2 } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Separator } from '@/components/ui/separator';
import { cn } from '@/lib/utils';
import { formatDistanceToNow, format } from 'date-fns';

interface Notification {
  id: string;
  type: string;
  title: string;
  message: string;
  read: boolean;
  link: string | null;
  created_at: string;
}

interface NotificationsResponse {
  notifications: Notification[];
  total: number;
  unreadCount: number;
  hasMore: boolean;
}

const notificationTypeLabels: Record<string, string> = {
  booking_request: 'Booking Request',
  booking_confirmed: 'Booking Confirmed',
  booking_declined: 'Booking Declined',
  booking_cancelled: 'Booking Cancelled',
  booking_completed: 'Booking Completed',
  payment_received: 'Payment Received',
  payment_failed: 'Payment Failed',
  payout_requested: 'Payout Requested',
  payout_processed: 'Payout Processed',
  ticket_purchased: 'Ticket Purchased',
  ticket_transferred: 'Ticket Transferred',
  event_reminder: 'Event Reminder',
  event_cancelled: 'Event Cancelled',
  event_updated: 'Event Updated',
  review_received: 'Review Received',
  review_requested: 'Review Requested',
  message_received: 'Message Received',
  profile_verified: 'Profile Verified',
  system: 'System',
  welcome: 'Welcome',
  promotional: 'Promotional',
};

export default function NotificationsPage() {
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);
  const [total, setTotal] = useState(0);
  const [unreadCount, setUnreadCount] = useState(0);
  const [hasMore, setHasMore] = useState(false);
  const [filter, setFilter] = useState<'all' | 'unread'>('all');
  const [offset, setOffset] = useState(0);

  const fetchNotifications = useCallback(async (reset = false) => {
    try {
      const currentOffset = reset ? 0 : offset;
      if (reset) {
        setLoading(true);
      } else {
        setLoadingMore(true);
      }

      const unreadParam = filter === 'unread' ? '&unread=true' : '';
      const res = await fetch(`/api/notifications?limit=20&offset=${currentOffset}${unreadParam}`);
      
      if (res.ok) {
        const data: NotificationsResponse = await res.json();
        
        if (reset) {
          setNotifications(data.notifications);
        } else {
          setNotifications(prev => [...prev, ...data.notifications]);
        }
        
        setTotal(data.total);
        setUnreadCount(data.unreadCount);
        setHasMore(data.hasMore);
        setOffset(currentOffset + data.notifications.length);
      }
    } catch (error) {
      console.error('Failed to fetch notifications:', error);
    } finally {
      setLoading(false);
      setLoadingMore(false);
    }
  }, [filter, offset]);

  useEffect(() => {
    setOffset(0);
    fetchNotifications(true);
  }, [filter]); // eslint-disable-line react-hooks/exhaustive-deps

  const markAsRead = async (notificationId: string) => {
    try {
      await fetch('/api/notifications', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ notificationId }),
      });

      setNotifications(prev =>
        prev.map(n =>
          n.id === notificationId ? { ...n, read: true } : n
        )
      );
      setUnreadCount(prev => Math.max(0, prev - 1));
    } catch (error) {
      console.error('Failed to mark as read:', error);
    }
  };

  const markAllAsRead = async () => {
    try {
      await fetch('/api/notifications', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ markAllRead: true }),
      });

      setNotifications(prev =>
        prev.map(n => ({ ...n, read: true }))
      );
      setUnreadCount(0);
    } catch (error) {
      console.error('Failed to mark all as read:', error);
    }
  };

  const deleteNotification = async (notificationId: string) => {
    try {
      await fetch(`/api/notifications?id=${notificationId}`, {
        method: 'DELETE',
      });

      const notification = notifications.find(n => n.id === notificationId);
      setNotifications(prev => prev.filter(n => n.id !== notificationId));
      setTotal(prev => prev - 1);
      if (notification && !notification.read) {
        setUnreadCount(prev => Math.max(0, prev - 1));
      }
    } catch (error) {
      console.error('Failed to delete notification:', error);
    }
  };

  const handleNotificationClick = (notification: Notification) => {
    if (!notification.read) {
      markAsRead(notification.id);
    }
    if (notification.link) {
      window.location.href = notification.link;
    }
  };

  const getNotificationStyles = (type: string) => {
    const styles: Record<string, { bg: string; border: string; icon: string }> = {
      booking_request: { bg: 'bg-blue-50', border: 'border-blue-200', icon: 'text-blue-600' },
      booking_confirmed: { bg: 'bg-green-50', border: 'border-green-200', icon: 'text-green-600' },
      booking_declined: { bg: 'bg-red-50', border: 'border-red-200', icon: 'text-red-600' },
      booking_cancelled: { bg: 'bg-orange-50', border: 'border-orange-200', icon: 'text-orange-600' },
      payment_received: { bg: 'bg-green-50', border: 'border-green-200', icon: 'text-green-600' },
      payment_failed: { bg: 'bg-red-50', border: 'border-red-200', icon: 'text-red-600' },
      payout_processed: { bg: 'bg-green-50', border: 'border-green-200', icon: 'text-green-600' },
      ticket_purchased: { bg: 'bg-purple-50', border: 'border-purple-200', icon: 'text-purple-600' },
      event_reminder: { bg: 'bg-yellow-50', border: 'border-yellow-200', icon: 'text-yellow-600' },
      review_received: { bg: 'bg-pink-50', border: 'border-pink-200', icon: 'text-pink-600' },
      message_received: { bg: 'bg-indigo-50', border: 'border-indigo-200', icon: 'text-indigo-600' },
    };
    return styles[type] || { bg: 'bg-gray-50', border: 'border-gray-200', icon: 'text-gray-600' };
  };

  // Group notifications by date
  const groupedNotifications = notifications.reduce((groups, notification) => {
    const date = format(new Date(notification.created_at), 'yyyy-MM-dd');
    if (!groups[date]) {
      groups[date] = [];
    }
    groups[date].push(notification);
    return groups;
  }, {} as Record<string, Notification[]>);

  const formatDateHeader = (dateStr: string) => {
    const date = new Date(dateStr);
    const today = new Date();
    const yesterday = new Date(today);
    yesterday.setDate(yesterday.getDate() - 1);

    if (format(date, 'yyyy-MM-dd') === format(today, 'yyyy-MM-dd')) {
      return 'Today';
    }
    if (format(date, 'yyyy-MM-dd') === format(yesterday, 'yyyy-MM-dd')) {
      return 'Yesterday';
    }
    return format(date, 'EEEE, MMMM d, yyyy');
  };

  return (
    <div className="container max-w-4xl py-8">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-3xl font-bold">Notifications</h1>
          <p className="text-muted-foreground mt-1">
            {unreadCount > 0 
              ? `You have ${unreadCount} unread notification${unreadCount === 1 ? '' : 's'}`
              : 'You\'re all caught up!'
            }
          </p>
        </div>
        <div className="flex items-center gap-2">
          <Select
            value={filter}
            onValueChange={(value: 'all' | 'unread') => setFilter(value)}
          >
            <SelectTrigger className="w-32">
              <Filter className="h-4 w-4 mr-2" />
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">All</SelectItem>
              <SelectItem value="unread">Unread</SelectItem>
            </SelectContent>
          </Select>
          
          {unreadCount > 0 && (
            <Button variant="outline" onClick={markAllAsRead}>
              <CheckCheck className="h-4 w-4 mr-2" />
              Mark all read
            </Button>
          )}
        </div>
      </div>

      {loading ? (
        <Card>
          <CardContent className="flex items-center justify-center py-12">
            <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
          </CardContent>
        </Card>
      ) : notifications.length === 0 ? (
        <Card>
          <CardContent className="flex flex-col items-center justify-center py-16 text-center">
            <Bell className="h-16 w-16 text-muted-foreground/30 mb-4" />
            <h3 className="text-xl font-semibold mb-2">No notifications</h3>
            <p className="text-muted-foreground">
              {filter === 'unread' 
                ? 'You have no unread notifications'
                : 'You don\'t have any notifications yet'
              }
            </p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-6">
          {Object.entries(groupedNotifications).map(([date, dateNotifications]) => (
            <div key={date}>
              <h2 className="text-sm font-semibold text-muted-foreground mb-3">
                {formatDateHeader(date)}
              </h2>
              <Card>
                <CardContent className="p-0">
                  {dateNotifications.map((notification, index) => {
                    const styles = getNotificationStyles(notification.type);
                    return (
                      <div key={notification.id}>
                        <div
                          className={cn(
                            'flex gap-4 p-4 cursor-pointer hover:bg-muted/50 transition-colors',
                            !notification.read && 'bg-primary/5'
                          )}
                          onClick={() => handleNotificationClick(notification)}
                        >
                          {/* Icon */}
                          <div
                            className={cn(
                              'flex h-10 w-10 shrink-0 items-center justify-center rounded-full border',
                              styles.bg,
                              styles.border,
                              styles.icon
                            )}
                          >
                            <Bell className="h-5 w-5" />
                          </div>

                          {/* Content */}
                          <div className="flex-1 min-w-0">
                            <div className="flex items-start justify-between gap-2">
                              <div>
                                <span className="text-xs font-medium text-muted-foreground">
                                  {notificationTypeLabels[notification.type] || notification.type}
                                </span>
                                <h4
                                  className={cn(
                                    'font-medium mt-0.5',
                                    !notification.read && 'font-semibold'
                                  )}
                                >
                                  {notification.title}
                                </h4>
                              </div>
                              <div className="flex items-center gap-1">
                                {!notification.read && (
                                  <span className="h-2 w-2 rounded-full bg-primary" />
                                )}
                              </div>
                            </div>
                            <p className="text-sm text-muted-foreground mt-1">
                              {notification.message}
                            </p>
                            <p className="text-xs text-muted-foreground/70 mt-2">
                              {formatDistanceToNow(new Date(notification.created_at), {
                                addSuffix: true,
                              })}
                            </p>
                          </div>

                          {/* Actions */}
                          <div className="flex shrink-0 items-start gap-1">
                            {!notification.read && (
                              <Button
                                variant="ghost"
                                size="icon"
                                className="h-8 w-8"
                                onClick={(e) => {
                                  e.stopPropagation();
                                  markAsRead(notification.id);
                                }}
                                title="Mark as read"
                              >
                                <Check className="h-4 w-4" />
                              </Button>
                            )}
                            <Button
                              variant="ghost"
                              size="icon"
                              className="h-8 w-8 text-muted-foreground hover:text-destructive"
                              onClick={(e) => {
                                e.stopPropagation();
                                deleteNotification(notification.id);
                              }}
                              title="Delete"
                            >
                              <Trash2 className="h-4 w-4" />
                            </Button>
                          </div>
                        </div>
                        {index < dateNotifications.length - 1 && <Separator />}
                      </div>
                    );
                  })}
                </CardContent>
              </Card>
            </div>
          ))}

          {hasMore && (
            <div className="text-center">
              <Button
                variant="outline"
                onClick={() => fetchNotifications(false)}
                disabled={loadingMore}
              >
                {loadingMore ? (
                  <>
                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                    Loading...
                  </>
                ) : (
                  'Load More'
                )}
              </Button>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

'use client'

import { useEffect, useState } from 'react'
import { useParams, useRouter, useSearchParams } from 'next/navigation'
import Link from 'next/link'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { Badge } from '@/components/ui/badge'
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar'
import { 
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import { 
  ArrowLeft,
  Loader2,
  Calendar,
  Clock,
  MapPin,
  CheckCircle,
  AlertCircle
} from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import { useAuth } from '@/components/providers/auth-provider'
import { 
  type Provider, 
  type ProviderService, 
  type Event,
  SERVICE_CATEGORY_LABELS,
  PRICE_TYPE_LABELS,
  type SaProvince
} from '@/types/database'
import { formatCurrency } from '@/lib/helpers'
import { toast } from 'sonner'

// Province labels
const PROVINCE_LABELS: Record<SaProvince, string> = {
  gauteng: 'Gauteng',
  western_cape: 'Western Cape',
  kwazulu_natal: 'KwaZulu-Natal',
  eastern_cape: 'Eastern Cape',
  free_state: 'Free State',
  mpumalanga: 'Mpumalanga',
  limpopo: 'Limpopo',
  north_west: 'North West',
  northern_cape: 'Northern Cape',
}

interface ProviderWithProfile extends Provider {
  profile?: {
    full_name: string | null
    email?: string | null
    phone?: string | null
  }
}

export default function BookCrewPage() {
  const params = useParams()
  const router = useRouter()
  const searchParams = useSearchParams()
  const { profile } = useAuth()
  const providerId = params.id as string
  const preselectedEventId = searchParams.get('event')
  const requestedMode = searchParams.get('mode') === 'work' ? 'work' : 'services'

  const [provider, setProvider] = useState<ProviderWithProfile | null>(null)
  const [services, setServices] = useState<ProviderService[]>([])
  const [events, setEvents] = useState<Event[]>([])
  const [loading, setLoading] = useState(true)
  const [submitting, setSubmitting] = useState(false)

  // Form state
  const [bookingMode, setBookingMode] = useState<'services' | 'work'>(requestedMode)
  const [selectedEventId, setSelectedEventId] = useState(preselectedEventId || '')
  const [selectedServiceId, setSelectedServiceId] = useState('')
  const [workRole, setWorkRole] = useState('event_ops')
  const [offeredAmount, setOfferedAmount] = useState('')
  const [quantity, setQuantity] = useState(1)
  const [specialRequirements, setSpecialRequirements] = useState('')

  useEffect(() => {
    if (!profile) {
      router.push('/auth/signin')
      return
    }

    if (!profile.is_organizer) {
      router.push('/profile')
      toast.error('Only organisers can book crew')
      return
    }

    fetchData()
  }, [profile, providerId, router])

  const fetchData = async () => {
    if (!profile) return

    setLoading(true)
    try {
      const supabase = createClient()

      // Fetch provider
      const { data: providerData, error: providerError } = await supabase
        .from('providers')
        .select(`
          *,
          profile:profiles(full_name, email, phone)
        `)
        .eq('id', providerId)
        .single()

      if (providerError || !providerData) {
        toast.error('Provider not found')
        router.push('/crew')
        return
      }

      setProvider(providerData)

      const supportsWork = providerData.work_mode === 'looking_for_work' || providerData.work_mode === 'both'
      const supportsServices = providerData.work_mode === 'offering_services' || providerData.work_mode === 'both'

      if (requestedMode === 'work' && !supportsWork && supportsServices) {
        setBookingMode('services')
      }
      if (requestedMode === 'services' && !supportsServices && supportsWork) {
        setBookingMode('work')
      }

      // Fetch services
      const { data: servicesData } = await supabase
        .from('provider_services')
        .select('*')
        .eq('provider_id', providerId)
        .eq('is_available', true)
        .order('base_price', { ascending: true })

      setServices(servicesData || [])

      const supportsWorkAfterLoad = providerData.work_mode === 'looking_for_work' || providerData.work_mode === 'both'
      const supportsServicesAfterLoad = providerData.work_mode === 'offering_services' || providerData.work_mode === 'both' || (servicesData?.length || 0) > 0

      if (requestedMode === 'work' && !supportsWorkAfterLoad && supportsServicesAfterLoad) {
        setBookingMode('services')
      }
      if (requestedMode === 'services' && !supportsServicesAfterLoad && supportsWorkAfterLoad) {
        setBookingMode('work')
      }

      // Pre-select first service and set default amount
      if (servicesData && servicesData.length > 0) {
        setSelectedServiceId(servicesData[0].id)
        setOfferedAmount(servicesData[0].base_price.toString())
      }

      // Fetch organiser's upcoming events (published or locked)
      const { data: eventsData } = await supabase
        .from('events')
        .select('*')
        .eq('organizer_id', profile.id)
        .in('state', ['published', 'locked'])
        .gte('event_date', new Date().toISOString().split('T')[0])
        .order('event_date', { ascending: true })

      setEvents(eventsData || [])

      // Pre-select event if passed in URL
      if (preselectedEventId && eventsData?.some(e => e.id === preselectedEventId)) {
        setSelectedEventId(preselectedEventId)
      } else if (eventsData && eventsData.length > 0) {
        setSelectedEventId(eventsData[0].id)
      }
    } catch (error) {
      console.error('Error fetching data:', error)
      toast.error('Failed to load data')
    } finally {
      setLoading(false)
    }
  }

  // Update offered amount when service changes
  const handleServiceChange = (serviceId: string) => {
    setSelectedServiceId(serviceId)
    const service = services.find(s => s.id === serviceId)
    if (service) {
      setOfferedAmount((service.base_price * quantity).toString())
    }
  }

  // Update offered amount when quantity changes
  const handleQuantityChange = (newQuantity: number) => {
    setQuantity(newQuantity)
    const service = services.find(s => s.id === selectedServiceId)
    if (service) {
      setOfferedAmount((service.base_price * newQuantity).toString())
    }
  }

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault()

    if (!selectedEventId) {
      toast.error('Please select an event')
      return
    }

    if (bookingMode === 'services' && !selectedServiceId) {
      toast.error('Please select a service')
      return
    }

    if (!offeredAmount || parseFloat(offeredAmount) <= 0) {
      toast.error('Please enter a valid amount')
      return
    }

    const selectedEvent = events.find(e => e.id === selectedEventId)
    if (!selectedEvent) {
      toast.error('Invalid event selected')
      return
    }

    setSubmitting(true)
    try {
      const supabase = createClient()

      if (bookingMode === 'work') {
        const response = await fetch(`/api/events/${selectedEventId}/team`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            action: 'invite',
            fullName: provider?.profile?.full_name || provider?.business_name || 'Crew member',
            email: provider?.profile?.email || provider?.business_email || '',
            phone: provider?.profile?.phone || provider?.business_phone || '',
            role: workRole,
            offeredRate: parseFloat(offeredAmount),
            inviteMessage: specialRequirements.trim() || '',
          }),
        })

        const data = await response.json()
        if (!response.ok) {
          throw new Error(data.error || 'Failed to send work invite')
        }

        toast.success('Event work invite sent!')
        router.push(`/dashboard/organizer/events/${selectedEventId}/team`)
        return
      }

      const { data: newBooking, error } = await supabase
        .from('provider_bookings')
        .insert({
          event_id: selectedEventId,
          provider_id: providerId,
          service_id: selectedServiceId,
          organizer_id: profile!.id,
          offered_amount: parseFloat(offeredAmount),
          service_date: selectedEvent.event_date,
          quantity: quantity,
          special_requirements: specialRequirements.trim() || null,
          organizer_notes: specialRequirements.trim() || null,
        })
        .select('id')
        .single()

      if (error) {
        if (error.code === '23505') {
          toast.error('You have already booked this service for this event')
        } else {
          throw error
        }
        return
      }

      toast.success('Booking request sent! ≡ƒÄë')

      // Auto-open conversation linked to this booking
      try {
        const convoRes = await fetch('/api/conversations/start', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            recipientId: provider?.profile_id,
            contextType: 'provider_booking',
            contextId: newBooking.id,
          }),
        })
        const convoData = await convoRes.json()
        if (convoData.conversationId) {
          router.push(`/messages?chat=${convoData.conversationId}`)
          return
        }
      } catch {
        // fallback to crew dashboard if chat fails
      }
      router.push('/dashboard/organizer/crew')
    } catch (error) {
      console.error('Error creating booking:', error)
      toast.error('Failed to send booking request')
    } finally {
      setSubmitting(false)
    }
  }

  if (loading || !profile) {
    return (
      <div className="flex justify-center items-center min-h-[50vh]">
        <Loader2 className="h-8 w-8 animate-spin text-orange-500" />
      </div>
    )
  }

  if (!provider) {
    return null
  }

  const selectedService = services.find(s => s.id === selectedServiceId)
  const selectedEvent = events.find(e => e.id === selectedEventId)

  return (
    <div className="container mx-auto px-4 py-8 max-w-2xl">
      {/* Back Button */}
      <Link href={`/crew/${providerId}`} className="inline-flex items-center text-muted-foreground hover:text-foreground mb-6">
        <ArrowLeft className="h-4 w-4 mr-2" />
        Back to Provider
      </Link>

      {/* Provider Info */}
      <Card className="mb-6">
        <CardContent className="pt-6">
          <div className="flex items-center gap-4">
            <Avatar className="h-16 w-16">
              <AvatarImage src={provider.profile_image || undefined} />
              <AvatarFallback className="text-xl bg-orange-100 text-orange-600">
                {provider.business_name.charAt(0).toUpperCase()}
              </AvatarFallback>
            </Avatar>
            <div>
              <h2 className="text-xl font-semibold">{provider.business_name}</h2>
              <div className="mt-1 flex flex-wrap gap-2">
                <Badge variant="outline">
                  {SERVICE_CATEGORY_LABELS[provider.primary_category]}
                </Badge>
                {(provider.work_mode === 'looking_for_work' || provider.work_mode === 'both') && (
                  <Badge variant="secondary">Event Staff</Badge>
                )}
                {(provider.work_mode === 'offering_services' || provider.work_mode === 'both' || services.length > 0) && (
                  <Badge variant="outline">Service Provider</Badge>
                )}
              </div>
              <p className="text-sm text-muted-foreground flex items-center gap-1 mt-1">
                <MapPin className="h-3 w-3" />
                {PROVINCE_LABELS[provider.location]}
              </p>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Booking Form */}
      <Card>
        <CardHeader>
          <CardTitle>{bookingMode === 'work' ? 'Hire for Event Work' : 'Book Services'}</CardTitle>
          <CardDescription>
            {bookingMode === 'work'
              ? 'Send a staff hire invite with your offered rate. They can accept or negotiate in messages.'
              : 'Send a service booking request for your event. They can accept or negotiate in messages.'}
          </CardDescription>
        </CardHeader>
        <CardContent>
          {events.length === 0 ? (
            <div className="text-center py-8">
              <AlertCircle className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
              <h3 className="font-semibold mb-2">No upcoming events</h3>
              <p className="text-sm text-muted-foreground mb-4">
                You need a published event to book crew
              </p>
              <Link href="/dashboard/organizer/events/new">
                <Button>Create Event</Button>
              </Link>
            </div>
          ) : services.length === 0 ? (
            <div className="text-center py-8">
              <AlertCircle className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
              <h3 className="font-semibold mb-2">No services available</h3>
              <p className="text-sm text-muted-foreground">
                This provider hasn&apos;t listed any services yet
              </p>
            </div>
          ) : (
            <form onSubmit={handleSubmit} className="space-y-6">
              {(provider.work_mode === 'both' || (provider.work_mode === 'looking_for_work' && services.length > 0)) && (
                <div className="grid gap-2 md:grid-cols-2">
                  <Button
                    type="button"
                    variant={bookingMode === 'work' ? 'default' : 'outline'}
                    onClick={() => setBookingMode('work')}
                  >
                    Hire for Event Work
                  </Button>
                  <Button
                    type="button"
                    variant={bookingMode === 'services' ? 'default' : 'outline'}
                    onClick={() => setBookingMode('services')}
                  >
                    Book Services
                  </Button>
                </div>
              )}

              {/* Select Event */}
              <div>
                <Label htmlFor="event">Select Event *</Label>
                <Select value={selectedEventId} onValueChange={setSelectedEventId}>
                  <SelectTrigger>
                    <SelectValue placeholder="Choose an event" />
                  </SelectTrigger>
                  <SelectContent>
                    {events.map((event) => (
                      <SelectItem key={event.id} value={event.id}>
                        <div className="flex items-center gap-2">
                          <Calendar className="h-4 w-4" />
                          {event.title} - {new Date(event.event_date).toLocaleDateString()}
                        </div>
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                {selectedEvent && (
                  <p className="text-xs text-muted-foreground mt-1">
                    {selectedEvent.venue} ΓÇó {PROVINCE_LABELS[selectedEvent.location as SaProvince]}
                  </p>
                )}
              </div>

              {bookingMode === 'services' ? (
                <>
                  <div>
                    <Label htmlFor="service">Select Service *</Label>
                    <Select value={selectedServiceId} onValueChange={handleServiceChange}>
                      <SelectTrigger>
                        <SelectValue placeholder="Choose a service" />
                      </SelectTrigger>
                      <SelectContent>
                        {services.map((service) => (
                          <SelectItem key={service.id} value={service.id}>
                            <div className="flex justify-between items-center w-full">
                              <span>{service.service_name}</span>
                              <span className="text-muted-foreground ml-2">
                                {formatCurrency(service.base_price)} ({PRICE_TYPE_LABELS[service.price_type]})
                              </span>
                            </div>
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                    {selectedService?.description && (
                      <p className="text-xs text-muted-foreground mt-1">
                        {selectedService.description}
                      </p>
                    )}
                  </div>

                  <div>
                    <Label htmlFor="quantity">Quantity</Label>
                    <Input
                      id="quantity"
                      type="number"
                      min={1}
                      max={100}
                      value={quantity}
                      onChange={(e) => handleQuantityChange(parseInt(e.target.value) || 1)}
                    />
                    <p className="text-xs text-muted-foreground mt-1">
                      How many units/hours/days do you need?
                    </p>
                  </div>
                </>
              ) : (
                <div>
                  <Label htmlFor="work-role">Staff role needed *</Label>
                  <Select value={workRole} onValueChange={setWorkRole}>
                    <SelectTrigger id="work-role">
                      <SelectValue placeholder="Choose a role" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="door_staff">Door Staff</SelectItem>
                      <SelectItem value="guest_list_staff">Guest List Staff</SelectItem>
                      <SelectItem value="event_ops">Event Ops Lead</SelectItem>
                    </SelectContent>
                  </Select>
                  <p className="text-xs text-muted-foreground mt-1">
                    Send the role and shift offer you want this crew member to review.
                  </p>
                </div>
              )}

              {/* Offered Amount */}
              <div>
                <Label htmlFor="amount">{bookingMode === 'work' ? 'Your Rate Offer (R) *' : 'Your Offer (R) *'}</Label>
                <Input
                  id="amount"
                  type="number"
                  min="0"
                  step="0.01"
                  value={offeredAmount}
                  onChange={(e) => setOfferedAmount(e.target.value)}
                  required
                />
                {bookingMode === 'services' && selectedService && (
                  <p className="text-xs text-muted-foreground mt-1">
                    Listed service price: {formatCurrency(selectedService.base_price)} ├ù {quantity} = {formatCurrency(selectedService.base_price * quantity)}. You can still send a different offer.
                  </p>
                )}
                {bookingMode === 'work' && (
                  <p className="text-xs text-muted-foreground mt-1">
                    Send the shift rate you want to offer. They can accept it or message you to negotiate.
                  </p>
                )}
              </div>

              {/* Special Requirements */}
              <div>
                <Label htmlFor="requirements">Special Requirements / Notes</Label>
                <Textarea
                  id="requirements"
                  placeholder="Any specific requirements, timing details, or questions..."
                  value={specialRequirements}
                  onChange={(e) => setSpecialRequirements(e.target.value)}
                  rows={4}
                />
              </div>

              {/* Summary */}
              {selectedEvent && (bookingMode === 'work' || selectedService) && (
                <Card className="bg-orange-50 border-orange-200">
                  <CardContent className="pt-4">
                    <h4 className="font-semibold mb-2">Booking Summary</h4>
                    <div className="space-y-1 text-sm">
                      <p><strong>Event:</strong> {selectedEvent.title}</p>
                      <p><strong>Date:</strong> {new Date(selectedEvent.event_date).toLocaleDateString()}</p>
                      {bookingMode === 'work' ? (
                        <>
                          <p><strong>Hire type:</strong> Event Work</p>
                          <p><strong>Role:</strong> {workRole.replaceAll('_', ' ')}</p>
                        </>
                      ) : (
                        <>
                          <p><strong>Service:</strong> {selectedService?.service_name}</p>
                          <p><strong>Quantity:</strong> {quantity}</p>
                        </>
                      )}
                      <p className="text-lg font-bold text-orange-600 mt-2">
                        Offer: {formatCurrency(parseFloat(offeredAmount) || 0)}
                      </p>
                    </div>
                  </CardContent>
                </Card>
              )}

              <Button
                type="submit" 
                className="w-full bg-orange-500 hover:bg-orange-600"
                disabled={submitting}
              >
                {submitting ? (
                  <Loader2 className="h-4 w-4 animate-spin mr-2" />
                ) : (
                  <CheckCircle className="h-4 w-4 mr-2" />
                )}
                {bookingMode === 'work' ? 'Send Event Work Invite' : 'Send Booking Request'}
              </Button>

              <p className="text-xs text-center text-muted-foreground">
                {bookingMode === 'work'
                  ? 'They can accept your invite or message you to discuss rate and details.'
                  : 'The provider can accept your offer or message you to negotiate before payment.'}
              </p>
            </form>
          )}
        </CardContent>
      </Card>
    </div>
  )
}

