'use client'

/**
 * EVENT CHECK-IN PAGE
 * /dashboard/organizer/events/[id]/checkin
 * 
 * Scanner interface for door staff to check in attendees
 */

import { useEffect, useState, useRef, useCallback } from 'react'
import { useParams, useRouter } from 'next/navigation'
import { useAuth } from '@/components/providers/auth-provider'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Badge } from '@/components/ui/badge'
import { Separator } from '@/components/ui/separator'
import { Textarea } from '@/components/ui/textarea'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import { toast } from 'sonner'
import { formatDate, formatTime } from '@/lib/helpers'
import {
  Scan,
  Camera,
  CheckCircle,
  XCircle,
  AlertCircle,
  Users,
  Search,
  ArrowLeft,
  Loader2,
  User,
  Ticket,
  RefreshCw,
  UserPlus,
  Gift,
} from 'lucide-react'
import Link from 'next/link'
import { cn } from '@/lib/utils'

interface Event {
  id: string
  title: string
  event_date: string
  start_time: string
  venue: string
  tickets_sold: number
}

interface ScanResult {
  success: boolean
  status: 'valid' | 'used' | 'invalid' | 'error'
  message: string
  ticket?: {
    id: string
    code: string
    type: string
    holder: string
    checkedInAt?: string
  }
}

interface AttendanceStats {
  checkedIn: number
  total: number
}

interface AccessPass {
  id: string
  full_name: string
  code: string
  pass_type: string
  checked_in: boolean
}

export default function EventCheckinPage() {
  const params = useParams()
  const router = useRouter()
  const { profile, loading: authLoading } = useAuth()
  
  const [event, setEvent] = useState<Event | null>(null)
  const [roleLabel, setRoleLabel] = useState('Event Team')
  const [isOwner, setIsOwner] = useState(false)
  const [canManageGuestList, setCanManageGuestList] = useState(false)
  const [loading, setLoading] = useState(true)
  const [manualCode, setManualCode] = useState('')
  const [scanning, setScanning] = useState(false)
  const [cameraOpen, setCameraOpen] = useState(false)
  const [cameraStarting, setCameraStarting] = useState(false)
  const [cameraError, setCameraError] = useState('')
  const [confirmingCheckin, setConfirmingCheckin] = useState(false)
  const [lastScan, setLastScan] = useState<ScanResult | null>(null)
  const [attendance, setAttendance] = useState<AttendanceStats>({ checkedIn: 0, total: 0 })
  const [recentCheckins, setRecentCheckins] = useState<Array<{
    code: string
    holder: string
    time: string
  }>>([])
  const [accessPasses, setAccessPasses] = useState<AccessPass[]>([])
  const [creatingPass, setCreatingPass] = useState(false)
  const [passForm, setPassForm] = useState({
    fullName: '',
    email: '',
    phone: '',
    passType: 'guest_list',
    quantity: '1',
    notes: '',
  })
  
  const inputRef = useRef<HTMLInputElement>(null)
  const videoRef = useRef<HTMLVideoElement>(null)
  const mediaStreamRef = useRef<MediaStream | null>(null)
  const scanFrameRef = useRef<number | null>(null)
  const eventId = params.id as string

  // Load event data
  useEffect(() => {
    async function loadEvent() {
      if (!eventId) return

      try {
        const response = await fetch(`/api/events/${eventId}/team-access`, { cache: 'no-store' })
        const data = await response.json()

        if (!response.ok || !data.event) {
          toast.error(data.error || 'Not authorized')
          router.push('/dashboard/provider')
          return
        }

        const today = new Date()
        today.setHours(0, 0, 0, 0)
        const eventDate = new Date(data.event.event_date)
        eventDate.setHours(0, 0, 0, 0)

        if (eventDate < today) {
          toast.error('Check-in is closed for past events')
          router.push(data.isOwner ? `/dashboard/organizer/events/${eventId}/manage` : '/dashboard/provider')
          return
        }

        setEvent(data.event)
        setIsOwner(Boolean(data.isOwner))
        setRoleLabel(String(data.roleLabel || 'Event Team'))
        setCanManageGuestList(Boolean(data.permissions?.canManageGuestList))

        await refreshAttendance()
        await loadGuestList()
      } catch (error) {
        console.error('Check-in event load error:', error)
        toast.error('Failed to load event tools')
      } finally {
        setLoading(false)
      }
    }

    if (profile) {
      loadEvent()
    }
  }, [eventId, profile, router])

  // Refresh attendance stats
  const refreshAttendance = useCallback(async () => {
    try {
      const response = await fetch(`/api/events/${eventId}/attendance`, { cache: 'no-store' })
      const data = await response.json()
      if (!response.ok) {
        throw new Error(data.error || 'Failed to refresh attendance')
      }

      setAttendance({
        checkedIn: Number(data.stats?.checkedIn || 0),
        total: Number(data.stats?.totalTickets || 0),
      })
    } catch (error) {
      console.error('Attendance refresh error:', error)
    }
  }, [eventId])

  const loadGuestList = useCallback(async () => {
    try {
      const response = await fetch(`/api/events/${eventId}/guest-list`)
      const data = await response.json()
      if (response.ok) {
        setAccessPasses(data.passes || [])
      }
    } catch (error) {
      console.error('Guest list load error:', error)
    }
  }, [eventId])

  const stopCameraScanner = useCallback(() => {
    if (scanFrameRef.current) {
      cancelAnimationFrame(scanFrameRef.current)
      scanFrameRef.current = null
    }

    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach((track) => track.stop())
      mediaStreamRef.current = null
    }

    setCameraOpen(false)
    setCameraStarting(false)
  }, [])

  const handleCheckin = async (code: string) => {
    if (!code.trim() || scanning) return

    setScanning(true)
    setLastScan(null)

    try {
      const response = await fetch('/api/tickets/validate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          ticketCode: code.trim(),
          eventId,
        }),
      })

      const data = await response.json()
      const holderName = typeof data.ticket?.holder === 'string'
        ? data.ticket.holder
        : data.ticket?.holder?.full_name || 'Guest'

      const resolvedTicket = data.ticket
        ? {
            id: String(data.ticket.id || ''),
            code: String(data.ticket.code || data.ticket.ticket_code || code.trim().toUpperCase()),
            type: String(data.ticket.type || data.ticket.ticket_type || 'Entry'),
            holder: holderName,
            checkedInAt: data.ticket.checkedInAt || data.ticket.checked_in_at,
          }
        : undefined

      if (data.status === 'valid') {
        setLastScan({
          success: false,
          status: 'valid',
          message: 'Ticket verified. Confirm the name below before checking in.',
          ticket: resolvedTicket,
        })
        toast.success('Ticket verified ΓÇö ready to confirm')
      } else if (data.status === 'used') {
        setLastScan({
          success: false,
          status: 'used',
          message: data.message,
          ticket: resolvedTicket,
        })
        toast.warning('This attendee is already checked in')
      } else {
        setLastScan({
          success: false,
          status: 'invalid',
          message: data.message || data.error || 'Ticket is not valid for check-in',
          ticket: resolvedTicket,
        })
        toast.error(data.message || data.error || 'Ticket could not be verified')
      }
    } catch (error) {
      setLastScan({
        success: false,
        status: 'error',
        message: 'Validation failed. Please try again.',
      })
      toast.error('Validation failed')
    } finally {
      setScanning(false)
      inputRef.current?.focus()
    }
  }

  const handleConfirmCheckin = async () => {
    if (!lastScan?.ticket?.code || confirmingCheckin) return

    setConfirmingCheckin(true)
    try {
      const response = await fetch('/api/tickets/checkin', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          ticketCode: lastScan.ticket.code,
          eventId,
        }),
      })

      const data = await response.json()
      if (!response.ok || !data.success) {
        throw new Error(data.message || data.error || 'Check-in failed')
      }

      setLastScan({
        success: true,
        status: 'valid',
        message: data.message,
        ticket: data.ticket,
      })

      if (data.attendance) {
        setAttendance(data.attendance)
      }

      setRecentCheckins(prev => [{
        code: data.ticket.code,
        holder: data.ticket.holder,
        time: new Date().toLocaleTimeString(),
      }, ...prev.slice(0, 9)])

      setManualCode('')
      toast.success(`Γ£à ${data.ticket.holder} checked in!`)
    } catch (error) {
      toast.error(error instanceof Error ? error.message : 'Check-in failed')
    } finally {
      setConfirmingCheckin(false)
      inputRef.current?.focus()
    }
  }

  const startCameraScanner = useCallback(async () => {
    if (typeof window === 'undefined' || !navigator.mediaDevices?.getUserMedia) {
      const message = 'This device does not support camera scanning yet. Use the scanner field or enter the code manually.'
      setCameraError(message)
      toast.error(message)
      return
    }

    if (!("BarcodeDetector" in window)) {
      const message = 'Camera scan is not supported in this browser yet. Use the scanner field or enter the code manually.'
      setCameraError(message)
      toast.error(message)
      return
    }

    try {
      setCameraError('')
      setCameraStarting(true)
      setCameraOpen(true)

      const stream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: { ideal: 'environment' } },
        audio: false,
      })

      mediaStreamRef.current = stream

      if (videoRef.current) {
        videoRef.current.srcObject = stream
        await videoRef.current.play()
      }

      const Detector = (window as Window & { BarcodeDetector?: new (options?: { formats?: string[] }) => { detect: (source: HTMLVideoElement) => Promise<Array<{ rawValue?: string }>> } }).BarcodeDetector
      if (!Detector) {
        throw new Error('Barcode detector unavailable')
      }

      const detector = new Detector({ formats: ['qr_code', 'code_128', 'ean_13', 'ean_8'] })

      const scanLoop = async () => {
        if (!videoRef.current) return

        try {
          const codes = await detector.detect(videoRef.current)
          const value = String(codes?.[0]?.rawValue || '').trim()

          if (value) {
            setManualCode(value.toUpperCase())
            stopCameraScanner()
            handleCheckin(value)
            return
          }
        } catch {
          // ignore detection frame errors and keep scanning
        }

        scanFrameRef.current = requestAnimationFrame(scanLoop)
      }

      scanFrameRef.current = requestAnimationFrame(scanLoop)
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Camera access failed'
      setCameraError(message)
      toast.error(message)
      stopCameraScanner()
    } finally {
      setCameraStarting(false)
    }
  }, [handleCheckin, stopCameraScanner])

  const handleCreatePass = async (e: React.FormEvent) => {
    e.preventDefault()

    if (!passForm.fullName.trim()) {
      toast.error('Guest name is required')
      return
    }

    setCreatingPass(true)
    try {
      const response = await fetch(`/api/events/${eventId}/guest-list`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(passForm),
      })

      const data = await response.json()
      if (!response.ok) {
        throw new Error(data.error || 'Failed to create guest pass')
      }

      toast.success(`Created ${data.passes?.length || 1} access pass${(data.passes?.length || 1) > 1 ? 'es' : ''}`)
      setPassForm({
        fullName: '',
        email: '',
        phone: '',
        passType: 'guest_list',
        quantity: '1',
        notes: '',
      })
      await loadGuestList()
      await refreshAttendance()
    } catch (error) {
      toast.error(error instanceof Error ? error.message : 'Failed to create guest pass')
    } finally {
      setCreatingPass(false)
    }
  }

  // Handle manual code submission
  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    handleCheckin(manualCode)
  }

  // Auto-focus input
  useEffect(() => {
    if (!loading) {
      inputRef.current?.focus()
    }
  }, [loading])

  useEffect(() => {
    return () => {
      if (scanFrameRef.current) {
        cancelAnimationFrame(scanFrameRef.current)
      }
      if (mediaStreamRef.current) {
        mediaStreamRef.current.getTracks().forEach((track) => track.stop())
      }
    }
  }, [])

  if (authLoading || loading) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
      </div>
    )
  }

  if (!event) return null

  const attendancePercent = attendance.total > 0 
    ? Math.round((attendance.checkedIn / attendance.total) * 100) 
    : 0

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <div className="bg-white border-b sticky top-0 z-10">
        <div className="container mx-auto px-4 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <Link href={isOwner ? '/dashboard/organizer' : '/dashboard/provider'}>
                <Button variant="ghost" size="icon">
                  <ArrowLeft className="h-5 w-5" />
                </Button>
              </Link>
              <div>
                <h1 className="font-bold text-lg">{event.title}</h1>
                <p className="text-sm text-muted-foreground">
                  {formatDate(event.event_date)} ΓÇó {formatTime(event.start_time)}
                </p>
                <div className="mt-1 flex flex-wrap gap-2">
                  {!isOwner && <Badge variant="secondary">{roleLabel}</Badge>}
                  {!isOwner && <Badge variant="outline">Working this event</Badge>}
                </div>
              </div>
            </div>
            
            <div className="flex items-center gap-2">
              {isOwner ? (
                <Link href={`/dashboard/organizer/events/${event.id}/manage`}>
                  <Button variant="outline" size="sm">
                    <Users className="h-4 w-4 mr-2" />
                    Manage Event
                  </Button>
                </Link>
              ) : (
                <Link href="/dashboard/provider">
                  <Button variant="outline" size="sm">
                    <Users className="h-4 w-4 mr-2" />
                    Crew Dashboard
                  </Button>
                </Link>
              )}
              <Button variant="outline" size="sm" onClick={refreshAttendance}>
                <RefreshCw className="h-4 w-4 mr-2" />
                Refresh
              </Button>
            </div>
          </div>
        </div>
      </div>

      <div className="container mx-auto px-4 py-6">
        <div className="grid lg:grid-cols-3 gap-6">
          {/* Main Scanner Area */}
          <div className="lg:col-span-2 space-y-6">
            {/* Attendance Stats */}
            <Card>
              <CardContent className="p-6">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-4">
                    <div className="h-16 w-16 rounded-full bg-neutral-100 flex items-center justify-center">
                      <Users className="h-8 w-8 text-primary" />
                    </div>
                    <div>
                      <p className="text-3xl font-bold">
                        {attendance.checkedIn} / {attendance.total}
                      </p>
                      <p className="text-muted-foreground">Checked In</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-4xl font-bold text-primary">{attendancePercent}%</p>
                    <p className="text-sm text-muted-foreground">Attendance</p>
                  </div>
                </div>
                
                {/* Progress Bar */}
                <div className="mt-4 h-3 bg-gray-200 rounded-full overflow-hidden">
                  <div 
                    className="h-full bg-neutral-900 transition-all duration-500"
                    style={{ width: `${attendancePercent}%` }}
                  />
                </div>
              </CardContent>
            </Card>

            {/* Manual Entry */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Scan className="h-5 w-5" />
                  Door scanner
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="flex flex-wrap gap-2">
                  <Button
                    type="button"
                    variant="outline"
                    onClick={() => {
                      inputRef.current?.focus()
                      setLastScan(null)
                      toast.success('Scanner ready ΓÇö scan now or paste the code here')
                    }}
                  >
                    <Scan className="h-4 w-4 mr-2" />
                    Ready for scanner
                  </Button>
                  <Button
                    type="button"
                    variant="outline"
                    onClick={() => {
                      if (cameraOpen) {
                        stopCameraScanner()
                      } else {
                        startCameraScanner()
                      }
                    }}
                    disabled={cameraStarting}
                  >
                    {cameraStarting ? <Loader2 className="h-4 w-4 mr-2 animate-spin" /> : <Camera className="h-4 w-4 mr-2" />}
                    {cameraOpen ? 'Close camera' : 'Use camera'}
                  </Button>
                </div>

                {cameraOpen && (
                  <div className="overflow-hidden rounded-lg border bg-black">
                    <video ref={videoRef} className="h-72 w-full object-cover" autoPlay playsInline muted />
                    <div className="bg-white p-3 text-sm text-muted-foreground">
                      Point the attendee QR code at the camera.
                    </div>
                  </div>
                )}

                {cameraError && (
                  <div className="rounded-lg border border-yellow-200 bg-yellow-50 p-3 text-sm text-yellow-800">
                    {cameraError}
                  </div>
                )}

                <form onSubmit={handleManualSubmit} className="flex gap-3">
                  <Input
                    ref={inputRef}
                    value={manualCode}
                    onChange={(e) => setManualCode(e.target.value.toUpperCase())}
                    placeholder="Tap Ready for scanner, use Camera, or enter the ticket code"
                    className="font-mono text-lg"
                    disabled={scanning}
                    autoComplete="off"
                  />
                  <Button type="submit" disabled={!manualCode.trim() || scanning} size="lg">
                    {scanning ? (
                      <Loader2 className="h-5 w-5 animate-spin" />
                    ) : (
                      <>
                        <Search className="h-5 w-5 mr-2" />
                        Verify
                      </>
                    )}
                  </Button>
                </form>
                <p className="text-xs text-muted-foreground">
                  The input box is the live capture field for a handheld scanner. The new camera button can also scan directly in-browser when the device allows it.
                </p>
              </CardContent>
            </Card>

            {/* Last Scan Result */}
            {lastScan && (
              <Card className={cn(
                "border-2 transition-all",
                lastScan.status === 'valid' && "border-green-500 bg-green-50",
                lastScan.status === 'used' && "border-yellow-500 bg-yellow-50",
                lastScan.status === 'invalid' && "border-red-500 bg-red-50",
                lastScan.status === 'error' && "border-red-500 bg-red-50"
              )}>
                <CardContent className="p-6">
                  <div className="flex items-start gap-4">
                    <div className={cn(
                      "h-16 w-16 rounded-full flex items-center justify-center flex-shrink-0",
                      lastScan.status === 'valid' && "bg-green-100",
                      lastScan.status === 'used' && "bg-yellow-100",
                      (lastScan.status === 'invalid' || lastScan.status === 'error') && "bg-red-100"
                    )}>
                      {lastScan.status === 'valid' && <CheckCircle className="h-8 w-8 text-green-600" />}
                      {lastScan.status === 'used' && <AlertCircle className="h-8 w-8 text-yellow-600" />}
                      {(lastScan.status === 'invalid' || lastScan.status === 'error') && (
                        <XCircle className="h-8 w-8 text-red-600" />
                      )}
                    </div>
                    
                    <div className="flex-1">
                      <h3 className={cn(
                        "text-xl font-bold",
                        lastScan.status === 'valid' && "text-green-700",
                        lastScan.status === 'used' && "text-yellow-700",
                        (lastScan.status === 'invalid' || lastScan.status === 'error') && "text-red-700"
                      )}>
                        {lastScan.status === 'valid' && (lastScan.success ? 'Check-In Successful!' : 'Ticket Verified')} 
                        {lastScan.status === 'used' && 'Already Checked In'}
                        {lastScan.status === 'invalid' && 'Invalid Ticket'}
                        {lastScan.status === 'error' && 'Error'}
                      </h3>
                      <p className="text-muted-foreground">{lastScan.message}</p>
                      
                      {lastScan.ticket && (
                        <div className="mt-3 space-y-3">
                          <div className="flex items-center gap-4 flex-wrap">
                          <div className="flex items-center gap-2">
                            <User className="h-4 w-4 text-muted-foreground" />
                            <span className="font-medium">{lastScan.ticket.holder}</span>
                          </div>
                          <div className="flex items-center gap-2">
                            <Ticket className="h-4 w-4 text-muted-foreground" />
                            <span className="font-mono">{lastScan.ticket.code}</span>
                          </div>
                          <Badge variant="outline">{lastScan.ticket.type}</Badge>
                          </div>

                          {lastScan.status === 'valid' && !lastScan.success && (
                            <div className="flex gap-2 flex-wrap">
                              <Button onClick={handleConfirmCheckin} disabled={confirmingCheckin}>
                                {confirmingCheckin ? <Loader2 className="h-4 w-4 mr-2 animate-spin" /> : <CheckCircle className="h-4 w-4 mr-2" />}
                                Confirm check-in
                              </Button>
                              <Button variant="outline" onClick={() => setLastScan(null)}>
                                Cancel
                              </Button>
                            </div>
                          )}
                        </div>
                      )}
                    </div>
                  </div>
                </CardContent>
              </Card>
            )}
          </div>

          {/* Right Sidebar */}
          <div className="space-y-6">
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <UserPlus className="h-5 w-5 text-primary" />
                  Safer door flow
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-3 text-sm">
                <div className="rounded-lg bg-muted p-3">
                  <p className="font-medium">How to use it</p>
                  <ul className="mt-2 space-y-1 text-muted-foreground">
                    <li>ΓÇó Scan the attendee QR/barcode or enter the code</li>
                    <li>ΓÇó Review the personΓÇÖs details on screen</li>
                    <li>ΓÇó Tap confirm only after verifying the right person</li>
                  </ul>
                </div>

                <div className="rounded-lg border p-3">
                  <p className="font-medium">People & guest list</p>
                  <p className="text-muted-foreground mt-1">
                    {canManageGuestList
                      ? 'You can add guest or comp access for this event directly from this workspace.'
                      : 'You can verify arrivals here. Guest-list changes stay with the organiser or guest-list lead.'}
                  </p>
                  <p className="mt-2 text-muted-foreground">Guest / comp passes on this event: {accessPasses.length}</p>
                  {isOwner && (
                    <Link href={`/dashboard/organizer/events/${event.id}/manage`}>
                      <Button variant="outline" className="mt-3 w-full">Open people manager</Button>
                    </Link>
                  )}
                </div>
              </CardContent>
            </Card>

            {canManageGuestList && (
              <Card>
                <CardHeader>
                  <CardTitle className="flex items-center gap-2">
                    <Gift className="h-5 w-5 text-pink-600" />
                    Guest & comp access
                  </CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  <form onSubmit={handleCreatePass} className="space-y-3">
                    <Input
                      placeholder="Guest full name"
                      value={passForm.fullName}
                      onChange={(e) => setPassForm(prev => ({ ...prev, fullName: e.target.value }))}
                    />
                    <Input
                      placeholder="Email (optional)"
                      value={passForm.email}
                      onChange={(e) => setPassForm(prev => ({ ...prev, email: e.target.value }))}
                    />
                    <div className="grid grid-cols-2 gap-3">
                      <Input
                        placeholder="Phone"
                        value={passForm.phone}
                        onChange={(e) => setPassForm(prev => ({ ...prev, phone: e.target.value }))}
                      />
                      <Select
                        value={passForm.passType}
                        onValueChange={(value) => setPassForm(prev => ({ ...prev, passType: value }))}
                      >
                        <SelectTrigger>
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="guest_list">Guest List</SelectItem>
                          <SelectItem value="comp">Complimentary</SelectItem>
                          <SelectItem value="staff">Staff</SelectItem>
                          <SelectItem value="media">Media</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                    <div className="grid grid-cols-2 gap-3">
                      <Input
                        placeholder="Quantity"
                        type="number"
                        min="1"
                        max="20"
                        value={passForm.quantity}
                        onChange={(e) => setPassForm(prev => ({ ...prev, quantity: e.target.value }))}
                      />
                      <Button type="submit" disabled={creatingPass}>
                        {creatingPass ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <UserPlus className="mr-2 h-4 w-4" />}
                        Add pass
                      </Button>
                    </div>
                    <Textarea
                      placeholder="Notes for the door team"
                      value={passForm.notes}
                      onChange={(e) => setPassForm(prev => ({ ...prev, notes: e.target.value }))}
                      rows={3}
                    />
                  </form>

                  <div className="space-y-2">
                    {accessPasses.length === 0 ? (
                      <p className="text-sm text-muted-foreground">No guest or comp passes yet.</p>
                    ) : (
                      accessPasses.slice(0, 6).map((pass) => (
                        <div key={pass.id} className="rounded-md border p-2">
                          <div className="flex items-center justify-between gap-2">
                            <p className="font-medium text-sm">{pass.full_name}</p>
                            <Badge variant={pass.checked_in ? 'default' : 'outline'}>
                              {pass.pass_type.replace('_', ' ')}
                            </Badge>
                          </div>
                          <p className="text-xs text-muted-foreground font-mono mt-1">{pass.code}</p>
                        </div>
                      ))
                    )}
                  </div>
                </CardContent>
              </Card>
            )}

            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <CheckCircle className="h-5 w-5 text-green-600" />
                  Recent Check-ins
                </CardTitle>
              </CardHeader>
              <CardContent>
                {recentCheckins.length === 0 ? (
                  <p className="text-center text-muted-foreground py-8">
                    No check-ins yet
                  </p>
                ) : (
                  <div className="space-y-3">
                    {recentCheckins.map((checkin, i) => (
                      <div 
                        key={`${checkin.code}-${i}`}
                        className="flex items-center justify-between py-2 border-b last:border-0"
                      >
                        <div>
                          <p className="font-medium">{checkin.holder}</p>
                          <p className="text-xs text-muted-foreground font-mono">
                            {checkin.code}
                          </p>
                        </div>
                        <span className="text-xs text-muted-foreground">
                          {checkin.time}
                        </span>
                      </div>
                    ))}
                  </div>
                )}
              </CardContent>
            </Card>
          </div>
        </div>
      </div>
    </div>
  )
}

'use client'

import { useEffect, useState } from 'react'
import { useRouter } from 'next/navigation'
import Link from 'next/link'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import { ArrowLeft, Loader2, Image as ImageIcon } from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import { PROVINCES } from '@/lib/constants'
import { toast } from 'sonner'
import { useAuth } from '@/components/providers/auth-provider'
import { use } from 'react'
import { TicketTierEditor } from '@/components/events/ticket-tier-editor'
import { buildFallbackTier, createEmptyTier, getEventCapacityFromTiers, getStartingPriceFromTiers, normalizeTierPayload } from '@/lib/ticketing'

interface EditEventPageProps {
  params: Promise<{
    id: string
  }>
}

export default function EditEventPage({ params }: EditEventPageProps) {
  const { id } = use(params)
  const router = useRouter()
  const { profile, loading: authLoading } = useAuth()
  const [loading, setLoading] = useState(true)
  const [saving, setSaving] = useState(false)
  
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    venue: '',
    location: '',
    event_date: '',
    start_time: '',
    end_time: '',
    state: 'draft',
  })
  const [ticketTiers, setTicketTiers] = useState([
    createEmptyTier({
      name: 'General Admission',
      price: '150',
      quantity: '100',
    }),
  ])

  useEffect(() => {
    if (authLoading) return
    
    if (!profile) {
      router.push('/auth/signin')
      return
    }

    fetchEvent()
  }, [id, profile, authLoading, router])

  const fetchEvent = async () => {
    try {
      const supabase = createClient()
      
      const { data: event, error } = await supabase
        .from('events')
        .select('*')
        .eq('id', id)
        .single()

      if (error) throw error

      if (!event) {
        toast.error('Event not found')
        router.push('/dashboard/organizer')
        return
      }

      // Check if user owns this event
      if (event.organizer_id !== profile?.id) {
        toast.error('You do not have permission to edit this event')
        router.push('/dashboard/organizer')
        return
      }

      const today = new Date().toISOString().split('T')[0]
      if (event.event_date < today) {
        toast.error('Past events can no longer be edited')
        router.push(`/dashboard/organizer/events/${id}/manage`)
        return
      }

      setFormData({
        title: event.title || '',
        description: event.description || '',
        venue: event.venue || '',
        location: event.location || '',
        event_date: event.event_date || '',
        start_time: event.start_time || '',
        end_time: event.end_time || '',
        state: event.state || 'draft',
      })

      const { data: tiers, error: tiersError } = await supabase
        .from('event_ticket_types')
        .select('*')
        .eq('event_id', id)
        .order('sort_order', { ascending: true })

      if (tiersError && tiersError.code !== 'PGRST205') {
        console.error('Error fetching ticket tiers:', tiersError)
      }

      const fallbackTier = buildFallbackTier({
        id: event.id,
        ticket_price: Number(event.ticket_price || 0),
        capacity: Number(event.capacity || 0),
        tickets_sold: Number(event.tickets_sold || 0),
      })

      const tierRows = (tiers && tiers.length > 0 ? tiers : [fallbackTier]).map((tier) => ({
        id: tier.id,
        name: tier.name || 'General Admission',
        description: tier.description || '',
        price: String(tier.price ?? ''),
        quantity: String(tier.quantity ?? 0),
        sales_start: tier.sales_start ? String(tier.sales_start).slice(0, 16) : '',
        sales_end: tier.sales_end ? String(tier.sales_end).slice(0, 16) : '',
        is_active: tier.is_active ?? true,
        is_public: tier.is_public ?? true,
      }))

      setTicketTiers(tierRows)
    } catch (error) {
      console.error('Error fetching event:', error)
      toast.error('Failed to load event')
      router.push('/dashboard/organizer')
    } finally {
      setLoading(false)
    }
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    
    if (!profile) {
      toast.error('You must be logged in')
      return
    }

    if (!formData.event_date) {
      toast.error('Please select an event date')
      return
    }

    setSaving(true)

    try {
      const supabase = createClient()

      // Check if organizer already has another event on the same day (excluding this event)
      const { data: existingEvents, error: checkError } = await supabase
        .from('events')
        .select('id, title')
        .eq('organizer_id', profile.id)
        .eq('event_date', formData.event_date)
        .neq('id', id)
      
      if (checkError) throw checkError

      if (existingEvents && existingEvents.length > 0) {
        toast.error(`You already have an event scheduled on this date: "${existingEvents[0].title}". Please choose a different date.`)
        setSaving(false)
        return
      }

      const normalizedTiers = normalizeTierPayload(ticketTiers)

      if (normalizedTiers.length === 0) {
        toast.error('Please keep at least one valid ticket tier')
        setSaving(false)
        return
      }

      const { error } = await supabase
        .from('events')
        .update({
          title: formData.title,
          description: formData.description || null,
          venue: formData.venue,
          location: formData.location,
          event_date: formData.event_date,
          start_time: formData.start_time,
          end_time: formData.end_time || null,
          ticket_price: getStartingPriceFromTiers(ticketTiers),
          capacity: getEventCapacityFromTiers(ticketTiers),
        })
        .eq('id', id)

      if (error) throw error

      const normalizedIds = normalizedTiers
        .map((tier) => tier.id)
        .filter((tierId): tierId is string => Boolean(tierId))

      const { data: existingTierRows } = await supabase
        .from('event_ticket_types')
        .select('id')
        .eq('event_id', id)

      const idsToDelete = (existingTierRows || [])
        .map((tier) => tier.id)
        .filter((existingId) => !normalizedIds.includes(existingId))

      if (idsToDelete.length > 0) {
        await supabase
          .from('event_ticket_types')
          .delete()
          .in('id', idsToDelete)
      }

      for (const tier of normalizedTiers) {
        const payload = {
          event_id: id,
          name: tier.name,
          description: tier.description,
          price: tier.price,
          quantity: tier.quantity,
          sales_start: tier.sales_start,
          sales_end: tier.sales_end,
          sort_order: tier.sort_order,
          is_active: tier.is_active,
          is_public: tier.is_public,
        }

        if (tier.id) {
          await supabase
            .from('event_ticket_types')
            .update(payload)
            .eq('id', tier.id)
        } else {
          await supabase
            .from('event_ticket_types')
            .insert(payload)
        }
      }

      toast.success('Event and ticket tiers updated successfully!')
      router.push('/dashboard/organizer')
      
    } catch (error) {
      console.error('Error updating event:', error)
      toast.error('Failed to update event. Please try again.')
    } finally {
      setSaving(false)
    }
  }

  const handlePublish = async () => {
    setSaving(true)
    try {
      const supabase = createClient()
      
      const { error } = await supabase
        .from('events')
        .update({ 
          state: 'published',
          is_published: true 
        })
        .eq('id', id)

      if (error) throw error

      toast.success('Event published! It is now visible to everyone.')
      setFormData(prev => ({ ...prev, state: 'published' }))
    } catch (error) {
      console.error('Error publishing event:', error)
      toast.error('Failed to publish event')
    } finally {
      setSaving(false)
    }
  }

  const updateField = (field: string, value: string | boolean) => {
    setFormData(prev => ({ ...prev, [field]: value }))
  }

  if (authLoading || loading) {
    return (
      <div className="flex justify-center items-center min-h-[50vh]">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    )
  }

  return (
    <div className="container mx-auto px-4 py-8 max-w-2xl">
      <Link href="/dashboard/organizer" className="inline-flex items-center text-muted-foreground hover:text-primary mb-6">
        <ArrowLeft className="h-4 w-4 mr-2" />
        Back to Dashboard
      </Link>

      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <div>
              <CardTitle>Edit Event</CardTitle>
              <CardDescription>
                Update your event details
              </CardDescription>
            </div>
            <div className="flex gap-2">
              <Link href={`/dashboard/organizer/events/${id}/media`}>
                <Button variant="outline" size="sm">
                  <ImageIcon className="h-4 w-4 mr-2" />
                  Media
                </Button>
              </Link>
              {formData.state === 'draft' && (
                <Button onClick={handlePublish} disabled={saving} variant="outline" size="sm">
                  Publish Event
                </Button>
              )}
            </div>
          </div>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-6">
            {/* Basic Info */}
            <div className="space-y-4">
              <div>
                <Label htmlFor="title">Event Title *</Label>
                <Input
                  id="title"
                  placeholder="e.g. Amapiano Sundays"
                  value={formData.title}
                  onChange={(e) => updateField('title', e.target.value)}
                  required
                />
              </div>

              <div>
                <Label htmlFor="description">Description</Label>
                <textarea
                  id="description"
                  className="flex min-h-[120px] w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50"
                  placeholder="Tell people what your event is about..."
                  value={formData.description}
                  onChange={(e) => updateField('description', e.target.value)}
                />
              </div>
            </div>

            {/* Location */}
            <div className="space-y-4">
              <div>
                <Label htmlFor="venue">Venue *</Label>
                <Input
                  id="venue"
                  placeholder="e.g. The Venue, Melrose Arch"
                  value={formData.venue}
                  onChange={(e) => updateField('venue', e.target.value)}
                  required
                />
              </div>

              <div>
                <Label htmlFor="location">Province *</Label>
                <Select
                  value={formData.location}
                  onValueChange={(value) => updateField('location', value)}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select province" />
                  </SelectTrigger>
                  <SelectContent>
                    {Object.entries(PROVINCES).map(([value, label]) => (
                      <SelectItem key={value} value={value}>
                        {label}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>

            {/* Date & Time */}
            <div className="grid sm:grid-cols-3 gap-4">
              <div>
                <Label htmlFor="event_date">Event Date *</Label>
                <Input
                  id="event_date"
                  type="date"
                  value={formData.event_date}
                  onChange={(e) => updateField('event_date', e.target.value)}
                  required
                />
              </div>

              <div>
                <Label htmlFor="start_time">Start Time *</Label>
                <Input
                  id="start_time"
                  type="time"
                  value={formData.start_time}
                  onChange={(e) => updateField('start_time', e.target.value)}
                  required
                />
              </div>

              <div>
                <Label htmlFor="end_time">End Time</Label>
                <Input
                  id="end_time"
                  type="time"
                  value={formData.end_time}
                  onChange={(e) => updateField('end_time', e.target.value)}
                />
              </div>
            </div>

            <TicketTierEditor tiers={ticketTiers} onChange={setTicketTiers} />

            {/* Submit */}
            <div className="flex gap-4">
              <Button type="submit" disabled={saving} className="flex-1">
                {saving ? (
                  <>
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    Saving...
                  </>
                ) : (
                  'Save Changes'
                )}
              </Button>
              <Link href="/dashboard/organizer">
                <Button type="button" variant="outline">
                  Cancel
                </Button>
              </Link>
            </div>
          </form>
        </CardContent>
      </Card>
    </div>
  )
}

'use client'

import { useEffect, useMemo, useState } from 'react'
import Link from 'next/link'
import { useParams } from 'next/navigation'
import { useAuth } from '@/components/providers/auth-provider'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Textarea } from '@/components/ui/textarea'
import { Badge } from '@/components/ui/badge'
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import { toast } from 'sonner'
import { formatCurrency, formatDate, formatTime } from '@/lib/helpers'
import { RevenuePlannerLauncher } from '@/components/payments/revenue-planner'
import {
  ArrowLeft,
  BarChart3,
  Download,
  ExternalLink,
  Loader2,
  Mail,
  RefreshCw,
  Search,
  Send,
  Ticket,
  UserCheck,
  UserPlus,
  Users,
  Gift,
  CircleDollarSign,
  ShieldAlert,
  CheckCheck,
} from 'lucide-react'

interface EventSummary {
  id: string
  title: string
  event_date: string
  start_time: string
  venue: string
  tickets_sold: number
}

interface EventStats {
  totalPeople: number
  paidTickets: number
  guestPasses: number
  checkedIn: number
  pendingArrival: number
  uniqueBuyers: number
  emailableContacts: number
}

interface Attendee {
  id: string
  source: 'ticket' | 'guest_pass'
  userId: string | null
  name: string
  email: string | null
  phone: string | null
  code: string
  entryType: string
  checkedIn: boolean
  checkedInAt: string | null
  createdAt: string
  pricePaid: number
  buyerName?: string | null
  buyerEmail?: string | null
  claimedAt?: string | null
  deliveryStatus?: string | null
}

const emptyStats: EventStats = {
  totalPeople: 0,
  paidTickets: 0,
  guestPasses: 0,
  checkedIn: 0,
  pendingArrival: 0,
  uniqueBuyers: 0,
  emailableContacts: 0,
}

const campaignTemplateOptions = {
  event_reminder: [
    { value: 'arrival_info', label: 'Arrival info' },
    { value: 'doors_open', label: 'Doors open' },
    { value: 'final_call', label: 'Final reminder' },
  ],
  event_update: [
    { value: 'general_update', label: 'General update' },
    { value: 'venue_change', label: 'Venue change' },
    { value: 'time_change', label: 'Time change' },
  ],
  review_request: [
    { value: 'thank_you_review', label: 'Thank you + review' },
  ],
} as const

function getEventStatus(eventDate?: string) {
  if (!eventDate) {
    return { label: 'Upcoming', className: 'bg-blue-100 text-blue-700' }
  }

  const today = new Date()
  today.setHours(0, 0, 0, 0)

  const target = new Date(eventDate)
  target.setHours(0, 0, 0, 0)

  if (target.getTime() === today.getTime()) {
    return { label: 'Live today', className: 'bg-green-100 text-green-700' }
  }

  if (target < today) {
    return { label: 'Past event', className: 'bg-slate-100 text-slate-700' }
  }

  return { label: 'Upcoming', className: 'bg-blue-100 text-blue-700' }
}

export default function OrganizerEventManagePage() {
  const params = useParams()
  const eventId = params.id as string
  const { profile, loading: authLoading } = useAuth()

  const [loading, setLoading] = useState(true)
  const [sending, setSending] = useState(false)
  const [event, setEvent] = useState<EventSummary | null>(null)
  const [stats, setStats] = useState<EventStats>(emptyStats)
  const [attendees, setAttendees] = useState<Attendee[]>([])
  const [search, setSearch] = useState('')
  const [filter, setFilter] = useState('all')
  const [audience, setAudience] = useState('all')
  const [campaignType, setCampaignType] = useState('event_reminder')
  const [messagePreset, setMessagePreset] = useState('arrival_info')
  const [subject, setSubject] = useState('')
  const [message, setMessage] = useState('')
  const [creatingPass, setCreatingPass] = useState(false)
  const [checkingInId, setCheckingInId] = useState<string | null>(null)
  const [resendingId, setResendingId] = useState<string | null>(null)
  const [completingEvent, setCompletingEvent] = useState(false)
  const [passForm, setPassForm] = useState({
    fullName: '',
    email: '',
    phone: '',
    passType: 'guest_list',
    quantity: '1',
    notes: '',
  })

  const loadAttendees = async () => {
    if (!eventId) return

    try {
      setLoading(true)
      const response = await fetch(`/api/events/${eventId}/attendees`)
      const data = await response.json()

      if (!response.ok) {
        throw new Error(data.error || 'Failed to load event manager')
      }

      setEvent(data.event)
      setStats(data.stats || emptyStats)
      setAttendees(data.attendees || [])
    } catch (error) {
      toast.error(error instanceof Error ? error.message : 'Failed to load event manager')
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    if (profile?.id) {
      loadAttendees()
    }
  }, [profile?.id, eventId])

  useEffect(() => {
    const allowedPresets = campaignTemplateOptions[campaignType as keyof typeof campaignTemplateOptions] ?? campaignTemplateOptions.event_reminder

    if (!allowedPresets.some((option) => option.value === messagePreset)) {
      setMessagePreset(allowedPresets[0].value)
    }
  }, [campaignType, messagePreset])

  useEffect(() => {
    if (!event) return

    if (campaignType === 'review_request') {
      setSubject(`Thank you for attending ${event.title}`)
      setMessage(
        `Thanks for being part of ${event.title}. We would love your review and we have more events waiting for you on Ziyawa.`
      )
      return
    }

    if (campaignType === 'event_reminder') {
      if (messagePreset === 'doors_open') {
        setSubject(`Doors open soon for ${event.title}`)
        setMessage(
          `Doors open soon for ${event.title}. Please have your Ziyawa ticket ready, arrive early, and keep an eye on your dashboard for any last-minute notices.`
        )
        return
      }

      if (messagePreset === 'final_call') {
        setSubject(`Final reminder for ${event.title}`)
        setMessage(
          `This is your final reminder for ${event.title}. Your ticket is ready in your Ziyawa dashboard. Please arrive early and show your QR code or ticket code at the entrance.`
        )
        return
      }

      setSubject(`Reminder: ${event.title} is almost here`)
      setMessage(
        `Your event is coming up soon. Please arrive early, keep your ticket ready for check-in, and use your Ziyawa dashboard if you need your ticket again.`
      )
      return
    }

    if (campaignType === 'event_update') {
      if (messagePreset === 'venue_change') {
        setSubject(`Important venue update for ${event.title}`)
        setMessage(
          `Please note that there is an important venue-related update for ${event.title}. Check the event page and your ticket dashboard before travelling.`
        )
        return
      }

      if (messagePreset === 'time_change') {
        setSubject(`Important time update for ${event.title}`)
        setMessage(
          `We have an important schedule update for ${event.title}. Please review the latest start time and event details on Ziyawa before you arrive.`
        )
        return
      }

      setSubject(`Important update for ${event.title}`)
      setMessage(
        `We have an important update for ${event.title}. Please review the latest event details on Ziyawa before you travel.`
      )
      return
    }
  }, [campaignType, event, messagePreset])

  const filteredAttendees = useMemo(() => {
    const term = search.trim().toLowerCase()

    return attendees.filter((attendee) => {
      const matchesSearch = !term || [
        attendee.name,
        attendee.email || '',
        attendee.phone || '',
        attendee.code,
        attendee.entryType,
        attendee.buyerName || '',
        attendee.buyerEmail || '',
      ].some((value) => value.toLowerCase().includes(term))

      if (!matchesSearch) return false

      switch (filter) {
        case 'paid':
          return attendee.source === 'ticket'
        case 'guest_list':
          return attendee.source === 'guest_pass'
        case 'checked_in':
          return attendee.checkedIn
        case 'not_checked_in':
          return !attendee.checkedIn
        default:
          return true
      }
    })
  }, [attendees, filter, search])

  const visibleEmailableCount = useMemo(() => {
    const uniqueEmails = new Set(
      filteredAttendees
        .map((attendee) => attendee.email?.trim().toLowerCase())
        .filter(Boolean)
    )
    return uniqueEmails.size
  }, [filteredAttendees])

  const audienceRecipientCount = useMemo(() => {
    const selected = attendees.filter((attendee) => {
      switch (audience) {
        case 'paid':
          return attendee.source === 'ticket'
        case 'guest_list':
          return attendee.source === 'guest_pass'
        case 'checked_in':
          return attendee.checkedIn
        case 'not_checked_in':
          return !attendee.checkedIn
        default:
          return true
      }
    })

    return new Set(
      selected
        .map((attendee) => attendee.email?.trim().toLowerCase())
        .filter(Boolean)
    ).size
  }, [attendees, audience])

  const guestPasses = useMemo(
    () => attendees.filter((attendee) => attendee.source === 'guest_pass'),
    [attendees]
  )

  const paidRevenue = useMemo(
    () => attendees.filter((attendee) => attendee.source === 'ticket').reduce((sum, attendee) => sum + Number(attendee.pricePaid || 0), 0),
    [attendees]
  )

  const giftedTicketsCount = useMemo(
    () => attendees.filter((attendee) => attendee.source === 'ticket' && attendee.buyerEmail && attendee.email && attendee.buyerEmail !== attendee.email).length,
    [attendees]
  )

  const claimedGiftCount = useMemo(
    () => attendees.filter((attendee) => attendee.source === 'ticket' && Boolean(attendee.claimedAt)).length,
    [attendees]
  )

  const eventStatus = getEventStatus(event?.event_date)
  const isPastEvent = eventStatus.label === 'Past event'
  const activeTemplateOptions = campaignTemplateOptions[campaignType as keyof typeof campaignTemplateOptions] ?? campaignTemplateOptions.event_reminder
  const attendanceRate = stats.totalPeople > 0 ? Math.round((stats.checkedIn / stats.totalPeople) * 100) : 0
  const plannerTicketPrice = stats.paidTickets > 0 ? Math.round(paidRevenue / stats.paidTickets) : 150
  const plannerCapacity = Math.max(Number(event?.tickets_sold || 0), stats.totalPeople, 100)
  const recentArrivals = useMemo(
    () => attendees.filter((attendee) => attendee.checkedIn).sort((a, b) => {
      const first = a.checkedInAt ? new Date(a.checkedInAt).getTime() : 0
      const second = b.checkedInAt ? new Date(b.checkedInAt).getTime() : 0
      return second - first
    }).slice(0, 5),
    [attendees]
  )

  useEffect(() => {
    if (isPastEvent && campaignType !== 'review_request') {
      setCampaignType('review_request')
    }
  }, [campaignType, isPastEvent])

  const handleCreatePass = async (e: React.FormEvent) => {
    e.preventDefault()

    if (isPastEvent) {
      toast.error('Guest list is closed after the event date')
      return
    }

    if (!passForm.fullName.trim()) {
      toast.error('Guest name is required')
      return
    }

    try {
      setCreatingPass(true)
      const response = await fetch(`/api/events/${eventId}/guest-list`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(passForm),
      })

      const data = await response.json()
      if (!response.ok) {
        throw new Error(data.error || 'Failed to create guest pass')
      }

      toast.success(`Created ${data.passes?.length || 1} access pass${(data.passes?.length || 1) > 1 ? 'es' : ''}`)
      setPassForm({
        fullName: '',
        email: '',
        phone: '',
        passType: 'guest_list',
        quantity: '1',
        notes: '',
      })
      await loadAttendees()
    } catch (error) {
      toast.error(error instanceof Error ? error.message : 'Failed to create guest pass')
    } finally {
      setCreatingPass(false)
    }
  }

  const handleMarkPresent = async (attendee: Attendee) => {
    if (isPastEvent) {
      toast.error('Check-in is closed for past events')
      return
    }

    const confirmed = window.confirm(`Confirm check-in for ${attendee.name}?`)
    if (!confirmed) return

    try {
      setCheckingInId(attendee.id)
      const response = await fetch('/api/tickets/checkin', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          ticketId: attendee.id,
          eventId,
        }),
      })

      const data = await response.json()
      if (!response.ok) {
        throw new Error(data.message || data.error || 'Failed to check in attendee')
      }

      toast.success(`${attendee.name} is now checked in`)
      await loadAttendees()
    } catch (error) {
      toast.error(error instanceof Error ? error.message : 'Failed to check in attendee')
    } finally {
      setCheckingInId(null)
    }
  }

  const handleResendTicket = async (attendee: Attendee) => {
    if (attendee.source !== 'ticket') return

    try {
      setResendingId(attendee.id)
      const response = await fetch(`/api/tickets/${attendee.id}/resend`, {
        method: 'POST',
      })

      const data = await response.json()
      if (!response.ok) {
        throw new Error(data.error || 'Failed to resend ticket email')
      }

      toast.success(data.message || 'Ticket email resent')
      await loadAttendees()
    } catch (error) {
      toast.error(error instanceof Error ? error.message : 'Failed to resend ticket email')
    } finally {
      setResendingId(null)
    }
  }

  const handleSend = async () => {
    if (!subject.trim() || !message.trim()) {
      toast.error('Please add a subject and message')
      return
    }

    try {
      setSending(true)
      const response = await fetch(`/api/events/${eventId}/attendees`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          subject,
          message,
          audience,
          campaignType: isPastEvent ? 'review_request' : campaignType,
        }),
      })

      const data = await response.json()
      if (!response.ok) {
        throw new Error(data.error || 'Failed to send update')
      }

      toast.success(`Sent ${data.sentCount} attendee emails${data.failedCount ? `, ${data.failedCount} failed` : ''}`)
    } catch (error) {
      toast.error(error instanceof Error ? error.message : 'Failed to send attendee email')
    } finally {
      setSending(false)
    }
  }

  const handleExportAttendees = (scope: 'all' | 'filtered') => {
    const exportRows = scope === 'all' ? attendees : filteredAttendees

    if (exportRows.length === 0) {
      toast.error('There is no attendee data to export')
      return
    }

    const escapeValue = (value: string | number | null | undefined) => {
      const text = String(value ?? '').replace(/"/g, '""')
      return `"${text}"`
    }

    const headers = [
      'Name',
      'Email',
      'Phone',
      'Source',
      'Entry Type',
      'Code',
      'Checked In',
      'Buyer Name',
      'Buyer Email',
      'Price Paid',
      'Created At',
    ]

    const lines = [
      headers.join(','),
      ...exportRows.map((attendee) => ([
        attendee.name,
        attendee.email,
        attendee.phone,
        attendee.source === 'ticket' ? 'Paid ticket' : 'Guest / comp',
        attendee.entryType,
        attendee.code,
        attendee.checkedIn ? 'Yes' : 'No',
        attendee.buyerName,
        attendee.buyerEmail,
        attendee.pricePaid,
        attendee.createdAt,
      ].map(escapeValue).join(','))),
    ]

    const blob = new Blob([lines.join('\n')], { type: 'text/csv;charset=utf-8;' })
    const url = window.URL.createObjectURL(blob)
    const link = document.createElement('a')
    link.href = url
    link.download = `${(event?.title || 'event').toLowerCase().replace(/[^a-z0-9]+/g, '-')}-${scope}-attendees.csv`
    document.body.appendChild(link)
    link.click()
    document.body.removeChild(link)
    window.URL.revokeObjectURL(url)

    toast.success(`${exportRows.length} attendee rows exported`)
  }

  const handleCompleteEvent = async () => {
    const confirmed = window.confirm('Mark this event as completed? This will start the payout release process once hold rules are satisfied.')
    if (!confirmed) return

    try {
      setCompletingEvent(true)
      const response = await fetch(`/api/events/${eventId}/complete`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({}),
      })

      const data = await response.json()
      if (!response.ok) {
        throw new Error(data.error || 'Failed to complete event')
      }

      toast.success(`Event marked complete. ${data.releaseResult?.released || 0} payout batch${(data.releaseResult?.released || 0) === 1 ? '' : 'es'} released.`)
      await loadAttendees()
    } catch (error) {
      toast.error(error instanceof Error ? error.message : 'Failed to complete event')
    } finally {
      setCompletingEvent(false)
    }
  }

  if (authLoading || loading) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
      </div>
    )
  }

  if (!event) {
    return (
      <div className="container mx-auto px-4 py-8">
        <Card>
          <CardContent className="py-10 text-center text-muted-foreground">
            This event manager could not be loaded.
          </CardContent>
        </Card>
      </div>
    )
  }

  return (
    <div className="container mx-auto px-4 py-8 space-y-6">
      <div className="flex flex-col gap-4 lg:flex-row lg:items-center lg:justify-between">
        <div className="flex items-start gap-3">
          <Link href="/dashboard/organizer">
            <Button variant="outline" size="icon">
              <ArrowLeft className="h-4 w-4" />
            </Button>
          </Link>
          <div>
            <h1 className="text-3xl font-bold">Event Manager</h1>
            <p className="text-muted-foreground">
              {event.title} ΓÇó {formatDate(event.event_date)} ΓÇó {formatTime(event.start_time)}
            </p>
            <p className="text-sm text-muted-foreground">{event.venue}</p>
            <div className="mt-2 flex flex-wrap gap-2">
              <Badge variant="outline" className={eventStatus.className}>
                {eventStatus.label}
              </Badge>
              <Badge variant="secondary">{stats.paidTickets} tickets on record</Badge>
            </div>
          </div>
        </div>

        <div className="flex flex-wrap gap-2">
          {isPastEvent ? (
            <Button variant="outline" disabled>
              <UserCheck className="h-4 w-4 mr-2" />
              Check-in closed
            </Button>
          ) : (
            <Link href={`/dashboard/organizer/events/${event.id}/checkin`}>
              <Button variant="outline">
                <UserCheck className="h-4 w-4 mr-2" />
                Door / Check-in
              </Button>
            </Link>
          )}
          <Link href={`/dashboard/organizer/events/${event.id}/bookings`}>
            <Button>
              <Users className="h-4 w-4 mr-2" />
              Book, Manage &amp; Pay
            </Button>
          </Link>
          <RevenuePlannerLauncher
            showCard={false}
            triggerLabel="Revenue Planner"
            title="Event Revenue Planner"
            description="Use this event context to test sales, costs, and payout outcomes before making pricing decisions."
            initialTicketPrice={plannerTicketPrice}
            initialCapacity={plannerCapacity}
          />
          <Button variant="outline" onClick={() => handleExportAttendees('all')}>
            <Download className="h-4 w-4 mr-2" />
            Export CSV
          </Button>
          {(eventStatus.label === 'Live today' || eventStatus.label === 'Past event') && (
            <Button onClick={handleCompleteEvent} disabled={completingEvent}>
              {completingEvent ? <Loader2 className="h-4 w-4 mr-2 animate-spin" /> : <CheckCheck className="h-4 w-4 mr-2" />}
              Complete Event
            </Button>
          )}
          <Button variant="outline" onClick={loadAttendees}>
            <RefreshCw className="h-4 w-4 mr-2" />
            Refresh
          </Button>
        </div>
      </div>

      <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-4">
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center gap-3">
              <Users className="h-8 w-8 text-primary" />
              <div>
                <p className="text-2xl font-bold">{stats.totalPeople}</p>
                <p className="text-sm text-muted-foreground">People on list</p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center gap-3">
              <UserCheck className="h-8 w-8 text-green-600" />
              <div>
                <p className="text-2xl font-bold">{stats.checkedIn}</p>
                <p className="text-sm text-muted-foreground">Checked in</p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center gap-3">
              <Ticket className="h-8 w-8 text-primary" />
              <div>
                <p className="text-2xl font-bold">{stats.uniqueBuyers}</p>
                <p className="text-sm text-muted-foreground">Ticket buyers</p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center gap-3">
              <Mail className="h-8 w-8 text-orange-600" />
              <div>
                <p className="text-2xl font-bold">{stats.emailableContacts}</p>
                <p className="text-sm text-muted-foreground">Email contacts</p>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-4">
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center gap-3">
              <CircleDollarSign className="h-8 w-8 text-emerald-600" />
              <div>
                <p className="text-2xl font-bold">{formatCurrency(paidRevenue)}</p>
                <p className="text-sm text-muted-foreground">Paid ticket revenue</p>
              </div>
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center gap-3">
              <Gift className="h-8 w-8 text-pink-600" />
              <div>
                <p className="text-2xl font-bold">{giftedTicketsCount}</p>
                <p className="text-sm text-muted-foreground">Gifted tickets</p>
              </div>
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center gap-3">
              <BarChart3 className="h-8 w-8 text-blue-600" />
              <div>
                <p className="text-2xl font-bold">{claimedGiftCount}</p>
                <p className="text-sm text-muted-foreground">Claims completed</p>
              </div>
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center gap-3">
              <ShieldAlert className="h-8 w-8 text-amber-600" />
              <div>
                <p className="text-2xl font-bold">{Math.max(0, giftedTicketsCount - claimedGiftCount)}</p>
                <p className="text-sm text-muted-foreground">Pending ticket claims</p>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      <Tabs defaultValue="people" className="space-y-4">
        <TabsList className="grid w-full grid-cols-3">
          <TabsTrigger value="people">People</TabsTrigger>
          <TabsTrigger value="guestlist">Guest List & Comp</TabsTrigger>
          <TabsTrigger value="messages">Email updates</TabsTrigger>
        </TabsList>

        <TabsContent value="people" className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>Attendees and buyers</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex flex-col gap-3 md:flex-row md:flex-wrap">
                <div className="relative flex-1 min-w-[220px]">
                  <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                  <Input
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    placeholder="Search by name, email, code or ticket type"
                    className="pl-10"
                  />
                </div>
                <Select value={filter} onValueChange={setFilter}>
                  <SelectTrigger className="w-full md:w-[220px]">
                    <SelectValue placeholder="Filter people" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">All people</SelectItem>
                    <SelectItem value="paid">Paid tickets</SelectItem>
                    <SelectItem value="guest_list">Guest list / comp</SelectItem>
                    <SelectItem value="checked_in">Checked in</SelectItem>
                    <SelectItem value="not_checked_in">Not checked in</SelectItem>
                  </SelectContent>
                </Select>
                <Button variant="outline" onClick={() => handleExportAttendees('filtered')}>
                  <Download className="h-4 w-4 mr-2" />
                  Export filtered
                </Button>
              </div>

              <div className="grid gap-3 md:grid-cols-3">
                <div className="rounded-lg bg-muted p-3">
                  <p className="text-sm text-muted-foreground">Attendance rate</p>
                  <p className="text-2xl font-bold">{attendanceRate}%</p>
                </div>
                <div className="rounded-lg bg-muted p-3">
                  <p className="text-sm text-muted-foreground">Pending arrivals</p>
                  <p className="text-2xl font-bold">{stats.pendingArrival}</p>
                </div>
                <div className="rounded-lg bg-muted p-3">
                  <p className="text-sm text-muted-foreground">Latest arrival</p>
                  <p className="font-semibold">{recentArrivals[0]?.name || 'None yet'}</p>
                </div>
              </div>

              <div className="rounded-lg border">
                {filteredAttendees.length === 0 ? (
                  <div className="p-6 text-sm text-muted-foreground">No people match this filter yet.</div>
                ) : (
                  <div className="divide-y">
                    {filteredAttendees.map((attendee) => (
                      <div key={`${attendee.source}-${attendee.id}`} className="p-4">
                        <div className="flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between">
                          <div className="space-y-1">
                            <div className="flex flex-wrap items-center gap-2">
                              <p className="font-semibold">{attendee.name}</p>
                              <Badge
                                variant={attendee.checkedIn ? 'default' : 'outline'}
                                className={attendee.checkedIn ? 'bg-green-500 hover:bg-green-500 text-white' : ''}
                              >
                                {attendee.checkedIn ? 'Checked in' : 'Pending'}
                              </Badge>
                              <Badge variant="secondary">
                                {attendee.source === 'ticket' ? 'Paid ticket' : 'Guest / comp'}
                              </Badge>
                              {attendee.source === 'ticket' && attendee.buyerEmail && attendee.email && attendee.buyerEmail !== attendee.email && (
                                <Badge variant="outline">
                                  {attendee.claimedAt ? 'Gift claimed' : 'Gifted ticket'}
                                </Badge>
                              )}
                            </div>
                            <p className="text-sm text-muted-foreground">
                              {attendee.entryType} ΓÇó Code: {attendee.code}
                            </p>
                            <p className="text-sm text-muted-foreground">
                              Attending: {attendee.email || 'No email'}{attendee.phone ? ` ΓÇó ${attendee.phone}` : ''}
                            </p>
                            {attendee.source === 'ticket' && attendee.buyerName && (
                              <p className="text-sm text-muted-foreground">
                                Bought by: {attendee.buyerName}{attendee.buyerEmail ? ` ΓÇó ${attendee.buyerEmail}` : ''}
                              </p>
                            )}
                          </div>

                          <div className="text-sm text-muted-foreground lg:text-right">
                            <p>Added {formatDate(attendee.createdAt)}</p>
                            <p>
                              {attendee.source === 'ticket'
                                ? `Paid ${formatCurrency(attendee.pricePaid || 0)}`
                                : 'Guest access'}
                            </p>
                            {!isPastEvent && attendee.source === 'ticket' && attendee.email && attendee.buyerEmail && attendee.buyerEmail !== attendee.email && (
                              <Button
                                size="sm"
                                variant="outline"
                                className="mt-2 mr-2"
                                onClick={() => handleResendTicket(attendee)}
                                disabled={resendingId === attendee.id}
                              >
                                {resendingId === attendee.id ? <Loader2 className="h-4 w-4 mr-2 animate-spin" /> : <Mail className="h-4 w-4 mr-2" />}
                                Resend ticket
                              </Button>
                            )}
                            {!isPastEvent && !attendee.checkedIn && (
                              <Button
                                size="sm"
                                className="mt-2"
                                onClick={() => handleMarkPresent(attendee)}
                                disabled={checkingInId === attendee.id}
                              >
                                {checkingInId === attendee.id ? <Loader2 className="h-4 w-4 mr-2 animate-spin" /> : <UserCheck className="h-4 w-4 mr-2" />}
                                Verify & check in
                              </Button>
                            )}
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="guestlist" className="space-y-4">
          <div className="grid gap-4 lg:grid-cols-[1.1fr_0.9fr]">
            <Card>
              <CardHeader>
                <CardTitle>Add guest list or comp passes</CardTitle>
              </CardHeader>
              <CardContent>
                {isPastEvent && (
                  <div className="mb-4 rounded-lg border border-amber-200 bg-amber-50 p-3 text-sm text-amber-900">
                    Guest list and pass creation is closed because this event has already taken place.
                  </div>
                )}
                <form onSubmit={handleCreatePass} className="space-y-4">
                  <div>
                    <p className="mb-2 text-sm font-medium">Guest name</p>
                    <Input
                      value={passForm.fullName}
                      onChange={(e) => setPassForm((prev) => ({ ...prev, fullName: e.target.value }))}
                      placeholder="Full name"
                      disabled={isPastEvent}
                    />
                  </div>

                  <div className="grid gap-3 md:grid-cols-2">
                    <div>
                      <p className="mb-2 text-sm font-medium">Email</p>
                      <Input
                        value={passForm.email}
                        onChange={(e) => setPassForm((prev) => ({ ...prev, email: e.target.value }))}
                        placeholder="guest@email.com"
                        disabled={isPastEvent}
                      />
                    </div>
                    <div>
                      <p className="mb-2 text-sm font-medium">Phone</p>
                      <Input
                        value={passForm.phone}
                        onChange={(e) => setPassForm((prev) => ({ ...prev, phone: e.target.value }))}
                        placeholder="Optional phone"
                        disabled={isPastEvent}
                      />
                    </div>
                  </div>

                  <div className="grid gap-3 md:grid-cols-2">
                    <div>
                      <p className="mb-2 text-sm font-medium">Pass type</p>
                      <Select value={passForm.passType} onValueChange={(value) => setPassForm((prev) => ({ ...prev, passType: value }))} disabled={isPastEvent}>
                        <SelectTrigger>
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="guest_list">Guest list</SelectItem>
                          <SelectItem value="comp">Comp</SelectItem>
                          <SelectItem value="vip_guest">VIP guest</SelectItem>
                          <SelectItem value="staff">Staff</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                    <div>
                      <p className="mb-2 text-sm font-medium">Quantity</p>
                      <Input
                        value={passForm.quantity}
                        onChange={(e) => setPassForm((prev) => ({ ...prev, quantity: e.target.value }))}
                        type="number"
                        min="1"
                        max="20"
                        disabled={isPastEvent}
                      />
                    </div>
                  </div>

                  <div>
                    <p className="mb-2 text-sm font-medium">Notes</p>
                    <Textarea
                      value={passForm.notes}
                      onChange={(e) => setPassForm((prev) => ({ ...prev, notes: e.target.value }))}
                      rows={3}
                      placeholder="Optional notes for your team"
                      disabled={isPastEvent}
                    />
                  </div>

                  <Button type="submit" disabled={creatingPass || isPastEvent}>
                    {creatingPass ? <Loader2 className="h-4 w-4 mr-2 animate-spin" /> : <UserPlus className="h-4 w-4 mr-2" />}
                    Add pass
                  </Button>
                </form>
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle>Current guest list</CardTitle>
              </CardHeader>
              <CardContent>
                {guestPasses.length === 0 ? (
                  <p className="text-sm text-muted-foreground">No guest list or comp passes yet.</p>
                ) : (
                  <div className="space-y-3">
                    {guestPasses.map((guest) => (
                      <div key={guest.id} className="rounded-lg border p-3">
                        <div className="flex items-center justify-between gap-3">
                          <div>
                            <p className="font-medium">{guest.name}</p>
                            <p className="text-sm text-muted-foreground">{guest.entryType} ΓÇó {guest.code}</p>
                            <p className="text-sm text-muted-foreground">{guest.email || 'No email'}{guest.phone ? ` ΓÇó ${guest.phone}` : ''}</p>
                          </div>
                          <Badge
                            variant={guest.checkedIn ? 'default' : 'outline'}
                            className={guest.checkedIn ? 'bg-green-500 hover:bg-green-500 text-white' : ''}
                          >
                            {guest.checkedIn ? 'Checked in' : 'Pending'}
                          </Badge>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </CardContent>
            </Card>
          </div>
        </TabsContent>

        <TabsContent value="messages" className="space-y-4">
          <div className="grid gap-4 lg:grid-cols-[1.3fr_0.7fr]">
            <Card>
              <CardHeader>
                <CardTitle>Send attendee update</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                {isPastEvent && (
                  <div className="rounded-lg border border-blue-200 bg-blue-50 p-3 text-sm text-blue-900">
                    This event has passed, so only post-event thank-you and review emails can be sent.
                  </div>
                )}

                <div className="grid gap-3 md:grid-cols-3">
                  <div>
                    <p className="mb-2 text-sm font-medium">Campaign type</p>
                    <Select value={campaignType} onValueChange={setCampaignType} disabled={isPastEvent}>
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="event_reminder">Pre-event reminder</SelectItem>
                        <SelectItem value="event_update">Important event update</SelectItem>
                        <SelectItem value="review_request">Post-event thank you + review</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>

                  <div>
                    <p className="mb-2 text-sm font-medium">Audience</p>
                    <Select value={audience} onValueChange={setAudience}>
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="all">All attendees</SelectItem>
                        <SelectItem value="paid">Paid ticket buyers</SelectItem>
                        <SelectItem value="guest_list">Guest list / comp</SelectItem>
                        <SelectItem value="checked_in">Checked-in people only</SelectItem>
                        <SelectItem value="not_checked_in">Not checked in yet</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>

                  <div>
                    <p className="mb-2 text-sm font-medium">Quick template</p>
                    <Select value={messagePreset} onValueChange={setMessagePreset} disabled={isPastEvent}>
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        {activeTemplateOptions.map((option) => (
                          <SelectItem key={option.value} value={option.value}>{option.label}</SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                </div>

                <div className="rounded-lg border bg-muted/30 p-3 text-sm text-muted-foreground">
                  This message will go out as an <span className="font-medium text-foreground">email and an in-app notification</span> to about <span className="font-medium text-foreground">{audienceRecipientCount}</span> matching contacts.
                </div>

                <div>
                  <p className="mb-2 text-sm font-medium">Subject</p>
                  <Input value={subject} onChange={(e) => setSubject(e.target.value)} />
                </div>

                <div>
                  <p className="mb-2 text-sm font-medium">Message</p>
                  <Textarea
                    value={message}
                    onChange={(e) => setMessage(e.target.value)}
                    rows={8}
                    placeholder="Write the update your attendees should receive"
                  />
                </div>

                <Button onClick={handleSend} disabled={sending} className="w-full md:w-auto">
                  {sending ? (
                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                  ) : (
                    <Send className="h-4 w-4 mr-2" />
                  )}
                  Send update
                </Button>
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle>Lifecycle actions</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4 text-sm">
                <div className="rounded-lg bg-muted p-3">
                  <p className="font-medium">Audience reachable now</p>
                  <p className="text-2xl font-bold">{audienceRecipientCount}</p>
                </div>

                <div className="space-y-2">
                  <div className="flex items-center gap-2">
                    <Ticket className="h-4 w-4 text-primary" />
                    <span>Paid tickets: {stats.paidTickets}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Gift className="h-4 w-4 text-pink-600" />
                    <span>Guest / comp: {stats.guestPasses}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <UserCheck className="h-4 w-4 text-green-600" />
                    <span>Checked in: {stats.checkedIn}</span>
                  </div>
                </div>

                <div className="rounded-lg border p-3">
                  <p className="font-medium mb-2">Recommended flow</p>
                  <ul className="space-y-2 text-muted-foreground">
                    <li>ΓÇó Send reminder the day before</li>
                    <li>ΓÇó Send a doors-open or arrival update on the morning of the event</li>
                    <li>ΓÇó Use urgent updates for venue or time changes</li>
                    <li>ΓÇó Send thank-you and review request after the event</li>
                  </ul>
                </div>

              </CardContent>
            </Card>
          </div>
        </TabsContent>
      </Tabs>
    </div>
  )
}

'use client';

import { useState } from 'react';
import Image from 'next/image';
import { createClient } from '@/lib/supabase/client';
import { 
  uploadUserFile, 
  deleteFile, 
  getPathFromUrl,
  type UploadResult 
} from '@/lib/storage';
import { 
  Plus, 
  Trash2, 
  Calendar,
  MapPin,
  Upload,
  Briefcase,
  Image as ImageIcon,
  ExternalLink,
  Star
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Switch } from '@/components/ui/switch';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog';
import { ProviderPortfolio, ProviderPortfolioMedia } from '@/types/database';

interface PortfolioWithMedia extends ProviderPortfolio {
  media?: ProviderPortfolioMedia[];
}

interface ProviderPortfolioManagerProps {
  providerId: string;
  userId: string;
  initialPortfolio: PortfolioWithMedia[];
}

export function ProviderPortfolioManager({ providerId, userId, initialPortfolio }: ProviderPortfolioManagerProps) {
  const [portfolio, setPortfolio] = useState<PortfolioWithMedia[]>(initialPortfolio);
  const [isAddingEntry, setIsAddingEntry] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [newEntry, setNewEntry] = useState({
    event_name: '',
    client_name: '',
    description: '',
    date: '',
    venue: '',
    location: '',
    services_provided: '',
    is_featured: false,
    cover_image_url: '',
  });
  const supabase = createClient();

  // Handle cover image upload using storage utilities
  const handleCoverUpload = async (file: File) => {
    setUploading(true);
    try {
      const result: UploadResult = await uploadUserFile(file, 'providers', userId, 'portfolio');
      
      if (!result.success || !result.url) {
        alert(result.error || 'Failed to upload image');
        return;
      }

      setNewEntry(prev => ({ ...prev, cover_image_url: result.url! }));
    } catch (error) {
      console.error('Upload error:', error);
      alert('Failed to upload image');
    } finally {
      setUploading(false);
    }
  };

  // Add portfolio entry
  const handleAddEntry = async () => {
    if (!newEntry.event_name) return;

    const { data, error } = await supabase
      .from('provider_portfolio')
      .insert({
        provider_id: providerId,
        event_name: newEntry.event_name,
        client_name: newEntry.client_name || null,
        description: newEntry.description || null,
        date: newEntry.date || null,
        venue: newEntry.venue || null,
        location: newEntry.location || null,
        services_provided: newEntry.services_provided ? newEntry.services_provided.split(',').map(s => s.trim()) : null,
        is_featured: newEntry.is_featured,
        cover_image_url: newEntry.cover_image_url || null,
      })
      .select()
      .single();

    if (error) {
      console.error('Error adding portfolio entry:', error);
      alert('Failed to add portfolio entry');
      return;
    }

    setPortfolio(prev => [{ ...data, media: [] }, ...prev]);
    setNewEntry({
      event_name: '',
      client_name: '',
      description: '',
      date: '',
      venue: '',
      location: '',
      services_provided: '',
      is_featured: false,
      cover_image_url: '',
    });
    setIsAddingEntry(false);
  };

  // Delete portfolio entry
  const handleDeleteEntry = async (id: string) => {
    if (!confirm('Are you sure you want to delete this portfolio entry?')) return;

    // Find the entry to get its cover image URL
    const entry = portfolio.find(p => p.id === id);

    const { error } = await supabase
      .from('provider_portfolio')
      .delete()
      .eq('id', id);

    if (error) {
      console.error('Error deleting portfolio entry:', error);
      return;
    }

    // Also delete cover image from storage if it exists
    if (entry?.cover_image_url) {
      const path = getPathFromUrl(entry.cover_image_url);
      if (path) {
        await deleteFile(path);
      }
    }

    setPortfolio(prev => prev.filter(p => p.id !== id));
  };

  // Toggle featured
  const handleToggleFeatured = async (id: string, isFeatured: boolean) => {
    const { error } = await supabase
      .from('provider_portfolio')
      .update({ is_featured: isFeatured })
      .eq('id', id);

    if (error) {
      console.error('Error updating portfolio entry:', error);
      return;
    }

    setPortfolio(prev => prev.map(p => p.id === id ? { ...p, is_featured: isFeatured } : p));
  };

  // Format date
  const formatDate = (dateStr: string | null): string => {
    if (!dateStr) return '';
    return new Date(dateStr).toLocaleDateString('en-ZA', {
      year: 'numeric',
      month: 'short',
    });
  };

  return (
    <div className="space-y-6">
      {/* Add Entry Button */}
      <Dialog open={isAddingEntry} onOpenChange={setIsAddingEntry}>
        <DialogTrigger asChild>
          <Button>
            <Plus className="h-4 w-4 mr-2" />
            Add Project
          </Button>
        </DialogTrigger>
        <DialogContent className="max-w-lg max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Add Portfolio Entry</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-4">
            {/* Cover Image */}
            <div className="space-y-2">
              <Label>Cover Image</Label>
              <div className="flex gap-4">
                <div className="w-32 h-24 rounded-lg bg-neutral-100 overflow-hidden flex items-center justify-center">
                  {newEntry.cover_image_url ? (
                    <Image
                      src={newEntry.cover_image_url}
                      alt="Cover"
                      width={128}
                      height={96}
                      className="object-cover w-full h-full"
                    />
                  ) : (
                    <ImageIcon className="h-8 w-8 text-neutral-300" />
                  )}
                </div>
                <div className="flex-1">
                  <input
                    type="file"
                    accept="image/*"
                    onChange={(e) => {
                      const file = e.target.files?.[0];
                      if (file) handleCoverUpload(file);
                    }}
                    className="hidden"
                    id="cover-upload"
                  />
                  <label htmlFor="cover-upload">
                    <Button variant="outline" size="sm" asChild>
                      <span className="cursor-pointer">
                        {uploading ? (
                          <span className="animate-pulse">Uploading...</span>
                        ) : (
                          <>
                            <Upload className="h-4 w-4 mr-2" />
                            Upload Image
                          </>
                        )}
                      </span>
                    </Button>
                  </label>
                </div>
              </div>
            </div>

            {/* Event Name */}
            <div className="space-y-2">
              <Label>Event/Project Name *</Label>
              <Input
                placeholder="e.g., Afropunk Johannesburg 2024"
                value={newEntry.event_name}
                onChange={(e) => setNewEntry(prev => ({ ...prev, event_name: e.target.value }))}
              />
            </div>

            {/* Client Name */}
            <div className="space-y-2">
              <Label>Client (optional)</Label>
              <Input
                placeholder="e.g., Afropunk LLC"
                value={newEntry.client_name}
                onChange={(e) => setNewEntry(prev => ({ ...prev, client_name: e.target.value }))}
              />
            </div>

            {/* Date */}
            <div className="space-y-2">
              <Label>Date</Label>
              <Input
                type="date"
                value={newEntry.date}
                onChange={(e) => setNewEntry(prev => ({ ...prev, date: e.target.value }))}
              />
            </div>

            {/* Venue */}
            <div className="space-y-2">
              <Label>Venue</Label>
              <Input
                placeholder="e.g., Constitution Hill"
                value={newEntry.venue}
                onChange={(e) => setNewEntry(prev => ({ ...prev, venue: e.target.value }))}
              />
            </div>

            {/* Location */}
            <div className="space-y-2">
              <Label>Location</Label>
              <Input
                placeholder="e.g., Johannesburg, Gauteng"
                value={newEntry.location}
                onChange={(e) => setNewEntry(prev => ({ ...prev, location: e.target.value }))}
              />
            </div>

            {/* Services Provided */}
            <div className="space-y-2">
              <Label>Services Provided</Label>
              <Input
                placeholder="e.g., Sound, Lighting, Stage Design"
                value={newEntry.services_provided}
                onChange={(e) => setNewEntry(prev => ({ ...prev, services_provided: e.target.value }))}
              />
              <p className="text-xs text-neutral-500">Separate with commas</p>
            </div>

            {/* Description */}
            <div className="space-y-2">
              <Label>Description</Label>
              <Textarea
                placeholder="Describe the project, your role, and any highlights..."
                value={newEntry.description}
                onChange={(e) => setNewEntry(prev => ({ ...prev, description: e.target.value }))}
                rows={3}
              />
            </div>

            {/* Featured */}
            <div className="flex items-center justify-between">
              <div>
                <Label htmlFor="featured">Featured Project</Label>
                <p className="text-xs text-neutral-500">Show at the top of your portfolio</p>
              </div>
              <Switch
                id="featured"
                checked={newEntry.is_featured}
                onCheckedChange={(v) => setNewEntry(prev => ({ ...prev, is_featured: v }))}
              />
            </div>

            <Button 
              onClick={handleAddEntry} 
              className="w-full"
              disabled={!newEntry.event_name || uploading}
            >
              Add Project
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      {/* Portfolio Grid */}
      {portfolio.length > 0 ? (
        <div className="space-y-4">
          {portfolio.map((entry) => (
            <div 
              key={entry.id} 
              className="bg-white rounded-xl border border-neutral-200 overflow-hidden group"
            >
              <div className="flex flex-col md:flex-row">
                {/* Cover Image */}
                <div className="w-full md:w-48 h-48 md:h-auto relative bg-neutral-100 flex-shrink-0">
                  {entry.cover_image_url ? (
                    <Image
                      src={entry.cover_image_url}
                      alt={entry.event_name}
                      fill
                      className="object-cover"
                    />
                  ) : (
                    <div className="w-full h-full flex items-center justify-center">
                      <Briefcase className="h-12 w-12 text-neutral-300" />
                    </div>
                  )}
                  {entry.is_featured && (
                    <span className="absolute top-2 left-2 px-2 py-0.5 bg-yellow-500 text-white text-xs rounded">
                      Featured
                    </span>
                  )}
                </div>

                {/* Content */}
                <div className="flex-1 p-4">
                  <div className="flex items-start justify-between">
                    <div>
                      <h3 className="font-semibold text-neutral-900">{entry.event_name}</h3>
                      {entry.client_name && (
                        <p className="text-sm text-neutral-500">for {entry.client_name}</p>
                      )}
                    </div>
                    <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button
                        onClick={() => handleToggleFeatured(entry.id, !entry.is_featured)}
                        className={`px-3 py-1 text-xs rounded-full border transition-colors ${
                          entry.is_featured 
                            ? 'border-yellow-500 bg-yellow-500 text-white' 
                            : 'border-neutral-300 text-neutral-600 hover:border-neutral-400'
                        }`}
                      >
                        {entry.is_featured ? 'Featured' : 'Feature'}
                      </button>
                      <button
                        onClick={() => handleDeleteEntry(entry.id)}
                        className="p-1.5 text-neutral-400 hover:text-red-500"
                      >
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </div>
                  </div>

                  {/* Meta */}
                  <div className="flex flex-wrap gap-4 mt-2 text-sm text-neutral-500">
                    {entry.date && (
                      <span className="flex items-center gap-1">
                        <Calendar className="h-4 w-4" />
                        {formatDate(entry.date)}
                      </span>
                    )}
                    {(entry.venue || entry.location) && (
                      <span className="flex items-center gap-1">
                        <MapPin className="h-4 w-4" />
                        {[entry.venue, entry.location].filter(Boolean).join(', ')}
                      </span>
                    )}
                  </div>

                  {/* Services */}
                  {entry.services_provided && entry.services_provided.length > 0 && (
                    <div className="flex flex-wrap gap-1 mt-3">
                      {entry.services_provided.map((service, i) => (
                        <span 
                          key={i} 
                          className="px-2 py-0.5 bg-neutral-100 text-neutral-600 text-xs rounded"
                        >
                          {service}
                        </span>
                      ))}
                    </div>
                  )}

                  {/* Description */}
                  {entry.description && (
                    <p className="text-sm text-neutral-600 mt-3 line-clamp-2">
                      {entry.description}
                    </p>
                  )}

                  {/* Media count */}
                  {entry.media && entry.media.length > 0 && (
                    <p className="text-xs text-neutral-400 mt-2">
                      {entry.media.length} photo{entry.media.length !== 1 ? 's' : ''}
                    </p>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="text-center py-16 bg-white rounded-xl border border-neutral-200">
          <div className="w-16 h-16 mx-auto mb-4 rounded-full bg-neutral-100 flex items-center justify-center">
            <Briefcase className="h-8 w-8 text-neutral-400" />
          </div>
          <h3 className="text-lg font-semibold text-neutral-900 mb-1">No portfolio entries yet</h3>
          <p className="text-neutral-500 mb-4">Showcase your past projects to build trust with clients</p>
          <Button onClick={() => setIsAddingEntry(true)}>
            <Plus className="h-4 w-4 mr-2" />
            Add Your First Project
          </Button>
        </div>
      )}

      {/* Tips */}
      <div className="p-4 bg-neutral-100 rounded-xl">
        <h4 className="font-medium text-neutral-900 mb-2">≡ƒÆí Pro Tips</h4>
        <ul className="text-sm text-neutral-600 space-y-1">
          <li>ΓÇó Add high-quality photos from your best projects</li>
          <li>ΓÇó Feature 2-3 projects that show your range</li>
          <li>ΓÇó Include well-known clients to build credibility</li>
          <li>ΓÇó Be specific about services provided</li>
        </ul>
      </div>
    </div>
  );
}

'use client'

import { useEffect, useState } from 'react'
import { useRouter } from 'next/navigation'
import Link from 'next/link'
import Image from 'next/image'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { Switch } from '@/components/ui/switch'
import { 
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import { Badge } from '@/components/ui/badge'
import { 
  Loader2, 
  Plus, 
  ArrowLeft,
  Trash2,
  Edit,
  Upload,
  ImageIcon,
  X
} from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import { useAuth } from '@/components/providers/auth-provider'
import { 
  type Provider,
  type ProviderService,
  type ServiceCategory, 
  type PriceType,
  SERVICE_CATEGORY_LABELS,
  PRICE_TYPE_LABELS
} from '@/types/database'
import { formatCurrency } from '@/lib/helpers'
import { toast } from 'sonner'

export default function ProviderServicesPage() {
  const router = useRouter()
  const { profile } = useAuth()
  const [provider, setProvider] = useState<Provider | null>(null)
  const [services, setServices] = useState<ProviderService[]>([])
  const [loading, setLoading] = useState(true)
  const [saving, setSaving] = useState(false)
  const [uploading, setUploading] = useState(false)
  const [showForm, setShowForm] = useState(false)
  const [editingService, setEditingService] = useState<ProviderService | null>(null)
  
  // Form state
  const [serviceName, setServiceName] = useState('')
  const [description, setDescription] = useState('')
  const [category, setCategory] = useState<ServiceCategory>('sound_lighting')
  const [basePrice, setBasePrice] = useState('')
  const [priceType, setPriceType] = useState<PriceType>('fixed')
  const [isAvailable, setIsAvailable] = useState(true)
  const [imageUrl, setImageUrl] = useState<string | null>(null)

  useEffect(() => {
    if (!profile) {
      router.push('/auth/signin')
      return
    }

    if (!profile.is_provider) {
      router.push('/profile')
      return
    }

    fetchData()
  }, [profile, router])

  const fetchData = async () => {
    if (!profile) return
    
    setLoading(true)
    try {
      const supabase = createClient()
      
      // Fetch provider
      const { data: providerData, error: providerError } = await supabase
        .from('providers')
        .select('*')
        .eq('profile_id', profile.id)
        .single()

      if (providerError || !providerData) {
        router.push('/dashboard/provider/setup')
        return
      }

      setProvider(providerData)

      // Fetch services
      const { data: servicesData } = await supabase
        .from('provider_services')
        .select('*')
        .eq('provider_id', providerData.id)
        .order('created_at', { ascending: false })

      setServices(servicesData || [])
    } catch (error) {
      console.error('Error fetching data:', error)
      toast.error('Failed to load services')
    } finally {
      setLoading(false)
    }
  }

  const resetForm = () => {
    setServiceName('')
    setDescription('')
    setCategory('sound_lighting')
    setBasePrice('')
    setPriceType('fixed')
    setIsAvailable(true)
    setImageUrl(null)
    setEditingService(null)
    setShowForm(false)
  }

  const handleEdit = (service: ProviderService) => {
    setEditingService(service)
    setServiceName(service.service_name)
    setDescription(service.description || '')
    setCategory(service.category)
    setBasePrice(service.base_price.toString())
    setPriceType(service.price_type)
    setIsAvailable(service.is_available)
    setImageUrl(service.image_url || null)
    setShowForm(true)
  }

  const handleImageUpload = async (file: File) => {
    if (!profile || !provider) return
    
    // Validate file
    if (!file.type.startsWith('image/')) {
      toast.error('Please upload an image file')
      return
    }
    
    if (file.size > 5 * 1024 * 1024) {
      toast.error('Image must be less than 5MB')
      return
    }

    setUploading(true)
    try {
      const supabase = createClient()
      const fileExt = file.name.split('.').pop()
      const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`
      const filePath = `providers/${profile.id}/services/${fileName}`
      
      const { error: uploadError } = await supabase.storage
        .from('media')
        .upload(filePath, file)

      if (uploadError) throw uploadError

      const { data: { publicUrl } } = supabase.storage
        .from('media')
        .getPublicUrl(filePath)

      setImageUrl(publicUrl)
      toast.success('Image uploaded!')
    } catch (error) {
      console.error('Error uploading image:', error)
      toast.error('Failed to upload image')
    } finally {
      setUploading(false)
    }
  }

  const removeImage = () => {
    setImageUrl(null)
  }

  const handleDelete = async (serviceId: string) => {
    if (!confirm('Are you sure you want to delete this service?')) return

    try {
      const supabase = createClient()
      const { error } = await supabase
        .from('provider_services')
        .delete()
        .eq('id', serviceId)

      if (error) throw error

      toast.success('Service deleted')
      fetchData()
    } catch (error) {
      console.error('Error deleting service:', error)
      toast.error('Failed to delete service')
    }
  }

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault()
    
    if (!serviceName.trim()) {
      toast.error('Service name is required')
      return
    }

    if (!basePrice || parseFloat(basePrice) < 0) {
      toast.error('Please enter a valid price')
      return
    }

    setSaving(true)
    try {
      const supabase = createClient()
      
      const serviceData = {
        provider_id: provider!.id,
        service_name: serviceName.trim(),
        description: description.trim() || null,
        category,
        base_price: parseFloat(basePrice),
        price_type: priceType,
        is_available: isAvailable,
        image_url: imageUrl,
      }

      if (editingService) {
        const { error } = await supabase
          .from('provider_services')
          .update(serviceData)
          .eq('id', editingService.id)

        if (error) throw error
        toast.success('Service updated!')
      } else {
        const { error } = await supabase
          .from('provider_services')
          .insert(serviceData)

        if (error) throw error
        toast.success('Service added!')
      }

      resetForm()
      fetchData()
    } catch (error) {
      console.error('Error saving service:', error)
      toast.error('Failed to save service')
    } finally {
      setSaving(false)
    }
  }

  if (loading || !profile) {
    return (
      <div className="flex justify-center items-center min-h-[50vh]">
        <Loader2 className="h-8 w-8 animate-spin text-orange-500" />
      </div>
    )
  }

  return (
    <div className="container mx-auto px-4 py-8 max-w-4xl">
      {/* Header */}
      <div className="mb-8">
        <Link href="/dashboard/provider" className="inline-flex items-center text-muted-foreground hover:text-foreground mb-4">
          <ArrowLeft className="h-4 w-4 mr-2" />
          Back to Dashboard
        </Link>
        
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold">Manage Services</h1>
            <p className="text-muted-foreground">Add and edit the services you offer</p>
          </div>
          {!showForm && (
            <Button onClick={() => setShowForm(true)} className="bg-orange-500 hover:bg-orange-600">
              <Plus className="h-4 w-4 mr-2" />
              Add Service
            </Button>
          )}
        </div>
      </div>

      {/* Add/Edit Form */}
      {showForm && (
        <Card className="mb-8 border-orange-200">
          <CardHeader>
            <CardTitle>{editingService ? 'Edit Service' : 'Add New Service'}</CardTitle>
            <CardDescription>
              Describe the service you offer and set your pricing
            </CardDescription>
          </CardHeader>
          <CardContent>
            <form onSubmit={handleSubmit} className="space-y-4">
              {/* Service Image */}
              <div>
                <Label>Service Image</Label>
                <div className="mt-2">
                  {imageUrl ? (
                    <div className="relative w-full max-w-xs">
                      <div className="aspect-video rounded-lg overflow-hidden bg-neutral-100">
                        <Image
                          src={imageUrl}
                          alt="Service"
                          width={320}
                          height={180}
                          className="w-full h-full object-cover"
                        />
                      </div>
                      <button
                        type="button"
                        onClick={removeImage}
                        className="absolute -top-2 -right-2 p-1 bg-red-500 text-white rounded-full hover:bg-red-600"
                      >
                        <X className="h-4 w-4" />
                      </button>
                    </div>
                  ) : (
                    <label className="flex flex-col items-center justify-center w-full max-w-xs aspect-video border-2 border-dashed border-neutral-300 rounded-lg cursor-pointer hover:border-orange-500 hover:bg-orange-50 transition-colors">
                      <div className="flex flex-col items-center justify-center py-4">
                        {uploading ? (
                          <Loader2 className="h-8 w-8 animate-spin text-orange-500" />
                        ) : (
                          <>
                            <ImageIcon className="h-8 w-8 text-neutral-400 mb-2" />
                            <p className="text-sm text-neutral-500">Click to upload image</p>
                            <p className="text-xs text-neutral-400 mt-1">PNG, JPG up to 5MB</p>
                          </>
                        )}
                      </div>
                      <input
                        type="file"
                        accept="image/*"
                        className="hidden"
                        onChange={(e) => {
                          const file = e.target.files?.[0]
                          if (file) handleImageUpload(file)
                        }}
                        disabled={uploading}
                      />
                    </label>
                  )}
                </div>
              </div>

              <div className="grid md:grid-cols-2 gap-4">
                <div>
                  <Label htmlFor="serviceName">Service Name *</Label>
                  <Input
                    id="serviceName"
                    placeholder="e.g., Full Sound System Setup"
                    value={serviceName}
                    onChange={(e) => setServiceName(e.target.value)}
                    required
                  />
                </div>
                
                <div>
                  <Label htmlFor="category">Category *</Label>
                  <Select value={category} onValueChange={(v) => setCategory(v as ServiceCategory)}>
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      {Object.entries(SERVICE_CATEGORY_LABELS).map(([value, label]) => (
                        <SelectItem key={value} value={value}>{label}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </div>

              <div>
                <Label htmlFor="description">Description</Label>
                <Textarea
                  id="description"
                  placeholder="What's included in this service? Any requirements?"
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  rows={3}
                />
              </div>

              <div className="grid md:grid-cols-2 gap-4">
                <div>
                  <Label htmlFor="price">Base Price (R) *</Label>
                  <Input
                    id="price"
                    type="number"
                    min="0"
                    step="0.01"
                    placeholder="0.00"
                    value={basePrice}
                    onChange={(e) => setBasePrice(e.target.value)}
                    required
                  />
                </div>
                
                <div>
                  <Label htmlFor="priceType">Price Type *</Label>
                  <Select value={priceType} onValueChange={(v) => setPriceType(v as PriceType)}>
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      {Object.entries(PRICE_TYPE_LABELS).map(([value, label]) => (
                        <SelectItem key={value} value={value}>{label}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </div>

              <div className="flex items-center space-x-2">
                <Switch
                  id="available"
                  checked={isAvailable}
                  onCheckedChange={setIsAvailable}
                />
                <Label htmlFor="available">Service is available for booking</Label>
              </div>

              <div className="flex gap-2 pt-4">
                <Button type="button" variant="outline" onClick={resetForm}>
                  Cancel
                </Button>
                <Button type="submit" className="bg-orange-500 hover:bg-orange-600" disabled={saving}>
                  {saving && <Loader2 className="h-4 w-4 animate-spin mr-2" />}
                  {editingService ? 'Save Changes' : 'Add Service'}
                </Button>
              </div>
            </form>
          </CardContent>
        </Card>
      )}

      {/* Services List */}
      {services.length === 0 && !showForm ? (
        <Card>
          <CardContent className="py-12 text-center">
            <h3 className="font-semibold text-lg mb-2">No services yet</h3>
            <p className="text-muted-foreground mb-4">
              Add your first service to start receiving booking requests
            </p>
            <Button onClick={() => setShowForm(true)}>
              <Plus className="h-4 w-4 mr-2" />
              Add Your First Service
            </Button>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-4">
          {services.map((service) => (
            <Card key={service.id}>
              <CardContent className="py-4">
                <div className="flex items-start justify-between gap-4">
                  {/* Service Image */}
                  {service.image_url && (
                    <div className="w-24 h-24 rounded-lg overflow-hidden bg-neutral-100 flex-shrink-0">
                      <Image
                        src={service.image_url}
                        alt={service.service_name}
                        width={96}
                        height={96}
                        className="w-full h-full object-cover"
                      />
                    </div>
                  )}
                  
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <h3 className="font-semibold">{service.service_name}</h3>
                      <Badge variant="outline">
                        {SERVICE_CATEGORY_LABELS[service.category]}
                      </Badge>
                      <Badge variant={service.is_available ? 'default' : 'secondary'}>
                        {service.is_available ? 'Active' : 'Inactive'}
                      </Badge>
                    </div>
                    {service.description && (
                      <p className="text-sm text-muted-foreground mb-2">{service.description}</p>
                    )}
                    <p className="font-bold text-orange-600">
                      {formatCurrency(service.base_price)} 
                      <span className="text-sm font-normal text-muted-foreground ml-1">
                        ({PRICE_TYPE_LABELS[service.price_type]})
                      </span>
                    </p>
                  </div>
                  
                  <div className="flex gap-2">
                    <Button
                      size="sm"
                      variant="outline"
                      onClick={() => handleEdit(service)}
                    >
                      <Edit className="h-4 w-4" />
                    </Button>
                    <Button
                      size="sm"
                      variant="outline"
                      className="text-red-600 hover:bg-red-50"
                      onClick={() => handleDelete(service.id)}
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </div>
  )
}

'use client'

import { useEffect, useState } from 'react'
import { useRouter } from 'next/navigation'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { 
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import { Loader2, Users, ArrowRight, ArrowLeft } from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import { useAuth } from '@/components/providers/auth-provider'
import {
  type ServiceCategory,
  type SaProvince,
  type PriceType,
  type CrewWorkMode,
  SERVICE_CATEGORY_LABELS,
} from '@/types/database'
import { toast } from 'sonner'

// Province labels
const PROVINCE_LABELS: Record<SaProvince, string> = {
  gauteng: 'Gauteng',
  western_cape: 'Western Cape',
  kwazulu_natal: 'KwaZulu-Natal',
  eastern_cape: 'Eastern Cape',
  free_state: 'Free State',
  mpumalanga: 'Mpumalanga',
  limpopo: 'Limpopo',
  north_west: 'North West',
  northern_cape: 'Northern Cape',
}

export default function ProviderSetupPage() {
  const router = useRouter()
  const { profile, refreshProfile } = useAuth()
  const [loading, setLoading] = useState(false)
  const [checkingExisting, setCheckingExisting] = useState(true)
  const [isEditing, setIsEditing] = useState(false)
  
  // Form state
  const [businessName, setBusinessName] = useState('')
  const [description, setDescription] = useState('')
  const [primaryCategory, setPrimaryCategory] = useState<ServiceCategory>('sound_lighting')
  const [location, setLocation] = useState<SaProvince>('gauteng')
  const [businessPhone, setBusinessPhone] = useState('')
  const [businessEmail, setBusinessEmail] = useState('')
  const [website, setWebsite] = useState('')
  const [isAvailable, setIsAvailable] = useState(true)
  const [advanceNoticeDays, setAdvanceNoticeDays] = useState(3)
  const [workMode, setWorkMode] = useState<CrewWorkMode>('offering_services')
  const [activeSection, setActiveSection] = useState<'work' | 'services'>('work')
  const [baseRate, setBaseRate] = useState('')
  const [rateType, setRateType] = useState<PriceType>('daily')
  const [availabilityNotes, setAvailabilityNotes] = useState('')
  const [workRoles, setWorkRoles] = useState('')

  useEffect(() => {
    if (!profile) {
      router.push('/auth/signin')
      return
    }

    checkExistingProvider()
  }, [profile, router])

  const checkExistingProvider = async () => {
    if (!profile) return
    
    try {
      const supabase = createClient()
      const { data, error } = await supabase
        .from('providers')
        .select('*')
        .eq('profile_id', profile.id)
        .single()

      if (data && !error) {
        // Pre-fill form with existing data
        setBusinessName(data.business_name)
        setDescription(data.description || '')
        setPrimaryCategory(data.primary_category)
        setLocation(data.location)
        setBusinessPhone(data.business_phone || '')
        setBusinessEmail(data.business_email || '')
        setWebsite(data.website || '')
        setIsAvailable(data.is_available !== false)
        setAdvanceNoticeDays(data.advance_notice_days)
        setWorkMode(data.work_mode || 'offering_services')
        setActiveSection(data.work_mode === 'offering_services' ? 'services' : 'work')
        setBaseRate(data.base_rate ? String(data.base_rate) : '')
        setRateType(data.rate_type || 'daily')
        setAvailabilityNotes(data.availability_notes || '')
        setWorkRoles(Array.isArray(data.work_roles) ? data.work_roles.join(', ') : '')
        setIsEditing(true)
      }
    } catch (error) {
      console.error('Error checking existing provider:', error)
    } finally {
      setCheckingExisting(false)
    }
  }

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault()
    
    if (!businessName.trim()) {
      toast.error('Business name is required')
      return
    }

    setLoading(true)
    try {
      const supabase = createClient()
      
      await supabase
        .from('profiles')
        .update({ is_provider: true })
        .eq('id', profile!.id)

      const legacyProviderData = {
        profile_id: profile!.id,
        business_name: businessName.trim(),
        description: description.trim() || null,
        primary_category: primaryCategory,
        location: location,
        business_phone: businessPhone.trim() || null,
        business_email: businessEmail.trim() || null,
        website: website.trim() || null,
        is_available: isAvailable,
        advance_notice_days: advanceNoticeDays,
      }

      const providerData = {
        ...legacyProviderData,
        work_mode: workMode,
        base_rate: baseRate.trim() ? Number(baseRate) : null,
        rate_type: rateType,
        availability_notes: availabilityNotes.trim() || null,
        work_roles: workRoles.split(',').map((role) => role.trim()).filter(Boolean),
      }

      const saveProvider = async (payload: typeof providerData | typeof legacyProviderData) => {
        if (isEditing) {
          return supabase
            .from('providers')
            .update(payload)
            .eq('profile_id', profile!.id)
        }

        return supabase
          .from('providers')
          .insert(payload)
      }

      let saveResult = await saveProvider(providerData)
      let usedLegacyFallback = false

      if (saveResult.error && String(saveResult.error.message || '').toLowerCase().includes('work_mode')) {
        saveResult = await saveProvider(legacyProviderData)
        usedLegacyFallback = !saveResult.error
      }

      if (saveResult.error) throw saveResult.error

      await refreshProfile()
      toast.success(
        usedLegacyFallback
          ? 'Crew profile saved. Apply the latest Crew migration to unlock rates and availability fields.'
          : isEditing
            ? 'Crew profile updated!'
            : 'Crew profile created! ≡ƒÄë'
      )
      router.push('/dashboard/provider')
    } catch (error) {
      console.error('Error saving crew profile:', error)
      toast.error('Failed to save crew profile')
    } finally {
      setLoading(false)
    }
  }

  if (checkingExisting || !profile) {
    return (
      <div className="flex justify-center items-center min-h-[50vh]">
        <Loader2 className="h-8 w-8 animate-spin text-orange-500" />
      </div>
    )
  }

  return (
    <div className="container mx-auto px-4 py-8 max-w-2xl">
      {isEditing && (
        <button
          onClick={() => router.push('/dashboard/provider')}
          className="inline-flex items-center text-muted-foreground hover:text-foreground mb-6 text-sm"
        >
          <ArrowLeft className="h-4 w-4 mr-2" />
          Back to Dashboard
        </button>
      )}
      <div className="text-center mb-8">
        <div className="inline-flex items-center justify-center p-3 bg-orange-100 rounded-full mb-4">
          <Users className="h-8 w-8 text-orange-600" />
        </div>
        <h1 className="text-3xl font-bold mb-2">
          {isEditing ? 'Edit Crew Profile' : 'Set Up Your Crew Profile'}
        </h1>
        <p className="text-muted-foreground">
          {isEditing
            ? 'Update your crew identity, rates, and availability'
            : 'Choose whether you want My Work, My Services, or both on Ziyawa.'}
        </p>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Crew Profile Information</CardTitle>
          <CardDescription>
            Start with one focus now if you want, and enable the other later from your Crew Dashboard.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-6">

            {/* ΓöÇΓöÇ STEP 1: Work Mode (always at top) ΓöÇΓöÇ */}
            <div className="rounded-lg border-2 border-orange-200 bg-orange-50/40 p-4 space-y-3">
              <p className="font-semibold text-sm text-foreground">How do you want to work on Ziyawa?</p>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
                {([
                  { value: 'looking_for_work', label: 'My Work', desc: 'Get hired for event staff roles' },
                  { value: 'offering_services', label: 'My Services', desc: 'Offer bookable services' },
                  { value: 'both', label: 'Both', desc: 'Work and services' },
                ] as { value: CrewWorkMode; label: string; desc: string }[]).map(({ value, label, desc }) => (
                  <button
                    key={value}
                    type="button"
                    onClick={() => {
                      setWorkMode(value)
                      if (value === 'looking_for_work') setActiveSection('work')
                      if (value === 'offering_services') setActiveSection('services')
                    }}
                    className={`rounded-lg border-2 p-3 text-left transition-colors ${
                      workMode === value
                        ? 'border-orange-500 bg-white shadow-sm'
                        : 'border-neutral-200 bg-white hover:border-neutral-300'
                    }`}
                  >
                    <p className="font-medium text-sm">{label}</p>
                    <p className="text-xs text-muted-foreground mt-0.5">{desc}</p>
                  </button>
                ))}
              </div>
              <p className="text-xs text-muted-foreground">
                This stays synced with My Work and My Services in your Crew Dashboard.
              </p>
            </div>

            {/* ΓöÇΓöÇ STEP 2: Section toggle for "Both" mode ΓöÇΓöÇ */}
            {workMode === 'both' && (
              <div className="flex rounded-lg border bg-muted/20 p-1 gap-1">
                <button
                  type="button"
                  onClick={() => setActiveSection('work')}
                  className={`flex-1 py-2 px-4 rounded-md text-sm font-medium transition-colors ${
                    activeSection === 'work'
                      ? 'bg-white shadow-sm text-foreground'
                      : 'text-muted-foreground hover:text-foreground'
                  }`}
                >
                  Work Profile Settings
                </button>
                <button
                  type="button"
                  onClick={() => setActiveSection('services')}
                  className={`flex-1 py-2 px-4 rounded-md text-sm font-medium transition-colors ${
                    activeSection === 'services'
                      ? 'bg-white shadow-sm text-foreground'
                      : 'text-muted-foreground hover:text-foreground'
                  }`}
                >
                  Services Settings
                </button>
              </div>
            )}

            {/* ΓöÇΓöÇ COMMON FIELDS (always visible) ΓöÇΓöÇ */}
            <div>
              <Label htmlFor="businessName">Display Name or Business Name *</Label>
              <Input
                id="businessName"
                placeholder="e.g., SoundPro SA or Sipho Crew"
                value={businessName}
                onChange={(e) => setBusinessName(e.target.value)}
                required
              />
            </div>

            <div>
              <Label htmlFor="description">About You or Your Business</Label>
              <Textarea
                id="description"
                placeholder="Tell organisers what you do well, how you work, and what makes your business reliable..."
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                rows={4}
              />
            </div>

            <div>
              <Label htmlFor="location">Location *</Label>
              <Select value={location} onValueChange={(v) => setLocation(v as SaProvince)}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {Object.entries(PROVINCE_LABELS).map(([value, label]) => (
                    <SelectItem key={value} value={value}>{label}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="grid md:grid-cols-2 gap-4">
              <div>
                <Label htmlFor="phone">Business Phone</Label>
                <Input
                  id="phone"
                  type="tel"
                  placeholder="+27 XX XXX XXXX"
                  value={businessPhone}
                  onChange={(e) => setBusinessPhone(e.target.value)}
                />
              </div>
              <div>
                <Label htmlFor="email">Business Email</Label>
                <Input
                  id="email"
                  type="email"
                  placeholder="contact@business.co.za"
                  value={businessEmail}
                  onChange={(e) => setBusinessEmail(e.target.value)}
                />
              </div>
            </div>

            <div>
              <Label htmlFor="website">Website</Label>
              <Input
                id="website"
                type="url"
                placeholder="https://www.yourbusiness.co.za"
                value={website}
                onChange={(e) => setWebsite(e.target.value)}
              />
            </div>

            {/* ΓöÇΓöÇ WORK PROFILE FIELDS ΓöÇΓöÇ */}
            {(workMode === 'looking_for_work' || (workMode === 'both' && activeSection === 'work')) && (
              <div className="space-y-4 rounded-lg border border-neutral-200 p-4 bg-muted/20">
                <p className="text-sm font-semibold text-foreground">Work Profile</p>
                <div className="rounded-lg border border-dashed bg-muted/30 p-3 text-xs text-muted-foreground">
                  This rate is only used when organizers hire you for event work. Service prices are set per service in My Services.
                </div>
                <div className="grid gap-4 md:grid-cols-2">
                  <div>
                    <Label htmlFor="baseRate">Starting rate for event work</Label>
                    <Input
                      id="baseRate"
                      type="number"
                      min={0}
                      step="0.01"
                      placeholder="500"
                      value={baseRate}
                      onChange={(e) => setBaseRate(e.target.value)}
                    />
                  </div>
                  <div>
                    <Label htmlFor="rateType">Rate type</Label>
                    <Select value={rateType} onValueChange={(v) => setRateType(v as PriceType)}>
                      <SelectTrigger id="rateType">
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="hourly">Per hour</SelectItem>
                        <SelectItem value="daily">Per day</SelectItem>
                        <SelectItem value="fixed">Fixed price</SelectItem>
                        <SelectItem value="negotiable">Negotiable</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>
                <div>
                  <Label htmlFor="workRoles">Skills &amp; Roles</Label>
                  <Input
                    id="workRoles"
                    placeholder="e.g. Door staff, Guest list, Runner, Ops, MC support"
                    value={workRoles}
                    onChange={(e) => setWorkRoles(e.target.value)}
                  />
                  <p className="text-xs text-muted-foreground mt-1">
                    Comma-separated list of roles you can fill at events.
                  </p>
                </div>
                <div>
                  <Label htmlFor="availabilityNotes">Availability and work notes</Label>
                  <Textarea
                    id="availabilityNotes"
                    placeholder="Available on weekends, open to Gauteng and nearby travel, own transport, short-notice okay..."
                    value={availabilityNotes}
                    onChange={(e) => setAvailabilityNotes(e.target.value)}
                    rows={3}
                  />
                </div>
              </div>
            )}

            {/* ΓöÇΓöÇ SERVICES FIELDS ΓöÇΓöÇ */}
            {(workMode === 'offering_services' || (workMode === 'both' && activeSection === 'services')) && (
              <div className="space-y-4 rounded-lg border border-neutral-200 p-4 bg-muted/20">
                <p className="text-sm font-semibold text-foreground">Services Settings</p>
                <div>
                  <Label htmlFor="category">Primary Service Category *</Label>
                  <Select value={primaryCategory} onValueChange={(v) => setPrimaryCategory(v as ServiceCategory)}>
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      {Object.entries(SERVICE_CATEGORY_LABELS).map(([value, label]) => (
                        <SelectItem key={value} value={value}>{label}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  <p className="text-xs text-muted-foreground mt-1">
                    You can list services in multiple categories. This is your main one.
                  </p>
                </div>
                <div>
                  <Label htmlFor="availability">Booking Availability</Label>
                  <Select value={isAvailable ? 'available' : 'paused'} onValueChange={(value) => setIsAvailable(value === 'available')}>
                    <SelectTrigger id="availability">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="available">Available for bookings</SelectItem>
                      <SelectItem value="paused">Pause bookings for now</SelectItem>
                    </SelectContent>
                  </Select>
                  <p className="text-xs text-muted-foreground mt-1">
                    Toggle this anytime when your team is fully booked.
                  </p>
                </div>
                <div>
                  <Label htmlFor="notice">Minimum Advance Notice (days)</Label>
                  <Input
                    id="notice"
                    type="number"
                    min={0}
                    max={90}
                    value={advanceNoticeDays}
                    onChange={(e) => setAdvanceNoticeDays(parseInt(e.target.value) || 0)}
                  />
                  <p className="text-xs text-muted-foreground mt-1">
                    How many days notice do you need before a service booking?
                  </p>
                </div>
              </div>
            )}

            {/* Submit */}
            <Button 
              type="submit" 
              className="w-full bg-orange-500 hover:bg-orange-600"
              disabled={loading}
            >
              {loading ? (
                <Loader2 className="h-4 w-4 animate-spin mr-2" />
              ) : (
                <ArrowRight className="h-4 w-4 mr-2" />
              )}
              {isEditing ? 'Save Crew Changes' : 'Create Crew Profile'}
            </Button>
          </form>
        </CardContent>
      </Card>
    </div>
  )
}

'use client';

import { useState, useEffect } from 'react';
import { Bell, Mail, Smartphone, Save, Loader2 } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Switch } from '@/components/ui/switch';
import { Label } from '@/components/ui/label';
import { Separator } from '@/components/ui/separator';
import { useToast } from '@/hooks/use-toast';

interface NotificationPreferences {
  email_enabled: boolean;
  push_enabled: boolean;
  booking_notifications: boolean;
  payment_notifications: boolean;
  event_notifications: boolean;
  message_notifications: boolean;
  review_notifications: boolean;
  system_notifications: boolean;
  marketing_notifications: boolean;
}

const defaultPreferences: NotificationPreferences = {
  email_enabled: true,
  push_enabled: true,
  booking_notifications: true,
  payment_notifications: true,
  event_notifications: true,
  message_notifications: true,
  review_notifications: true,
  system_notifications: true,
  marketing_notifications: false,
};

export default function NotificationSettingsPage() {
  const [preferences, setPreferences] = useState<NotificationPreferences>(defaultPreferences);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [hasChanges, setHasChanges] = useState(false);
  const { toast } = useToast();

  useEffect(() => {
    fetchPreferences();
  }, []);

  const fetchPreferences = async () => {
    try {
      const res = await fetch('/api/notifications/preferences');
      if (res.ok) {
        const data = await res.json();
        setPreferences(data.preferences);
      }
    } catch (error) {
      console.error('Failed to fetch preferences:', error);
      toast({
        title: 'Error',
        description: 'Failed to load notification preferences',
        variant: 'destructive',
      });
    } finally {
      setLoading(false);
    }
  };

  const handleToggle = (key: keyof NotificationPreferences, value: boolean) => {
    setPreferences(prev => ({ ...prev, [key]: value }));
    setHasChanges(true);
  };

  const savePreferences = async () => {
    try {
      setSaving(true);
      const res = await fetch('/api/notifications/preferences', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(preferences),
      });

      if (res.ok) {
        toast({
          title: 'Saved',
          description: 'Your notification preferences have been updated',
        });
        setHasChanges(false);
      } else {
        throw new Error('Failed to save');
      }
    } catch (error) {
      console.error('Failed to save preferences:', error);
      toast({
        title: 'Error',
        description: 'Failed to save notification preferences',
        variant: 'destructive',
      });
    } finally {
      setSaving(false);
    }
  };

  if (loading) {
    return (
      <div className="container max-w-2xl py-8">
        <div className="flex items-center justify-center py-12">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      </div>
    );
  }

  return (
    <div className="container max-w-2xl py-8">
      <div className="mb-8">
        <h1 className="text-3xl font-bold">Notification Settings</h1>
        <p className="text-muted-foreground mt-1">
          Manage how and when you receive notifications
        </p>
      </div>

      <div className="space-y-6">
        {/* Delivery Channels */}
        <Card>
          <CardHeader>
            <CardTitle className="text-lg">Delivery Channels</CardTitle>
            <CardDescription>
              Choose how you want to receive notifications
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="flex h-10 w-10 items-center justify-center rounded-full bg-blue-100">
                  <Mail className="h-5 w-5 text-blue-600" />
                </div>
                <div>
                  <Label className="font-medium">Email Notifications</Label>
                  <p className="text-sm text-muted-foreground">
                    Receive notifications via email
                  </p>
                </div>
              </div>
              <Switch
                checked={preferences.email_enabled}
                onCheckedChange={(checked) => handleToggle('email_enabled', checked)}
              />
            </div>

            <Separator />

            <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="flex h-10 w-10 items-center justify-center rounded-full bg-purple-100">
                  <Smartphone className="h-5 w-5 text-purple-600" />
                </div>
                <div>
                  <Label className="font-medium">Push Notifications</Label>
                  <p className="text-sm text-muted-foreground">
                    Receive push notifications in browser
                  </p>
                </div>
              </div>
              <Switch
                checked={preferences.push_enabled}
                onCheckedChange={(checked) => handleToggle('push_enabled', checked)}
              />
            </div>
          </CardContent>
        </Card>

        {/* Notification Categories */}
        <Card>
          <CardHeader>
            <CardTitle className="text-lg">Notification Categories</CardTitle>
            <CardDescription>
              Choose which types of notifications you want to receive
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="flex items-center justify-between">
              <div>
                <Label className="font-medium">Bookings</Label>
                <p className="text-sm text-muted-foreground">
                  Booking requests, confirmations, and updates
                </p>
              </div>
              <Switch
                checked={preferences.booking_notifications}
                onCheckedChange={(checked) => handleToggle('booking_notifications', checked)}
              />
            </div>

            <Separator />

            <div className="flex items-center justify-between">
              <div>
                <Label className="font-medium">Payments</Label>
                <p className="text-sm text-muted-foreground">
                  Payment confirmations, refunds, and payouts
                </p>
              </div>
              <Switch
                checked={preferences.payment_notifications}
                onCheckedChange={(checked) => handleToggle('payment_notifications', checked)}
              />
            </div>

            <Separator />

            <div className="flex items-center justify-between">
              <div>
                <Label className="font-medium">Events</Label>
                <p className="text-sm text-muted-foreground">
                  Event reminders, updates, and cancellations
                </p>
              </div>
              <Switch
                checked={preferences.event_notifications}
                onCheckedChange={(checked) => handleToggle('event_notifications', checked)}
              />
            </div>

            <Separator />

            <div className="flex items-center justify-between">
              <div>
                <Label className="font-medium">Messages</Label>
                <p className="text-sm text-muted-foreground">
                  New messages from artists and clients
                </p>
              </div>
              <Switch
                checked={preferences.message_notifications}
                onCheckedChange={(checked) => handleToggle('message_notifications', checked)}
              />
            </div>

            <Separator />

            <div className="flex items-center justify-between">
              <div>
                <Label className="font-medium">Reviews</Label>
                <p className="text-sm text-muted-foreground">
                  New reviews and review requests
                </p>
              </div>
              <Switch
                checked={preferences.review_notifications}
                onCheckedChange={(checked) => handleToggle('review_notifications', checked)}
              />
            </div>

            <Separator />

            <div className="flex items-center justify-between">
              <div>
                <Label className="font-medium">System</Label>
                <p className="text-sm text-muted-foreground">
                  Important account and security updates
                </p>
              </div>
              <Switch
                checked={preferences.system_notifications}
                onCheckedChange={(checked) => handleToggle('system_notifications', checked)}
              />
            </div>
          </CardContent>
        </Card>

        {/* Marketing */}
        <Card>
          <CardHeader>
            <CardTitle className="text-lg">Marketing & Promotions</CardTitle>
            <CardDescription>
              Updates about new features and special offers
            </CardDescription>
          </CardHeader>
          <CardContent>
            <div className="flex items-center justify-between">
              <div>
                <Label className="font-medium">Marketing Emails</Label>
                <p className="text-sm text-muted-foreground">
                  Promotional content, tips, and platform updates
                </p>
              </div>
              <Switch
                checked={preferences.marketing_notifications}
                onCheckedChange={(checked) => handleToggle('marketing_notifications', checked)}
              />
            </div>
          </CardContent>
        </Card>

        {/* Save Button */}
        {hasChanges && (
          <div className="flex justify-end">
            <Button onClick={savePreferences} disabled={saving}>
              {saving ? (
                <>
                  <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                  Saving...
                </>
              ) : (
                <>
                  <Save className="h-4 w-4 mr-2" />
                  Save Changes
                </>
              )}
            </Button>
          </div>
        )}
      </div>
    </div>
  );
}

'use client'

import { useEffect, useState, useRef, useCallback, Suspense } from 'react'
import { useRouter, useSearchParams } from 'next/navigation'
import Link from 'next/link'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Badge } from '@/components/ui/badge'
import { Separator } from '@/components/ui/separator'
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs'
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar'
import { Switch } from '@/components/ui/switch'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import {
  User,
  Shield,
  ShieldCheck,
  Bell,
  CheckCircle,
  XCircle,
  Clock,
  Loader2,
  Upload,
  ArrowRight,
  Calendar,
  Music,
  Wrench,
  Smartphone,
  AlertTriangle,
  RefreshCw,
} from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import { useAuth } from '@/components/providers/auth-provider'
import { toast } from 'sonner'

// ΓöÇΓöÇ Types ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

interface VerificationRequest {
  id: string
  entity_type: 'individual' | 'business'
  status: 'pending' | 'approved' | 'rejected'
  submitted_at: string
  reviewed_at: string | null
  rejection_reason: string | null
  id_type?: string
  business_name?: string
}

// ΓöÇΓöÇ Helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function VerificationStatusBadge({ status }: { status: string }) {
  if (status === 'approved') return <Badge className="bg-green-500 text-white"><CheckCircle className="h-3 w-3 mr-1" />Verified</Badge>
  if (status === 'pending') return <Badge variant="outline" className="border-orange-400 text-orange-600"><Clock className="h-3 w-3 mr-1" />Pending review</Badge>
  return <Badge variant="destructive"><XCircle className="h-3 w-3 mr-1" />Rejected</Badge>
}

// ΓöÇΓöÇ Main Component ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export default function SettingsPage() {
  return (
    <Suspense>
      <SettingsPageInner />
    </Suspense>
  )
}

function SettingsPageInner() {
  const router = useRouter()
  const searchParams = useSearchParams()
  const { user, profile, refreshProfile, loading: authLoading } = useAuth()
  const supabase = createClient()

  const defaultTab = searchParams.get('tab') ?? 'profile'

  // Profile tab state
  const [fullName, setFullName] = useState('')
  const [phone, setPhone] = useState('')
  const [savingProfile, setSavingProfile] = useState(false)
  const [avatarUploading, setAvatarUploading] = useState(false)
  const avatarInputRef = useRef<HTMLInputElement>(null)

  // Account tab state
  const [upgrading, setUpgrading] = useState<string | null>(null)

  // Verification tab state
  const [verificationRequests, setVerificationRequests] = useState<VerificationRequest[]>([])
  const [loadingVerification, setLoadingVerification] = useState(true)
  const [entityType, setEntityType] = useState<'individual' | 'business'>('individual')
  const [idType, setIdType] = useState<'sa_id' | 'passport'>('sa_id')
  const [idNumber, setIdNumber] = useState('')
  const [businessName, setBusinessName] = useState('')
  const [regNumber, setRegNumber] = useState('')
  const [repIdNumber, setRepIdNumber] = useState('')
  const [docFrontUrl, setDocFrontUrl] = useState('')
  const [docBackUrl, setDocBackUrl] = useState('')
  const [regCertUrl, setRegCertUrl] = useState('')
  const [repFrontUrl, setRepFrontUrl] = useState('')
  const [repBackUrl, setRepBackUrl] = useState('')
  const [uploadingDoc, setUploadingDoc] = useState<string | null>(null)
  const [submittingVerification, setSubmittingVerification] = useState(false)

  // Security tab state
  const [mfaFactors, setMfaFactors] = useState<{ id: string; factor_type: string }[]>([])
  const [loadingMfa, setLoadingMfa] = useState(true)
  const [enrollingMfa, setEnrollingMfa] = useState(false)
  const [unenrollingMfa, setUnenrollingMfa] = useState(false)
  const [mfaQr, setMfaQr] = useState<string | null>(null)
  const [mfaSecret, setMfaSecret] = useState<string | null>(null)
  const [mfaFactorId, setMfaFactorId] = useState<string | null>(null)
  const [mfaCode, setMfaCode] = useState('')
  const [verifyingMfa, setVerifyingMfa] = useState(false)
  const [unenrollCode, setUnenrollCode] = useState('')

  useEffect(() => {
    if (!authLoading && !user) {
      router.replace('/auth/signin')
    }
  }, [authLoading, user, router])

  useEffect(() => {
    if (profile) {
      setFullName(profile.full_name || '')
      setPhone((profile as { phone?: string }).phone || '')
    }
  }, [profile])

  const fetchVerificationStatus = useCallback(async () => {
    setLoadingVerification(true)
    try {
      const res = await fetch('/api/verification/submit')
      if (res.ok) {
        const data = await res.json()
        setVerificationRequests(data.requests ?? [])
      }
    } catch {
      // silent
    } finally {
      setLoadingVerification(false)
    }
  }, [])

  const fetchMfaFactors = useCallback(async () => {
    setLoadingMfa(true)
    try {
      const { data } = await supabase.auth.mfa.listFactors()
      setMfaFactors(data?.totp ?? [])
    } catch {
      // silent
    } finally {
      setLoadingMfa(false)
    }
  }, [supabase])

  useEffect(() => {
    if (user) {
      void fetchVerificationStatus()
      void fetchMfaFactors()
    }
  }, [user, fetchVerificationStatus, fetchMfaFactors])

  if (authLoading || !user || !profile) return null

  // ΓöÇΓöÇ Handlers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  const handleSaveProfile = async (e: React.FormEvent) => {
    e.preventDefault()
    setSavingProfile(true)
    try {
      const { error } = await supabase
        .from('profiles')
        .update({ full_name: fullName, phone: phone || null })
        .eq('id', profile.id)
      if (error) throw error
      await refreshProfile()
      toast.success('Profile updated')
    } catch {
      toast.error('Failed to update profile')
    } finally {
      setSavingProfile(false)
    }
  }

  const handleAvatarChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file) return
    if (file.size > 2 * 1024 * 1024) {
      toast.error('Image must be under 2MB')
      return
    }
    setAvatarUploading(true)
    try {
      const ext = file.name.split('.').pop()
      const path = `avatars/${user.id}.${ext}`
      const { error: uploadError } = await supabase.storage
        .from('media')
        .upload(path, file, { upsert: true })
      if (uploadError) throw uploadError
      const { data: urlData } = supabase.storage.from('media').getPublicUrl(path)
      const { error: updateError } = await supabase
        .from('profiles')
        .update({ avatar_url: urlData.publicUrl })
        .eq('id', profile.id)
      if (updateError) throw updateError
      await refreshProfile()
      toast.success('Avatar updated')
    } catch {
      toast.error('Failed to upload avatar')
    } finally {
      setAvatarUploading(false)
    }
  }

  const handleUpgrade = async (role: 'organizer' | 'artist' | 'provider') => {
    setUpgrading(role)
    try {
      if (role === 'provider') {
        router.push('/dashboard/provider/setup?intent=join-crew')
        return
      }
      const { error } = await supabase
        .from('profiles')
        .update(role === 'organizer' ? { is_organizer: true } : { is_artist: true })
        .eq('id', profile.id)
      if (error) throw error
      await refreshProfile()
      toast.success(role === 'organizer' ? 'You are now an Event Organiser! ≡ƒÄë' : 'You are now an Artist! ≡ƒÄñ')
    } catch {
      toast.error('Failed to upgrade. Please try again.')
    } finally {
      setUpgrading(null)
    }
  }

  const uploadDocumentFile = async (
    file: File,
    docKey: string,
    setter: (url: string) => void
  ) => {
    if (file.size > 10 * 1024 * 1024) {
      toast.error('File must be under 10MB')
      return
    }
    setUploadingDoc(docKey)
    try {
      const ext = file.name.split('.').pop()
      const path = `verification/${user.id}/${docKey}-${Date.now()}.${ext}`
      const { error: uploadError } = await supabase.storage
        .from('verification-documents')
        .upload(path, file, { upsert: true })
      if (uploadError) throw uploadError
      setter(path)
      toast.success('Document uploaded')
    } catch {
      toast.error('Failed to upload document')
    } finally {
      setUploadingDoc(null)
    }
  }

  const handleSubmitVerification = async () => {
    setSubmittingVerification(true)
    try {
      const body: Record<string, unknown> = { entity_type: entityType }
      if (entityType === 'individual') {
        Object.assign(body, { id_type: idType, id_number: idNumber, doc_front_url: docFrontUrl, doc_back_url: docBackUrl })
      } else {
        Object.assign(body, {
          business_name: businessName,
          registration_number: regNumber,
          company_reg_cert_url: regCertUrl,
          rep_id_number: repIdNumber,
          rep_id_front_url: repFrontUrl,
          rep_id_back_url: repBackUrl,
        })
      }
      const res = await fetch('/api/verification/submit', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      })
      const data = await res.json()
      if (!res.ok) throw new Error(data.error)
      toast.success(data.message)
      await fetchVerificationStatus()
    } catch (e) {
      toast.error(e instanceof Error ? e.message : 'Submission failed')
    } finally {
      setSubmittingVerification(false)
    }
  }

  const handleEnrollMfa = async () => {
    setEnrollingMfa(true)
    try {
      const { data, error } = await supabase.auth.mfa.enroll({ factorType: 'totp', friendlyName: 'Authenticator app' })
      if (error) throw error
      setMfaFactorId(data.id)
      setMfaQr(data.totp.qr_code)
      setMfaSecret(data.totp.secret)
    } catch {
      toast.error('Failed to start 2FA setup')
    } finally {
      setEnrollingMfa(false)
    }
  }

  const handleVerifyMfa = async () => {
    if (!mfaFactorId || !mfaCode) return
    setVerifyingMfa(true)
    try {
      const { data: challengeData, error: challengeError } = await supabase.auth.mfa.challenge({ factorId: mfaFactorId })
      if (challengeError) throw challengeError
      const { error: verifyError } = await supabase.auth.mfa.verify({
        factorId: mfaFactorId,
        challengeId: challengeData.id,
        code: mfaCode,
      })
      if (verifyError) throw verifyError
      toast.success('2FA enabled successfully!')
      setMfaQr(null)
      setMfaSecret(null)
      setMfaFactorId(null)
      setMfaCode('')
      await fetchMfaFactors()
    } catch {
      toast.error('Invalid code. Please try again.')
    } finally {
      setVerifyingMfa(false)
    }
  }

  const handleUnenrollMfa = async () => {
    const factor = mfaFactors[0]
    if (!factor) return
    setUnenrollingMfa(true)
    try {
      const { error } = await supabase.auth.mfa.unenroll({ factorId: factor.id })
      if (error) throw error
      toast.success('2FA disabled')
      setUnenrollCode('')
      await fetchMfaFactors()
    } catch {
      toast.error('Failed to disable 2FA')
    } finally {
      setUnenrollingMfa(false)
    }
  }

  // ΓöÇΓöÇ Derived state ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  const latestRequest = verificationRequests[0] ?? null
  const hasPending = latestRequest?.status === 'pending'
  const isVerified = profile.is_verified
  const mfaEnabled = mfaFactors.length > 0

  const needsVerification = profile.is_artist || profile.is_organizer || (profile as { is_provider?: boolean }).is_provider
  const canSubmitVerification = !isVerified && !hasPending

  const verificationComplete = entityType === 'individual'
    ? !!idNumber && !!docFrontUrl
    : !!businessName && !!regNumber && !!regCertUrl && !!repIdNumber && !!repFrontUrl

  // ΓöÇΓöÇ Render ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  return (
    <div className="container mx-auto px-4 py-8 max-w-3xl">
      <div className="mb-6">
        <h1 className="text-2xl font-bold">Account Settings</h1>
        <p className="text-muted-foreground">Manage your profile, roles, verification, and security</p>
      </div>

      <Tabs defaultValue={defaultTab}>
        <TabsList className="mb-6 flex-wrap h-auto gap-1">
          <TabsTrigger value="profile" className="flex items-center gap-1.5">
            <User className="h-4 w-4" />Profile
          </TabsTrigger>
          <TabsTrigger value="account" className="flex items-center gap-1.5">
            <ArrowRight className="h-4 w-4" />Account
          </TabsTrigger>
          <TabsTrigger value="verification" className="flex items-center gap-1.5">
            <ShieldCheck className="h-4 w-4" />Verification
            {hasPending && <span className="ml-1 h-2 w-2 rounded-full bg-orange-500 inline-block" />}
          </TabsTrigger>
          <TabsTrigger value="security" className="flex items-center gap-1.5">
            <Shield className="h-4 w-4" />Security
          </TabsTrigger>
          <TabsTrigger value="notifications" className="flex items-center gap-1.5">
            <Bell className="h-4 w-4" />Notifications
          </TabsTrigger>
        </TabsList>

        {/* ΓöÇΓöÇ PROFILE TAB ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
        <TabsContent value="profile">
          <Card>
            <CardHeader>
              <CardTitle>Your Profile</CardTitle>
              <CardDescription>How you appear on Ziyawa</CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">
              {/* Avatar */}
              <div className="flex items-center gap-4">
                <Avatar className="h-20 w-20">
                  <AvatarImage src={profile.avatar_url || undefined} />
                  <AvatarFallback className="text-2xl">
                    {profile.full_name?.charAt(0) || profile.email.charAt(0).toUpperCase()}
                  </AvatarFallback>
                </Avatar>
                <div>
                  <input
                    ref={avatarInputRef}
                    type="file"
                    accept="image/*"
                    className="hidden"
                    onChange={handleAvatarChange}
                  />
                  <Button
                    variant="outline"
                    size="sm"
                    disabled={avatarUploading}
                    onClick={() => avatarInputRef.current?.click()}
                  >
                    {avatarUploading ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <Upload className="h-4 w-4 mr-2" />}
                    Change photo
                  </Button>
                  <p className="text-xs text-muted-foreground mt-1">JPG, PNG or WebP ┬╖ max 2MB</p>
                </div>
              </div>

              <Separator />

              <form onSubmit={handleSaveProfile} className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="full-name">Full name</Label>
                  <Input
                    id="full-name"
                    value={fullName}
                    onChange={(e) => setFullName(e.target.value)}
                    placeholder="Your full name"
                    maxLength={100}
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="email">Email</Label>
                  <Input id="email" value={profile.email} disabled className="bg-muted/40" />
                  <p className="text-xs text-muted-foreground">Email cannot be changed here</p>
                </div>
                <div className="space-y-2">
                  <Label htmlFor="phone">Phone number</Label>
                  <Input
                    id="phone"
                    value={phone}
                    onChange={(e) => setPhone(e.target.value)}
                    placeholder="+27 81 234 5678"
                    type="tel"
                    maxLength={20}
                  />
                </div>
                <Button type="submit" disabled={savingProfile}>
                  {savingProfile && <Loader2 className="h-4 w-4 animate-spin mr-2" />}
                  Save changes
                </Button>
              </form>
            </CardContent>
          </Card>
        </TabsContent>

        {/* ΓöÇΓöÇ ACCOUNT TAB ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
        <TabsContent value="account">
          <div className="space-y-4">
            <Card>
              <CardHeader>
                <CardTitle>Your Roles</CardTitle>
                <CardDescription>You can hold multiple roles at once</CardDescription>
              </CardHeader>
              <CardContent className="space-y-3">
                {[
                  { active: profile.is_organizer, label: 'Event Organiser', desc: 'Create events, book artists, sell tickets', icon: Calendar },
                  { active: profile.is_artist, label: 'Artist', desc: 'Get discovered and booked for events', icon: Music },
                  { active: (profile as { is_provider?: boolean }).is_provider, label: 'Crew', desc: 'Offer services or work events as crew', icon: Wrench },
                ].map(({ active, label, desc, icon: Icon }) => (
                  <div key={label} className="flex items-center justify-between p-3 rounded-lg border">
                    <div className="flex items-center gap-3">
                      <Icon className="h-5 w-5 text-muted-foreground" />
                      <div>
                        <p className="font-medium text-sm">{label}</p>
                        <p className="text-xs text-muted-foreground">{desc}</p>
                      </div>
                    </div>
                    {active
                      ? <Badge className="bg-green-500 text-white"><CheckCircle className="h-3 w-3 mr-1" />Active</Badge>
                      : null
                    }
                  </div>
                ))}
              </CardContent>
            </Card>

            {/* Role upgrades ΓÇö only show roles not yet active */}
            {profile.is_admin !== true && (!profile.is_organizer || !profile.is_artist || !(profile as { is_provider?: boolean }).is_provider) && (
              <Card>
                <CardHeader>
                  <CardTitle>Expand your account</CardTitle>
                  <CardDescription>Add a role to unlock more of the platform</CardDescription>
                </CardHeader>
                <CardContent className="space-y-3">
                  {!profile.is_organizer && (
                    <div className="flex items-center justify-between p-3 rounded-lg border border-dashed hover:border-primary transition-colors">
                      <div className="flex items-center gap-3">
                        <Calendar className="h-5 w-5 text-primary" />
                        <div>
                          <p className="font-medium text-sm">Become an Organiser</p>
                          <p className="text-xs text-muted-foreground">Host events, book artists, sell tickets</p>
                        </div>
                      </div>
                      <Button size="sm" disabled={upgrading === 'organizer'} onClick={() => handleUpgrade('organizer')}>
                        {upgrading === 'organizer' ? <Loader2 className="h-4 w-4 animate-spin" /> : 'Enable'}
                      </Button>
                    </div>
                  )}
                  {!profile.is_artist && (
                    <div className="flex items-center justify-between p-3 rounded-lg border border-dashed hover:border-primary transition-colors">
                      <div className="flex items-center gap-3">
                        <Music className="h-5 w-5 text-primary" />
                        <div>
                          <p className="font-medium text-sm">Become an Artist</p>
                          <p className="text-xs text-muted-foreground">Create a profile, get booked, earn money</p>
                        </div>
                      </div>
                      <Button size="sm" variant="secondary" disabled={upgrading === 'artist'} onClick={() => handleUpgrade('artist')}>
                        {upgrading === 'artist' ? <Loader2 className="h-4 w-4 animate-spin" /> : 'Enable'}
                      </Button>
                    </div>
                  )}
                  {!(profile as { is_provider?: boolean }).is_provider && (
                    <div className="flex items-center justify-between p-3 rounded-lg border border-dashed hover:border-orange-500 transition-colors">
                      <div className="flex items-center gap-3">
                        <Wrench className="h-5 w-5 text-orange-600" />
                        <div>
                          <p className="font-medium text-sm">Join Crew</p>
                          <p className="text-xs text-muted-foreground">Work events or offer services to organisers</p>
                        </div>
                      </div>
                      <Button size="sm" variant="outline" className="border-orange-500 text-orange-600" disabled={upgrading === 'provider'} onClick={() => handleUpgrade('provider')}>
                        {upgrading === 'provider' ? <Loader2 className="h-4 w-4 animate-spin" /> : 'Enable'}
                      </Button>
                    </div>
                  )}
                </CardContent>
              </Card>
            )}
          </div>
        </TabsContent>

        {/* ΓöÇΓöÇ VERIFICATION TAB ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
        <TabsContent value="verification">
          <div className="space-y-4">
            {/* Status card */}
            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-base">Verification status</CardTitle>
                <Button variant="ghost" size="sm" onClick={fetchVerificationStatus}>
                  <RefreshCw className="h-4 w-4" />
                </Button>
              </CardHeader>
              <CardContent>
                {loadingVerification ? (
                  <div className="flex items-center gap-2 text-muted-foreground text-sm">
                    <Loader2 className="h-4 w-4 animate-spin" />Checking status...
                  </div>
                ) : isVerified ? (
                  <div className="flex items-center gap-3">
                    <CheckCircle className="h-8 w-8 text-green-500" />
                    <div>
                      <p className="font-semibold text-green-700">Identity verified</p>
                      <p className="text-sm text-muted-foreground">You can withdraw funds from your wallet at any time</p>
                    </div>
                  </div>
                ) : latestRequest ? (
                  <div className="space-y-2">
                    <div className="flex items-center gap-2">
                      <VerificationStatusBadge status={latestRequest.status} />
                      <span className="text-sm text-muted-foreground">
                        Submitted {new Date(latestRequest.submitted_at).toLocaleDateString('en-ZA')}
                      </span>
                    </div>
                    {latestRequest.status === 'pending' && (
                      <p className="text-sm text-muted-foreground">Our team reviews within 1ΓÇô2 business days. We&apos;ll notify you by email.</p>
                    )}
                    {latestRequest.status === 'rejected' && latestRequest.rejection_reason && (
                      <div className="mt-2 p-3 rounded-lg bg-red-50 border border-red-200">
