                </CardHeader>
                <CardContent className="space-y-5">
                  {/* Entity type */}
                  <div className="space-y-2">
                    <Label>I am verifying as</Label>
                    <div className="flex gap-3">
                      {(['individual', 'business'] as const).map((t) => (
                        <button
                          key={t}
