                      <div className="space-y-2">
                        <Label>Registered business name</Label>
                        <Input value={businessName} onChange={(e) => setBusinessName(e.target.value)} placeholder="Acme Events (Pty) Ltd" />
                      </div>
                      <div className="space-y-2">
                        <Label>CIPC registration number</Label>
                        <Input value={regNumber} onChange={(e) => setRegNumber(e.target.value)} placeholder="2024/123456/07" />
                      </div>
                      <DocUpload
                        label="CIPC registration certificate"
                        docKey="reg-cert"
                        value={regCertUrl}
                        uploading={uploadingDoc === 'reg-cert'}
                        onFile={(f) => uploadDocumentFile(f, 'reg-cert', setRegCertUrl)}
                      />
                      <Separator />
                      <p className="text-sm font-medium text-muted-foreground">Representative&apos;s ID (director / member / sole proprietor)</p>
                      <div className="space-y-2">
                        <Label>Representative SA ID number</Label>
                        <Input value={repIdNumber} onChange={(e) => setRepIdNumber(e.target.value)} placeholder="0001010000000" maxLength={13} />
                      </div>
                      <DocUpload
                        label="Representative ΓÇö front of ID"
                        docKey="rep-front"
                        value={repFrontUrl}
                        uploading={uploadingDoc === 'rep-front'}
                        onFile={(f) => uploadDocumentFile(f, 'rep-front', setRepFrontUrl)}
                      />
                      <DocUpload
                        label="Representative ΓÇö back of ID"
                        docKey="rep-back"
                        value={repBackUrl}
                        uploading={uploadingDoc === 'rep-back'}
                        onFile={(f) => uploadDocumentFile(f, 'rep-back', setRepBackUrl)}
                      />
                    </div>
                  )}

                  <Button
                    className="w-full"
                    disabled={submittingVerification || !verificationComplete || !!uploadingDoc}
                    onClick={handleSubmitVerification}
                  >
                    {submittingVerification ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <ShieldCheck className="h-4 w-4 mr-2" />}
                    Submit for review
                  </Button>
                  <p className="text-xs text-center text-muted-foreground">
                    Documents are stored securely. Our team will review within 1ΓÇô2 business days.
                  </p>
                </CardContent>
              </Card>
            )}
          </div>
        </TabsContent>

        {/* ΓöÇΓöÇ SECURITY TAB ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
        <TabsContent value="security">
          <Card>
            <CardHeader>
              <CardTitle>Two-factor authentication (2FA)</CardTitle>
              <CardDescription>
                Add an extra layer of security using an authenticator app (Google Authenticator, Microsoft Authenticator, etc.)
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-5">
              {loadingMfa ? (
                <div className="flex items-center gap-2 text-muted-foreground text-sm">
                  <Loader2 className="h-4 w-4 animate-spin" />Checking 2FA status...
                </div>
              ) : mfaEnabled ? (
                <div className="space-y-4">
                  <div className="flex items-center gap-3 p-3 rounded-lg bg-green-50 border border-green-200">
                    <ShieldCheck className="h-6 w-6 text-green-600" />
                    <div>
                      <p className="font-semibold text-green-700">2FA is enabled</p>
                      <p className="text-sm text-muted-foreground">Your account is protected with an authenticator app</p>
                    </div>
                  </div>
                  <Separator />
                  <p className="text-sm font-medium">Disable 2FA</p>
                  <p className="text-xs text-muted-foreground">This will remove 2FA protection from your account. Not recommended.</p>
                  <Button
                    variant="destructive"
                    onClick={handleUnenrollMfa}
                    disabled={unenrollingMfa}
                    size="sm"
                  >
                    {unenrollingMfa ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : null}
                    Disable 2FA
                  </Button>
                </div>
              ) : mfaQr ? (
                <div className="space-y-4">
                  <p className="text-sm font-medium">Step 1 ΓÇö Scan this QR code with your authenticator app</p>
                  {/* eslint-disable-next-line @next/next/no-img-element */}
                  <img src={mfaQr} alt="2FA QR code" className="w-48 h-48 border rounded-lg" />
                  {mfaSecret && (
                    <p className="text-xs text-muted-foreground break-all">
                      Or enter this key manually: <span className="font-mono font-semibold">{mfaSecret}</span>
                    </p>
                  )}
                  <Separator />
                  <p className="text-sm font-medium">Step 2 ΓÇö Enter the 6-digit code from your app</p>
                  <Input
                    value={mfaCode}
                    onChange={(e) => setMfaCode(e.target.value.replace(/\D/g, '').slice(0, 6))}
                    placeholder="000000"
                    className="font-mono text-center text-lg tracking-widest w-36"
                    maxLength={6}
                  />
                  <div className="flex gap-2">
                    <Button onClick={handleVerifyMfa} disabled={verifyingMfa || mfaCode.length !== 6}>
                      {verifyingMfa ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <ShieldCheck className="h-4 w-4 mr-2" />}
                      Activate 2FA
                    </Button>
                    <Button variant="outline" onClick={() => { setMfaQr(null); setMfaSecret(null); setMfaFactorId(null); setMfaCode('') }}>
                      Cancel
                    </Button>
                  </div>
                </div>
              ) : (
                <div className="space-y-4">
                  <div className="flex items-center gap-3 p-3 rounded-lg bg-muted/40 border">
                    <Smartphone className="h-6 w-6 text-muted-foreground" />
                    <div>
                      <p className="font-medium">2FA is not enabled</p>
                      <p className="text-sm text-muted-foreground">Enable to protect your account with a second factor</p>
                    </div>
                    <Switch checked={false} onCheckedChange={() => handleEnrollMfa()} className="ml-auto" />
                  </div>
                  <Button onClick={handleEnrollMfa} disabled={enrollingMfa} variant="outline">
                    {enrollingMfa ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <ShieldCheck className="h-4 w-4 mr-2" />}
                    Set up 2FA
                  </Button>
                </div>
              )}
            </CardContent>
          </Card>
        </TabsContent>

        {/* ΓöÇΓöÇ NOTIFICATIONS TAB ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
        <TabsContent value="notifications">
          <Card>
            <CardHeader>
              <CardTitle>Notification preferences</CardTitle>
              <CardDescription>Control what emails and in-app alerts you receive</CardDescription>
            </CardHeader>
            <CardContent>
              <Link href="/dashboard/settings/notifications">
                <Button variant="outline" className="w-full">
                  Manage notification preferences
                  <ArrowRight className="ml-2 h-4 w-4" />
                </Button>
              </Link>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>
    </div>
  )
}

// ΓöÇΓöÇ Document upload sub-component ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function DocUpload({
  label,
  docKey,
  value,
  uploading,
  onFile,
}: {
  label: string
  docKey: string
  value: string
  uploading: boolean
  onFile: (f: File) => void
}) {
  const inputRef = useRef<HTMLInputElement>(null)
  return (
    <div className="space-y-1.5">
      <Label>{label}</Label>
      <div
        className={`flex items-center gap-3 rounded-lg border-2 border-dashed p-3 cursor-pointer transition-colors ${value ? 'border-green-400 bg-green-50/40' : 'hover:border-muted-foreground'}`}
        onClick={() => inputRef.current?.click()}
      >
        <input
          ref={inputRef}
          type="file"
          accept="image/*,application/pdf"
          className="hidden"
          onChange={(e) => { const f = e.target.files?.[0]; if (f) onFile(f) }}
        />
        {uploading ? (
          <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
        ) : value ? (
          <CheckCircle className="h-5 w-5 text-green-600" />
        ) : (
          <Upload className="h-5 w-5 text-muted-foreground" />
        )}
        <p className="text-sm text-muted-foreground">
          {uploading ? 'Uploading...' : value ? 'Uploaded Γ£ô (click to replace)' : 'Click to upload (JPG, PNG or PDF, max 10MB)'}
        </p>
      </div>
    </div>
  )
}

'use client'

/**
 * Ticket with QR Code - Client Component
 * Shows QR code in a dialog for scanning
 */

import { useMemo, useState } from 'react'
import { useRouter } from 'next/navigation'
import { QRCodeSVG } from 'qrcode.react'
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { QrCode, Download, Share2, CheckCircle, Loader2 } from 'lucide-react'
import { toast } from 'sonner'

interface TicketWithQRProps {
  ticketCode: string
  eventId: string
  ticketId: string
  eventDate: string
  isCheckedIn?: boolean
}

export function TicketWithQR({ ticketCode, eventId, ticketId, eventDate, isCheckedIn = false }: TicketWithQRProps) {
  const router = useRouter()
  const [open, setOpen] = useState(false)
  const [checkingIn, setCheckingIn] = useState(false)
  const [checkedIn, setCheckedIn] = useState(isCheckedIn)

  const canSelfCheckIn = useMemo(() => {
    const today = new Date()
    today.setHours(0, 0, 0, 0)

    const target = new Date(eventDate)
    target.setHours(0, 0, 0, 0)

    return target.getTime() === today.getTime()
  }, [eventDate])

  // QR code data for scanning
  const qrData = JSON.stringify({
    code: ticketCode,
    event: eventId,
    ticket: ticketId,
  })

  // Share ticket
  const handleShare = async () => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: 'My Ziyawa Ticket',
          text: `Ticket Code: ${ticketCode}`,
          url: window.location.href,
        })
      } catch (err) {
        // User cancelled or share failed
      }
    } else {
      // Fallback: copy to clipboard
      await navigator.clipboard.writeText(ticketCode)
      toast.success('Ticket code copied!')
    }
  }

  const handleSelfCheckIn = async () => {
    try {
      setCheckingIn(true)
      const response = await fetch('/api/tickets/checkin', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          ticketCode,
          ticketId,
          eventId,
          selfCheckIn: true,
        }),
      })

      const data = await response.json()
      if (!response.ok) {
        throw new Error(data.message || data.error || 'Unable to check you in')
      }

      setCheckedIn(true)
      toast.success(data.message || 'You are checked in')
      router.refresh()
    } catch (error) {
      toast.error(error instanceof Error ? error.message : 'Check-in failed')
    } finally {
      setCheckingIn(false)
    }
  }

  // Download QR code as image
  const handleDownload = () => {
    const svg = document.getElementById(`qr-${ticketId}`)
    if (!svg) return

    const svgData = new XMLSerializer().serializeToString(svg)
    const canvas = document.createElement('canvas')
    const ctx = canvas.getContext('2d')
    const img = new Image()

    img.onload = () => {
      canvas.width = img.width
      canvas.height = img.height
      ctx?.drawImage(img, 0, 0)
      
      const link = document.createElement('a')
      link.download = `ziyawa-ticket-${ticketCode}.png`
      link.href = canvas.toDataURL('image/png')
      link.click()
    }

    img.src = 'data:image/svg+xml;base64,' + btoa(svgData)
  }

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <div className="flex flex-wrap items-center gap-2">
        {checkedIn ? (
          <Button size="sm" className="bg-green-500 hover:bg-green-500" disabled>
            <CheckCircle className="h-4 w-4 mr-2" />
            Checked In
          </Button>
        ) : canSelfCheckIn ? (
          <Button size="sm" onClick={handleSelfCheckIn} disabled={checkingIn}>
            {checkingIn ? <Loader2 className="h-4 w-4 mr-2 animate-spin" /> : <CheckCircle className="h-4 w-4 mr-2" />}
            I'm Here
          </Button>
        ) : null}

        <DialogTrigger asChild>
          <Button variant="outline" size="sm">
            <QrCode className="h-4 w-4 mr-2" />
            Show QR
          </Button>
        </DialogTrigger>
      </div>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle>Your Ticket QR Code</DialogTitle>
        </DialogHeader>
        
        <div className="flex flex-col items-center py-6">
          {/* QR Code */}
          <div className="bg-white p-4 rounded-xl border-2 border-purple-200 shadow-lg">
            <QRCodeSVG 
              id={`qr-${ticketId}`}
              value={qrData}
              size={200}
              level="H"
              includeMargin
              imageSettings={{
                src: '/logo-small.png',
                height: 30,
                width: 30,
                excavate: true,
              }}
            />
          </div>

          {/* Ticket Code */}
          <div className="mt-4 text-center">
            <p className="text-sm text-muted-foreground">Ticket Code</p>
            <p className="font-mono font-bold text-2xl tracking-wider">{ticketCode}</p>
          </div>

          {/* Instructions */}
          <p className="text-sm text-muted-foreground text-center mt-4">
            Show this QR code at the event entrance for quick check-in
          </p>

          {!checkedIn && canSelfCheckIn && (
            <Button className="mt-4" onClick={handleSelfCheckIn} disabled={checkingIn}>
              {checkingIn ? <Loader2 className="h-4 w-4 mr-2 animate-spin" /> : <CheckCircle className="h-4 w-4 mr-2" />}
              Check in now
            </Button>
          )}

          {!checkedIn && !canSelfCheckIn && (
            <p className="mt-4 text-xs text-muted-foreground text-center">
              Self check-in opens on the event day.
            </p>
          )}

          {/* Actions */}
          <div className="flex gap-3 mt-6">
            <Button variant="outline" onClick={handleDownload}>
              <Download className="h-4 w-4 mr-2" />
              Save
            </Button>
            <Button variant="outline" onClick={handleShare}>
              <Share2 className="h-4 w-4 mr-2" />
              Share
            </Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  )
}

'use client';

import { useState } from 'react';
import Image from 'next/image';
import Link from 'next/link';
import { 
  Calendar, 
  MapPin, 
  Star, 
  CheckCircle, 
  Users,
  Ticket,
  Clock,
  Shield
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { SocialLinksRow } from '@/components/shared';
import { TrustBadge, TrackRecordCard } from '@/components/shared/trust-badges';
import { ReviewsList } from '@/components/shared/reviews';
import { OrganizerSocialLink, OrganizerMedia, Review } from '@/types/database';
import { formatDate } from '@/lib/helpers';

interface OrganizerProfileProps {
  profile: {
    id: string;
    full_name: string | null;
    avatar_url: string | null;
    location: string | null;
    company_name: string | null;
    bio: string | null;
    total_events_hosted: number;
    total_artists_paid: number;
    payment_completion_rate: number;
    organizer_rating: number;
    total_organizer_reviews: number;
    years_organizing: number;
    verified_at: string | null;
    is_verified?: boolean;
    verified_entity_type?: string | null;
    created_at: string;
  };
  socialLinks: OrganizerSocialLink[];
  media: OrganizerMedia[];
  pastEvents: Array<{
    id: string;
    title: string;
    event_date: string;
    venue: string | null;
    location: string;
    cover_image: string | null;
    tickets_sold: number;
    ticket_price: number;
  }>;
  upcomingEvents: Array<{
    id: string;
    title: string;
    event_date: string;
    venue: string | null;
    location: string;
    cover_image: string | null;
    ticket_price: number;
  }>;
  reviews: Array<Review & { reviewer: { id: string; full_name: string | null; avatar_url: string | null } }>;
}

export function OrganizerProfile({
  profile,
  socialLinks,
  media,
  pastEvents,
  upcomingEvents,
  reviews
}: OrganizerProfileProps) {
  const [activeTab, setActiveTab] = useState('events');

  const displayName = profile.company_name || profile.full_name || 'Organizer';
  const coverImage = pastEvents[0]?.cover_image || media.find(m => m.is_featured)?.url;
  const logoImage = media.find(m => m.is_logo)?.url || profile.avatar_url;

  // Calculate total attendees
  const totalAttendees = pastEvents.reduce((sum, e) => sum + e.tickets_sold, 0);

  // Transform social links for the shared component
  const transformedSocialLinks = socialLinks.map(link => ({
    platform: link.platform,
    url: link.url,
    username: link.username
  }));

  return (
    <div className="min-h-screen bg-neutral-50">
      {/* Hero Section */}
      <div className="relative h-64 md:h-80 bg-neutral-200">
        {coverImage && (
          <Image
            src={coverImage}
            alt={displayName}
            fill
            className="object-cover"
          />
        )}
        <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/40 to-transparent" />
        
        {/* Profile Info Overlay */}
        <div className="absolute bottom-0 left-0 right-0 p-6">
          <div className="max-w-6xl mx-auto flex items-end gap-4">
            {/* Logo/Avatar */}
            <div className="w-24 h-24 md:w-32 md:h-32 rounded-xl overflow-hidden bg-white shadow-lg border-4 border-white">
              {logoImage ? (
                <Image
                  src={logoImage}
                  alt={displayName}
                  width={128}
                  height={128}
                  className="object-cover w-full h-full"
                />
              ) : (
                <div className="w-full h-full bg-neutral-200 flex items-center justify-center">
                  <Users className="h-12 w-12 text-neutral-400" />
                </div>
              )}
            </div>
            
            {/* Name and badges */}
            <div className="flex-1 text-white pb-2">
              <div className="flex items-center gap-2 flex-wrap">
                <h1 className="text-2xl md:text-3xl font-bold">{displayName}</h1>
                {profile.verified_at && (
                  <TrustBadge 
                    type="organizer" 
                    isVerified={true}
                    totalBookings={profile.total_events_hosted}
                    rating={profile.organizer_rating}
                  />
                )}
                {profile.is_verified && (
                  <span className="inline-flex items-center gap-1 text-xs font-semibold bg-amber-500 text-white px-2 py-0.5 rounded-full">
                    <CheckCircle className="h-3 w-3" />
                    {profile.verified_entity_type === 'business' ? 'Verified Business' : 'Verified'}
                  </span>
                )}
              </div>
              {profile.location && (
                <p className="text-white/80 flex items-center gap-1 mt-1">
                  <MapPin className="h-4 w-4" />
                  {profile.location}
                </p>
              )}
              {socialLinks.length > 0 && (
                <div className="mt-2">
                  <SocialLinksRow links={transformedSocialLinks} size="sm" />
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Trust Stats Bar */}
      <div className="bg-white border-b border-neutral-200">
        <div className="max-w-6xl mx-auto px-4 py-4">
          <div className="grid grid-cols-2 md:grid-cols-5 gap-4 text-center">
            <div>
              <p className="text-2xl font-bold text-neutral-900">{profile.total_events_hosted}</p>
              <p className="text-sm text-neutral-500">Events Hosted</p>
            </div>
            <div>
              <p className="text-2xl font-bold text-neutral-900">{totalAttendees.toLocaleString()}</p>
              <p className="text-sm text-neutral-500">Total Attendees</p>
            </div>
            <div>
              <p className="text-2xl font-bold text-neutral-900">{profile.total_artists_paid}</p>
              <p className="text-sm text-neutral-500">Artists Paid</p>
            </div>
            <div>
              <p className="text-2xl font-bold text-green-600">{profile.payment_completion_rate}%</p>
              <p className="text-sm text-neutral-500">Payment Rate</p>
            </div>
            <div>
              <div className="flex items-center justify-center gap-1">
                <Star className="h-5 w-5 fill-yellow-400 text-yellow-400" />
                <span className="text-2xl font-bold text-neutral-900">
                  {profile.organizer_rating > 0 ? profile.organizer_rating.toFixed(1) : 'New'}
                </span>
              </div>
              <p className="text-sm text-neutral-500">{profile.total_organizer_reviews} Reviews</p>
            </div>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="max-w-6xl mx-auto px-4 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Left Column - Main Content */}
          <div className="lg:col-span-2 space-y-6">
            {/* Bio */}
            {profile.bio && (
              <div className="bg-white rounded-xl p-6 border border-neutral-200">
                <h2 className="font-semibold text-neutral-900 mb-3">About</h2>
                <p className="text-neutral-600 whitespace-pre-wrap">{profile.bio}</p>
              </div>
            )}

            {/* Tabs */}
            <Tabs value={activeTab} onValueChange={setActiveTab}>
              <TabsList className="bg-white border border-neutral-200 p-1">
                <TabsTrigger value="events">
                  Upcoming Events ({upcomingEvents.length})
                </TabsTrigger>
                <TabsTrigger value="past">
                  Past Events ({pastEvents.length})
                </TabsTrigger>
                <TabsTrigger value="reviews">
                  Reviews ({reviews.length})
                </TabsTrigger>
              </TabsList>

              <TabsContent value="events" className="mt-4">
                {upcomingEvents.length > 0 ? (
                  <div className="grid gap-4">
                    {upcomingEvents.map((event) => (
                      <Link key={event.id} href={`/events/${event.id}`}>
                        <div className="bg-white rounded-xl border border-neutral-200 overflow-hidden hover:shadow-lg transition-shadow flex">
                          <div className="w-32 h-32 relative bg-neutral-100 flex-shrink-0">
                            {event.cover_image ? (
                              <Image
                                src={event.cover_image}
                                alt={event.title}
                                fill
                                className="object-cover"
                              />
                            ) : (
                              <div className="w-full h-full flex items-center justify-center">
                                <Calendar className="h-8 w-8 text-neutral-300" />
                              </div>
                            )}
                          </div>
                          <div className="p-4 flex-1">
                            <h3 className="font-semibold text-neutral-900">{event.title}</h3>
                            <div className="flex items-center gap-1 text-sm text-neutral-500 mt-1">
                              <Calendar className="h-4 w-4" />
                              {formatDate(event.event_date)}
                            </div>
                            <div className="flex items-center gap-1 text-sm text-neutral-500">
                              <MapPin className="h-4 w-4" />
                              {event.venue || event.location}
                            </div>
                            <p className="text-sm font-medium text-neutral-900 mt-2">
                              From R{event.ticket_price}
                            </p>
                          </div>
                        </div>
                      </Link>
                    ))}
                  </div>
                ) : (
                  <div className="text-center py-12 bg-white rounded-xl border border-neutral-200">
                    <Calendar className="h-12 w-12 text-neutral-300 mx-auto mb-3" />
                    <p className="text-neutral-500">No upcoming events</p>
                  </div>
                )}
              </TabsContent>

              <TabsContent value="past" className="mt-4">
                {pastEvents.length > 0 ? (
                  <div className="grid gap-4">
                    {pastEvents.map((event) => (
                      <div key={event.id} className="bg-white rounded-xl border border-neutral-200 overflow-hidden flex">
                        <div className="w-32 h-32 relative bg-neutral-100 flex-shrink-0">
                          {event.cover_image ? (
                            <Image
                              src={event.cover_image}
                              alt={event.title}
                              fill
                              className="object-cover"
                            />
                          ) : (
                            <div className="w-full h-full flex items-center justify-center">
                              <Calendar className="h-8 w-8 text-neutral-300" />
                            </div>
                          )}
                        </div>
                        <div className="p-4 flex-1">
                          <h3 className="font-semibold text-neutral-900">{event.title}</h3>
                          <div className="flex items-center gap-1 text-sm text-neutral-500 mt-1">
                            <Calendar className="h-4 w-4" />
                            {formatDate(event.event_date)}
                          </div>
                          <div className="flex items-center gap-1 text-sm text-neutral-500">
                            <MapPin className="h-4 w-4" />
                            {event.venue || event.location}
                          </div>
                          <div className="flex items-center gap-1 text-sm text-green-600 mt-2">
                            <Ticket className="h-4 w-4" />
                            {event.tickets_sold.toLocaleString()} tickets sold
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="text-center py-12 bg-white rounded-xl border border-neutral-200">
                    <Clock className="h-12 w-12 text-neutral-300 mx-auto mb-3" />
                    <p className="text-neutral-500">No past events yet</p>
                  </div>
                )}
              </TabsContent>

              <TabsContent value="reviews" className="mt-4">
                {reviews.length > 0 ? (
                  <ReviewsList 
                    reviews={reviews} 
                    averageRating={profile.organizer_rating}
                    totalReviews={profile.total_organizer_reviews}
                  />
                ) : (
                  <div className="text-center py-12 bg-white rounded-xl border border-neutral-200">
                    <Star className="h-12 w-12 text-neutral-300 mx-auto mb-3" />
                    <p className="text-neutral-500">No reviews yet</p>
                  </div>
                )}
              </TabsContent>
            </Tabs>
          </div>

          {/* Right Column - Sidebar */}
          <div className="space-y-6">
            {/* Trust Card */}
            <TrackRecordCard
              type="organizer"
              totalBookings={profile.total_events_hosted}
              completedBookings={profile.total_events_hosted}
              cancelledBookings={0}
              totalPaid={0}
              rating={profile.organizer_rating}
              totalReviews={profile.total_organizer_reviews}
              memberSince={profile.created_at}
              isVerified={!!profile.verified_at}
            />

            {/* Quick Stats */}
            <div className="bg-white rounded-xl p-6 border border-neutral-200">
              <h3 className="font-semibold text-neutral-900 mb-4">Quick Facts</h3>
              <ul className="space-y-3 text-sm">
                <li className="flex items-center gap-2 text-neutral-600">
                  <Clock className="h-4 w-4 text-neutral-400" />
                  Organizing for {profile.years_organizing || 1}+ year{(profile.years_organizing || 1) > 1 ? 's' : ''}
                </li>
                <li className="flex items-center gap-2 text-neutral-600">
                  <Shield className="h-4 w-4 text-neutral-400" />
                  {profile.payment_completion_rate}% payment completion
                </li>
                <li className="flex items-center gap-2 text-neutral-600">
                  <Users className="h-4 w-4 text-neutral-400" />
                  {totalAttendees.toLocaleString()} total attendees
                </li>
                {profile.verified_at && (
                  <li className="flex items-center gap-2 text-green-600">
                    <CheckCircle className="h-4 w-4" />
                    Verified organizer
                  </li>
                )}
              </ul>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

'use client'

/**
 * USER SUPPORT TICKET DETAIL PAGE
 * /support/[id]
 * 
 * View ticket details and reply thread
 */

import { useState, useEffect } from 'react'
import { useParams, useRouter } from 'next/navigation'
import Link from 'next/link'
import { useAuth } from '@/components/providers/auth-provider'
import { createClient } from '@/lib/supabase/client'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Textarea } from '@/components/ui/textarea'
import { Badge } from '@/components/ui/badge'
import { Separator } from '@/components/ui/separator'
import {
  ArrowLeft,
  Clock,
  CheckCircle,
  AlertCircle,
  Loader2,
  Send,
  MessageSquare,
  User,
  Shield,
} from 'lucide-react'
import { toast } from 'sonner'
import { format } from 'date-fns'

interface TicketReply {
  id: string
  ticket_id: string
  user_id: string
  message: string
  is_staff: boolean
  created_at: string
  user?: {
    full_name: string
    avatar_url: string
  }
}

interface SupportTicket {
  id: string
  ticket_number: string
  user_id: string
  subject: string
  category: string
  priority: string
  status: string
  message: string
  created_at: string
  updated_at: string
  resolved_at: string | null
}

const STATUS_CONFIG: Record<string, { label: string; color: string; icon: any }> = {
  open: { label: 'Open', color: 'bg-green-100 text-green-700', icon: AlertCircle },
  in_progress: { label: 'In Progress', color: 'bg-blue-100 text-blue-700', icon: Clock },
  waiting: { label: 'Awaiting Your Reply', color: 'bg-yellow-100 text-yellow-700', icon: Clock },
  resolved: { label: 'Resolved', color: 'bg-neutral-100 text-neutral-700', icon: CheckCircle },
  closed: { label: 'Closed', color: 'bg-neutral-100 text-neutral-700', icon: CheckCircle },
}

const PRIORITY_COLORS: Record<string, string> = {
  low: 'bg-neutral-100 text-neutral-700',
  medium: 'bg-blue-100 text-blue-700',
  high: 'bg-orange-100 text-orange-700',
  urgent: 'bg-red-100 text-red-700',
}

const CATEGORY_LABELS: Record<string, string> = {
  general: 'General Inquiry',
  payment: 'Payment Issue',
  event: 'Event Related',
  technical: 'Technical Problem',
  report: 'Report Issue',
  refund: 'Refund Request',
  account: 'Account Help',
  other: 'Other',
}

export default function UserTicketDetailPage() {
  const params = useParams()
  const router = useRouter()
  const { user, loading: authLoading } = useAuth()
  const ticketId = params.id as string
  const supabase = createClient()

  const [ticket, setTicket] = useState<SupportTicket | null>(null)
  const [replies, setReplies] = useState<TicketReply[]>([])
  const [loading, setLoading] = useState(true)
  const [replyText, setReplyText] = useState('')
  const [submitting, setSubmitting] = useState(false)

  // Redirect if not logged in
  useEffect(() => {
    if (!authLoading && !user) {
      router.push('/auth/signin?redirect=/support')
    }
  }, [user, authLoading, router])

  // Fetch ticket and replies
  useEffect(() => {
    if (user && ticketId) {
      fetchTicket()
    }
  }, [user, ticketId])

  const fetchTicket = async () => {
    setLoading(true)

    // Fetch ticket
    const { data: ticketData, error: ticketError } = await supabase
      .from('support_tickets')
      .select('*')
      .eq('id', ticketId)
      .eq('user_id', user?.id) // Ensure user owns this ticket
      .single()

    if (ticketError || !ticketData) {
      toast.error('Ticket not found')
      router.push('/support')
      return
    }

    setTicket(ticketData)

    // Fetch replies
    const { data: repliesData } = await supabase
      .from('ticket_replies')
      .select(`
        *,
        user:profiles(full_name, avatar_url)
      `)
      .eq('ticket_id', ticketId)
      .order('created_at', { ascending: true })

    setReplies(repliesData || [])
    setLoading(false)
  }

  // Submit reply
  const handleSubmitReply = async (e: React.FormEvent) => {
    e.preventDefault()
    
    if (!replyText.trim()) {
      toast.error('Please enter a message')
      return
    }

    setSubmitting(true)

    try {
      // Insert reply
      const { error: replyError } = await supabase
        .from('ticket_replies')
        .insert({
          ticket_id: ticketId,
          user_id: user?.id,
          message: replyText.trim(),
          is_staff: false,
        })

      if (replyError) throw replyError

      // Update ticket status to in_progress if it was waiting
      if (ticket?.status === 'waiting') {
        await supabase
          .from('support_tickets')
          .update({ status: 'in_progress', updated_at: new Date().toISOString() })
          .eq('id', ticketId)
      }

      toast.success('Reply sent!')
      setReplyText('')
      fetchTicket()
    } catch (error) {
      console.error('Error sending reply:', error)
      toast.error('Failed to send reply')
    } finally {
      setSubmitting(false)
    }
  }

  if (authLoading || loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
      </div>
    )
  }

  if (!ticket) {
    return null
  }

  const statusConfig = STATUS_CONFIG[ticket.status] || STATUS_CONFIG.open
  const StatusIcon = statusConfig.icon
  const isOpen = !['resolved', 'closed'].includes(ticket.status)

  return (
    <div className="min-h-screen bg-neutral-50">
      <div className="container max-w-4xl mx-auto py-8 px-4">
        {/* Header */}
        <div className="mb-6">
          <Link href="/support">
            <Button variant="ghost" size="sm" className="mb-4">
              <ArrowLeft className="h-4 w-4 mr-2" />
              Back to Support
            </Button>
          </Link>
          
          <div className="flex items-start justify-between">
            <div>
              <div className="flex items-center gap-3 mb-2">
                <h1 className="text-2xl font-bold">{ticket.subject}</h1>
                <Badge variant="outline">#{ticket.ticket_number}</Badge>
              </div>
              <div className="flex items-center gap-3 text-sm text-muted-foreground">
                <span>{CATEGORY_LABELS[ticket.category] || ticket.category}</span>
                <span>ΓÇó</span>
                <span>Created {format(new Date(ticket.created_at), 'MMM d, yyyy \'at\' h:mm a')}</span>
              </div>
            </div>
            <div className="flex items-center gap-2">
              <Badge className={PRIORITY_COLORS[ticket.priority]}>
                {ticket.priority.charAt(0).toUpperCase() + ticket.priority.slice(1)}
              </Badge>
              <Badge className={statusConfig.color}>
                <StatusIcon className="h-3 w-3 mr-1" />
                {statusConfig.label}
              </Badge>
            </div>
          </div>
        </div>

        {/* Conversation */}
        <Card className="mb-6">
          <CardHeader>
            <CardTitle className="text-lg">Conversation</CardTitle>
          </CardHeader>
          <CardContent className="space-y-6">
            {/* Original message */}
            <div className="flex gap-4">
              <div className="w-10 h-10 rounded-full bg-neutral-100 flex items-center justify-center flex-shrink-0">
                <User className="h-5 w-5 text-primary" />
              </div>
              <div className="flex-1">
                <div className="flex items-center gap-2 mb-1">
                  <span className="font-medium">You</span>
                  <span className="text-xs text-muted-foreground">
                    {format(new Date(ticket.created_at), 'MMM d, yyyy \'at\' h:mm a')}
                  </span>
                </div>
                <div className="p-4 rounded-lg bg-neutral-50 text-sm whitespace-pre-wrap">
                  {ticket.message}
                </div>
              </div>
            </div>

            {/* Replies */}
            {replies.map((reply) => (
              <div key={reply.id} className="flex gap-4">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center flex-shrink-0 ${
                  reply.is_staff ? 'bg-blue-100' : 'bg-neutral-100'
                }`}>
                  {reply.is_staff ? (
                    <Shield className="h-5 w-5 text-blue-600" />
                  ) : (
                    <User className="h-5 w-5 text-primary" />
                  )}
                </div>
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-1">
                    <span className="font-medium">
                      {reply.is_staff ? 'Ziyawa Support' : reply.user?.full_name || 'You'}
                    </span>
                    {reply.is_staff && (
                      <Badge variant="outline" className="text-xs">Staff</Badge>
                    )}
                    <span className="text-xs text-muted-foreground">
                      {format(new Date(reply.created_at), 'MMM d, yyyy \'at\' h:mm a')}
                    </span>
                  </div>
                  <div className={`p-4 rounded-lg text-sm whitespace-pre-wrap ${
                    reply.is_staff ? 'bg-blue-50' : 'bg-neutral-50'
                  }`}>
                    {reply.message}
                  </div>
                </div>
              </div>
            ))}

            {/* Resolved message */}
            {!isOpen && (
              <div className="flex items-center gap-2 p-4 rounded-lg bg-green-50 text-green-700">
                <CheckCircle className="h-5 w-5" />
                <span>This ticket has been {ticket.status}.</span>
              </div>
            )}
          </CardContent>
        </Card>

        {/* Reply Form */}
        {isOpen && (
          <Card>
            <CardHeader>
              <CardTitle className="text-lg">Reply</CardTitle>
            </CardHeader>
            <CardContent>
              <form onSubmit={handleSubmitReply} className="space-y-4">
                <Textarea
                  value={replyText}
                  onChange={(e) => setReplyText(e.target.value)}
                  placeholder="Type your reply..."
                  rows={4}
                />
                <div className="flex justify-end">
                  <Button type="submit" disabled={submitting || !replyText.trim()}>
                    {submitting ? (
                      <>
                        <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                        Sending...
                      </>
                    ) : (
                      <>
                        <Send className="h-4 w-4 mr-2" />
                        Send Reply
                      </>
                    )}
                  </Button>
                </div>
              </form>
            </CardContent>
          </Card>
        )}
      </div>
    </div>
  )
}

'use client';

import { useState } from 'react';
import Link from 'next/link';
import Image from 'next/image';
import { useRouter } from 'next/navigation';
import { 
  MapPin, 
  Music, 
  ArrowLeft, 
  Calendar, 
  DollarSign, 
  Star,
  Clock,
  CheckCircle,
  ExternalLink,
  ChevronDown,
  Play,
  Loader2
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { formatCurrency } from '@/lib/helpers';
import { PROVINCES } from '@/lib/constants';
import { useAuth } from '@/components/providers/auth-provider';
import { toast } from 'sonner';
import { 
  SocialLinksRow, 
  MediaGallery, 
  VideoCarousel,
  TrustBadge, 
  TrustStats, 
  TrackRecordCard,
  ReviewsList,
  PortfolioGrid
} from '@/components/shared';
import type { 
  Artist, 
  Profile, 
  ArtistSocialLink, 
  ArtistMedia, 
  ArtistPortfolio,
  ArtistDiscography,
  Review,
  Booking,
  Event
} from '@/types/database';

interface ArtistWithProfile extends Artist {
  profiles: Pick<Profile, 'id' | 'full_name' | 'email' | 'avatar_url'> & {
    is_verified?: boolean
    verified_entity_type?: string | null
  };
}

interface BookingWithEvent extends Booking {
  events: Pick<Event, 'id' | 'title' | 'venue' | 'event_date' | 'cover_image'>;
}

interface ReviewWithReviewer extends Review {
  reviewer: {
    full_name: string | null;
    avatar_url: string | null;
  };
}

interface ArtistProfileEnhancedProps {
  artist: ArtistWithProfile;
  socialLinks: ArtistSocialLink[];
  media: ArtistMedia[];
  portfolio: ArtistPortfolio[];
  discography: ArtistDiscography[];
  reviews: ReviewWithReviewer[];
  upcomingBookings: BookingWithEvent[];
}

export function ArtistProfileEnhanced({ 
  artist, 
  socialLinks, 
  media, 
  portfolio,
  discography,
  reviews,
  upcomingBookings
}: ArtistProfileEnhancedProps) {
  const { profile } = useAuth();
  const router = useRouter();
  const isOrganizer = profile?.is_organizer || profile?.is_admin;
  const [showFullBio, setShowFullBio] = useState(false);

  // Separate media by type
  const images = media.filter(m => m.media_type === 'image');
  const videos = media.filter(m => 
    ['youtube_video', 'tiktok_video', 'instagram_reel', 'facebook_video', 'video_url'].includes(m.media_type)
  );
  const featuredMedia = media.filter(m => m.is_featured);
  const coverImage = media.find(m => m.is_cover_image);
  const profileImage = media.find(m => m.is_profile_image);

  // Calculate trust metrics
  const completionRate = artist.total_bookings > 0 
    ? Math.round((artist.completed_bookings / artist.total_bookings) * 100) 
    : 0;
  const showUpRate = artist.total_bookings > 0 && artist.no_show_count !== undefined
    ? Math.round(((artist.total_bookings - artist.no_show_count) / artist.total_bookings) * 100)
    : 100;
  const isTrusted = artist.total_bookings >= 10 && completionRate >= 95 && artist.average_rating >= 4.5;

  // Bio display
  const bioText = artist.bio_long || artist.bio;
  const shouldTruncateBio = bioText && bioText.length > 400;

  return (
    <div className="min-h-screen bg-white">
      {/* Hero Section */}
      <div className="relative">
        {/* Cover Image */}
        <div className="h-64 md:h-80 bg-neutral-900 relative overflow-hidden">
          {coverImage ? (
            <Image
              src={coverImage.url}
              alt={artist.stage_name}
              fill
              className="object-cover opacity-60"
            />
          ) : artist.profile_image ? (
            <Image
              src={artist.profile_image}
              alt={artist.stage_name}
              fill
              className="object-cover opacity-40 blur-sm"
            />
          ) : (
            <div className="absolute inset-0 bg-gradient-to-br from-neutral-800 to-neutral-900" />
          )}
          {/* Gradient overlay */}
          <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent" />
        </div>

        {/* Profile Card Overlay */}
        <div className="max-w-6xl mx-auto px-4 relative">
          <div className="absolute -bottom-32 left-4 right-4 md:left-0 md:right-auto">
            <div className="flex flex-col md:flex-row items-center md:items-end gap-4 md:gap-6">
              {/* Profile Image */}
              <div className="w-40 h-40 md:w-48 md:h-48 rounded-2xl border-4 border-white shadow-xl overflow-hidden bg-neutral-200">
                {(profileImage?.url || artist.profile_image) ? (
                  <Image
                    src={profileImage?.url || artist.profile_image!}
                    alt={artist.stage_name}
                    width={192}
                    height={192}
                    className="w-full h-full object-cover"
                  />
                ) : (
                  <div className="w-full h-full flex items-center justify-center text-6xl font-bold text-neutral-400">
                    {artist.stage_name.charAt(0)}
                  </div>
                )}
              </div>

              {/* Name and badges */}
              <div className="text-center md:text-left pb-4">
                <div className="flex flex-wrap items-center justify-center md:justify-start gap-2 mb-2">
                  <h1 className="text-3xl md:text-4xl font-bold text-white drop-shadow-lg">
                    {artist.stage_name}
                  </h1>
                  {artist.verified_at && (
                    <TrustBadge 
                      type="artist" 
                      isVerified={true} 
                      isTrusted={isTrusted}
                      size="md"
                    />
                  )}
                  {artist.profiles.is_verified && (
                    <Badge className="bg-amber-500 text-white">
                      <CheckCircle className="h-3 w-3 mr-1" />
                      {artist.profiles.verified_entity_type === 'business' ? 'Verified Business' : 'Verified'}
                    </Badge>
                  )}
                </div>
                <p className="text-white/80">{artist.profiles.full_name}</p>
              </div>
            </div>
          </div>

          {/* Back button */}
          <Link 
            href="/artists" 
            className="absolute top-4 left-4 md:top-[-220px] inline-flex items-center text-white/80 hover:text-white transition-colors"
          >
            <ArrowLeft className="h-4 w-4 mr-2" />
            Back to Artists
          </Link>
        </div>
      </div>

      {/* Main Content */}
      <div className="max-w-6xl mx-auto px-4 pt-36 pb-12">
        <div className="grid lg:grid-cols-3 gap-8">
          {/* Left Column - Main Content */}
          <div className="lg:col-span-2 space-y-8">
            {/* Quick Info Row */}
            <div className="flex flex-wrap items-center gap-3">
              <Badge variant="secondary" className="gap-1 px-3 py-1">
                <Music className="h-3 w-3" />
                {artist.genre}
              </Badge>
              <Badge variant="outline" className="gap-1 px-3 py-1 border-neutral-300">
                <MapPin className="h-3 w-3" />
                {PROVINCES[artist.location as keyof typeof PROVINCES]}
              </Badge>
              {artist.years_active && (
                <Badge variant="outline" className="gap-1 px-3 py-1 border-neutral-300">
                  <Clock className="h-3 w-3" />
                  {artist.years_active}+ years
                </Badge>
              )}
              <Badge 
                className={artist.is_available ? 'bg-green-100 text-green-700' : 'bg-neutral-100 text-neutral-500'}
              >
                {artist.is_available ? 'ΓùÅ Available' : 'Γùï Unavailable'}
              </Badge>
            </div>

            {/* Social Links */}
            {socialLinks.length > 0 && (
              <SocialLinksRow links={socialLinks} size="md" />
            )}

            {/* Trust Stats */}
            <TrustStats
              completedBookings={artist.completed_bookings}
              totalBookings={artist.total_bookings}
              rating={artist.average_rating}
              totalReviews={artist.total_reviews}
              responseRate={artist.response_rate}
              showUpRate={showUpRate}
              type="artist"
              className="p-6 bg-neutral-50 rounded-xl"
            />

            {/* Bio */}
            <div>
              <h2 className="text-xl font-semibold text-neutral-900 mb-4">About</h2>
              {bioText ? (
                <div>
                  <p className="text-neutral-600 whitespace-pre-wrap leading-relaxed">
                    {shouldTruncateBio && !showFullBio 
                      ? `${bioText.substring(0, 400)}...` 
                      : bioText}
                  </p>
                  {shouldTruncateBio && (
                    <button
                      onClick={() => setShowFullBio(!showFullBio)}
                      className="mt-2 text-neutral-900 font-medium hover:underline inline-flex items-center gap-1"
                    >
                      {showFullBio ? 'Show less' : 'Read more'}
                      <ChevronDown className={`h-4 w-4 transition-transform ${showFullBio ? 'rotate-180' : ''}`} />
                    </button>
                  )}
                </div>
              ) : (
                <p className="text-neutral-500 italic">No bio available.</p>
              )}
            </div>

            {/* Tabs for Media, Videos, Discography, Portfolio, Reviews */}
            <Tabs defaultValue="media" className="w-full">
              <TabsList className="w-full justify-start border-b border-neutral-200 bg-transparent p-0 h-auto">
                {images.length > 0 && (
                  <TabsTrigger 
                    value="media" 
                    className="data-[state=active]:border-b-2 data-[state=active]:border-black rounded-none px-4 py-3"
                  >
                    Photos ({images.length})
                  </TabsTrigger>
                )}
                {videos.length > 0 && (
                  <TabsTrigger 
                    value="videos"
                    className="data-[state=active]:border-b-2 data-[state=active]:border-black rounded-none px-4 py-3"
                  >
                    Videos ({videos.length})
                  </TabsTrigger>
                )}
                {discography.length > 0 && (
                  <TabsTrigger 
                    value="music"
                    className="data-[state=active]:border-b-2 data-[state=active]:border-black rounded-none px-4 py-3"
                  >
                    Music ({discography.length})
                  </TabsTrigger>
                )}
                {portfolio.length > 0 && (
                  <TabsTrigger 
                    value="portfolio"
                    className="data-[state=active]:border-b-2 data-[state=active]:border-black rounded-none px-4 py-3"
                  >
                    Past Shows ({portfolio.length})
                  </TabsTrigger>
                )}
                <TabsTrigger 
                  value="reviews"
                  className="data-[state=active]:border-b-2 data-[state=active]:border-black rounded-none px-4 py-3"
                >
                  Reviews ({reviews.length})
                </TabsTrigger>
              </TabsList>

              {/* Photos Tab */}
              {images.length > 0 && (
                <TabsContent value="media" className="pt-6">
                  <MediaGallery 
                    media={images.map(m => ({
                      id: m.id,
                      media_type: m.media_type,
                      url: m.url,
                      thumbnail_url: m.thumbnail_url,
                      title: m.title,
                      description: m.description,
                      is_featured: m.is_featured,
                    }))} 
                    columns={3}
                    showTitles
                  />
                </TabsContent>
              )}

              {/* Videos Tab */}
              {videos.length > 0 && (
                <TabsContent value="videos" className="pt-6">
                  <VideoCarousel 
                    videos={videos.map(v => ({
                      id: v.id,
                      media_type: v.media_type,
                      url: v.url,
                      thumbnail_url: v.thumbnail_url,
                      title: v.title,
                      embed_id: v.embed_id,
                    }))}
                  />
                </TabsContent>
              )}

              {/* Music/Discography Tab */}
              {discography.length > 0 && (
                <TabsContent value="music" className="pt-6">
                  <div className="grid gap-4 md:grid-cols-2">
                    {discography.map((release) => (
                      <div key={release.id} className="flex gap-4 p-4 border border-neutral-200 rounded-xl">
                        {/* Album Art */}
                        <div className="w-24 h-24 rounded-lg bg-neutral-100 overflow-hidden flex-shrink-0">
                          {release.cover_art_url ? (
                            <Image
                              src={release.cover_art_url}
                              alt={release.title}
                              width={96}
                              height={96}
                              className="w-full h-full object-cover"
                            />
                          ) : (
                            <div className="w-full h-full flex items-center justify-center">
                              <Music className="h-8 w-8 text-neutral-300" />
                            </div>
                          )}
                        </div>
                        {/* Info */}
                        <div className="flex-1 min-w-0">
                          <h4 className="font-semibold text-neutral-900 truncate">{release.title}</h4>
                          <p className="text-sm text-neutral-500 capitalize">
                            {release.release_type} ΓÇó {release.release_date ? new Date(release.release_date).getFullYear() : 'TBA'}
                          </p>
                          {release.label && (
                            <p className="text-sm text-neutral-500">{release.label}</p>
                          )}
                          {/* Streaming links */}
                          <div className="flex gap-2 mt-2">
                            {release.spotify_url && (
                              <a href={release.spotify_url} target="_blank" rel="noopener noreferrer" 
                                 className="text-neutral-400 hover:text-green-600">
                                <Music className="h-4 w-4" />
                              </a>
                            )}
                            {release.apple_music_url && (
                              <a href={release.apple_music_url} target="_blank" rel="noopener noreferrer"
                                 className="text-neutral-400 hover:text-pink-600">
                                <Music className="h-4 w-4" />
                              </a>
                            )}
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </TabsContent>
              )}

              {/* Portfolio Tab */}
              {portfolio.length > 0 && (
                <TabsContent value="portfolio" className="pt-6">
                  <PortfolioGrid 
                    type="artist"
                    items={portfolio}
                  />
                </TabsContent>
              )}

              {/* Reviews Tab */}
              <TabsContent value="reviews" className="pt-6">
                <ReviewsList
                  reviews={reviews.map(r => ({
                    ...r,
                    reviewer: r.reviewer,
                  }))}
                  averageRating={artist.average_rating}
                  totalReviews={artist.total_reviews}
                />
              </TabsContent>
            </Tabs>

            {/* Upcoming Events */}
            {upcomingBookings.length > 0 && (
              <div>
                <h2 className="text-xl font-semibold text-neutral-900 mb-4">Upcoming Events</h2>
                <div className="space-y-3">
                  {upcomingBookings.slice(0, 3).map((booking) => (
                    <Link 
                      key={booking.id}
                      href={`/events/${booking.events.id}`}
                      className="flex gap-4 p-4 border border-neutral-200 rounded-xl hover:border-neutral-300 transition-colors"
                    >
                      <div className="w-20 h-20 rounded-lg bg-neutral-100 overflow-hidden flex-shrink-0">
                        {booking.events.cover_image ? (
                          <Image
                            src={booking.events.cover_image}
                            alt={booking.events.title}
                            width={80}
                            height={80}
                            className="w-full h-full object-cover"
                          />
                        ) : (
                          <div className="w-full h-full flex items-center justify-center">
                            <Calendar className="h-6 w-6 text-neutral-300" />
                          </div>
                        )}
                      </div>
                      <div className="flex-1 min-w-0">
                        <h4 className="font-semibold text-neutral-900 truncate">{booking.events.title}</h4>
                        <p className="text-sm text-neutral-500">
                          {new Date(booking.events.event_date).toLocaleDateString('en-ZA', {
                            day: 'numeric',
                            month: 'long',
                            year: 'numeric',
                          })}
                        </p>
                        <p className="text-sm text-neutral-500">{booking.events.venue}</p>
                      </div>
                      <ExternalLink className="h-5 w-5 text-neutral-400 flex-shrink-0" />
                    </Link>
                  ))}
                </div>
              </div>
            )}
          </div>

          {/* Right Column - Sticky Booking Card */}
          <div className="lg:col-span-1">
            <div className="sticky top-24 space-y-6">
              {/* Booking Card */}
              <div className="bg-white border border-neutral-200 rounded-xl p-6 shadow-sm">
                <h3 className="font-semibold text-lg text-neutral-900 mb-4">Book This Artist</h3>
                
                <div className="text-center mb-6">
                  <p className="text-sm text-neutral-500 mb-1">Starting from</p>
                  <p className="text-4xl font-bold text-neutral-900">
                    {formatCurrency(artist.base_price)}
                  </p>
                </div>

                <div className="space-y-3 mb-6 text-sm">
                  <div className="flex justify-between py-2 border-b border-neutral-100">
                    <span className="text-neutral-500">Genre</span>
                    <span className="font-medium text-neutral-900">{artist.genre}</span>
                  </div>
                  <div className="flex justify-between py-2 border-b border-neutral-100">
                    <span className="text-neutral-500">Location</span>
                    <span className="font-medium text-neutral-900">
                      {PROVINCES[artist.location as keyof typeof PROVINCES]}
                    </span>
                  </div>
                  <div className="flex justify-between py-2 border-b border-neutral-100">
                    <span className="text-neutral-500">Notice Required</span>
                    <span className="font-medium text-neutral-900">{artist.advance_notice_days} days</span>
                  </div>
                  <div className="flex justify-between py-2">
                    <span className="text-neutral-500">Status</span>
                    <span className={artist.is_available ? 'text-green-600 font-medium' : 'text-red-500'}>
                      {artist.is_available ? 'Available for booking' : 'Not available'}
                    </span>
                  </div>
                </div>

                {isOrganizer ? (
                  <div className="space-y-3">
                    <Link href={`/dashboard/organizer/book?artist=${artist.id}`}>
                      <Button className="w-full" size="lg" disabled={!artist.is_available}>
                        {artist.is_available ? 'Request Booking' : 'Not Available'}
                      </Button>
                    </Link>
                    <p className="text-xs text-muted-foreground text-center">
                      Chat becomes available once you send a booking request.
                    </p>
                  </div>
                ) : profile ? (
                  <div className="text-center">
                    <p className="text-sm text-neutral-500 mb-3">
                      Only event organizers can book artists
                    </p>
                    <Link href="/profile">
                      <Button variant="outline" className="w-full">
                        Become an Organizer
                      </Button>
                    </Link>
                  </div>
                ) : (
                  <div className="text-center">
                    <p className="text-sm text-neutral-500 mb-3">
                      Sign in to contact this artist
                    </p>
                    <Link href="/auth/signin">
                      <Button className="w-full">
                        Sign In
                      </Button>
                    </Link>
                  </div>
                )}
              </div>

              {/* Track Record Card */}
              <TrackRecordCard
                type="artist"
                totalBookings={artist.total_bookings}
                completedBookings={artist.completed_bookings}
                cancelledBookings={artist.cancelled_bookings}
                totalEarned={artist.total_earned}
                rating={artist.average_rating}
                totalReviews={artist.total_reviews}
                memberSince={artist.created_at}
                isVerified={!!artist.verified_at}
              />

              {/* Contact Info */}
              {(artist.record_label || artist.management_contact) && (
                <div className="bg-neutral-50 rounded-xl p-6">
                  <h3 className="font-semibold text-neutral-900 mb-4">Contact</h3>
                  {artist.record_label && (
                    <div className="mb-3">
                      <p className="text-sm text-neutral-500">Record Label</p>
                      <p className="text-neutral-900">{artist.record_label}</p>
                    </div>
                  )}
                  {artist.management_contact && (
                    <div>
                      <p className="text-sm text-neutral-500">Management</p>
                      <p className="text-neutral-900">{artist.management_contact}</p>
                    </div>
                  )}
                </div>
              )}

              {/* Press Kit / Rider */}
              {(artist.press_kit_url || artist.rider_document_url) && (
                <div className="space-y-2">
                  {artist.press_kit_url && (
                    <a 
                      href={artist.press_kit_url}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="flex items-center justify-between p-3 border border-neutral-200 rounded-lg hover:border-neutral-300 transition-colors"
                    >
                      <span className="text-neutral-700">Press Kit</span>
                      <ExternalLink className="h-4 w-4 text-neutral-400" />
                    </a>
                  )}
                  {artist.rider_document_url && (
                    <a 
                      href={artist.rider_document_url}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="flex items-center justify-between p-3 border border-neutral-200 rounded-lg hover:border-neutral-300 transition-colors"
                    >
                      <span className="text-neutral-700">Technical Rider</span>
                      <ExternalLink className="h-4 w-4 text-neutral-400" />
                    </a>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

import Link from 'next/link'
import Image from 'next/image'
import { Card, CardContent, CardFooter } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar'
import { MapPin, Music } from 'lucide-react'
import { formatCurrency } from '@/lib/helpers'
import { PROVINCES } from '@/lib/constants'
import type { Artist, Profile, SaProvince } from '@/types/database'

interface ArtistWithProfile {
  id: string
  stage_name: string
  bio?: string | null
  genre: string
  base_price: number
  location: SaProvince | string
  is_available: boolean
  profile_image?: string | null
  profiles?: Pick<Profile, 'id' | 'full_name' | 'email' | 'avatar_url'> | null
}

interface ArtistsGridProps {
  artists: ArtistWithProfile[]
}

export function ArtistsGrid({ artists }: ArtistsGridProps) {
  return (
    <div className="grid md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
      {artists.map((artist) => (
        <ArtistCard key={artist.id} artist={artist} />
      ))}
    </div>
  )
}

function ArtistCard({ artist }: { artist: ArtistWithProfile }) {
  return (
    <Card className="overflow-hidden hover:shadow-lg transition-shadow">
      {/* Profile Image */}
      <div className="relative h-48 bg-gradient-to-br from-primary/20 to-primary/5 flex items-center justify-center overflow-hidden">
        {artist.profile_image ? (
          <Image
            src={artist.profile_image}
            alt={artist.stage_name}
            fill
            className="object-cover"
          />
        ) : (
          <Avatar className="h-24 w-24">
            <AvatarImage src={artist.profiles?.avatar_url || undefined} />
            <AvatarFallback className="text-3xl">
              {artist.stage_name.charAt(0)}
            </AvatarFallback>
          </Avatar>
        )}
        
        {/* Genre Badge */}
        <Badge className="absolute top-3 left-3" variant="secondary">
          {artist.genre}
        </Badge>
      </div>

      <CardContent className="p-4">
        <h3 className="text-lg font-semibold mb-1">{artist.stage_name}</h3>
        
        <div className="space-y-2 text-sm text-muted-foreground">
          <div className="flex items-center gap-2">
            <MapPin className="h-4 w-4" />
            <span>{PROVINCES[artist.location as keyof typeof PROVINCES]}</span>
          </div>
          
          <div className="flex items-center gap-2">
            <Music className="h-4 w-4" />
            <span>From {formatCurrency(artist.base_price)}</span>
          </div>
        </div>

        {artist.bio && (
          <p className="mt-3 text-sm text-muted-foreground line-clamp-2">
            {artist.bio}
          </p>
        )}
      </CardContent>

      <CardFooter className="p-4 pt-0">
        <Link href={`/artists/${artist.id}`} className="w-full">
          <Button variant="outline" className="w-full">
            View Profile
          </Button>
        </Link>
      </CardFooter>
    </Card>
  )
}

'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { createClient } from '@/lib/supabase/client'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Separator } from '@/components/ui/separator'
import { Checkbox } from '@/components/ui/checkbox'
import { Mail, Lock } from 'lucide-react'

type AuthMode = 'signin' | 'signup' | 'forgot-password'

interface AuthFormProps {
  onSuccess?: () => void
  defaultMode?: AuthMode
}

export function AuthForm({ onSuccess, defaultMode = 'signin' }: AuthFormProps) {
  const [mode, setMode] = useState<AuthMode>(defaultMode)
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [fullName, setFullName] = useState('')
  const [loading, setLoading] = useState(false)
  const [googleLoading, setGoogleLoading] = useState(false)
  const [acceptedTerms, setAcceptedTerms] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [message, setMessage] = useState<string | null>(null)
  const router = useRouter()
  const nextPath = typeof window !== 'undefined'
    ? new URLSearchParams(window.location.search).get('next')
    : null

  const supabase = createClient()

  const getRedirectUrl = () => {
    const baseUrl = typeof window !== 'undefined' 
      ? window.location.origin 
      : process.env.NEXT_PUBLIC_APP_URL || 'http://localhost:3000'
    return `${baseUrl}/auth/callback`
  }

  const handleGoogleSignIn = async () => {
    setGoogleLoading(true)
    setError(null)
    try {
      const { error: oauthError } = await supabase.auth.signInWithOAuth({
        provider: 'google',
        options: {
          redirectTo: getRedirectUrl(),
        },
      })
      if (oauthError) throw oauthError
      // Browser will redirect to Google ΓÇö no further action needed
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Google sign-in failed')
      setGoogleLoading(false)
    }
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setLoading(true)
    setError(null)
    setMessage(null)

    try {
      if (mode === 'signup') {
        if (!acceptedTerms) {
          setError('You must accept the Terms of Service and Privacy Policy to create an account.')
          setLoading(false)
          return
        }
        // Sign up new user
        const { error: signUpError } = await supabase.auth.signUp({
          email,
          password,
          options: {
            emailRedirectTo: getRedirectUrl(),
            data: {
              full_name: fullName,
            },
          },
        })

        if (signUpError) throw signUpError
        setMessage('Check your email to confirm your account!')
        
      } else if (mode === 'signin') {
        // Sign in with password
        const { data, error: signInError } = await supabase.auth.signInWithPassword({
          email,
          password,
        })

        if (signInError) throw signInError
        
        // Check if user is admin and redirect accordingly
        if (data.user) {
          const { data: profile } = await supabase
            .from('profiles')
            .select('is_admin')
            .eq('id', data.user.id)
            .single()
          
          if (profile?.is_admin === true) {
            // Admin users go to admin panel
            router.push('/admin')
            router.refresh()
            return
          }
        }
        
        // Regular users go to their intended destination if provided
        router.push(nextPath || '/profile')
        router.refresh()
        
      } else if (mode === 'forgot-password') {
        // Send password reset email
        const { error: resetError } = await supabase.auth.resetPasswordForEmail(email, {
          redirectTo: `${getRedirectUrl()}?next=/auth/reset-password`,
        })

        if (resetError) throw resetError
        setMessage('Check your email for password reset instructions!')
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'An error occurred')
    } finally {
      setLoading(false)
    }
  }

  const getTitle = () => {
    switch (mode) {
      case 'signup': return 'Create account'
      case 'forgot-password': return 'Reset Password'
      default: return 'Welcome back'
    }
  }

  const getDescription = () => {
    switch (mode) {
      case 'signup': return 'Join Ziyawa and start grooving'
      case 'forgot-password': return 'We\'ll send you a reset link'
      default: return 'Sign in to your Ziyawa account'
    }
  }

  const getButtonText = () => {
    if (loading) return 'Loading...'
    switch (mode) {
      case 'signup': return 'Create Account'
      case 'forgot-password': return 'Send Reset Link'
      default: return 'Sign In'
    }
  }

  return (
    <Card className="w-full max-w-md mx-auto">
      <CardHeader className="text-center">
        <CardTitle className="text-2xl">{getTitle()}</CardTitle>
        <CardDescription>{getDescription()}</CardDescription>
      </CardHeader>
      <CardContent>
        <form onSubmit={handleSubmit} className="space-y-4">
          {mode === 'signup' && (
            <div className="space-y-2">
              <Label htmlFor="fullName">Full Name</Label>
              <Input
                id="fullName"
                name="fullName"
                type="text"
                placeholder="Enter your full name"
                value={fullName}
                onChange={(e) => setFullName(e.target.value)}
                autoComplete="name"
                required
              />
            </div>
          )}

          <div className="space-y-2">
            <Label htmlFor="email">Email</Label>
            <Input
              id="email"
              name="email"
              type="email"
              placeholder="you@example.com"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              autoComplete="email"
              required
            />
          </div>

          {(mode === 'signin' || mode === 'signup') && (
            <div className="space-y-2">
              <div className="flex items-center justify-between">
                <Label htmlFor="password">Password</Label>
                {mode === 'signin' && (
                  <button
                    type="button"
                    className="text-xs text-muted-foreground hover:text-primary"
                    onClick={() => setMode('forgot-password')}
                  >
                    Forgot password?
                  </button>
                )}
              </div>
              <Input
                id="password"
                name="password"
                type="password"
                placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                autoComplete={mode === 'signup' ? 'new-password' : 'current-password'}
                required
                minLength={6}
              />
            </div>
          )}

          {mode === 'signup' && (
            <div className="flex items-start space-x-2">
              <Checkbox
                id="terms"
                checked={acceptedTerms}
                onCheckedChange={(checked) => setAcceptedTerms(checked === true)}
              />
              <label htmlFor="terms" className="text-xs text-muted-foreground leading-snug cursor-pointer">
                I agree to the{' '}
                <a href="/terms" target="_blank" rel="noopener noreferrer" className="underline underline-offset-2 hover:text-primary">Terms of Service</a>{' '}
                and{' '}
                <a href="/privacy" target="_blank" rel="noopener noreferrer" className="underline underline-offset-2 hover:text-primary">Privacy Policy</a>.
              </label>
            </div>
          )}

          {error && (
            <p className="text-sm text-red-600 bg-red-50 p-3 rounded-md">{error}</p>
          )}

          {message && (
            <p className="text-sm text-green-600 bg-green-50 p-3 rounded-md">{message}</p>
          )}

          <Button type="submit" className="w-full" disabled={loading}>
            {mode === 'forgot-password' && <Mail className="mr-2 h-4 w-4" />}
            {(mode === 'signin' || mode === 'signup') && <Lock className="mr-2 h-4 w-4" />}
            {getButtonText()}
          </Button>
        </form>

        {(mode === 'signin' || mode === 'signup') && (
          <>
            <div className="relative my-5">
              <Separator />
              <span className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 bg-card px-2 text-xs text-muted-foreground">
                or
              </span>
            </div>
            <Button
              type="button"
              variant="outline"
              className="w-full"
              onClick={handleGoogleSignIn}
              disabled={googleLoading}
            >
              {googleLoading ? (
                <svg className="mr-2 h-4 w-4 animate-spin" viewBox="0 0 24 24" fill="none"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" /><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8z" /></svg>
              ) : (
                <svg className="mr-2 h-4 w-4" viewBox="0 0 24 24"><path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/><path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/><path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.84z" fill="#FBBC05"/><path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/></svg>
              )}
              Continue with Google
            </Button>
          </>
        )}

        {/* Navigation Links */}
        <div className="mt-4 text-center text-sm space-y-2">
          {mode === 'signin' && (
            <p>
              Don&apos;t have an account?{' '}
              <button
                type="button"
                className="text-primary font-medium hover:underline"
                onClick={() => setMode('signup')}
              >
                Sign up
              </button>
            </p>
          )}
          
          {mode === 'signup' && (
            <p>
              Already have an account?{' '}
              <button
                type="button"
                className="text-primary font-medium hover:underline"
                onClick={() => setMode('signin')}
              >
                Sign in
              </button>
            </p>
          )}
          
          {mode === 'forgot-password' && (
            <p>
              <button
                type="button"
                className="text-primary font-medium hover:underline"
                onClick={() => setMode('signin')}
              >
                ΓåÉ Back to sign in
              </button>
            </p>
          )}
        </div>
      </CardContent>
    </Card>
  )
}

'use client';

import { useState } from 'react';
import Link from 'next/link';
import { formatDistanceToNow } from 'date-fns';
import { Star, MessageSquare, TrendingUp, Clock, Filter, ChevronRight } from 'lucide-react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { StarRating } from '@/components/reviews/star-rating';
import { useToast } from '@/hooks/use-toast';

interface Profile {
  id: string;
  full_name: string | null;
  avatar_url: string | null;
}

interface EventInfo {
  id: string;
  title: string;
}

interface Review {
  id: string;
  event_id: string;
  user_id: string;
  rating: number;
  title: string | null;
  comment: string | null;
  is_verified_attendee: boolean;
  is_anonymous: boolean;
  helpful_count: number;
  organizer_response: string | null;
  organizer_responded_at: string | null;
  created_at: string;
  profiles: Profile | null;
  events: EventInfo | null;
}

interface Event {
  id: string;
  title: string;
  cover_image: string | null;
  event_date: string;
}

interface RatingSummary {
  average_rating: number;
  total_reviews: number;
}

interface OrganizerReviewsDashboardProps {
  events: Event[];
  reviews: Review[];
  ratingSummaries: Record<string, RatingSummary>;
  stats: {
    totalReviews: number;
    averageRating: number;
    pendingResponses: number;
  };
}

export function OrganizerReviewsDashboard({
  events,
  reviews: initialReviews,
  ratingSummaries,
  stats,
}: OrganizerReviewsDashboardProps) {
  const [reviews, setReviews] = useState(initialReviews);
  const [filterEvent, setFilterEvent] = useState<string>('all');
  const [filterStatus, setFilterStatus] = useState<string>('all');
  const [respondingTo, setRespondingTo] = useState<Review | null>(null);
  const [response, setResponse] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { toast } = useToast();

  // Filter reviews
  const filteredReviews = reviews.filter((review) => {
    if (filterEvent !== 'all' && review.event_id !== filterEvent) return false;
    if (filterStatus === 'pending' && review.organizer_response) return false;
    if (filterStatus === 'responded' && !review.organizer_response) return false;
    return true;
  });

  const handleSubmitResponse = async () => {
    if (!respondingTo || !response.trim()) return;

    setIsSubmitting(true);
    try {
      const res = await fetch(`/api/reviews/${respondingTo.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ organizerResponse: response.trim() }),
      });

      if (res.ok) {
        const data = await res.json();
        setReviews((prev) =>
          prev.map((r) =>
            r.id === respondingTo.id
              ? { ...r, organizer_response: response.trim(), organizer_responded_at: new Date().toISOString() }
              : r
          )
        );
        toast({ title: 'Response posted successfully' });
        setRespondingTo(null);
        setResponse('');
      }
    } catch (error) {
      console.error('Error submitting response:', error);
      toast({
        title: 'Error',
        description: 'Failed to post response',
        variant: 'destructive',
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="space-y-8">
      {/* Header */}
      <div>
        <h1 className="text-3xl font-bold">Reviews</h1>
        <p className="text-muted-foreground">
          Manage and respond to reviews across all your events
        </p>
      </div>

      {/* Stats Cards */}
      <div className="grid sm:grid-cols-3 gap-4">
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center gap-4">
              <div className="p-3 rounded-full bg-yellow-100 dark:bg-yellow-900/30">
                <Star className="h-6 w-6 text-yellow-600" />
              </div>
              <div>
                <p className="text-2xl font-bold">{stats.averageRating.toFixed(1)}</p>
                <p className="text-sm text-muted-foreground">Average Rating</p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center gap-4">
              <div className="p-3 rounded-full bg-blue-100 dark:bg-blue-900/30">
                <TrendingUp className="h-6 w-6 text-blue-600" />
              </div>
              <div>
                <p className="text-2xl font-bold">{stats.totalReviews}</p>
                <p className="text-sm text-muted-foreground">Total Reviews</p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center gap-4">
              <div className="p-3 rounded-full bg-orange-100 dark:bg-orange-900/30">
                <Clock className="h-6 w-6 text-orange-600" />
              </div>
              <div>
                <p className="text-2xl font-bold">{stats.pendingResponses}</p>
                <p className="text-sm text-muted-foreground">Pending Responses</p>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Tabs */}
      <Tabs defaultValue="reviews">
        <TabsList>
          <TabsTrigger value="reviews">All Reviews</TabsTrigger>
          <TabsTrigger value="events">By Event</TabsTrigger>
        </TabsList>

        {/* All Reviews Tab */}
        <TabsContent value="reviews" className="space-y-4">
          {/* Filters */}
          <div className="flex flex-wrap gap-3 items-center">
            <Filter className="h-4 w-4 text-muted-foreground" />
            <Select value={filterEvent} onValueChange={setFilterEvent}>
              <SelectTrigger className="w-[200px]">
                <SelectValue placeholder="Filter by event" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All Events</SelectItem>
                {events.map((event) => (
                  <SelectItem key={event.id} value={event.id}>
                    {event.title}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>

            <Select value={filterStatus} onValueChange={setFilterStatus}>
              <SelectTrigger className="w-[160px]">
                <SelectValue placeholder="Response status" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All Status</SelectItem>
                <SelectItem value="pending">Needs Response</SelectItem>
                <SelectItem value="responded">Responded</SelectItem>
              </SelectContent>
            </Select>
          </div>

          {/* Reviews List */}
          {filteredReviews.length === 0 ? (
            <Card>
              <CardContent className="py-12 text-center text-muted-foreground">
                No reviews found
              </CardContent>
            </Card>
          ) : (
            <div className="space-y-4">
              {filteredReviews.map((review) => (
                <Card key={review.id}>
                  <CardContent className="pt-6">
                    <div className="flex items-start justify-between gap-4">
                      <div className="flex items-start gap-3 flex-1">
                        <Avatar>
                          {!review.is_anonymous && review.profiles?.avatar_url && (
                            <AvatarImage src={review.profiles.avatar_url} />
                          )}
                          <AvatarFallback>
                            {review.is_anonymous ? 'A' : (review.profiles?.full_name?.[0] || 'U')}
                          </AvatarFallback>
                        </Avatar>
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-2 flex-wrap">
                            <span className="font-medium">
                              {review.is_anonymous ? 'Anonymous' : review.profiles?.full_name || 'Unknown'}
                            </span>
                            {review.is_verified_attendee && (
                              <Badge variant="secondary" className="text-xs">Verified</Badge>
                            )}
                            <span className="text-xs text-muted-foreground">
                              {formatDistanceToNow(new Date(review.created_at), { addSuffix: true })}
                            </span>
                          </div>
                          <Link
                            href={`/events/${review.event_id}`}
                            className="text-sm text-primary hover:underline"
                          >
                            {review.events?.title}
                          </Link>
                          <div className="mt-1">
                            <StarRating rating={review.rating} size="sm" />
                          </div>
                          {review.title && (
                            <p className="font-medium mt-2">{review.title}</p>
                          )}
                          {review.comment && (
                            <p className="text-muted-foreground text-sm mt-1">{review.comment}</p>
                          )}

                          {/* Organizer Response */}
                          {review.organizer_response && (
                            <div className="mt-3 p-3 bg-muted/50 rounded-lg border-l-2 border-primary">
                              <p className="text-xs font-medium text-muted-foreground mb-1">
                                Your response
                              </p>
                              <p className="text-sm">{review.organizer_response}</p>
                            </div>
                          )}
                        </div>
                      </div>

                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => {
                          setRespondingTo(review)
                          setResponse(review.organizer_response || '')
                        }}
                      >
                        <MessageSquare className="h-4 w-4 mr-2" />
                        {review.organizer_response ? 'Edit Response' : 'Respond'}
                      </Button>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}
        </TabsContent>

        {/* By Event Tab */}
        <TabsContent value="events" className="space-y-4">
          {events.length === 0 ? (
            <Card>
              <CardContent className="py-12 text-center text-muted-foreground">
                No events yet
              </CardContent>
            </Card>
          ) : (
            <div className="grid sm:grid-cols-2 gap-4">
              {events.map((event) => {
                const summary = ratingSummaries[event.id];
                return (
                  <Card key={event.id} className="overflow-hidden">
                    <div className="flex">
                      {event.cover_image && (
                        <div className="w-24 h-24 flex-shrink-0">
                          {/* eslint-disable-next-line @next/next/no-img-element */}
                          <img
                            src={event.cover_image}
                            alt={event.title}
                            className="w-full h-full object-cover"
                          />
                        </div>
                      )}
                      <CardContent className="flex-1 p-4">
                        <h3 className="font-semibold line-clamp-1">{event.title}</h3>
                        {summary ? (
                          <div className="flex items-center gap-2 mt-1">
                            <StarRating rating={summary.average_rating} size="sm" />
                            <span className="text-sm text-muted-foreground">
                              ({summary.total_reviews} reviews)
                            </span>
                          </div>
                        ) : (
                          <p className="text-sm text-muted-foreground mt-1">No reviews yet</p>
                        )}
                        <Link
                          href={`/events/${event.id}`}
                          className="text-sm text-primary hover:underline inline-flex items-center mt-2"
                        >
                          View Event <ChevronRight className="h-4 w-4" />
                        </Link>
                      </CardContent>
                    </div>
                  </Card>
                );
              })}
            </div>
          )}
        </TabsContent>
      </Tabs>

      {/* Response Dialog */}
      <Dialog open={!!respondingTo} onOpenChange={(open) => !open && setRespondingTo(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Respond to Review</DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            {respondingTo && (
              <div className="p-3 bg-muted rounded-lg">
                <div className="flex items-center gap-2 mb-2">
                  <StarRating rating={respondingTo.rating} size="sm" />
                  <span className="text-sm text-muted-foreground">
                    by {respondingTo.is_anonymous ? 'Anonymous' : respondingTo.profiles?.full_name}
                  </span>
                </div>
                {respondingTo.comment && (
                  <p className="text-sm">{respondingTo.comment}</p>
                )}
              </div>
            )}
            <Textarea
              placeholder="Write a professional response..."
              value={response}
              onChange={(e) => setResponse(e.target.value)}
              rows={4}
            />
            <p className="text-xs text-muted-foreground">
              Your response will be visible to everyone viewing this review.
            </p>
            <div className="flex gap-3">
              <Button
                variant="outline"
                onClick={() => setRespondingTo(null)}
                className="flex-1"
              >
                Cancel
              </Button>
              <Button
                onClick={handleSubmitResponse}
                disabled={isSubmitting || !response.trim()}
                className="flex-1"
              >
                {isSubmitting ? 'Posting...' : 'Post Response'}
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

'use client'

import { useState } from 'react'
import Link from 'next/link'
import Image from 'next/image'
import { useRouter } from 'next/navigation'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar'
import { Separator } from '@/components/ui/separator'
import { Calendar, MapPin, Clock, Users, Ticket, Music, ArrowLeft, Play, ImageIcon, Star, CheckCircle, Flag } from 'lucide-react'
import { formatCurrency, formatDate, formatTime, getDaysUntilEvent, isEventPast } from '@/lib/helpers'
import { PROVINCES } from '@/lib/constants'
import { useAuth } from '@/components/providers/auth-provider'
import { PaymentDialog } from '@/components/payments/payment-dialog'
import { ReportDialog } from '@/components/report-dialog'
import { extractYouTubeId, getYouTubeThumbnail } from '@/types/database'
import type { Event, Profile, Artist, Booking, EventMedia } from '@/types/database'
import { buildFallbackTier, isTierOnSale, type EventTicketTier } from '@/lib/ticketing'

interface EventWithOrganizer extends Event {
  profiles: Pick<Profile, 'id' | 'full_name' | 'avatar_url' | 'company_name' | 'location' | 'bio' | 'verified_at'>
}

interface OrganizerStats {
  totalEvents: number;
  upcomingEvents: number;
  rating: number;
  totalReviews: number;
}

interface BookingWithArtist extends Booking {
  artists: Pick<Artist, 'id' | 'stage_name' | 'genre' | 'profile_image'>
}

interface EventDetailsProps {
  event: EventWithOrganizer
  bookings: BookingWithArtist[]
  media?: EventMedia[]
  organizerStats?: OrganizerStats
  ticketTiers?: EventTicketTier[]
}

export function EventDetails({ event, bookings, media = [], organizerStats, ticketTiers = [] }: EventDetailsProps) {
  const { user, profile } = useAuth()
  const router = useRouter()
  const [showPayment, setShowPayment] = useState(false)
  const [lightboxOpen, setLightboxOpen] = useState(false)
  const [lightboxIndex, setLightboxIndex] = useState(0)
  const [selectedTierId, setSelectedTierId] = useState(ticketTiers[0]?.id || '')
  const [ticketQuantity, setTicketQuantity] = useState(1)

  const daysUntil = getDaysUntilEvent(event.event_date)
  const ticketsRemaining = event.capacity - event.tickets_sold
  const isSoldOut = ticketsRemaining <= 0
  const isPast = isEventPast(event.event_date)

  // Separate media by type
  const galleryImages = media.filter(m => m.media_type === 'image' && m.is_gallery)
  const promoVideos = media.filter(m => m.media_type !== 'image')
  const fallbackTier = buildFallbackTier({
    id: event.id,
    ticket_price: Number(event.ticket_price || 0),
    capacity: Number(event.capacity || 0),
    tickets_sold: Number(event.tickets_sold || 0),
  })
  const resolvedTicketTiers = ticketTiers.length > 0
    ? ticketTiers.filter((tier) => tier.is_public !== false)
    : [fallbackTier]
  const selectedTier = resolvedTicketTiers.find((tier) => tier.id === selectedTierId) || resolvedTicketTiers[0]

  const handleBuyTicket = () => {
    if (!user) {
      router.push('/auth/signin')
      return
    }
    setShowPayment(true)
  }

  return (
    <div className="max-w-4xl mx-auto">
      {/* Back Button */}
      <Link href="/ziwaphi" className="inline-flex items-center text-muted-foreground hover:text-primary mb-6">
        <ArrowLeft className="h-4 w-4 mr-2" />
        Back to Events
      </Link>

      <div className="grid lg:grid-cols-3 gap-8">
        {/* Main Content */}
        <div className="lg:col-span-2 space-y-6">
          {/* Cover Image */}
          <div className="relative h-64 md:h-80 bg-gradient-to-br from-primary/20 to-primary/5 rounded-lg overflow-hidden">
            {event.cover_image ? (
              <Image
                src={event.cover_image}
                alt={event.title}
                fill
                className="object-cover"
              />
            ) : (
              <div className="w-full h-full flex items-center justify-center">
                <Calendar className="h-16 w-16 text-primary/40" />
              </div>
            )}
            
            {/* Status Badge */}
            {isPast ? (
              <Badge className="absolute top-4 left-4" variant="secondary">
                Event Ended
              </Badge>
            ) : (
              <Badge className="absolute top-4 left-4" variant="secondary">
                {daysUntil === 0 ? 'Today!' : daysUntil === 1 ? 'Tomorrow' : `In ${daysUntil} days`}
              </Badge>
            )}
          </div>

          {/* Event Title & Info */}
          <div>
            <h1 className="text-3xl font-bold mb-4">{event.title}</h1>
            
            <div className="grid sm:grid-cols-2 gap-4">
              <div className="flex items-center gap-3 text-muted-foreground">
                <Calendar className="h-5 w-5" />
                <span>{formatDate(event.event_date)}</span>
              </div>
              
              <div className="flex items-center gap-3 text-muted-foreground">
                <Clock className="h-5 w-5" />
                <span>
                  {formatTime(event.start_time)}
                  {event.end_time && ` - ${formatTime(event.end_time)}`}
                </span>
              </div>
              
              <div className="flex items-center gap-3 text-muted-foreground">
                <MapPin className="h-5 w-5" />
                <a
                  href={`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(event.venue)}`}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="hover:text-primary hover:underline transition-colors"
                >
                  {event.venue}
                </a>
              </div>
              
              <div className="flex items-center gap-3 text-muted-foreground">
                <Users className="h-5 w-5" />
                <span>
                  {PROVINCES[event.location as keyof typeof PROVINCES]}
                </span>
              </div>
            </div>
          </div>

          <Separator />

          {/* Description */}
          {event.description && (
            <div>
              <h2 className="text-xl font-semibold mb-3">About This Event</h2>
              <p className="text-muted-foreground whitespace-pre-wrap">{event.description}</p>
            </div>
          )}

          {/* Lineup */}
          {bookings.length > 0 && (
            <div>
              <h2 className="text-xl font-semibold mb-4">Lineup</h2>
              <div className="grid sm:grid-cols-2 gap-4">
                {bookings.map((booking) => (
                  <Link key={booking.id} href={`/artists/${booking.artists.id}`}>
                    <Card className="hover:shadow-md transition-shadow">
                      <CardContent className="p-4 flex items-center gap-4">
                        <Avatar className="h-12 w-12">
                          <AvatarImage src={booking.artists.profile_image || undefined} />
                          <AvatarFallback>
                            {booking.artists.stage_name.charAt(0)}
                          </AvatarFallback>
                        </Avatar>
                        <div>
                          <p className="font-medium">{booking.artists.stage_name}</p>
                          <p className="text-sm text-muted-foreground">{booking.artists.genre}</p>
                        </div>
                      </CardContent>
                    </Card>
                  </Link>
                ))}
              </div>
            </div>
          )}

          {/* Organizer - Enhanced Trust Section */}
          <div>
            <h2 className="text-xl font-semibold mb-3">Hosted By</h2>
            <Link href={`/organizers/${event.profiles.id}`}>
              <Card className="hover:shadow-md transition-shadow cursor-pointer">
                <CardContent className="p-4">
                  <div className="flex items-start gap-4">
                    {/* Avatar */}
                    <Avatar className="h-14 w-14">
                      <AvatarImage src={event.profiles.avatar_url || undefined} />
                      <AvatarFallback className="bg-neutral-100 text-neutral-600 font-semibold text-lg">
                        {(event.profiles.company_name || event.profiles.full_name || 'O').charAt(0).toUpperCase()}
                      </AvatarFallback>
                    </Avatar>

                    {/* Info */}
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2">
                        <h3 className="font-semibold text-lg">
                          {event.profiles.company_name || event.profiles.full_name || 'Event Organizer'}
                        </h3>
                        {event.profiles.verified_at && (
                          <CheckCircle className="h-5 w-5 text-blue-500 flex-shrink-0" />
                        )}
                      </div>

                      {/* Stats */}
                      {organizerStats && (
                        <div className="flex flex-wrap items-center gap-3 mt-2">
                          {organizerStats.totalReviews > 0 && (
                            <div className="flex items-center gap-1 text-sm">
                              <Star className="h-4 w-4 fill-yellow-400 text-yellow-400" />
                              <span className="font-medium">{organizerStats.rating.toFixed(1)}</span>
                              <span className="text-muted-foreground">
                                ({organizerStats.totalReviews} reviews)
                              </span>
                            </div>
                          )}
                          <div className="flex items-center gap-1 text-sm text-muted-foreground">
                            <Calendar className="h-4 w-4" />
                            <span>{organizerStats.totalEvents} events hosted</span>
                          </div>
                        </div>
                      )}

                      <p className="text-sm text-primary mt-2 flex items-center gap-1">
                        View organizer profile
                        <ArrowLeft className="h-3 w-3 rotate-180" />
                      </p>
                    </div>
                  </div>

                  {/* Trust badges */}
                  {organizerStats && organizerStats.totalEvents >= 3 && (
                    <div className="flex flex-wrap gap-2 mt-3 pt-3 border-t">
                      {event.profiles.verified_at && (
                        <Badge variant="secondary" className="bg-blue-50 text-blue-700">
                          <CheckCircle className="h-3 w-3 mr-1" />
                          Verified
                        </Badge>
                      )}
                      {organizerStats.totalEvents >= 5 && (
                        <Badge variant="secondary" className="bg-neutral-100 text-neutral-700">
                          Experienced Host
                        </Badge>
                      )}
                      {organizerStats.rating >= 4.5 && organizerStats.totalReviews >= 5 && (
                        <Badge variant="secondary" className="bg-yellow-50 text-yellow-700">
                          <Star className="h-3 w-3 mr-1 fill-current" />
                          Top Rated
                        </Badge>
                      )}
                    </div>
                  )}
                </CardContent>
              </Card>
            </Link>
          </div>

          {/* Event Gallery */}
          {galleryImages.length > 0 && (
            <div>
              <h2 className="text-xl font-semibold mb-4 flex items-center gap-2">
                <ImageIcon className="h-5 w-5" />
                Gallery
              </h2>
              <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                {galleryImages.slice(0, 6).map((item, index) => (
                  <div 
                    key={item.id} 
                    className="aspect-square rounded-lg overflow-hidden bg-neutral-100 cursor-pointer hover:opacity-90 transition-opacity"
                    onClick={() => {
                      setLightboxIndex(index)
                      setLightboxOpen(true)
                    }}
                  >
                    <Image
                      src={item.url}
                      alt={item.title || 'Event gallery'}
                      width={300}
                      height={300}
                      className="w-full h-full object-cover"
                    />
                  </div>
                ))}
              </div>
              {galleryImages.length > 6 && (
                <p className="text-sm text-muted-foreground mt-2">
                  +{galleryImages.length - 6} more photos
                </p>
              )}
            </div>
          )}

          {/* Promo Videos */}
          {promoVideos.length > 0 && (
            <div>
              <h2 className="text-xl font-semibold mb-4 flex items-center gap-2">
                <Play className="h-5 w-5" />
                Promo Videos
              </h2>
              <div className="grid gap-4">
                {promoVideos.slice(0, 2).map((video) => {
                  const embedId = video.embed_id || extractYouTubeId(video.url)
                  const thumbnail = video.thumbnail_url || (embedId ? getYouTubeThumbnail(embedId) : null)
                  
                  return (
                    <a 
                      key={video.id}
                      href={video.url}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="relative aspect-video rounded-lg overflow-hidden bg-neutral-100 group"
                    >
                      {thumbnail && (
                        <Image
                          src={thumbnail}
                          alt={video.title || 'Promo video'}
                          fill
                          className="object-cover"
                        />
                      )}
                      <div className="absolute inset-0 flex items-center justify-center bg-black/30 group-hover:bg-black/40 transition-colors">
                        <div className="w-16 h-16 rounded-full bg-white/90 flex items-center justify-center">
                          <Play className="h-8 w-8 text-neutral-900 ml-1" fill="currentColor" />
                        </div>
                      </div>
                      {video.title && (
                        <div className="absolute bottom-0 left-0 right-0 p-3 bg-gradient-to-t from-black/70 to-transparent">
                          <p className="text-white text-sm font-medium truncate">{video.title}</p>
                        </div>
                      )}
                    </a>
                  )
                })}
              </div>
            </div>
          )}
        </div>

        {/* Sidebar - Ticket Card */}
        <div className="lg:col-span-1">
          <Card className="sticky top-24">
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Ticket className="h-5 w-5" />
                Get Tickets
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="text-center">
                <p className="text-3xl font-bold text-primary">
                  {selectedTier?.price === 0 ? 'Free' : formatCurrency(selectedTier?.price || event.ticket_price)}
                </p>
                <p className="text-sm text-muted-foreground">
                  {resolvedTicketTiers.length > 1 ? 'selected tier price' : 'per ticket'}
                </p>
              </div>

              <div className="space-y-2">
                {resolvedTicketTiers.map((tier) => {
                  const remaining = Math.max(0, tier.quantity - tier.sold_count)
                  const isAvailable = isTierOnSale(tier)
                  const isSelected = selectedTier?.id === tier.id

                  return (
                    <button
                      key={tier.id}
                      type="button"
                      onClick={() => setSelectedTierId(tier.id)}
                      className={`w-full rounded-lg border px-3 py-3 text-left transition ${isSelected ? 'border-primary bg-primary/5' : 'border-neutral-200'} ${!isAvailable ? 'opacity-60' : ''}`}
                      disabled={!isAvailable}
                    >
                      <div className="flex items-center justify-between gap-4">
                        <div>
                          <p className="font-medium">{tier.name}</p>
                          {tier.description && (
                            <p className="text-xs text-muted-foreground mt-1">{tier.description}</p>
                          )}
                        </div>
                        <div className="text-right">
                          <p className="font-semibold">{tier.price === 0 ? 'Free' : formatCurrency(tier.price)}</p>
                          <p className="text-xs text-muted-foreground">{remaining} left</p>
                        </div>
                      </div>
                    </button>
                  )
                })}
              </div>

              <div className="space-y-2 text-sm">
                <label className="flex items-center justify-between gap-3">
                  <span className="text-muted-foreground">Quantity</span>
                  <input
                    type="number"
                    min="1"
                    max={Math.max(1, Math.min(10, (selectedTier?.quantity || 1) - (selectedTier?.sold_count || 0)))}
                    value={ticketQuantity}
                    onChange={(e) => setTicketQuantity(Math.max(1, Number(e.target.value) || 1))}
                    className="w-20 rounded-md border border-input bg-background px-2 py-1 text-right"
                  />
                </label>
                <p className="text-xs text-muted-foreground">
                  Buying for another groovist? You can assign each ticket holder at checkout.
                </p>
              </div>

              <Separator />

              <div className="space-y-2 text-sm">
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Capacity</span>
                  <span>{event.capacity}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Sold</span>
                  <span>{event.tickets_sold}</span>
                </div>
                <div className="flex justify-between font-medium">
                  <span>Available</span>
                  <span className={ticketsRemaining <= 20 ? 'text-red-500' : ''}>
                    {ticketsRemaining}
                  </span>
                </div>
              </div>

              <Separator />

              <Button 
                className="w-full" 
                size="lg"
                disabled={isSoldOut || isPast || !selectedTier || !isTierOnSale(selectedTier)}
                onClick={handleBuyTicket}
              >
                {isPast ? 'Event Ended' : isSoldOut ? 'Sold Out' : selectedTier ? `Buy ${selectedTier.name}` : 'Buy Ticket'}
              </Button>

              {!user && (
                <p className="text-xs text-center text-muted-foreground">
                  You&apos;ll need to sign in to purchase tickets
                </p>
              )}

              {/* Report Event */}
              <div className="pt-2 border-t">
                <ReportDialog
                  type="event"
                  targetId={event.id}
                  targetName={event.title}
                  trigger={
                    <Button variant="ghost" size="sm" className="w-full text-muted-foreground hover:text-red-600">
                      <Flag className="h-4 w-4 mr-2" />
                      Report this event
                    </Button>
                  }
                />
              </div>
            </CardContent>
          </Card>
        </div>
      </div>

      {/* Payment Dialog */}
      {user && profile && (
        <PaymentDialog
          open={showPayment}
          onOpenChange={setShowPayment}
          event={event}
          user={profile}
          quantity={ticketQuantity}
          selectedTier={selectedTier}
        />
      )}

      {/* Lightbox */}
      {lightboxOpen && galleryImages.length > 0 && (
        <div 
          className="fixed inset-0 z-50 bg-black/90 flex items-center justify-center"
          onClick={() => setLightboxOpen(false)}
        >
          <button
            className="absolute top-4 right-4 text-white hover:text-neutral-300 z-10"
            onClick={() => setLightboxOpen(false)}
          >
            <span className="sr-only">Close</span>
            <svg className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
          <div className="relative max-w-4xl max-h-[90vh] w-full mx-4">
            <Image
              src={galleryImages[lightboxIndex].url}
              alt={galleryImages[lightboxIndex].title || 'Gallery image'}
              width={1200}
              height={800}
              className="w-full h-auto max-h-[90vh] object-contain"
              onClick={(e) => e.stopPropagation()}
            />
            {galleryImages.length > 1 && (
              <>
                <button
                  className="absolute left-0 top-1/2 -translate-y-1/2 -translate-x-12 text-white hover:text-neutral-300 p-2"
                  onClick={(e) => {
                    e.stopPropagation()
                    setLightboxIndex(prev => prev === 0 ? galleryImages.length - 1 : prev - 1)
                  }}
                >
                  <svg className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
                  </svg>
                </button>
                <button
                  className="absolute right-0 top-1/2 -translate-y-1/2 translate-x-12 text-white hover:text-neutral-300 p-2"
                  onClick={(e) => {
                    e.stopPropagation()
                    setLightboxIndex(prev => prev === galleryImages.length - 1 ? 0 : prev + 1)
                  }}
                >
                  <svg className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                  </svg>
                </button>
              </>
            )}
          </div>
        </div>
      )}
    </div>
  )
}

'use client'

import { useEffect, useMemo, useState } from 'react'
import {
  BadgeDollarSign,
  CalendarDays,
  ClipboardList,
  Clock3,
  Loader2,
  ShieldCheck,
  UserPlus,
  UserX,
  Wallet,
} from 'lucide-react'
import { toast } from 'sonner'
import { Button } from '@/components/ui/button'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Badge } from '@/components/ui/badge'
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Textarea } from '@/components/ui/textarea'
import { formatCurrency, formatDate } from '@/lib/helpers'

interface TeamPerson {
  id: string
  fullName: string
  email: string
  phone?: string
  roleLabel: string
  status: string
  kind: 'member' | 'invite'
  createdAt?: string
}

interface TeamShift {
  id: string
  memberId: string
  fullName: string
  roleLabel: string
  shiftTitle: string
  workDate: string
  hoursWorked: number
  notes?: string
  status: string
  createdAt?: string
}

interface TeamPayment {
  id: string
  memberId: string
  fullName: string
  roleLabel: string
  amount: number
  currency: string
  paymentMethod: string
  notes?: string
  status: string
  paidAt?: string | null
  createdAt?: string
}

interface EventStaffManagerProps {
  eventId: string
  eventTitle?: string
  isPastEvent?: boolean
}

export function EventStaffManager({ eventId, eventTitle = 'This event', isPastEvent = false }: EventStaffManagerProps) {
  const [loading, setLoading] = useState(true)
  const [busyAction, setBusyAction] = useState<string | null>(null)
  const [currentEventTitle, setCurrentEventTitle] = useState(eventTitle)
  const [people, setPeople] = useState<TeamPerson[]>([])
  const [shifts, setShifts] = useState<TeamShift[]>([])
  const [payments, setPayments] = useState<TeamPayment[]>([])

  const [inviteForm, setInviteForm] = useState({
    fullName: '',
    email: '',
    phone: '',
    role: 'door_staff',
    offeredRate: '',
    inviteMessage: '',
  })

  const [shiftForm, setShiftForm] = useState({
    memberId: '',
    shiftTitle: '',
    workDate: new Date().toISOString().slice(0, 10),
    hoursWorked: '5',
    notes: '',
    status: 'worked',
  })

  const [paymentForm, setPaymentForm] = useState({
    memberId: '',
    amount: '',
    paymentMethod: 'cash',
    notes: '',
    status: 'planned',
  })

  const loadData = async () => {
    try {
      setLoading(true)
      const response = await fetch(`/api/events/${eventId}/team`, { cache: 'no-store' })
      const data = await response.json()

      if (!response.ok) {
        throw new Error(data.error || 'Failed to load staff tools')
      }

      setCurrentEventTitle(data.event?.title || eventTitle)
      setPeople([...(data.members || []), ...(data.invites || [])])
      setShifts(data.shifts || [])
      setPayments(data.payments || [])
    } catch (error) {
      toast.error(error instanceof Error ? error.message : 'Failed to load staff tools')
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    loadData()
  }, [eventId])

  const activeMembers = useMemo(
    () => people.filter((person) => person.kind === 'member' && person.status !== 'revoked'),
    [people]
  )

  useEffect(() => {
    if (activeMembers.length > 0 && !shiftForm.memberId) {
      setShiftForm((prev) => ({ ...prev, memberId: activeMembers[0].id }))
    }

    if (activeMembers.length > 0 && !paymentForm.memberId) {
      setPaymentForm((prev) => ({ ...prev, memberId: activeMembers[0].id }))
    }
  }, [activeMembers, paymentForm.memberId, shiftForm.memberId])

  const pendingInvites = useMemo(
    () => people.filter((person) => person.kind === 'invite' && person.status === 'pending'),
    [people]
  )

  const totalPaid = useMemo(
    () => payments
      .filter((payment) => payment.status === 'paid')
      .reduce((sum, payment) => sum + Number(payment.amount || 0), 0),
    [payments]
  )

  const outstandingPay = useMemo(
    () => payments
      .filter((payment) => payment.status !== 'paid')
      .reduce((sum, payment) => sum + Number(payment.amount || 0), 0),
    [payments]
  )

  const teamHistory = useMemo(() => {
    return activeMembers.map((member) => {
      const memberShifts = shifts.filter((shift) => shift.memberId === member.id)
      const memberPayments = payments.filter((payment) => payment.memberId === member.id)
      return {
        ...member,
        shiftCount: memberShifts.length,
        hoursWorked: memberShifts.reduce((sum, shift) => sum + Number(shift.hoursWorked || 0), 0),
        totalPaid: memberPayments.filter((payment) => payment.status === 'paid').reduce((sum, payment) => sum + Number(payment.amount || 0), 0),
        pendingPay: memberPayments.filter((payment) => payment.status !== 'paid').reduce((sum, payment) => sum + Number(payment.amount || 0), 0),
        latestWorkDate: memberShifts[0]?.workDate || null,
      }
    })
  }, [activeMembers, payments, shifts])

  const handleInvite = async (e: React.FormEvent) => {
    e.preventDefault()

    if (!inviteForm.fullName.trim() || !inviteForm.email.trim()) {
      toast.error('Name and email are required')
      return
    }

    try {
      setBusyAction('invite')
      const response = await fetch(`/api/events/${eventId}/team`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          action: 'invite',
          ...inviteForm,
          offeredRate: inviteForm.offeredRate ? Number(inviteForm.offeredRate) : null,
        }),
      })

      const data = await response.json()
      if (!response.ok) {
        throw new Error(data.error || 'Failed to send invite')
      }

      toast.success(data.resent ? 'Invite resent successfully' : 'Event work invite sent')
      setInviteForm({ fullName: '', email: '', phone: '', role: 'door_staff', offeredRate: '', inviteMessage: '' })
      await loadData()
    } catch (error) {
      toast.error(error instanceof Error ? error.message : 'Failed to send invite')
    } finally {
      setBusyAction(null)
    }
  }

  const handleRevoke = async (person: TeamPerson) => {
    try {
      setBusyAction(`revoke-${person.id}`)
      const response = await fetch(`/api/events/${eventId}/team`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(
          person.kind === 'member'
            ? { action: 'revokeMember', memberId: person.id }
            : { action: 'revokeInvite', inviteId: person.id }
        ),
      })

      const data = await response.json()
      if (!response.ok) {
        throw new Error(data.error || 'Failed to update staff access')
      }

      toast.success(person.kind === 'member' ? 'Team access removed' : 'Invite revoked')
      await loadData()
    } catch (error) {
      toast.error(error instanceof Error ? error.message : 'Failed to update staff access')
    } finally {
      setBusyAction(null)
    }
  }

  const handleSaveShift = async (e: React.FormEvent) => {
    e.preventDefault()

    if (!shiftForm.memberId || !shiftForm.shiftTitle.trim()) {
      toast.error('Choose a staff member and add the work title')
      return
    }

    try {
      setBusyAction('shift')
      const response = await fetch(`/api/events/${eventId}/team`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          action: 'saveShift',
          memberId: shiftForm.memberId,
          shiftTitle: shiftForm.shiftTitle,
          workDate: shiftForm.workDate,
          hoursWorked: Number(shiftForm.hoursWorked || 0),
          notes: shiftForm.notes,
          status: shiftForm.status,
        }),
      })

      const data = await response.json()
      if (!response.ok) {
        throw new Error(data.error || 'Failed to save work log')
      }

      toast.success('Work log saved')
      setShiftForm((prev) => ({ ...prev, shiftTitle: '', hoursWorked: '5', notes: '', status: 'worked' }))
      await loadData()
    } catch (error) {
      toast.error(error instanceof Error ? error.message : 'Failed to save work log')
    } finally {
      setBusyAction(null)
    }
  }

  const handleDeleteShift = async (shiftId: string) => {
    try {
      setBusyAction(`shift-delete-${shiftId}`)
      const response = await fetch(`/api/events/${eventId}/team`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'deleteShift', shiftId }),
      })

      const data = await response.json()
      if (!response.ok) {
        throw new Error(data.error || 'Failed to delete work log')
      }

      toast.success('Work log removed')
      await loadData()
    } catch (error) {
      toast.error(error instanceof Error ? error.message : 'Failed to delete work log')
    } finally {
      setBusyAction(null)
    }
  }

  const handleRecordPayment = async (e: React.FormEvent) => {
    e.preventDefault()

    if (!paymentForm.memberId || Number(paymentForm.amount) <= 0) {
      toast.error('Choose a staff member and add a valid amount')
      return
    }

    try {
      setBusyAction('payment')
      const response = await fetch(`/api/events/${eventId}/team`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          action: 'recordPayment',
          memberId: paymentForm.memberId,
          amount: Number(paymentForm.amount),
          paymentMethod: paymentForm.paymentMethod,
          notes: paymentForm.notes,
          status: paymentForm.status,
        }),
      })

      const data = await response.json()
      if (!response.ok) {
        throw new Error(data.error || 'Failed to save staff payment')
      }

      toast.success(paymentForm.status === 'paid' ? 'Staff payment recorded' : 'Payment plan saved')
      setPaymentForm((prev) => ({ ...prev, amount: '', paymentMethod: 'cash', notes: '', status: 'planned' }))
      await loadData()
    } catch (error) {
      toast.error(error instanceof Error ? error.message : 'Failed to save staff payment')
    } finally {
      setBusyAction(null)
    }
  }

  const handleMarkPaymentPaid = async (paymentId: string) => {
    try {
      setBusyAction(`payment-paid-${paymentId}`)
      const response = await fetch(`/api/events/${eventId}/team`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'markPaymentPaid', paymentId }),
      })

      const data = await response.json()
      if (!response.ok) {
        throw new Error(data.error || 'Failed to update payment')
      }

      toast.success('Payment marked as paid')
      await loadData()
    } catch (error) {
      toast.error(error instanceof Error ? error.message : 'Failed to update payment')
    } finally {
      setBusyAction(null)
    }
  }

  if (loading) {
    return (
      <div className="flex min-h-[320px] items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
      </div>
    )
  }

  return (
    <div className="space-y-6">
      <Card className="border-primary/20 bg-gradient-to-r from-primary/10 via-background to-primary/5">
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <ShieldCheck className="h-5 w-5 text-primary" />
            Event Team and Staff Hub
          </CardTitle>
          <CardDescription>
            Invite trusted staff, log what they worked on, and keep all team payments for {currentEventTitle} in one place.
          </CardDescription>
        </CardHeader>
      </Card>

      <div className="rounded-lg bg-muted/40 p-3 text-sm text-muted-foreground">
        Staff invites only activate <strong>My Work</strong> for event crew. Artists and service providers should still be booked through the normal Ziyawa booking flow.
      </div>

      {isPastEvent && (
        <div className="rounded-lg border border-amber-200 bg-amber-50 p-3 text-sm text-amber-900">
          This event has passed. You can still close payments and review the full staff history here.
        </div>
      )}

      <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-4">
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center gap-3">
              <ShieldCheck className="h-8 w-8 text-primary" />
              <div>
                <p className="text-2xl font-bold">{activeMembers.length}</p>
                <p className="text-sm text-muted-foreground">Active staff</p>
              </div>
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center gap-3">
              <UserPlus className="h-8 w-8 text-blue-600" />
              <div>
                <p className="text-2xl font-bold">{pendingInvites.length}</p>
                <p className="text-sm text-muted-foreground">Pending invites</p>
              </div>
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center gap-3">
              <ClipboardList className="h-8 w-8 text-purple-600" />
              <div>
                <p className="text-2xl font-bold">{shifts.length}</p>
                <p className="text-sm text-muted-foreground">Work logs</p>
              </div>
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center gap-3">
              <Wallet className="h-8 w-8 text-emerald-600" />
              <div>
                <p className="text-2xl font-bold">{formatCurrency(totalPaid)}</p>
                <p className="text-sm text-muted-foreground">Staff paid</p>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      <Tabs defaultValue="team" className="space-y-4">
        <TabsList className="grid w-full grid-cols-2 md:grid-cols-4">
          <TabsTrigger value="team">Invite & Manage</TabsTrigger>
          <TabsTrigger value="work">Work Log</TabsTrigger>
          <TabsTrigger value="payments">Pay Staff</TabsTrigger>
          <TabsTrigger value="history">History</TabsTrigger>
        </TabsList>

        <TabsContent value="team" className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>Invite event staff</CardTitle>
              <CardDescription>Add door staff, guest-list staff, or event ops for this event only.</CardDescription>
            </CardHeader>
            <CardContent>
              <form onSubmit={handleInvite} className="space-y-4">
                <div className="grid gap-3 md:grid-cols-2">
                  <div>
                    <Label htmlFor="team-name">Full name</Label>
                    <Input
                      id="team-name"
                      value={inviteForm.fullName}
                      onChange={(e) => setInviteForm((prev) => ({ ...prev, fullName: e.target.value }))}
                      placeholder="Door staff name"
                      disabled={busyAction === 'invite'}
                    />
                  </div>
                  <div>
                    <Label htmlFor="team-email">Email</Label>
                    <Input
                      id="team-email"
                      type="email"
                      value={inviteForm.email}
                      onChange={(e) => setInviteForm((prev) => ({ ...prev, email: e.target.value }))}
                      placeholder="staff@example.com"
                      disabled={busyAction === 'invite'}
                    />
                  </div>
                </div>

                <div className="grid gap-3 md:grid-cols-2">
                  <div>
                    <Label htmlFor="team-phone">Phone</Label>
                    <Input
                      id="team-phone"
                      value={inviteForm.phone}
                      onChange={(e) => setInviteForm((prev) => ({ ...prev, phone: e.target.value }))}
                      placeholder="Optional phone"
                      disabled={busyAction === 'invite'}
                    />
                  </div>
                  <div>
                    <Label>Role</Label>
                    <Select value={inviteForm.role} onValueChange={(value) => setInviteForm((prev) => ({ ...prev, role: value }))}>
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="door_staff">Door Staff</SelectItem>
                        <SelectItem value="guest_list_staff">Guest List Staff</SelectItem>
                        <SelectItem value="event_ops">Event Ops Lead</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>

                <div className="grid gap-3 md:grid-cols-2">
                  <div>
                    <Label htmlFor="team-rate">Proposed rate</Label>
                    <Input
                      id="team-rate"
                      type="number"
                      min="0"
                      step="0.01"
                      value={inviteForm.offeredRate}
                      onChange={(e) => setInviteForm((prev) => ({ ...prev, offeredRate: e.target.value }))}
                      placeholder="Optional offer amount"
                      disabled={busyAction === 'invite'}
                    />
                    <p className="mt-1 text-xs text-muted-foreground">
                      You can invite at a custom rate. They can accept or message you to discuss it.
                    </p>
                  </div>
                  <div>
                    <Label htmlFor="team-message">Invite note</Label>
                    <Textarea
                      id="team-message"
                      value={inviteForm.inviteMessage}
                      onChange={(e) => setInviteForm((prev) => ({ ...prev, inviteMessage: e.target.value }))}
                      placeholder="Shift details, arrival time, pay expectations..."
                      disabled={busyAction === 'invite'}
                    />
                  </div>
                </div>

                <Button type="submit" disabled={busyAction === 'invite'}>
                  {busyAction === 'invite' ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <UserPlus className="mr-2 h-4 w-4" />}
                  Send invite
                </Button>
              </form>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Current staff and invites</CardTitle>
              <CardDescription>Manage who can work on the event and revoke access when needed.</CardDescription>
            </CardHeader>
            <CardContent className="space-y-3">
              {people.length === 0 ? (
                <div className="rounded-lg border border-dashed p-4 text-sm text-muted-foreground">
                  No event staff added yet.
                </div>
              ) : (
                people.map((person) => (
                  <div key={`${person.kind}-${person.id}`} className="flex flex-col gap-3 rounded-lg border p-3 md:flex-row md:items-center md:justify-between">
                    <div>
                      <div className="flex flex-wrap items-center gap-2">
                        <p className="font-medium">{person.fullName}</p>
                        <Badge variant={person.kind === 'member' ? 'default' : 'secondary'}>
                          {person.kind === 'member' ? 'Active access' : 'Invite'}
                        </Badge>
                        <Badge variant="outline">{person.roleLabel}</Badge>
                      </div>
                      <p className="text-sm text-muted-foreground">
                        {person.email}
                        {person.phone ? ` ΓÇó ${person.phone}` : ''}
                      </p>
                    </div>

                    <Button variant="outline" size="sm" onClick={() => handleRevoke(person)} disabled={busyAction === `revoke-${person.id}`}>
                      {busyAction === `revoke-${person.id}` ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <UserX className="mr-2 h-4 w-4" />}
                      {person.kind === 'member' ? 'Remove' : 'Revoke'}
                    </Button>
                  </div>
                ))
              )}
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="work" className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>Log who worked and what they did</CardTitle>
              <CardDescription>Track shifts, responsibilities, hours, and notes for each staff member.</CardDescription>
            </CardHeader>
            <CardContent>
              {activeMembers.length === 0 ? (
                <div className="rounded-lg border border-dashed p-4 text-sm text-muted-foreground">
                  Add or accept a staff member first to start recording work.
                </div>
              ) : (
                <form onSubmit={handleSaveShift} className="space-y-4">
                  <div className="grid gap-3 md:grid-cols-2">
                    <div>
                      <Label>Staff member</Label>
                      <Select value={shiftForm.memberId} onValueChange={(value) => setShiftForm((prev) => ({ ...prev, memberId: value }))}>
                        <SelectTrigger>
                          <SelectValue placeholder="Choose staff" />
                        </SelectTrigger>
                        <SelectContent>
                          {activeMembers.map((member) => (
                            <SelectItem key={member.id} value={member.id}>
                              {member.fullName} ΓÇó {member.roleLabel}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                    </div>
                    <div>
                      <Label htmlFor="shift-title">Work title</Label>
                      <Input
                        id="shift-title"
                        value={shiftForm.shiftTitle}
                        onChange={(e) => setShiftForm((prev) => ({ ...prev, shiftTitle: e.target.value }))}
                        placeholder="Main gate check-in"
                      />
                    </div>
                  </div>

                  <div className="grid gap-3 md:grid-cols-3">
                    <div>
                      <Label htmlFor="work-date">Date</Label>
                      <Input id="work-date" type="date" value={shiftForm.workDate} onChange={(e) => setShiftForm((prev) => ({ ...prev, workDate: e.target.value }))} />
                    </div>
                    <div>
                      <Label htmlFor="hours-worked">Hours</Label>
                      <Input id="hours-worked" type="number" min="0" step="0.5" value={shiftForm.hoursWorked} onChange={(e) => setShiftForm((prev) => ({ ...prev, hoursWorked: e.target.value }))} />
                    </div>
                    <div>
                      <Label>Status</Label>
                      <Select value={shiftForm.status} onValueChange={(value) => setShiftForm((prev) => ({ ...prev, status: value }))}>
                        <SelectTrigger>
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="scheduled">Scheduled</SelectItem>
                          <SelectItem value="worked">Worked</SelectItem>
                          <SelectItem value="cancelled">Cancelled</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                  </div>

                  <div>
                    <Label htmlFor="work-notes">Notes</Label>
                    <Textarea
                      id="work-notes"
                      value={shiftForm.notes}
                      onChange={(e) => setShiftForm((prev) => ({ ...prev, notes: e.target.value }))}
                      placeholder="Guest list support, VIP wristbands, walkie check, issue handling..."
                    />
                  </div>

                  <Button type="submit" disabled={busyAction === 'shift'}>
                    {busyAction === 'shift' ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <ClipboardList className="mr-2 h-4 w-4" />}
                    Save work log
                  </Button>
                </form>
              )}
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Recent work logs</CardTitle>
              <CardDescription>See who worked for you and what they handled.</CardDescription>
            </CardHeader>
            <CardContent className="space-y-3">
              {shifts.length === 0 ? (
                <div className="rounded-lg border border-dashed p-4 text-sm text-muted-foreground">
                  No work has been logged yet.
                </div>
              ) : (
                shifts.map((shift) => (
                  <div key={shift.id} className="flex flex-col gap-3 rounded-lg border p-3 md:flex-row md:items-center md:justify-between">
                    <div className="space-y-1">
                      <div className="flex flex-wrap items-center gap-2">
                        <p className="font-medium">{shift.fullName}</p>
                        <Badge variant="outline">{shift.roleLabel}</Badge>
                        <Badge variant="secondary">{shift.status}</Badge>
                      </div>
                      <p className="font-medium text-sm">{shift.shiftTitle}</p>
                      <p className="text-sm text-muted-foreground">
                        {formatDate(shift.workDate)} ΓÇó {shift.hoursWorked || 0}h
                      </p>
                      {shift.notes ? <p className="text-sm text-muted-foreground">{shift.notes}</p> : null}
                    </div>

                    <Button variant="outline" size="sm" onClick={() => handleDeleteShift(shift.id)} disabled={busyAction === `shift-delete-${shift.id}`}>
                      {busyAction === `shift-delete-${shift.id}` ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <UserX className="mr-2 h-4 w-4" />}
                      Remove
                    </Button>
                  </div>
                ))
              )}
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="payments" className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>Plan or record staff payments</CardTitle>
              <CardDescription>Keep a clean record of who has been paid, what for, and what is still outstanding.</CardDescription>
            </CardHeader>
            <CardContent>
              {activeMembers.length === 0 ? (
                <div className="rounded-lg border border-dashed p-4 text-sm text-muted-foreground">
                  Add staff members first before recording payments.
                </div>
              ) : (
                <form onSubmit={handleRecordPayment} className="space-y-4">
                  <div className="grid gap-3 md:grid-cols-2">
                    <div>
                      <Label>Staff member</Label>
                      <Select value={paymentForm.memberId} onValueChange={(value) => setPaymentForm((prev) => ({ ...prev, memberId: value }))}>
                        <SelectTrigger>
                          <SelectValue placeholder="Choose staff" />
                        </SelectTrigger>
                        <SelectContent>
                          {activeMembers.map((member) => (
                            <SelectItem key={member.id} value={member.id}>
                              {member.fullName} ΓÇó {member.roleLabel}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                    </div>
                    <div>
                      <Label htmlFor="payment-amount">Amount</Label>
                      <Input
                        id="payment-amount"
                        type="number"
                        min="0"
                        step="0.01"
                        value={paymentForm.amount}
                        onChange={(e) => setPaymentForm((prev) => ({ ...prev, amount: e.target.value }))}
                        placeholder="500"
                      />
                    </div>
                  </div>

                  <div className="grid gap-3 md:grid-cols-2">
                    <div>
                      <Label>Payment method</Label>
                      <Select value={paymentForm.paymentMethod} onValueChange={(value) => setPaymentForm((prev) => ({ ...prev, paymentMethod: value }))}>
                        <SelectTrigger>
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="cash">Cash</SelectItem>
                          <SelectItem value="bank_transfer">Bank transfer</SelectItem>
                          <SelectItem value="wallet">Wallet</SelectItem>
                          <SelectItem value="other">Other</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                    <div>
                      <Label>Status</Label>
                      <Select value={paymentForm.status} onValueChange={(value) => setPaymentForm((prev) => ({ ...prev, status: value }))}>
                        <SelectTrigger>
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="planned">Planned</SelectItem>
                          <SelectItem value="paid">Paid</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                  </div>

                  <div>
                    <Label htmlFor="payment-notes">What is this for?</Label>
                    <Textarea
                      id="payment-notes"
                      value={paymentForm.notes}
                      onChange={(e) => setPaymentForm((prev) => ({ ...prev, notes: e.target.value }))}
                      placeholder="Door shift, VIP support, setup crew, afterparty closeout..."
                    />
                  </div>

                  <Button type="submit" disabled={busyAction === 'payment'}>
                    {busyAction === 'payment' ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <BadgeDollarSign className="mr-2 h-4 w-4" />}
                    Save payment record
                  </Button>
                </form>
              )}
            </CardContent>
          </Card>

          <div className="grid gap-4 md:grid-cols-2">
            <Card>
              <CardHeader>
                <CardTitle>Total paid</CardTitle>
              </CardHeader>
              <CardContent>
                <p className="text-3xl font-bold">{formatCurrency(totalPaid)}</p>
              </CardContent>
            </Card>
            <Card>
              <CardHeader>
                <CardTitle>Still outstanding</CardTitle>
              </CardHeader>
              <CardContent>
                <p className="text-3xl font-bold">{formatCurrency(outstandingPay)}</p>
              </CardContent>
            </Card>
          </div>

          <Card>
            <CardHeader>
              <CardTitle>Payment records</CardTitle>
              <CardDescription>All staff payment entries for this event.</CardDescription>
            </CardHeader>
            <CardContent className="space-y-3">
              {payments.length === 0 ? (
                <div className="rounded-lg border border-dashed p-4 text-sm text-muted-foreground">
                  No staff payments recorded yet.
                </div>
              ) : (
                payments.map((payment) => (
                  <div key={payment.id} className="flex flex-col gap-3 rounded-lg border p-3 md:flex-row md:items-center md:justify-between">
                    <div>
                      <div className="flex flex-wrap items-center gap-2">
                        <p className="font-medium">{payment.fullName}</p>
                        <Badge variant="outline">{payment.roleLabel}</Badge>
                        <Badge variant={payment.status === 'paid' ? 'default' : 'secondary'}>{payment.status === 'paid' ? 'Paid' : 'Planned'}</Badge>
                      </div>
                      <p className="font-semibold">{formatCurrency(payment.amount)}</p>
                      <p className="text-sm text-muted-foreground">
                        {payment.paymentMethod.replace('_', ' ')}
                        {payment.paidAt ? ` ΓÇó ${formatDate(payment.paidAt)}` : ''}
                      </p>
                      {payment.notes ? <p className="text-sm text-muted-foreground">{payment.notes}</p> : null}
                    </div>

                    {payment.status !== 'paid' ? (
                      <Button variant="outline" size="sm" onClick={() => handleMarkPaymentPaid(payment.id)} disabled={busyAction === `payment-paid-${payment.id}`}>
                        {busyAction === `payment-paid-${payment.id}` ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Wallet className="mr-2 h-4 w-4" />}
                        Mark paid
                      </Button>
                    ) : null}
                  </div>
                ))
              )}
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="history" className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>Who worked for you and what they handled</CardTitle>
              <CardDescription>A clean per-person view of work history and pay status.</CardDescription>
            </CardHeader>
            <CardContent className="space-y-3">
              {teamHistory.length === 0 ? (
                <div className="rounded-lg border border-dashed p-4 text-sm text-muted-foreground">
                  No team history yet.
                </div>
              ) : (
