  "Ziwaphi?",
  "Well, you've come to the right place.",
  "Clicka daar!",
]

function SAFlag({ className = '' }: { className?: string }) {
  return (
    <svg viewBox="0 0 120 80" className={`inline-block ${className}`} style={{ width: '1.4em', height: '0.9em', verticalAlign: '-0.1em', marginLeft: '0.3em' }}>
      <defs>
        {/* Wave distortion filter */}
        <filter id="wave">
          <feTurbulence type="turbulence" baseFrequency="0.015 0.08" numOctaves="2" seed="3" result="turbulence">
            <animate attributeName="baseFrequency" values="0.015 0.08;0.02 0.1;0.015 0.08" dur="3s" repeatCount="indefinite" />
          </feTurbulence>
          <feDisplacementMap in="SourceGraphic" in2="turbulence" scale="6" xChannelSelector="R" yChannelSelector="G" />
        </filter>
        <clipPath id="flag-clip">
          <rect x="5" y="5" width="110" height="70" rx="4" />
