        <polygon points="0,14 0,66 26,40" fill="#FFFFFF" />
        <polygon points="0,18 0,62 22,40" fill="#000000" />
        {/* Green band extending from chevron */}
        <polygon points="36,32 60,32 36,40" fill="#007A4D" />
        <polygon points="36,48 60,48 36,40" fill="#007A4D" />
      </g>

      {/* Flagpole */}
      <line x1="5" y1="2" x2="5" y2="78" stroke="#888" strokeWidth="2" strokeLinecap="round" />
      <circle cx="5" cy="3" r="2" fill="#aaa" />

