export function TypewriterHero() {
  const [currentIndex, setCurrentIndex] = useState(0)
  const [currentText, setCurrentText] = useState('')
  const [isTyping, setIsTyping] = useState(true)
  const [showCursor, setShowCursor] = useState(true)

  useEffect(() => {
    if (currentIndex >= phrases.length) {
      // Loop back or stay on last
      setCurrentIndex(0)
      return
    }

    const phrase = phrases[currentIndex]
    let charIndex = 0
    setIsTyping(true)
    setCurrentText('')

    // Type out the phrase
    const typeInterval = setInterval(() => {
      if (charIndex <= phrase.length) {
        setCurrentText(phrase.slice(0, charIndex))
        charIndex++
      } else {
        clearInterval(typeInterval)
        setIsTyping(false)
        
        // Wait, then move to next phrase
        setTimeout(() => {
          setCurrentIndex(prev => (prev + 1) % phrases.length)
        }, 2000) // Show completed text for 2 seconds
      }
    }, 60) // Typing speed

    return () => clearInterval(typeInterval)
  }, [currentIndex])

  // Blinking cursor
  useEffect(() => {
    const cursorInterval = setInterval(() => {
      setShowCursor(prev => !prev)
    }, 500)
    return () => clearInterval(cursorInterval)
  }, [])

  const getTextStyle = () => {
    switch (currentIndex) {
      case 0: return 'text-foreground'
      case 1: return 'text-primary'
      case 2: return 'text-foreground'
      case 3: return 'text-primary text-4xl md:text-6xl lg:text-7xl'
      default: return 'text-foreground'
    }
  }

  return (
    <div className="min-h-[120px] md:min-h-[160px] flex flex-col items-center justify-center">
      <h1 className={`text-3xl md:text-5xl lg:text-6xl font-bold transition-all duration-300 ${getTextStyle()}`}>
        {currentText}
        {currentIndex === 0 && currentText.length === phrases[0].length && <SAFlag />}
      </h1>
      
      {/* Show arrow on last phrase when done typing */}
      {currentIndex === 3 && !isTyping && (
        <div className="mt-6 animate-bounce text-2xl">
          ≡ƒæç
        </div>
      )}
    </div>
  )
}

'use client'

/**
 * MediaUploader Component
 * 
 * Drag & drop file upload with preview.
 * Supports images, videos, and audio files.
 */

import { useState, useCallback, useRef } from 'react'
import { Upload, X, Image as ImageIcon, Video, Music, Loader2 } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { cn } from '@/lib/utils'

interface MediaUploaderProps {
  onUpload: (file: File) => Promise<{ success: boolean; url?: string; error?: string }>
  accept?: 'image' | 'video' | 'audio' | 'all'
  maxSize?: number // in MB
  multiple?: boolean
  className?: string
  disabled?: boolean
  placeholder?: string
}

interface UploadingFile {
  file: File
  preview?: string
  progress: number
  error?: string
}

export function MediaUploader({
  onUpload,
  accept = 'image',
  maxSize = 10,
  multiple = false,
  className,
  disabled = false,
  placeholder
}: MediaUploaderProps) {
  const [isDragging, setIsDragging] = useState(false)
  const [uploading, setUploading] = useState<UploadingFile[]>([])
  const inputRef = useRef<HTMLInputElement>(null)

  // Determine accepted file types
  const acceptedTypes = {
    image: 'image/jpeg,image/png,image/webp,image/gif',
    video: 'video/mp4,video/webm,video/quicktime',
    audio: 'audio/mpeg,audio/mp3,audio/wav',
    all: 'image/*,video/mp4,video/webm,audio/*'
  }

  const getFileIcon = (type: string) => {
    if (type.startsWith('video/')) return <Video className="h-8 w-8" />
    if (type.startsWith('audio/')) return <Music className="h-8 w-8" />
    return <ImageIcon className="h-8 w-8" />
  }

  const validateFile = (file: File): string | null => {
    const maxBytes = maxSize * 1024 * 1024
    if (file.size > maxBytes) {
      return `File too large. Maximum size is ${maxSize}MB`
    }

    const allowedTypes = acceptedTypes[accept].split(',')
    const isAllowed = allowedTypes.some(type => {
      if (type.endsWith('/*')) {
        return file.type.startsWith(type.replace('/*', '/'))
      }
      return file.type === type
    })

    if (!isAllowed) {
      return `Invalid file type. Allowed: ${accept}`
    }

    return null
  }

  const handleFiles = useCallback(async (files: FileList | File[]) => {
    const fileArray = Array.from(files)
    const filesToUpload = multiple ? fileArray : [fileArray[0]]

    for (const file of filesToUpload) {
      const error = validateFile(file)
      
      // Create preview for images
      let preview: string | undefined
      if (file.type.startsWith('image/')) {
        preview = URL.createObjectURL(file)
      }

      const uploadingFile: UploadingFile = {
        file,
        preview,
        progress: 0,
        error: error || undefined
      }

      setUploading(prev => [...prev, uploadingFile])

      if (!error) {
        try {
          setUploading(prev => 
            prev.map(u => u.file === file ? { ...u, progress: 50 } : u)
          )

          const result = await onUpload(file)

          if (result.success) {
            // Remove from uploading list on success
            setUploading(prev => prev.filter(u => u.file !== file))
          } else {
            setUploading(prev => 
              prev.map(u => u.file === file ? { ...u, error: result.error, progress: 0 } : u)
            )
          }
        } catch (err) {
          setUploading(prev => 
            prev.map(u => u.file === file ? { 
              ...u, 
              error: err instanceof Error ? err.message : 'Upload failed',
              progress: 0 
            } : u)
          )
        }
      }
    }
  }, [multiple, maxSize, accept, onUpload])

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault()
    e.stopPropagation()
    if (!disabled) setIsDragging(true)
  }, [disabled])

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault()
    e.stopPropagation()
    setIsDragging(false)
  }, [])

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault()
    e.stopPropagation()
    setIsDragging(false)
    
    if (disabled) return
    if (e.dataTransfer.files?.length) {
      handleFiles(e.dataTransfer.files)
    }
  }, [disabled, handleFiles])

  const handleClick = () => {
    if (!disabled) inputRef.current?.click()
  }

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.length) {
      handleFiles(e.target.files)
      e.target.value = '' // Reset to allow same file
    }
  }

  const removeFile = (file: File) => {
    setUploading(prev => {
      const item = prev.find(u => u.file === file)
      if (item?.preview) URL.revokeObjectURL(item.preview)
      return prev.filter(u => u.file !== file)
    })
  }

  const defaultPlaceholder = {
    image: 'Drop images here or click to upload',
    video: 'Drop videos here or click to upload',
    audio: 'Drop audio files here or click to upload',
    all: 'Drop files here or click to upload'
  }

  return (
    <div className={className}>
      {/* Drop Zone */}
      <div
        onClick={handleClick}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
        className={cn(
          'relative border-2 border-dashed rounded-lg p-8 transition-colors cursor-pointer',
          'flex flex-col items-center justify-center gap-3 min-h-[160px]',
          isDragging && 'border-black bg-gray-50',
          !isDragging && 'border-gray-300 hover:border-gray-400',
          disabled && 'opacity-50 cursor-not-allowed'
        )}
      >
        <input
          ref={inputRef}
          type="file"
          accept={acceptedTypes[accept]}
          multiple={multiple}
          onChange={handleInputChange}
          className="hidden"
          disabled={disabled}
        />
        
        <Upload className="h-10 w-10 text-gray-400" />
        <p className="text-sm text-gray-600 text-center">
          {placeholder || defaultPlaceholder[accept]}
        </p>
        <p className="text-xs text-gray-400">
          Max {maxSize}MB {multiple ? 'ΓÇó Multiple files allowed' : ''}
        </p>
      </div>

      {/* Uploading Files */}
      {uploading.length > 0 && (
        <div className="mt-4 space-y-3">
          {uploading.map((item, index) => (
            <div
              key={`${item.file.name}-${index}`}
              className={cn(
                'flex items-center gap-3 p-3 rounded-lg border',
                item.error ? 'border-red-200 bg-red-50' : 'border-gray-200 bg-gray-50'
              )}
            >
              {/* Preview or Icon */}
              <div className="flex-shrink-0 w-12 h-12 bg-gray-200 rounded flex items-center justify-center overflow-hidden">
                {item.preview ? (
                  <img 
                    src={item.preview} 
                    alt="" 
                    className="w-full h-full object-cover" 
                  />
                ) : (
                  getFileIcon(item.file.type)
                )}
              </div>

              {/* File Info */}
              <div className="flex-1 min-w-0">
                <p className="text-sm font-medium truncate">{item.file.name}</p>
                <p className="text-xs text-gray-500">
                  {(item.file.size / (1024 * 1024)).toFixed(2)} MB
                </p>
                {item.error && (
                  <p className="text-xs text-red-600 mt-1">{item.error}</p>
                )}
              </div>

              {/* Progress or Actions */}
              <div className="flex-shrink-0">
                {item.progress > 0 && !item.error ? (
                  <Loader2 className="h-5 w-5 animate-spin text-gray-400" />
                ) : (
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => removeFile(item.file)}
                    className="h-8 w-8 p-0"
                  >
                    <X className="h-4 w-4" />
                  </Button>
                )}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

'use client'

/**
 * Social Links Components
 * 
 * Form for adding/editing social media links
 * Display component with platform icons
 */

import { useState } from 'react'
import { 
  Instagram, 
  Twitter, 
  Facebook, 
  Youtube,
  Music2,
  Globe,
  Linkedin,
  Plus,
  Trash2,
  ExternalLink
} from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { validateSocialUrl, normalizeSocialUrl } from '@/lib/storage'
import { cn } from '@/lib/utils'

// Social platform definitions
export const SOCIAL_PLATFORMS = {
  instagram: { name: 'Instagram', icon: Instagram, color: '#E4405F', placeholder: 'https://instagram.com/username' },
  twitter: { name: 'X (Twitter)', icon: Twitter, color: '#000000', placeholder: 'https://x.com/username' },
  facebook: { name: 'Facebook', icon: Facebook, color: '#1877F2', placeholder: 'https://facebook.com/page' },
  youtube: { name: 'YouTube', icon: Youtube, color: '#FF0000', placeholder: 'https://youtube.com/@channel' },
  tiktok: { name: 'TikTok', icon: Music2, color: '#000000', placeholder: 'https://tiktok.com/@username' },
  linkedin: { name: 'LinkedIn', icon: Linkedin, color: '#0A66C2', placeholder: 'https://linkedin.com/in/username' },
  soundcloud: { name: 'SoundCloud', icon: Music2, color: '#FF5500', placeholder: 'https://soundcloud.com/artist' },
  spotify: { name: 'Spotify', icon: Music2, color: '#1DB954', placeholder: 'https://open.spotify.com/artist/...' },
  website: { name: 'Website', icon: Globe, color: '#000000', placeholder: 'https://yourwebsite.com' }
} as const

export type SocialPlatform = keyof typeof SOCIAL_PLATFORMS

export interface SocialLink {
  platform: SocialPlatform
  url: string
}

// =====================================================
// SOCIAL LINKS FORM
// =====================================================

interface SocialLinksFormProps {
  links: SocialLink[]
  onChange: (links: SocialLink[]) => void
  className?: string
}

export function SocialLinksForm({ links, onChange, className }: SocialLinksFormProps) {
  const [newPlatform, setNewPlatform] = useState<SocialPlatform | ''>('')
  const [newUrl, setNewUrl] = useState('')
  const [error, setError] = useState('')

  const availablePlatforms = Object.keys(SOCIAL_PLATFORMS).filter(
    p => !links.some(l => l.platform === p)
  ) as SocialPlatform[]

  const handleAdd = () => {
    setError('')

    if (!newPlatform) {
      setError('Select a platform')
      return
    }

    if (!newUrl.trim()) {
      setError('Enter your profile URL')
      return
    }

    const normalizedUrl = normalizeSocialUrl(newUrl)
    const validation = validateSocialUrl(normalizedUrl)

    if (!validation.valid) {
      setError(validation.error || 'Invalid URL')
      return
    }

    onChange([...links, { platform: newPlatform, url: normalizedUrl }])
    setNewPlatform('')
    setNewUrl('')
  }

  const handleRemove = (platform: SocialPlatform) => {
    onChange(links.filter(l => l.platform !== platform))
  }

  const handleUpdate = (platform: SocialPlatform, url: string) => {
    onChange(links.map(l => l.platform === platform ? { ...l, url: normalizeSocialUrl(url) } : l))
  }

  return (
    <div className={cn('space-y-4', className)}>
      {/* Existing Links */}
      {links.map(link => {
        const platform = SOCIAL_PLATFORMS[link.platform]
        const Icon = platform.icon

        return (
          <div key={link.platform} className="flex items-center gap-3">
            <div 
              className="flex-shrink-0 w-10 h-10 rounded-lg flex items-center justify-center"
              style={{ backgroundColor: `${platform.color}15` }}
            >
              <Icon className="h-5 w-5" style={{ color: platform.color }} />
            </div>
            
            <div className="flex-1">
              <Label className="text-xs text-gray-500">{platform.name}</Label>
              <Input
                value={link.url}
                onChange={(e) => handleUpdate(link.platform, e.target.value)}
                placeholder={platform.placeholder}
                className="mt-1"
              />
            </div>

            <Button
              variant="ghost"
              size="sm"
              onClick={() => handleRemove(link.platform)}
              className="flex-shrink-0 h-10 w-10 p-0 text-gray-400 hover:text-red-500"
            >
              <Trash2 className="h-4 w-4" />
            </Button>
          </div>
        )
      })}

      {/* Add New Link */}
      {availablePlatforms.length > 0 && (
        <div className="pt-4 border-t border-gray-100">
          <Label className="text-sm font-medium">Add social link</Label>
          
          <div className="mt-2 flex flex-wrap gap-2">
            {availablePlatforms.map(platformKey => {
              const platform = SOCIAL_PLATFORMS[platformKey]
              const Icon = platform.icon
              const isSelected = newPlatform === platformKey

              return (
                <button
                  key={platformKey}
                  type="button"
                  onClick={() => setNewPlatform(platformKey)}
                  className={cn(
                    'flex items-center gap-2 px-3 py-2 rounded-lg border transition-colors',
                    isSelected 
                      ? 'border-black bg-gray-50' 
                      : 'border-gray-200 hover:border-gray-300'
                  )}
                >
                  <Icon className="h-4 w-4" style={{ color: platform.color }} />
                  <span className="text-sm">{platform.name}</span>
                </button>
              )
            })}
          </div>

          {newPlatform && (
            <div className="mt-3 flex gap-2">
              <Input
                value={newUrl}
                onChange={(e) => setNewUrl(e.target.value)}
                placeholder={SOCIAL_PLATFORMS[newPlatform].placeholder}
                className="flex-1"
              />
              <Button onClick={handleAdd}>
                <Plus className="h-4 w-4 mr-1" />
                Add
              </Button>
            </div>
          )}

          {error && (
            <p className="mt-2 text-sm text-red-600">{error}</p>
          )}
        </div>
      )}

      {links.length === 0 && availablePlatforms.length === Object.keys(SOCIAL_PLATFORMS).length && (
        <p className="text-sm text-gray-500 text-center py-4">
          No social links added yet. Click a platform above to add one.
        </p>
      )}
    </div>
  )
}

// =====================================================
// SOCIAL LINKS DISPLAY
// =====================================================

interface SocialLinksDisplayProps {
  links: SocialLink[]
  size?: 'sm' | 'md' | 'lg'
  showLabels?: boolean
  className?: string
}

export function SocialLinksDisplay({ 
  links, 
  size = 'md', 
  showLabels = false,
  className 
}: SocialLinksDisplayProps) {
  if (links.length === 0) return null

  const sizeClasses = {
    sm: 'h-8 w-8',
    md: 'h-10 w-10',
    lg: 'h-12 w-12'
  }

  const iconSizes = {
    sm: 'h-4 w-4',
    md: 'h-5 w-5',
    lg: 'h-6 w-6'
  }

  return (
    <div className={cn('flex flex-wrap gap-2', className)}>
      {links.map(link => {
        const platform = SOCIAL_PLATFORMS[link.platform]
        if (!platform) return null
        
        const Icon = platform.icon

        return (
          <a
            key={link.platform}
            href={link.url}
            target="_blank"
            rel="noopener noreferrer"
            className={cn(
              'flex items-center gap-2 rounded-lg transition-colors',
              showLabels 
                ? 'px-3 py-2 border border-gray-200 hover:border-gray-300'
                : cn(sizeClasses[size], 'justify-center hover:bg-gray-100')
            )}
            title={platform.name}
          >
            <Icon className={iconSizes[size]} style={{ color: platform.color }} />
            {showLabels && (
              <span className="text-sm">{platform.name}</span>
            )}
          </a>
        )
      })}
    </div>
  )
}

// =====================================================
// SOCIAL LINK ICON (Single)
// =====================================================

interface SocialLinkIconProps {
  platform: SocialPlatform
  url: string
  size?: 'sm' | 'md' | 'lg'
  className?: string
}

export function SocialLinkIcon({ platform, url, size = 'md', className }: SocialLinkIconProps) {
  const platformData = SOCIAL_PLATFORMS[platform]
  if (!platformData) return null

  const Icon = platformData.icon
  
  const sizeClasses = {
    sm: 'h-8 w-8',
    md: 'h-10 w-10',
    lg: 'h-12 w-12'
  }

  const iconSizes = {
    sm: 'h-4 w-4',
    md: 'h-5 w-5',
    lg: 'h-6 w-6'
  }

  return (
    <a
      href={url}
      target="_blank"
      rel="noopener noreferrer"
      className={cn(
        'flex items-center justify-center rounded-lg transition-colors hover:bg-gray-100',
        sizeClasses[size],
        className
      )}
      title={platformData.name}
    >
      <Icon className={iconSizes[size]} style={{ color: platformData.color }} />
    </a>
  )
}

'use client'

/**
 * VideoEmbed Component
 * 
 * Embeds YouTube, TikTok, and other video platforms.
 * Handles URL parsing and responsive embedding.
 */

import { useState } from 'react'
import { Play, ExternalLink, Trash2 } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { extractYouTubeId, extractTikTokId, getYouTubeEmbedUrl, getYouTubeThumbnail } from '@/lib/storage'
import { cn } from '@/lib/utils'

interface VideoEmbedProps {
  url: string
  title?: string
  className?: string
}

interface VideoInputProps {
  onAdd: (url: string, platform: string) => void
  className?: string
}

interface VideoGridProps {
  videos: Array<{ url: string; title?: string; platform?: string }>
  onDelete?: (url: string) => void
  editable?: boolean
  className?: string
}

/**
 * Single Video Embed Display
 */
export function VideoEmbed({ url, title, className }: VideoEmbedProps) {
  const [isPlaying, setIsPlaying] = useState(false)
  
  // Detect platform
  const youtubeId = extractYouTubeId(url)
  const tiktokId = extractTikTokId(url)

  if (youtubeId) {
    return (
      <div className={cn('relative aspect-video rounded-lg overflow-hidden bg-black', className)}>
        {!isPlaying ? (
          // Thumbnail with play button
          <div 
            className="absolute inset-0 cursor-pointer group"
            onClick={() => setIsPlaying(true)}
          >
            <img
              src={getYouTubeThumbnail(youtubeId, 'hq')}
              alt={title || 'Video thumbnail'}
              className="w-full h-full object-cover"
            />
            <div className="absolute inset-0 bg-black/30 group-hover:bg-black/40 transition-colors" />
            <div className="absolute inset-0 flex items-center justify-center">
              <div className="w-16 h-16 bg-red-600 rounded-full flex items-center justify-center group-hover:scale-110 transition-transform">
                <Play className="h-8 w-8 text-white ml-1" fill="white" />
              </div>
            </div>
          </div>
        ) : (
          // YouTube embed
          <iframe
            src={`${getYouTubeEmbedUrl(youtubeId)}?autoplay=1`}
            title={title || 'YouTube video'}
            allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
            allowFullScreen
            className="absolute inset-0 w-full h-full"
          />
        )}
      </div>
    )
  }

  if (tiktokId) {
    return (
      <div className={cn('relative rounded-lg overflow-hidden bg-black', className)}>
        <blockquote 
          className="tiktok-embed" 
          cite={url}
          data-video-id={tiktokId}
        >
          <a href={url} target="_blank" rel="noopener noreferrer">
            View on TikTok
          </a>
        </blockquote>
        <script async src="https://www.tiktok.com/embed.js"></script>
      </div>
    )
  }

  // Fallback - external link
  return (
    <a 
      href={url}
      target="_blank"
      rel="noopener noreferrer"
      className={cn(
        'flex items-center gap-2 p-4 rounded-lg border border-gray-200',
        'hover:border-gray-300 transition-colors',
        className
      )}
    >
      <Play className="h-5 w-5 text-gray-500" />
      <span className="flex-1 truncate text-sm">{title || url}</span>
      <ExternalLink className="h-4 w-4 text-gray-400" />
    </a>
  )
}

/**
 * Video URL Input Form
 */
export function VideoInput({ onAdd, className }: VideoInputProps) {
  const [url, setUrl] = useState('')
  const [error, setError] = useState('')

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    setError('')

    if (!url.trim()) {
      setError('Please enter a video URL')
      return
    }

    // Detect platform
    const youtubeId = extractYouTubeId(url)
    const tiktokId = extractTikTokId(url)

    if (!youtubeId && !tiktokId) {
      setError('Only YouTube and TikTok links are supported')
      return
    }

    const platform = youtubeId ? 'youtube' : 'tiktok'
    onAdd(url.trim(), platform)
    setUrl('')
  }

  return (
    <form onSubmit={handleSubmit} className={cn('space-y-2', className)}>
      <div className="flex gap-2">
        <Input
          type="url"
          value={url}
          onChange={(e) => setUrl(e.target.value)}
          placeholder="Paste YouTube or TikTok link..."
          className="flex-1"
        />
        <Button type="submit">
          Add Video
        </Button>
      </div>
      {error && (
        <p className="text-sm text-red-600">{error}</p>
      )}
      <p className="text-xs text-gray-500">
        Supports YouTube and TikTok video links
      </p>
    </form>
  )
}

/**
 * Video Grid Display
 */
export function VideoGrid({ videos, onDelete, editable = false, className }: VideoGridProps) {
  if (videos.length === 0) {
    return (
      <div className={cn('text-center py-12 text-gray-500', className)}>
        <Play className="h-12 w-12 mx-auto mb-3 text-gray-300" />
        <p>No videos yet</p>
      </div>
    )
  }

  return (
    <div className={cn('grid grid-cols-1 md:grid-cols-2 gap-4', className)}>
      {videos.map((video, index) => (
        <div key={video.url || index} className="relative group">
          <VideoEmbed url={video.url} title={video.title} />
          
          {editable && onDelete && (
            <Button
              variant="ghost"
              size="sm"
              className={cn(
                'absolute top-2 right-2 h-8 w-8 p-0 z-10',
                'bg-white/90 hover:bg-red-500 hover:text-white',
                'opacity-0 group-hover:opacity-100 transition-opacity'
              )}
              onClick={() => onDelete(video.url)}
            >
              <Trash2 className="h-4 w-4" />
            </Button>
          )}
        </div>
      ))}
    </div>
  )
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { Bell, Check, CheckCheck, Trash2, X } from 'lucide-react';
import { Button } from '@/components/ui/button';
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from '@/components/ui/popover';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Separator } from '@/components/ui/separator';
import { cn } from '@/lib/utils';
import { formatDistanceToNow } from 'date-fns';

interface Notification {
  id: string;
  type: string;
  title: string;
  message: string;
  read: boolean;
  link: string | null;
  created_at: string;
}

interface NotificationsResponse {
  notifications: Notification[];
  total: number;
  unreadCount: number;
  hasMore: boolean;
}

export function NotificationCenter() {
  const [open, setOpen] = useState(false);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [unreadCount, setUnreadCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [hasMore, setHasMore] = useState(false);

  const fetchNotifications = useCallback(async () => {
    try {
      setLoading(true);
      const res = await fetch('/api/notifications?limit=10');
      if (res.ok) {
        const data: NotificationsResponse = await res.json();
        setNotifications(data.notifications);
        setUnreadCount(data.unreadCount);
        setHasMore(data.hasMore);
      }
    } catch (error) {
      console.error('Failed to fetch notifications:', error);
    } finally {
      setLoading(false);
    }
  }, []);

  // Fetch on mount and when popover opens
  useEffect(() => {
    fetchNotifications();
  }, [fetchNotifications]);

  useEffect(() => {
    if (open) {
      fetchNotifications();
    }
  }, [open, fetchNotifications]);

  // Poll for new notifications every 30 seconds
  useEffect(() => {
    const interval = setInterval(() => {
      if (!open) {
        // Only update count when popover is closed
        fetch('/api/notifications?limit=1')
          .then(res => res.json())
          .then((data: NotificationsResponse) => {
            setUnreadCount(data.unreadCount);
          })
          .catch(console.error);
      }
    }, 30000);

    return () => clearInterval(interval);
  }, [open]);

  const markAsRead = async (notificationId: string) => {
    try {
      await fetch('/api/notifications', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ notificationId }),
      });

      setNotifications(prev =>
        prev.map(n =>
          n.id === notificationId ? { ...n, read: true } : n
        )
      );
      setUnreadCount(prev => Math.max(0, prev - 1));
    } catch (error) {
      console.error('Failed to mark as read:', error);
    }
  };

  const markAllAsRead = async () => {
    try {
      await fetch('/api/notifications', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ markAllRead: true }),
      });

      setNotifications(prev =>
        prev.map(n => ({ ...n, read: true }))
      );
      setUnreadCount(0);
    } catch (error) {
      console.error('Failed to mark all as read:', error);
    }
  };

  const deleteNotification = async (notificationId: string) => {
    try {
      await fetch(`/api/notifications?id=${notificationId}`, {
        method: 'DELETE',
      });

      const notification = notifications.find(n => n.id === notificationId);
      setNotifications(prev => prev.filter(n => n.id !== notificationId));
      if (notification && !notification.read) {
        setUnreadCount(prev => Math.max(0, prev - 1));
      }
    } catch (error) {
      console.error('Failed to delete notification:', error);
    }
  };

  const handleNotificationClick = (notification: Notification) => {
    if (!notification.read) {
      markAsRead(notification.id);
    }
    if (notification.link) {
      setOpen(false);
      window.location.href = notification.link;
    }
  };

  const getNotificationIcon = (type: string) => {
    // Map notification types to icons/colors
    const typeIcons: Record<string, { bg: string; text: string }> = {
      booking_request: { bg: 'bg-blue-100', text: 'text-blue-600' },
      booking_confirmed: { bg: 'bg-green-100', text: 'text-green-600' },
      booking_declined: { bg: 'bg-red-100', text: 'text-red-600' },
      booking_cancelled: { bg: 'bg-orange-100', text: 'text-orange-600' },
      payment_received: { bg: 'bg-green-100', text: 'text-green-600' },
      payment_failed: { bg: 'bg-red-100', text: 'text-red-600' },
      payout_processed: { bg: 'bg-green-100', text: 'text-green-600' },
      ticket_purchased: { bg: 'bg-purple-100', text: 'text-purple-600' },
      ticket_checkin: { bg: 'bg-emerald-100', text: 'text-emerald-600' },
      event_reminder: { bg: 'bg-yellow-100', text: 'text-yellow-600' },
      event_updated: { bg: 'bg-amber-100', text: 'text-amber-700' },
      review_received: { bg: 'bg-pink-100', text: 'text-pink-600' },
      review_requested: { bg: 'bg-pink-100', text: 'text-pink-600' },
      message_received: { bg: 'bg-indigo-100', text: 'text-indigo-600' },
      system: { bg: 'bg-gray-100', text: 'text-gray-600' },
    };

    return typeIcons[type] || typeIcons.system;
  };

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button
          variant="ghost"
          size="icon"
          className="relative"
          aria-label="Notifications"
        >
          <Bell className="h-5 w-5" />
          {unreadCount > 0 && (
            <span className="absolute -top-1 -right-1 flex h-5 w-5 items-center justify-center rounded-full bg-primary text-[10px] font-medium text-primary-foreground">
              {unreadCount > 99 ? '99+' : unreadCount}
            </span>
          )}
        </Button>
      </PopoverTrigger>
      <PopoverContent
        className="w-80 p-0"
        align="end"
        sideOffset={8}
      >
        {/* Header */}
        <div className="flex items-center justify-between border-b px-4 py-3">
          <div>
            <h4 className="font-semibold">Notifications</h4>
            {unreadCount > 0 && (
              <p className="text-xs text-muted-foreground">
                {unreadCount} unread
              </p>
            )}
          </div>
          {unreadCount > 0 && (
            <Button
              variant="ghost"
              size="sm"
              onClick={markAllAsRead}
              className="h-8 text-xs"
            >
              <CheckCheck className="mr-1 h-3 w-3" />
              Mark all read
            </Button>
          )}
        </div>

        {/* Notifications List */}
        <ScrollArea className="h-[400px]">
          {loading && notifications.length === 0 ? (
            <div className="flex items-center justify-center py-8">
              <div className="h-5 w-5 animate-spin rounded-full border-2 border-primary border-t-transparent" />
            </div>
          ) : notifications.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-12 text-center">
              <Bell className="h-10 w-10 text-muted-foreground/50 mb-2" />
              <p className="text-sm font-medium text-muted-foreground">
                No notifications yet
              </p>
              <p className="text-xs text-muted-foreground/70">
                You&apos;re all caught up!
              </p>
            </div>
          ) : (
            <div>
              {notifications.map((notification, index) => (
                <div key={notification.id}>
                  <div
                    className={cn(
                      'flex gap-3 px-4 py-3 cursor-pointer hover:bg-muted/50 transition-colors',
                      !notification.read && 'bg-primary/5'
                    )}
                    onClick={() => handleNotificationClick(notification)}
                  >
                    {/* Icon */}
                    <div
                      className={cn(
                        'flex h-8 w-8 shrink-0 items-center justify-center rounded-full',
                        getNotificationIcon(notification.type).bg,
                        getNotificationIcon(notification.type).text
                      )}
                    >
                      <Bell className="h-4 w-4" />
                    </div>

                    {/* Content */}
                    <div className="flex-1 min-w-0">
                      <div className="flex items-start justify-between gap-2">
                        <p
                          className={cn(
                            'text-sm line-clamp-1',
                            !notification.read && 'font-semibold'
                          )}
                        >
                          {notification.title}
                        </p>
                        {!notification.read && (
                          <span className="h-2 w-2 shrink-0 rounded-full bg-primary" />
                        )}
                      </div>
                      <p className="text-xs text-muted-foreground line-clamp-2 mt-0.5">
                        {notification.message}
                      </p>
                      <p className="text-[10px] text-muted-foreground/70 mt-1">
                        {formatDistanceToNow(new Date(notification.created_at), {
                          addSuffix: true,
                        })}
                      </p>
                    </div>

                    {/* Actions */}
                    <div className="flex shrink-0 gap-1">
                      {!notification.read && (
                        <Button
                          variant="ghost"
                          size="icon"
                          className="h-7 w-7"
                          onClick={(e) => {
                            e.stopPropagation();
                            markAsRead(notification.id);
                          }}
                          title="Mark as read"
                        >
                          <Check className="h-3.5 w-3.5" />
                        </Button>
                      )}
                      <Button
                        variant="ghost"
                        size="icon"
                        className="h-7 w-7 text-muted-foreground hover:text-destructive"
                        onClick={(e) => {
                          e.stopPropagation();
                          deleteNotification(notification.id);
                        }}
                        title="Delete"
                      >
                        <X className="h-3.5 w-3.5" />
                      </Button>
                    </div>
                  </div>
                  {index < notifications.length - 1 && <Separator />}
                </div>
              ))}

              {hasMore && (
                <div className="p-4 text-center">
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => {
                      setOpen(false);
                      window.location.href = '/dashboard/notifications';
                    }}
                  >
                    View all notifications
                  </Button>
                </div>
              )}
            </div>
          )}
        </ScrollArea>

        {/* Footer */}
        <Separator />
        <div className="p-2">
          <Button
            variant="ghost"
            size="sm"
            className="w-full text-xs"
            onClick={() => {
              setOpen(false);
              window.location.href = '/dashboard/settings/notifications';
            }}
          >
            Notification preferences
          </Button>
        </div>
      </PopoverContent>
    </Popover>
  );
}

'use client'

import { useEffect, useState } from 'react'
import { useRouter } from 'next/navigation'
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Separator } from '@/components/ui/separator'
import { formatCurrency } from '@/lib/helpers'
import { calculateTicketSaleBreakdown } from '@/lib/constants'
import { toast } from 'sonner'
import type { Event, Profile } from '@/types/database'
import { Loader2, CreditCard, Shield, Gift } from 'lucide-react'
import type { EventTicketTier } from '@/lib/ticketing'

interface PaymentDialogProps {
  open: boolean
  onOpenChange: (open: boolean) => void
  event: Event
  user: Profile
  quantity?: number
  selectedTier?: EventTicketTier
}

interface TicketAttendeeInput {
  fullName: string
  email: string
  phone: string
}

export function PaymentDialog({ open, onOpenChange, event, user, quantity = 1, selectedTier }: PaymentDialogProps) {
  const [loading, setLoading] = useState(false)
  const [attendees, setAttendees] = useState<TicketAttendeeInput[]>([])
  const router = useRouter()

  // Calculate fees using our fee structure
  const unitPrice = Number(selectedTier?.price ?? event.ticket_price ?? 0)
  const ticketBasePriceCents = unitPrice * 100 * quantity // Convert Rands to cents
  const breakdown = calculateTicketSaleBreakdown(ticketBasePriceCents)
  const totalAmount = breakdown.buyerTotal // This is what the buyer pays (in cents)

  useEffect(() => {
    if (!open) return

    setAttendees((current) => Array.from({ length: quantity }, (_, index) => current[index] || {
      fullName: user.full_name || '',
      email: user.email || '',
      phone: '',
    }))
  }, [open, quantity, user.email, user.full_name])

  const updateAttendee = (index: number, field: keyof TicketAttendeeInput, value: string) => {
    setAttendees((current) => current.map((attendee, attendeeIndex) => (
      attendeeIndex === index
        ? { ...attendee, [field]: value }
        : attendee
    )))
  }

  const giftedCount = attendees.filter((attendee) => attendee.email.trim().toLowerCase() !== (user.email || '').trim().toLowerCase()).length

  const handlePayment = async () => {
    setLoading(true)

    try {
      const cleanedAttendees = attendees.map((attendee) => ({
        fullName: attendee.fullName.trim(),
        email: attendee.email.trim(),
        phone: attendee.phone.trim(),
      }))

      const hasMissingDetails = cleanedAttendees.some((attendee) => !attendee.fullName || !attendee.email)
      if (hasMissingDetails) {
        throw new Error('Please add a full name and email for each ticket holder')
      }

      // Call our ticket purchase API
      const response = await fetch('/api/payments/ticket', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          eventId: event.id,
          quantity: quantity,
          ticketTypeId: selectedTier?.id && !selectedTier.id.startsWith('legacy-') ? selectedTier.id : undefined,
          ticketTypeName: selectedTier?.name,
          attendees: cleanedAttendees,
        }),
      })

      const data = await response.json()

      if (!response.ok) {
        throw new Error(data.error || 'Failed to initialize payment')
      }

      // Redirect to Paystack checkout
      const authUrl = data.data?.authorization_url || data.authorizationUrl || data.authorization_url
      if (authUrl) {
        window.location.href = authUrl
      } else {
        throw new Error('No payment URL received')
      }
      
    } catch (error) {
      console.error('Payment error:', error)
      toast.error(error instanceof Error ? error.message : 'Payment failed. Please try again.')
      setLoading(false)
    }
    // Note: We don't setLoading(false) on success because we're redirecting
  }

  const handleClose = () => {
    if (!loading) {
      onOpenChange(false)
    }
  }

  return (
    <Dialog open={open} onOpenChange={handleClose}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle>Complete Your Purchase</DialogTitle>
          <DialogDescription>
            You&apos;re buying {quantity} {selectedTier?.name || 'ticket'}{quantity > 1 ? 's' : ''} for {event.title}
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-4 py-4">
          {/* Order Summary */}
          <div className="space-y-2">
            {selectedTier && (
              <div className="flex justify-between text-sm text-muted-foreground">
                <span>Tier</span>
                <span>{selectedTier.name}</span>
              </div>
            )}
            <div className="flex justify-between">
              <span>Ticket Price {quantity > 1 ? `(${quantity}x)` : ''}</span>
              <span>{formatCurrency(breakdown.ticketPrice / 100)}</span>
            </div>
            <div className="flex justify-between text-sm text-muted-foreground">
              <span>Booking Fee</span>
              <span>{formatCurrency(breakdown.bookingFee / 100)}</span>
            </div>
            <Separator />
            <div className="flex justify-between font-bold text-lg">
              <span>Total</span>
              <span>{formatCurrency(totalAmount / 100)}</span>
            </div>
          </div>

          <div className="rounded-lg border p-4 space-y-3">
            <div className="flex items-center gap-2">
              <Gift className="h-4 w-4 text-primary" />
              <p className="font-medium">Who are these tickets for?</p>
            </div>
            <p className="text-xs text-muted-foreground">
              Use the buyer email for your own ticket, or enter another groovist&apos;s email and we&apos;ll send it directly for claim and access.
            </p>
            <div className="space-y-3">
              {attendees.map((attendee, index) => (
                <div key={index} className="rounded-lg bg-muted/40 p-3 space-y-3">
                  <p className="text-sm font-medium">Ticket {index + 1}</p>
                  <div className="space-y-2">
                    <Label htmlFor={`ticket-holder-name-${index}`}>Full name</Label>
                    <Input
                      id={`ticket-holder-name-${index}`}
                      value={attendee.fullName}
                      onChange={(e) => updateAttendee(index, 'fullName', e.target.value)}
                      placeholder="Ticket holder name"
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor={`ticket-holder-email-${index}`}>Email</Label>
                    <Input
                      id={`ticket-holder-email-${index}`}
                      type="email"
                      value={attendee.email}
                      onChange={(e) => updateAttendee(index, 'email', e.target.value)}
                      placeholder="holder@email.com"
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor={`ticket-holder-phone-${index}`}>Phone <span className="text-muted-foreground">optional</span></Label>
                    <Input
                      id={`ticket-holder-phone-${index}`}
                      value={attendee.phone}
                      onChange={(e) => updateAttendee(index, 'phone', e.target.value)}
                      placeholder="Optional phone"
                    />
                  </div>
                </div>
              ))}
            </div>
            {giftedCount > 0 && (
              <p className="text-xs text-primary">
                {giftedCount} ticket{giftedCount > 1 ? 's' : ''} will be delivered to another groovist by email.
              </p>
            )}
          </div>

          {/* Security Badge - Simplified */}
          <div className="bg-green-50 border border-green-200 rounded-lg p-3 text-sm flex items-center gap-3">
            <Shield className="h-5 w-5 text-green-600 flex-shrink-0" />
            <p className="text-green-700">
              Secure payments by <span className="font-semibold">Paystack</span>
            </p>
          </div>

          {/* Payment Button */}
          <Button 
            onClick={handlePayment} 
            className="w-full" 
            size="lg"
            disabled={loading}
          >
            {loading ? (
              <>
                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                Connecting to Paystack...
              </>
            ) : (
              <>
                <CreditCard className="mr-2 h-4 w-4" />
                Pay {formatCurrency(totalAmount / 100)}
              </>
            )}
          </Button>

          <p className="text-xs text-center text-muted-foreground">
            By completing this purchase, you agree to our Terms of Service.
          </p>
        </div>
      </DialogContent>
    </Dialog>
  )
}

'use client'

import { createContext, useContext, useEffect, useState } from 'react'
import { createClient } from '@/lib/supabase/client'
import type { User } from '@supabase/supabase-js'
import type { Profile } from '@/types/database'

interface AuthContextType {
  user: User | null
  profile: Profile | null
  loading: boolean
  signOut: () => Promise<void>
  refreshProfile: () => Promise<void>
}

const AuthContext = createContext<AuthContextType>({
  user: null,
  profile: null,
  loading: true,
  signOut: async () => {},
  refreshProfile: async () => {},
})

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<User | null>(null)
  const [profile, setProfile] = useState<Profile | null>(null)
  const [loading, setLoading] = useState(true)
  const supabase = createClient()

  // Fetch user profile from database, create if doesn't exist
  const fetchProfile = async (userId: string, userEmail?: string) => {
    const { data, error } = await supabase
      .from('profiles')
      .select('*')
      .eq('id', userId)
      .single()

    if (error) {
      // If profile doesn't exist, create it
      if (error.code === 'PGRST116' && userEmail) {
        const { data: newProfile, error: createError } = await supabase
          .from('profiles')
          .insert({
            id: userId,
            email: userEmail,
            full_name: userEmail.split('@')[0],
            is_artist: false,
            is_organizer: false,
            is_provider: false,
            is_admin: false,
          })
          .select()
          .single()

        if (createError) {
          console.error('Error creating profile:', createError)
          return null
        }
        return newProfile
      }
      console.error('Error fetching profile:', error)
      return null
    }
    return data
  }

  // Refresh profile data
  const refreshProfile = async () => {
    if (user) {
      const profileData = await fetchProfile(user.id)
      setProfile(profileData)
    }
  }

  // Sign out user
  const signOut = async () => {
    await supabase.auth.signOut()
    setUser(null)
    setProfile(null)
  }

  useEffect(() => {
    // Get initial session
    const getInitialSession = async () => {
      const { data: { session } } = await supabase.auth.getSession()
      
      if (session?.user) {
        setUser(session.user)
        const profileData = await fetchProfile(session.user.id, session.user.email)
        setProfile(profileData)
      }
      
      setLoading(false)
    }

    getInitialSession()

    // Listen for auth changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange(
      async (event, session) => {
        if (session?.user) {
          setUser(session.user)
          const profileData = await fetchProfile(session.user.id, session.user.email)
          setProfile(profileData)
        } else {
          setUser(null)
          setProfile(null)
        }
        setLoading(false)
      }
    )

    return () => subscription.unsubscribe()
  }, [])

  return (
    <AuthContext.Provider value={{ user, profile, loading, signOut, refreshProfile }}>
      {children}
    </AuthContext.Provider>
  )
}

export function useAuth() {
  const context = useContext(AuthContext)
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider')
  }
  return context
}

'use client';

import { useState, useEffect } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Label } from '@/components/ui/label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Checkbox } from '@/components/ui/checkbox';
import { Calendar } from '@/components/ui/calendar';
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from '@/components/ui/popover';
import { 
  Search, 
  MapPin, 
  Calendar as CalendarIcon, 
  Filter, 
  X,
  SlidersHorizontal
} from 'lucide-react';
import { format } from 'date-fns';
import { cn } from '@/lib/utils';

// South African provinces
const SA_PROVINCES = [
  { value: 'gauteng', label: 'Gauteng' },
  { value: 'western_cape', label: 'Western Cape' },
  { value: 'kwazulu_natal', label: 'KwaZulu-Natal' },
  { value: 'eastern_cape', label: 'Eastern Cape' },
  { value: 'free_state', label: 'Free State' },
  { value: 'limpopo', label: 'Limpopo' },
  { value: 'mpumalanga', label: 'Mpumalanga' },
  { value: 'north_west', label: 'North West' },
  { value: 'northern_cape', label: 'Northern Cape' },
];

const SORT_OPTIONS = [
  { value: 'date', label: 'Date (Soonest)' },
  { value: 'price-low', label: 'Price (Low to High)' },
  { value: 'price-high', label: 'Price (High to Low)' },
  { value: 'popular', label: 'Most Popular' },
];

interface SearchFiltersProps {
  onSearch?: (filters: SearchFilters) => void;
  className?: string;
  compact?: boolean;
}

export interface SearchFilters {
  q: string;
  location: string;
  dateFrom: string;
  dateTo: string;
  priceMin: string;
  priceMax: string;
  isFree: boolean;
  sortBy: string;
}

export function SearchFilters({ onSearch, className, compact = false }: SearchFiltersProps) {
  const router = useRouter();
  const searchParams = useSearchParams();

  // Initialize from URL params
  const [query, setQuery] = useState(searchParams.get('q') || '');
  const [location, setLocation] = useState(searchParams.get('location') || '');
  const [dateFrom, setDateFrom] = useState<Date | undefined>(
    searchParams.get('dateFrom') ? new Date(searchParams.get('dateFrom')!) : undefined
  );
  const [dateTo, setDateTo] = useState<Date | undefined>(
    searchParams.get('dateTo') ? new Date(searchParams.get('dateTo')!) : undefined
  );
  const [priceMin, setPriceMin] = useState(searchParams.get('priceMin') || '');
  const [priceMax, setPriceMax] = useState(searchParams.get('priceMax') || '');
  const [isFree, setIsFree] = useState(searchParams.get('isFree') === 'true');
  const [sortBy, setSortBy] = useState(searchParams.get('sortBy') || 'date');
  const [showAdvanced, setShowAdvanced] = useState(false);

  // Build URL with filters
  const buildSearchParams = () => {
    const params = new URLSearchParams();
    if (query) params.set('q', query);
    if (location) params.set('location', location);
    if (dateFrom) params.set('dateFrom', format(dateFrom, 'yyyy-MM-dd'));
    if (dateTo) params.set('dateTo', format(dateTo, 'yyyy-MM-dd'));
    if (priceMin && !isFree) params.set('priceMin', priceMin);
    if (priceMax && !isFree) params.set('priceMax', priceMax);
    if (isFree) params.set('isFree', 'true');
    if (sortBy && sortBy !== 'date') params.set('sortBy', sortBy);
    return params.toString();
  };

  const handleSearch = () => {
    const params = buildSearchParams();
    router.push(`/ziwaphi${params ? '?' + params : ''}`);
    
    if (onSearch) {
      onSearch({
        q: query,
        location,
        dateFrom: dateFrom ? format(dateFrom, 'yyyy-MM-dd') : '',
        dateTo: dateTo ? format(dateTo, 'yyyy-MM-dd') : '',
        priceMin: isFree ? '' : priceMin,
        priceMax: isFree ? '' : priceMax,
        isFree,
        sortBy,
      });
    }
  };

  const clearFilters = () => {
    setQuery('');
    setLocation('');
    setDateFrom(undefined);
    setDateTo(undefined);
    setPriceMin('');
    setPriceMax('');
    setIsFree(false);
    setSortBy('date');
    router.push('/ziwaphi');
  };

  const hasActiveFilters = query || location || dateFrom || dateTo || priceMin || priceMax || isFree || sortBy !== 'date';

  // Handle Enter key
  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleSearch();
    }
  };

  if (compact) {
    return (
      <div className={cn("flex items-center gap-2", className)}>
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Search events..."
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onKeyDown={handleKeyDown}
            className="pl-9"
          />
        </div>
        <Button onClick={handleSearch} size="sm">
          Search
        </Button>
      </div>
    );
  }

  return (
    <div className={cn("space-y-4", className)}>
      {/* Main Search Bar */}
      <div className="flex flex-col sm:flex-row gap-3">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-muted-foreground" />
          <Input
            placeholder="Search by event name, venue, or description..."
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onKeyDown={handleKeyDown}
            className="pl-10 h-12 text-lg"
          />
        </div>
        
        <Select value={location} onValueChange={setLocation}>
          <SelectTrigger className="w-full sm:w-[200px] h-12">
            <MapPin className="h-4 w-4 mr-2" />
            <SelectValue placeholder="All Provinces" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All Provinces</SelectItem>
            {SA_PROVINCES.map((province) => (
              <SelectItem key={province.value} value={province.value}>
                {province.label}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>

        <Button onClick={handleSearch} className="h-12 px-8">
          <Search className="h-5 w-5 mr-2" />
          Search
        </Button>
      </div>

      {/* Filter Toggle */}
      <div className="flex items-center justify-between">
        <Button
          variant="ghost"
          size="sm"
          onClick={() => setShowAdvanced(!showAdvanced)}
          className="text-muted-foreground"
        >
          <SlidersHorizontal className="h-4 w-4 mr-2" />
          {showAdvanced ? 'Hide Filters' : 'More Filters'}
        </Button>

        {hasActiveFilters && (
          <Button
            variant="ghost"
            size="sm"
            onClick={clearFilters}
            className="text-muted-foreground hover:text-destructive"
          >
            <X className="h-4 w-4 mr-2" />
            Clear All
          </Button>
        )}
      </div>

      {/* Advanced Filters */}
      {showAdvanced && (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 p-4 bg-muted/50 rounded-lg border">
          {/* Date Range */}
          <div className="space-y-2">
            <Label>From Date</Label>
            <Popover>
              <PopoverTrigger asChild>
                <Button
                  variant="outline"
                  className={cn(
                    "w-full justify-start text-left font-normal",
                    !dateFrom && "text-muted-foreground"
                  )}
                >
                  <CalendarIcon className="mr-2 h-4 w-4" />
                  {dateFrom ? format(dateFrom, "PPP") : "Pick a date"}
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-auto p-0" align="start">
                <Calendar
                  mode="single"
                  selected={dateFrom}
                  onSelect={setDateFrom}
                  disabled={(date: Date) => date < new Date()}
                  initialFocus
                />
              </PopoverContent>
            </Popover>
          </div>

          <div className="space-y-2">
            <Label>To Date</Label>
            <Popover>
              <PopoverTrigger asChild>
                <Button
                  variant="outline"
                  className={cn(
                    "w-full justify-start text-left font-normal",
                    !dateTo && "text-muted-foreground"
                  )}
                >
                  <CalendarIcon className="mr-2 h-4 w-4" />
                  {dateTo ? format(dateTo, "PPP") : "Pick a date"}
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-auto p-0" align="start">
                <Calendar
                  mode="single"
                  selected={dateTo}
                  onSelect={setDateTo}
                  disabled={(date: Date) => date < (dateFrom || new Date())}
                  initialFocus
                />
              </PopoverContent>
            </Popover>
          </div>

          {/* Price Range */}
          <div className="space-y-2">
            <Label>Price Range (R)</Label>
            <div className="flex items-center gap-2">
              <Input
                type="number"
                placeholder="Min"
                value={priceMin}
                onChange={(e) => setPriceMin(e.target.value)}
                disabled={isFree}
                className="w-full"
              />
              <span className="text-muted-foreground">-</span>
              <Input
                type="number"
                placeholder="Max"
                value={priceMax}
                onChange={(e) => setPriceMax(e.target.value)}
                disabled={isFree}
                className="w-full"
              />
            </div>
          </div>

          {/* Sort By */}
          <div className="space-y-2">
            <Label>Sort By</Label>
            <Select value={sortBy} onValueChange={setSortBy}>
              <SelectTrigger className="w-full">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {SORT_OPTIONS.map((option) => (
                  <SelectItem key={option.value} value={option.value}>
                    {option.label}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          {/* Free Events Checkbox */}
          <div className="flex items-center space-x-2 sm:col-span-2 lg:col-span-4">
            <Checkbox
              id="free-events"
              checked={isFree}
              onCheckedChange={(checked) => setIsFree(checked === true)}
            />
            <label
              htmlFor="free-events"
              className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70 cursor-pointer"
            >
              Show only free events
            </label>
          </div>
        </div>
      )}

      {/* Active Filter Tags */}
      {hasActiveFilters && (
        <div className="flex flex-wrap gap-2">
          {query && (
            <FilterTag label={`"${query}"`} onRemove={() => setQuery('')} />
          )}
          {location && (
            <FilterTag 
              label={SA_PROVINCES.find(p => p.value === location)?.label || location} 
              onRemove={() => setLocation('')} 
            />
          )}
          {dateFrom && (
            <FilterTag 
              label={`From: ${format(dateFrom, 'MMM d')}`} 
              onRemove={() => setDateFrom(undefined)} 
            />
          )}
          {dateTo && (
            <FilterTag 
              label={`To: ${format(dateTo, 'MMM d')}`} 
              onRemove={() => setDateTo(undefined)} 
            />
          )}
          {isFree && (
            <FilterTag label="Free Events" onRemove={() => setIsFree(false)} />
          )}
          {!isFree && (priceMin || priceMax) && (
            <FilterTag 
              label={`R${priceMin || '0'} - R${priceMax || 'Γê₧'}`} 
              onRemove={() => { setPriceMin(''); setPriceMax(''); }} 
            />
          )}
        </div>
      )}
    </div>
  );
}

function FilterTag({ label, onRemove }: { label: string; onRemove: () => void }) {
  return (
    <span className="inline-flex items-center gap-1 px-3 py-1 bg-neutral-100 dark:bg-neutral-800 text-neutral-700 dark:text-neutral-300 rounded-full text-sm">
      {label}
      <button
        onClick={onRemove}
        className="ml-1 hover:text-neutral-900 dark:hover:text-neutral-100"
      >
        <X className="h-3 w-3" />
      </button>
    </span>
  );
}

