    }).format(amount);
  };

  return (
    <div className={cn('grid grid-cols-3 gap-4', className)}>
      <div className="text-center p-4 bg-neutral-50 rounded-xl">
        <p className="text-2xl font-bold text-neutral-900">{totalGigs}</p>
        <p className="text-sm text-neutral-500">
          {type === 'artist' ? 'Total Gigs' : 'Total Jobs'}
        </p>
      </div>
      <div className="text-center p-4 bg-green-50 rounded-xl">
        <p className="text-2xl font-bold text-green-700">{verifiedGigs}</p>
        <p className="text-sm text-green-600">Verified</p>
      </div>
      {totalEarned !== undefined && (
        <div className="text-center p-4 bg-neutral-50 rounded-xl">
          <p className="text-2xl font-bold text-neutral-900">{formatCurrency(totalEarned)}</p>
          <p className="text-sm text-neutral-500">Earned via Ziyawa</p>
        </div>
      )}
    </div>
  );
}

'use client';

import { useState } from 'react';
import Image from 'next/image';
import { Star, ThumbsUp, Flag, MessageSquare, CheckCircle, Play } from 'lucide-react';
import { Review, VideoReview } from '@/types/database';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui/button';
import { Textarea } from '@/components/ui/textarea';

interface ReviewWithAuthor extends Review {
  reviewer?: {
    full_name: string | null;
    avatar_url: string | null;
  };
  video_review?: VideoReview | null;
}

interface ReviewCardProps {
  review: ReviewWithAuthor;
  onRespond?: (reviewId: string, response: string) => void;
  canRespond?: boolean;
  className?: string;
}

export function ReviewCard({ review, onRespond, canRespond = false, className }: ReviewCardProps) {
  const [showResponseForm, setShowResponseForm] = useState(false);
  const [response, setResponse] = useState('');

  const formatDate = (date: string) => {
    return new Date(date).toLocaleDateString('en-ZA', {
      day: 'numeric',
      month: 'short',
      year: 'numeric',
    });
  };

  const handleSubmitResponse = () => {
    if (onRespond && response.trim()) {
      onRespond(review.id, response);
      setShowResponseForm(false);
      setResponse('');
    }
  };

  return (
    <div className={cn('bg-white border border-neutral-200 rounded-xl p-5', className)}>
      {/* Header */}
      <div className="flex items-start justify-between mb-4">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-neutral-200 overflow-hidden">
            {review.reviewer?.avatar_url ? (
              <Image
                src={review.reviewer.avatar_url}
                alt=""
                width={40}
                height={40}
                className="object-cover"
              />
            ) : (
              <div className="w-full h-full flex items-center justify-center text-neutral-500 text-sm font-medium">
                {review.reviewer?.full_name?.charAt(0) || '?'}
              </div>
            )}
          </div>
          <div>
            <p className="font-medium text-neutral-900">
              {review.reviewer?.full_name || 'Anonymous'}
            </p>
            <p className="text-sm text-neutral-500">{formatDate(review.created_at)}</p>
          </div>
        </div>

        {/* Rating stars */}
        <div className="flex items-center gap-1">
          {[1, 2, 3, 4, 5].map((star) => (
            <Star
              key={star}
              className={cn(
                'h-4 w-4',
                star <= review.overall_rating
                  ? 'text-yellow-500 fill-current'
                  : 'text-neutral-300'
              )}
            />
          ))}
        </div>
      </div>

      {/* Verified badge */}
      {review.is_verified && (
        <div className="flex items-center gap-1.5 mb-3 text-sm text-green-700">
          <CheckCircle className="h-4 w-4" />
          <span>Verified booking via Ziyawa</span>
        </div>
      )}

      {/* Title */}
      {review.title && (
        <h4 className="font-semibold text-neutral-900 mb-2">{review.title}</h4>
      )}

      {/* Content */}
      {review.content && (
        <p className="text-neutral-700 mb-4">{review.content}</p>
      )}

      {/* Video review preview */}
      {review.video_review && (
        <div className="relative aspect-video rounded-lg overflow-hidden bg-neutral-100 mb-4">
          {review.video_review.thumbnail_url ? (
            <Image
              src={review.video_review.thumbnail_url}
              alt="Video review"
              fill
              className="object-cover"
            />
          ) : (
            <div className="w-full h-full flex items-center justify-center">
              <Play className="h-12 w-12 text-neutral-400" />
            </div>
          )}
          <div className="absolute inset-0 flex items-center justify-center bg-black/30">
            <div className="w-14 h-14 rounded-full bg-white/90 flex items-center justify-center">
              <Play className="h-7 w-7 text-neutral-900 ml-1" fill="currentColor" />
            </div>
          </div>
        </div>
      )}

      {/* Category ratings */}
      {(review.professionalism_rating || review.communication_rating || review.quality_rating) && (
        <div className="grid grid-cols-2 md:grid-cols-3 gap-3 mb-4 p-3 bg-neutral-50 rounded-lg">
          {review.professionalism_rating && (
            <div>
              <p className="text-xs text-neutral-500">Professionalism</p>
              <div className="flex items-center gap-1">
                <Star className="h-3 w-3 text-yellow-500" fill="currentColor" />
                <span className="text-sm font-medium">{review.professionalism_rating}</span>
              </div>
            </div>
          )}
          {review.communication_rating && (
            <div>
              <p className="text-xs text-neutral-500">Communication</p>
              <div className="flex items-center gap-1">
                <Star className="h-3 w-3 text-yellow-500" fill="currentColor" />
                <span className="text-sm font-medium">{review.communication_rating}</span>
              </div>
            </div>
          )}
          {review.quality_rating && (
            <div>
              <p className="text-xs text-neutral-500">Quality</p>
              <div className="flex items-center gap-1">
                <Star className="h-3 w-3 text-yellow-500" fill="currentColor" />
                <span className="text-sm font-medium">{review.quality_rating}</span>
              </div>
            </div>
          )}
          {review.punctuality_rating && (
            <div>
              <p className="text-xs text-neutral-500">Punctuality</p>
              <div className="flex items-center gap-1">
                <Star className="h-3 w-3 text-yellow-500" fill="currentColor" />
                <span className="text-sm font-medium">{review.punctuality_rating}</span>
              </div>
            </div>
          )}
        </div>
      )}

      {/* Trust indicators */}
      <div className="flex flex-wrap gap-2 mb-4">
        {review.showed_up === true && (
          <span className="inline-flex items-center gap-1 px-2 py-1 bg-green-50 text-green-700 text-xs rounded-full">
            <CheckCircle className="h-3 w-3" />
            Showed up on time
          </span>
        )}
        {review.payment_on_time === true && (
          <span className="inline-flex items-center gap-1 px-2 py-1 bg-green-50 text-green-700 text-xs rounded-full">
            <CheckCircle className="h-3 w-3" />
            Paid on time
          </span>
        )}
        {review.would_recommend === true && (
          <span className="inline-flex items-center gap-1 px-2 py-1 bg-blue-50 text-blue-700 text-xs rounded-full">
            <ThumbsUp className="h-3 w-3" />
            Would recommend
          </span>
        )}
      </div>

      {/* Response */}
      {review.response && (
        <div className="mt-4 pl-4 border-l-2 border-neutral-200">
          <p className="text-sm font-medium text-neutral-900 mb-1">Response</p>
          <p className="text-sm text-neutral-600">{review.response}</p>
          {review.response_at && (
            <p className="text-xs text-neutral-400 mt-1">{formatDate(review.response_at)}</p>
          )}
        </div>
      )}

      {/* Respond button */}
      {canRespond && !review.response && (
        <>
          {showResponseForm ? (
            <div className="mt-4 space-y-3">
              <Textarea
                placeholder="Write your response..."
                value={response}
                onChange={(e) => setResponse(e.target.value)}
                rows={3}
              />
              <div className="flex gap-2">
                <Button size="sm" onClick={handleSubmitResponse} disabled={!response.trim()}>
                  Submit Response
                </Button>
                <Button size="sm" variant="outline" onClick={() => setShowResponseForm(false)}>
                  Cancel
                </Button>
              </div>
            </div>
          ) : (
            <Button
              size="sm"
              variant="outline"
              className="mt-4"
              onClick={() => setShowResponseForm(true)}
            >
              <MessageSquare className="h-4 w-4 mr-1" />
              Respond
            </Button>
          )}
        </>
      )}
    </div>
  );
}

// Reviews list with summary
interface ReviewsListProps {
  reviews: ReviewWithAuthor[];
  averageRating: number;
  totalReviews: number;
  onRespond?: (reviewId: string, response: string) => void;
  canRespond?: boolean;
  className?: string;
}

export function ReviewsList({
  reviews,
  averageRating,
  totalReviews,
  onRespond,
  canRespond,
  className,
}: ReviewsListProps) {
  // Calculate rating distribution
  const distribution = [5, 4, 3, 2, 1].map((star) => ({
    star,
    count: reviews.filter((r) => r.overall_rating === star).length,
    percentage: totalReviews > 0 
      ? (reviews.filter((r) => r.overall_rating === star).length / totalReviews) * 100 
      : 0,
  }));

  return (
    <div className={className}>
      {/* Summary */}
      <div className="flex flex-col md:flex-row gap-8 mb-8">
        {/* Average rating */}
        <div className="text-center md:text-left">
          <div className="text-5xl font-bold text-neutral-900">
            {averageRating > 0 ? averageRating.toFixed(1) : '-'}
          </div>
          <div className="flex items-center justify-center md:justify-start gap-1 mt-2">
            {[1, 2, 3, 4, 5].map((star) => (
              <Star
                key={star}
                className={cn(
                  'h-5 w-5',
                  star <= Math.round(averageRating)
                    ? 'text-yellow-500 fill-current'
                    : 'text-neutral-300'
                )}
              />
            ))}
          </div>
          <p className="text-sm text-neutral-500 mt-1">{totalReviews} reviews</p>
        </div>

        {/* Distribution */}
        <div className="flex-1 space-y-2">
          {distribution.map(({ star, count, percentage }) => (
            <div key={star} className="flex items-center gap-3">
              <span className="text-sm text-neutral-600 w-12">{star} star</span>
              <div className="flex-1 h-2 bg-neutral-100 rounded-full overflow-hidden">
                <div
                  className="h-full bg-yellow-500 rounded-full transition-all"
                  style={{ width: `${percentage}%` }}
                />
              </div>
              <span className="text-sm text-neutral-500 w-8">{count}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Reviews */}
      {reviews.length > 0 ? (
        <div className="space-y-4">
          {reviews.map((review) => (
            <ReviewCard
              key={review.id}
              review={review}
              onRespond={onRespond}
              canRespond={canRespond}
            />
          ))}
        </div>
      ) : (
        <div className="text-center py-12 bg-neutral-50 rounded-xl">
          <Star className="h-12 w-12 text-neutral-300 mx-auto mb-3" />
          <p className="text-neutral-600">No reviews yet</p>
          <p className="text-sm text-neutral-500">Be the first to leave a review</p>
        </div>
      )}
    </div>
  );
}

// Star rating input
interface StarRatingInputProps {
  value: number;
  onChange: (value: number) => void;
  size?: 'sm' | 'md' | 'lg';
  label?: string;
  className?: string;
}

export function StarRatingInput({ 
  value, 
  onChange, 
  size = 'md',
  label,
  className 
}: StarRatingInputProps) {
  const [hoverValue, setHoverValue] = useState(0);

  const sizes = {
    sm: 'h-5 w-5',
    md: 'h-7 w-7',
    lg: 'h-9 w-9',
  };

  return (
    <div className={className}>
      {label && <p className="text-sm text-neutral-600 mb-2">{label}</p>}
      <div className="flex items-center gap-1">
        {[1, 2, 3, 4, 5].map((star) => (
          <button
            key={star}
            type="button"
            onClick={() => onChange(star)}
            onMouseEnter={() => setHoverValue(star)}
            onMouseLeave={() => setHoverValue(0)}
            className="p-0.5 hover:scale-110 transition-transform"
          >
            <Star
              className={cn(
                sizes[size],
                'transition-colors',
                (hoverValue || value) >= star
                  ? 'text-yellow-500 fill-current'
                  : 'text-neutral-300'
              )}
            />
          </button>
        ))}
      </div>
    </div>
  );
}

'use client';

import { Star, Shield, CheckCircle, TrendingUp, Clock, Percent } from 'lucide-react';
import { cn } from '@/lib/utils';

interface TrustBadgeProps {
  type: 'artist' | 'organizer' | 'provider';
  isVerified?: boolean;
  isTrusted?: boolean;
  completionRate?: number;
  totalBookings?: number;
  rating?: number;
  size?: 'sm' | 'md' | 'lg';
  showLabel?: boolean;
  className?: string;
}

export function TrustBadge({ 
  type,
  isVerified, 
  isTrusted,
  completionRate,
  totalBookings = 0,
  rating = 0,
  size = 'md',
  showLabel = true,
  className 
}: TrustBadgeProps) {
  // Determine trust level
  const getTrustLevel = () => {
    if (isTrusted) return 'trusted';
    if (isVerified) return 'verified';
    if (totalBookings >= 5 && completionRate && completionRate >= 90) return 'reliable';
    if (totalBookings >= 1) return 'active';
    return 'new';
  };

  const level = getTrustLevel();

  const levelConfig = {
    trusted: {
      label: type === 'organizer' ? 'Trusted Organizer' : type === 'provider' ? 'Trusted Provider' : 'Trusted Artist',
      icon: Shield,
      bgColor: 'bg-black',
      textColor: 'text-white',
      description: '100% reliable track record',
    },
    verified: {
      label: 'Ziyawa Verified',
      icon: CheckCircle,
      bgColor: 'bg-neutral-900',
      textColor: 'text-white',
      description: 'Identity verified',
    },
    reliable: {
      label: 'Reliable',
      icon: TrendingUp,
      bgColor: 'bg-neutral-700',
      textColor: 'text-white',
      description: 'Strong track record',
    },
    active: {
      label: 'Active',
      icon: CheckCircle,
      bgColor: 'bg-neutral-200',
      textColor: 'text-neutral-700',
      description: 'Recently active',
    },
    new: {
      label: 'New',
      icon: Star,
      bgColor: 'bg-neutral-100',
      textColor: 'text-neutral-500',
      description: 'New to Ziyawa',
    },
  };

  const config = levelConfig[level];
  const Icon = config.icon;

  const sizes = {
    sm: 'text-xs px-2 py-0.5',
    md: 'text-sm px-2.5 py-1',
    lg: 'text-sm px-3 py-1.5',
  };

  const iconSizes = {
    sm: 'h-3 w-3',
    md: 'h-4 w-4',
    lg: 'h-4 w-4',
  };

  return (
    <div
      className={cn(
        'inline-flex items-center gap-1.5 rounded-full font-medium',
        config.bgColor,
        config.textColor,
        sizes[size],
        className
      )}
      title={config.description}
    >
      <Icon className={iconSizes[size]} />
      {showLabel && <span>{config.label}</span>}
    </div>
  );
}

// Stats bar showing trust metrics
interface TrustStatsProps {
  completedBookings: number;
  totalBookings: number;
  rating: number;
  totalReviews: number;
  responseRate?: number;
  showUpRate?: number; // For artists
  paymentRate?: number; // For organizers
  type: 'artist' | 'organizer' | 'provider';
  className?: string;
}

export function TrustStats({
  completedBookings,
  totalBookings,
  rating,
  totalReviews,
  responseRate,
  showUpRate,
  paymentRate,
  type,
  className,
}: TrustStatsProps) {
  const completionRate = totalBookings > 0 
    ? Math.round((completedBookings / totalBookings) * 100) 
    : 0;

  const stats = [
    {
      label: type === 'organizer' ? 'Events Hosted' : 'Bookings',
      value: totalBookings.toString(),
      show: true,
    },
    {
      label: 'Completion Rate',
      value: `${completionRate}%`,
      icon: Percent,
      highlight: completionRate >= 95,
      show: totalBookings > 0,
    },
    {
      label: 'Rating',
      value: rating > 0 ? rating.toFixed(1) : '-',
      icon: Star,
      highlight: rating >= 4.5,
      subtext: totalReviews > 0 ? `(${totalReviews})` : undefined,
      show: true,
    },
    {
      label: 'Response Rate',
      value: responseRate ? `${responseRate}%` : '-',
      icon: Clock,
      show: !!responseRate,
    },
    {
      label: 'Show-up Rate',
      value: showUpRate ? `${showUpRate}%` : '-',
      highlight: showUpRate && showUpRate >= 95,
      show: type === 'artist' && !!showUpRate,
    },
    {
      label: 'Payment Rate',
      value: paymentRate ? `${paymentRate}%` : '-',
      highlight: paymentRate && paymentRate >= 95,
      show: type === 'organizer' && !!paymentRate,
    },
  ].filter(s => s.show);

  return (
    <div className={cn('grid grid-cols-2 md:grid-cols-4 gap-4', className)}>
      {stats.map((stat) => (
        <div key={stat.label} className="text-center">
          <div className={cn(
            'text-2xl font-bold',
            stat.highlight ? 'text-black' : 'text-neutral-700'
          )}>
            {stat.value}
            {stat.subtext && (
              <span className="text-sm font-normal text-neutral-500 ml-1">{stat.subtext}</span>
            )}
          </div>
          <div className="text-sm text-neutral-500">{stat.label}</div>
        </div>
      ))}
    </div>
  );
}

// Compact trust indicator for cards
interface TrustIndicatorProps {
  rating: number;
  totalReviews: number;
  completionRate?: number;
  isVerified?: boolean;
  className?: string;
}

export function TrustIndicator({ 
  rating, 
  totalReviews, 
  completionRate,
  isVerified,
  className 
}: TrustIndicatorProps) {
  return (
    <div className={cn('flex items-center gap-3 text-sm', className)}>
      {/* Rating */}
      <div className="flex items-center gap-1">
        <Star className="h-4 w-4 text-yellow-500" fill="currentColor" />
        <span className="font-medium">{rating > 0 ? rating.toFixed(1) : 'New'}</span>
        {totalReviews > 0 && (
          <span className="text-neutral-500">({totalReviews})</span>
        )}
      </div>

      {/* Completion rate */}
      {completionRate !== undefined && completionRate > 0 && (
        <div className="flex items-center gap-1 text-neutral-600">
          <CheckCircle className={cn(
            'h-4 w-4',
            completionRate >= 95 ? 'text-green-600' : 'text-neutral-400'
          )} />
          <span>{completionRate}%</span>
        </div>
      )}

      {/* Verified badge */}
      {isVerified && (
        <div className="flex items-center gap-1 text-black">
          <Shield className="h-4 w-4" />
          <span className="text-xs font-medium">Verified</span>
        </div>
      )}
    </div>
  );
}

// Track record card for detailed view
interface TrackRecordCardProps {
  type: 'artist' | 'organizer' | 'provider';
  totalBookings: number;
  completedBookings: number;
  cancelledBookings?: number;
  totalEarned?: number;
  totalPaid?: number;
  rating: number;
  totalReviews: number;
  memberSince: string;
  isVerified?: boolean;
  className?: string;
}

export function TrackRecordCard({
  type,
  totalBookings,
  completedBookings,
  cancelledBookings = 0,
  totalEarned,
  totalPaid,
  rating,
  totalReviews,
  memberSince,
  isVerified,
  className,
}: TrackRecordCardProps) {
  const completionRate = totalBookings > 0 
    ? Math.round((completedBookings / totalBookings) * 100) 
    : 0;

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('en-ZA', {
      style: 'currency',
      currency: 'ZAR',
      minimumFractionDigits: 0,
      maximumFractionDigits: 0,
    }).format(amount);
  };

  const formatDate = (date: string) => {
    return new Date(date).toLocaleDateString('en-ZA', {
      month: 'short',
      year: 'numeric',
    });
  };

  return (
    <div className={cn('bg-white border border-neutral-200 rounded-xl p-6', className)}>
      <div className="flex items-center justify-between mb-6">
        <h3 className="font-semibold text-neutral-900">Track Record</h3>
        {isVerified && (
          <TrustBadge type={type} isVerified={isVerified} size="sm" />
        )}
      </div>

      <div className="space-y-4">
        {/* Bookings/Events */}
        <div className="flex justify-between items-center py-2 border-b border-neutral-100">
          <span className="text-neutral-600">
            {type === 'organizer' ? 'Events Hosted' : 'Total Bookings'}
          </span>
          <span className="font-semibold text-neutral-900">{totalBookings}</span>
        </div>

        {/* Completed */}
        <div className="flex justify-between items-center py-2 border-b border-neutral-100">
          <span className="text-neutral-600">Completed</span>
          <span className="font-semibold text-neutral-900">{completedBookings}</span>
        </div>

        {/* Completion Rate */}
        <div className="flex justify-between items-center py-2 border-b border-neutral-100">
          <span className="text-neutral-600">Completion Rate</span>
          <span className={cn(
            'font-semibold',
            completionRate >= 95 ? 'text-green-600' : 
            completionRate >= 80 ? 'text-neutral-900' : 'text-orange-600'
          )}>
            {completionRate}%
          </span>
        </div>

        {/* Cancelled */}
        {cancelledBookings > 0 && (
          <div className="flex justify-between items-center py-2 border-b border-neutral-100">
            <span className="text-neutral-600">Cancelled</span>
            <span className="font-semibold text-red-600">{cancelledBookings}</span>
          </div>
        )}

        {/* Rating */}
        <div className="flex justify-between items-center py-2 border-b border-neutral-100">
          <span className="text-neutral-600">Rating</span>
          <div className="flex items-center gap-2">
            <Star className="h-4 w-4 text-yellow-500" fill="currentColor" />
            <span className="font-semibold text-neutral-900">
              {rating > 0 ? rating.toFixed(1) : '-'}
            </span>
            <span className="text-neutral-500 text-sm">({totalReviews} reviews)</span>
          </div>
        </div>

        {/* Money earned/paid */}
        {(type === 'artist' || type === 'provider') && totalEarned !== undefined && (
          <div className="flex justify-between items-center py-2 border-b border-neutral-100">
            <span className="text-neutral-600">Earned via Ziyawa</span>
            <span className="font-semibold text-neutral-900">{formatCurrency(totalEarned)}</span>
          </div>
        )}

        {type === 'organizer' && totalPaid !== undefined && (
          <div className="flex justify-between items-center py-2 border-b border-neutral-100">
            <span className="text-neutral-600">Paid to Artists</span>
            <span className="font-semibold text-neutral-900">{formatCurrency(totalPaid)}</span>
          </div>
        )}

        {/* Member since */}
        <div className="flex justify-between items-center py-2">
          <span className="text-neutral-600">Member Since</span>
          <span className="font-semibold text-neutral-900">{formatDate(memberSince)}</span>
        </div>
      </div>

      {/* Trust message */}
      {totalBookings >= 10 && completionRate >= 95 && (
        <div className="mt-6 p-3 bg-neutral-50 rounded-lg border border-neutral-100">
          <div className="flex items-center gap-2 text-sm">
            <Shield className="h-4 w-4 text-black" />
            <span className="font-medium text-neutral-900">
              {type === 'artist' && 'This artist has NEVER cancelled a show'}
              {type === 'organizer' && 'This organizer ALWAYS pays on time'}
              {type === 'provider' && 'This provider has a perfect track record'}
            </span>
          </div>
        </div>
      )}
    </div>
  );
}

'use client';

import { useState, useRef, useEffect, useCallback } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Card, CardContent } from '@/components/ui/card';
import { Avatar, AvatarFallback } from '@/components/ui/avatar';
import { Badge } from '@/components/ui/badge';
import { Skeleton } from '@/components/ui/skeleton';
import { 
  Send, 
  Bot, 
  User, 
  Calendar, 
  MapPin, 
  Clock,
  Ticket,
  ExternalLink,
  Sparkles
} from 'lucide-react';
import Link from 'next/link';
import { formatCurrency } from '@/lib/helpers';
import { parseQuery, type ParsedQuery } from '@/lib/ziwaphi/query-parser';
import { 
  FAQ_DATABASE, 
  QUICK_ACTIONS, 
  getRandomGreeting,
  searchFAQ,
  type FAQItem 
} from '@/lib/ziwaphi/knowledge-base';

// =====================================================
// TYPES
// =====================================================

interface EventResult {
  id: string;
  title: string;
  date: string;
  time: string;
  venue: string;
  city: string;
  province: string;
  image_url: string | null;
  min_price: number;
  max_price: number;
  is_free: boolean;
  category: string | null;
}

interface Message {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  timestamp: Date;
  events?: EventResult[];
  faq?: FAQItem;
  isTyping?: boolean;
}

// =====================================================
// MAIN COMPONENT
// =====================================================

export function ZiwaphiChat() {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [hasGreeted, setHasGreeted] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // Initial greeting
  useEffect(() => {
    if (!hasGreeted) {
      const greeting = getRandomGreeting();
      setMessages([
        {
          id: 'greeting',
          role: 'assistant',
          content: greeting,
          timestamp: new Date(),
        },
      ]);
      setHasGreeted(true);
    }
  }, [hasGreeted]);

  // Auto-scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // Handle sending message
  const handleSend = useCallback(async () => {
    const trimmedInput = input.trim();
    if (!trimmedInput || isLoading) return;

    const userMessage: Message = {
      id: `user-${Date.now()}`,
      role: 'user',
      content: trimmedInput,
      timestamp: new Date(),
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    // Add typing indicator
    const typingMessage: Message = {
      id: 'typing',
      role: 'assistant',
      content: '',
      timestamp: new Date(),
      isTyping: true,
    };
    setMessages(prev => [...prev, typingMessage]);

    try {
      // Parse the query
      const parsed = parseQuery(trimmedInput);
      
      // Handle different intents
      let assistantMessage: Message;

      if (parsed.intent === 'greeting') {
        assistantMessage = {
          id: `assistant-${Date.now()}`,
          role: 'assistant',
          content: "Hey! ≡ƒæï What would you like to do? You can ask me about events, how to use Ziyawa, or any questions you have!",
          timestamp: new Date(),
        };
      } else if (parsed.intent === 'faq') {
        const faq = parsed.faqId ? FAQ_DATABASE.find(f => f.id === parsed.faqId) : searchFAQ(trimmedInput);
        
        if (faq) {
          assistantMessage = {
            id: `assistant-${Date.now()}`,
            role: 'assistant',
            content: '',
            timestamp: new Date(),
            faq,
          };
        } else {
          assistantMessage = {
            id: `assistant-${Date.now()}`,
            role: 'assistant',
            content: "I'm not sure about that one. Here are some things I can help with:\n\nΓÇó Finding events\nΓÇó Buying tickets\nΓÇó Becoming an organizer, artist, or vendor\nΓÇó Payment and wallet questions\n\nOr you can [create a support ticket](/support) for more specific help! ≡ƒÆ¼",
            timestamp: new Date(),
          };
        }
      } else if (parsed.intent === 'search_events' || parsed.intent === 'unknown') {
        // Search for events
        const events = await searchEvents(parsed);
        
        if (events.length > 0) {
          const locationText = parsed.searchParams.location?.city || parsed.searchParams.location?.province || '';
          const dateText = parsed.searchParams.dateRange?.label || '';
          const categoryText = parsed.searchParams.category || '';
          
          const contextParts = [dateText, locationText, categoryText].filter(Boolean);
          const contextText = contextParts.length > 0 ? ` for ${contextParts.join(' in ')}` : '';
          
          assistantMessage = {
            id: `assistant-${Date.now()}`,
            role: 'assistant',
            content: `I found ${events.length} event${events.length > 1 ? 's' : ''}${contextText}! ≡ƒÄë`,
            timestamp: new Date(),
            events,
          };
        } else {
          assistantMessage = {
            id: `assistant-${Date.now()}`,
            role: 'assistant',
            content: "I couldn't find any events matching that. Try:\n\nΓÇó \"Events this weekend in Joburg\"\nΓÇó \"Free events in Cape Town\"\nΓÇó \"Amapiano parties next month\"\n\nOr browse all events on the [homepage](/)! ≡ƒÄ╡",
            timestamp: new Date(),
          };
        }
      } else {
        assistantMessage = {
          id: `assistant-${Date.now()}`,
          role: 'assistant',
          content: "I'm here to help! You can:\n\n≡ƒÄë Ask about events: \"What's happening this weekend?\"\n≡ƒÄ½ Ask about tickets: \"How do I buy tickets?\"\n≡ƒÆ¼ Get support: \"How do I contact support?\"\n\nWhat would you like to know?",
          timestamp: new Date(),
        };
      }

      // Remove typing indicator and add response
      setMessages(prev => prev.filter(m => m.id !== 'typing').concat(assistantMessage));
    } catch (error) {
      console.error('Ziwaphi error:', error);
      setMessages(prev => prev.filter(m => m.id !== 'typing').concat({
        id: `assistant-${Date.now()}`,
        role: 'assistant',
        content: "Oops! Something went wrong. Please try again or [contact support](/support). ≡ƒÖÅ",
        timestamp: new Date(),
      }));
    } finally {
      setIsLoading(false);
    }
  }, [input, isLoading]);

  // Handle quick action
  const handleQuickAction = useCallback((action: typeof QUICK_ACTIONS[0]) => {
    if (action.action === 'link' && action.href) {
      window.location.href = action.href;
      return;
    }
    
    if (action.query) {
      setInput(action.query);
      // Trigger send after a short delay
      setTimeout(() => {
        inputRef.current?.form?.requestSubmit();
      }, 100);
    }
  }, []);

  // Handle key press
  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="flex flex-col h-[600px] max-h-[80vh] bg-background rounded-lg border">
      {/* Header */}
      <div className="flex items-center gap-3 p-4 border-b bg-gradient-to-r from-primary/10 to-primary/5">
        <Avatar className="h-10 w-10 bg-primary">
          <AvatarFallback className="bg-primary text-primary-foreground">
            <Bot className="h-5 w-5" />
          </AvatarFallback>
        </Avatar>
        <div>
          <h2 className="font-semibold flex items-center gap-2">
            Ziwaphi <Sparkles className="h-4 w-4 text-primary" />
          </h2>
          <p className="text-xs text-muted-foreground">Your event discovery assistant</p>
        </div>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map(message => (
          <MessageBubble key={message.id} message={message} />
        ))}
        
        {/* Quick actions (show only after greeting, before first user message) */}
        {messages.length === 1 && messages[0].role === 'assistant' && (
          <div className="flex flex-wrap gap-2 mt-4">
            {QUICK_ACTIONS.map(action => (
              <Button
                key={action.id}
                variant="outline"
                size="sm"
                onClick={() => handleQuickAction(action)}
                className="text-sm"
              >
                <span className="mr-1">{action.icon}</span>
                {action.label}
              </Button>
            ))}
          </div>
        )}
        
        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <form 
        onSubmit={(e) => { e.preventDefault(); handleSend(); }}
        className="p-4 border-t"
      >
        <div className="flex gap-2">
          <Input
            ref={inputRef}
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyPress={handleKeyPress}
            placeholder="Ask about events or how to use Ziyawa..."
            disabled={isLoading}
            className="flex-1"
          />
          <Button type="submit" disabled={isLoading || !input.trim()}>
            <Send className="h-4 w-4" />
          </Button>
        </div>
      </form>
    </div>
  );
}

