      </Card>
    </Link>
  );
}

// =====================================================
// EVENT SEARCH API CALL
// =====================================================

async function searchEvents(parsed: ParsedQuery): Promise<EventResult[]> {
  try {
    const params = new URLSearchParams();
    
    if (parsed.searchParams.dateRange) {
      params.set('startDate', parsed.searchParams.dateRange.start.toISOString());
      params.set('endDate', parsed.searchParams.dateRange.end.toISOString());
    }
    
    if (parsed.searchParams.location?.city) {
      params.set('city', parsed.searchParams.location.city);
    }
    
    if (parsed.searchParams.location?.province) {
      params.set('province', parsed.searchParams.location.province);
    }
    
    if (parsed.searchParams.category) {
      params.set('category', parsed.searchParams.category);
    }
    
    if (parsed.searchParams.priceRange?.isFree) {
      params.set('free', 'true');
    } else if (parsed.searchParams.priceRange?.max) {
      params.set('maxPrice', parsed.searchParams.priceRange.max.toString());
    }
    
    if (parsed.searchParams.searchText) {
      params.set('q', parsed.searchParams.searchText);
    }

    const response = await fetch(`/api/ziwaphi/search?${params.toString()}`);
    
    if (!response.ok) {
      throw new Error('Search failed');
    }
    
    const data = await response.json();
    return data.events || [];
  } catch (error) {
    console.error('Event search error:', error);
    return [];
  }
}

'use client';

import * as React from 'react';

const TOAST_LIMIT = 1;
const TOAST_REMOVE_DELAY = 5000;

type ToasterToast = {
  id: string;
  title?: string;
  description?: string;
  action?: React.ReactNode;
  variant?: 'default' | 'destructive';
};

const actionTypes = {
  ADD_TOAST: 'ADD_TOAST',
  UPDATE_TOAST: 'UPDATE_TOAST',
  DISMISS_TOAST: 'DISMISS_TOAST',
  REMOVE_TOAST: 'REMOVE_TOAST',
} as const;

let count = 0;

function genId() {
  count = (count + 1) % Number.MAX_SAFE_INTEGER;
  return count.toString();
}

type ActionType = typeof actionTypes;

type Action =
  | {
      type: ActionType['ADD_TOAST'];
      toast: ToasterToast;
    }
  | {
      type: ActionType['UPDATE_TOAST'];
      toast: Partial<ToasterToast>;
    }
  | {
      type: ActionType['DISMISS_TOAST'];
      toastId?: ToasterToast['id'];
    }
  | {
      type: ActionType['REMOVE_TOAST'];
      toastId?: ToasterToast['id'];
    };

interface State {
  toasts: ToasterToast[];
}

const toastTimeouts = new Map<string, ReturnType<typeof setTimeout>>();

const addToRemoveQueue = (toastId: string) => {
  if (toastTimeouts.has(toastId)) {
    return;
  }

  const timeout = setTimeout(() => {
    toastTimeouts.delete(toastId);
    dispatch({
      type: 'REMOVE_TOAST',
      toastId: toastId,
    });
  }, TOAST_REMOVE_DELAY);

  toastTimeouts.set(toastId, timeout);
};

export const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case 'ADD_TOAST':
      return {
        ...state,
        toasts: [action.toast, ...state.toasts].slice(0, TOAST_LIMIT),
      };

    case 'UPDATE_TOAST':
      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === action.toast.id ? { ...t, ...action.toast } : t
        ),
      };

    case 'DISMISS_TOAST': {
      const { toastId } = action;

      if (toastId) {
        addToRemoveQueue(toastId);
      } else {
        state.toasts.forEach((toast) => {
          addToRemoveQueue(toast.id);
        });
      }

      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === toastId || toastId === undefined
            ? {
                ...t,
              }
            : t
        ),
      };
    }
    case 'REMOVE_TOAST':
      if (action.toastId === undefined) {
        return {
          ...state,
          toasts: [],
        };
      }
      return {
        ...state,
        toasts: state.toasts.filter((t) => t.id !== action.toastId),
      };
  }
};

const listeners: Array<(state: State) => void> = [];

let memoryState: State = { toasts: [] };

function dispatch(action: Action) {
  memoryState = reducer(memoryState, action);
  listeners.forEach((listener) => {
    listener(memoryState);
  });
}

type Toast = Omit<ToasterToast, 'id'>;

function toast({ ...props }: Toast) {
  const id = genId();

  const update = (props: ToasterToast) =>
    dispatch({
      type: 'UPDATE_TOAST',
      toast: { ...props, id },
    });
  const dismiss = () => dispatch({ type: 'DISMISS_TOAST', toastId: id });

  dispatch({
    type: 'ADD_TOAST',
    toast: {
      ...props,
      id,
    },
  });

  return {
    id: id,
    dismiss,
    update,
  };
}

function useToast() {
  const [state, setState] = React.useState<State>(memoryState);

  React.useEffect(() => {
    listeners.push(setState);
    return () => {
      const index = listeners.indexOf(setState);
      if (index > -1) {
        listeners.splice(index, 1);
      }
    };
  }, [state]);

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) => dispatch({ type: 'DISMISS_TOAST', toastId }),
  };
}

export { useToast, toast };

/**
 * Utility functions for Ziyawa
 */

import { PLATFORM_CONFIG, PLATFORM_FEES } from './constants'

/**
 * Format currency in South African Rand
 */
export function formatCurrency(amount: number): string {
  return new Intl.NumberFormat('en-ZA', {
    style: 'currency',
    currency: 'ZAR',
    minimumFractionDigits: 0,
    maximumFractionDigits: 2,
  }).format(amount)
}

/**
 * Format date for display
 */
export function formatDate(date: string | Date): string {
  return new Intl.DateTimeFormat('en-ZA', {
    weekday: 'short',
    day: 'numeric',
    month: 'short',
    year: 'numeric',
  }).format(new Date(date))
}

/**
 * Format time for display (24h format common in SA)
 */
export function formatTime(time: string): string {
  // Handle HH:mm:ss or HH:mm format
  const [hours, minutes] = time.split(':')
  return `${hours}:${minutes}`
}

/**
 * Calculate platform fee
 */
export function calculatePlatformFee(amount: number): number {
  const feePercent = PLATFORM_FEES.ticketing.commissionPercent + PLATFORM_FEES.ticketing.platformFeePercent
  return Math.round(amount * (feePercent / 100) * 100) / 100
}

/**
 * Calculate net amount after platform fee
 */
export function calculateNetAmount(amount: number): number {
  return amount - calculatePlatformFee(amount)
}

/**
 * Generate a unique reference code
 */
export function generateReference(prefix: string = 'REF'): string {
  const timestamp = Date.now().toString(36)
  const random = Math.random().toString(36).substring(2, 8).toUpperCase()
  return `${prefix}-${timestamp}-${random}`
}

/**
 * Generate a ticket code
 */
export function generateTicketCode(): string {
  const random = Math.random().toString(36).substring(2, 10).toUpperCase()
  return `ZYW-${random}`
}

/**
 * Check if an event date is in the past
 */
export function isEventPast(eventDate: string): boolean {
  const today = new Date()
  today.setHours(0, 0, 0, 0)
  return new Date(eventDate) < today
}

/**
 * Get days until event
 */
export function getDaysUntilEvent(eventDate: string): number {
  const today = new Date()
  today.setHours(0, 0, 0, 0)
  const event = new Date(eventDate)
  const diff = event.getTime() - today.getTime()
  return Math.ceil(diff / (1000 * 60 * 60 * 24))
}

/**
 * Truncate text with ellipsis
 */
export function truncate(text: string, maxLength: number): string {
  if (text.length <= maxLength) return text
  return text.substring(0, maxLength - 3) + '...'
}

