  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_ROLE_KEY!
);

// =====================================================
// TYPES
// =====================================================

export type NotificationType =
  | 'booking_request'
  | 'booking_accepted'
  | 'booking_declined'
  | 'booking_confirmed'
  | 'booking_cancelled'
  | 'booking_completed'
  | 'payment_received'
  | 'payment_failed'
  | 'payout_sent'
  | 'payout_completed'
  | 'refund_issued'
  | 'ticket_purchased'
  | 'ticket_checkin'
  | 'event_reminder'
  | 'event_cancelled'
  | 'event_updated'
  | 'review_requested'
  | 'welcome'
  | 'profile_verified'
  | 'review_received'
  | 'message_received';

export interface CreateNotificationParams {
  userId: string;
  type: NotificationType;
  title: string;
  message: string;
  link?: string;
  eventId?: string;
  bookingId?: string;
  transactionId?: string;
  metadata?: Record<string, unknown>;
  sendEmail?: boolean;
}

export interface Notification {
  id: string;
  user_id: string;
  type: NotificationType;
  title: string;
  message: string;
  link: string | null;
  event_id: string | null;
  booking_id: string | null;
  transaction_id: string | null;
  metadata: Record<string, unknown>;
  read: boolean;
  read_at: string | null;
  email_sent: boolean;
  created_at: string;
}

